with new_qas(youtube_id, doctor_slug, question, answer, meta, keywords) as (
  values
    ('1sZoEppv0Z8', 'jeonghanmi', '피부과 의사들도 비타민C 앰플을 꼭 챙겨 바르나요?', '미백과 항산화는 물론 콜라겐을 재생시키는 효과까지 입증돼 있어 피부과 의사들도 꾸준히 바르고 있습니다. 비타민C는 기미와 주근깨 같은 색소를 옅게 하고 노화로 거칠어진 피부결을 매끄럽게 한다는 임상 결과가 잘 정리돼 있습니다. 손상받은 피부세포에 발랐을 때 염증을 줄이고 손상 자체를 막아주는 항산화 효과도 입증돼 있습니다. 1987년 미국 듀크대학의 Sheldon Pinnell 교수가 비타민C가 콜라겐 합성을 유도한다는 사실을 세계 최초로 발표했고, 그래서 비타민C의 아버지라는 별명을 얻었습니다. 콜라겐이 늘어나면 피부가 탱탱해지고 부드러워지며 주름까지 줄어들기 때문에 단순 미백을 넘어 안티에이징 핵심 성분으로 자리잡은 것입니다. 바나나 실험에서도 비타민C를 바른 쪽만 색이 변하지 않을 정도로 산화 방지력이 분명합니다.', '비타민C 앰플의 미백·항산화·콜라겐 재생 효과를 피부과 전문의 정한미가 정리합니다.', array['비타민C', '항산화', '콜라겐', '미백', '안티에이징', 'CE페룰릭']::text[]),
    ('1sZoEppv0Z8', 'jeonghanmi', 'CE페룰릭이 비싼데도 피부과 의사들이 고집하는 이유가 뭔가요?', '비타민C에 비타민E와 페룰릭애씨드가 결합돼 가장 안정적이고 강력한 항산화 조합이기 때문입니다. 비타민C는 효과가 좋지만 공기와 빛을 만나면 금방 변성돼 기능을 잃어버리는 단점이 있는데, Pinnell 교수가 비타민E와 페룰릭애씨드를 함께 넣으면 안정성이 크게 올라간다는 사실을 밝혀냈습니다. 비타민E는 비타민C 효과를 보조하면서 피부 브라이트닝 역할을 더해주고, 페룰릭애씨드는 비타민C를 안정화하면서 자외선으로부터 피부를 보호하는 효과까지 갖고 있습니다. 스킨수티컬즈의 CE페룰릭은 이 세 가지 조합 그대로 만들어진 대표 제품이라 30ml 20만원대로 비싼데도 피부과 의사들이 꾸준히 사용해온 이유가 여기 있습니다. 단순한 항산화 앰플이 아니라 30년 전 연구를 토대로 한 과학적 배경이 담긴 제품이에요. 변성에 강하고 효과가 잘 유지되니 한 번에 너무 많이 쓰지 않아도 충분합니다.', 'CE페룰릭의 세 가지 조합과 안정화 원리를 피부과 전문의 정한미가 설명합니다.', array['CE페룰릭', '비타민C', '비타민E', '페룰릭애씨드', '항산화', '스킨수티컬즈']::text[]),
    ('1sZoEppv0Z8', 'jeonghanmi', 'CE페룰릭 너무 비싼데 비슷한 효과의 저렴한 대안이 있나요?', '닥터디퍼런트의 C.E.Q가 동일한 세 가지 조합을 갖춘 가성비 대안으로 추천드립니다. C.E.Q는 비타민C 15%에 비타민E와 페룰릭애씨드까지 같은 조합을 갖추고 있고, 15ml 4만원대 또는 30ml 8만원대 패키지로 CE페룰릭의 약 1/3 가격에 같은 용량을 살 수 있습니다. 바나나 실험으로 비교해도 두 제품 모두 산화 방지력이 비슷하게 유지되는 모습이 확인됩니다. 추가로 코엔자임Q10, 풀러렌, 글루코노락톤 같은 항산화 성분이 함께 들어가 비타민C 안정화를 더욱 도와줍니다. 15ml 용기라 짧게 쓰는 만큼 제품 색상 변화도 CE페룰릭보다 적은 편이에요. CE페룰릭은 휴가 후처럼 피부가 상했을 때 쓰고, 평소엔 C.E.Q로 부담 없이 꾸준히 발라주는 조합도 좋습니다.', 'CE페룰릭 대신 가성비로 쓸 수 있는 C.E.Q 앰플을 피부과 전문의 정한미가 추천드립니다.', array['CEQ', 'CE페룰릭', '비타민C', '가성비', '닥터디퍼런트', '항산화앰플']::text[]),
    ('1sZoEppv0Z8', 'jeonghanmi', '비타민C 앰플 바르면 따가운데 잘못 쓰고 있는 건가요?', 'pH가 낮아 자극이 있을 수 있으니 피부 컨디션을 보고 세안 직후 가장 먼저 바르시면 됩니다. 비타민C는 pH 3.5 이하에서 침투가 잘 되기 때문에 CE페룰릭과 C.E.Q 모두 pH가 3.0 정도로 맞춰져 있습니다. 우리 피부는 pH 4.5~5.5 정도이므로 컨디션이 안 좋을 땐 따갑거나 뒤집어지는 느낌이 들 수 있어, 아토피나 민감 피부는 수분크림이나 재생크림으로 장벽을 회복한 뒤 사용해야 합니다. 바르는 순서는 세안 후 다른 기초 단계 전에 가장 먼저 바르는 것이 흡수에 유리합니다. 한 번에 6~7방울 정도를 떨어뜨려 얼굴과 목 전체에 골고루 두드려 흡수시키면 충분합니다. 아침에 바르면 자외선 손상 보호 효과를 함께 누릴 수 있고, 저녁에도 사용하면 항산화와 콜라겐 효과를 강화할 수 있습니다.', '비타민C 앰플의 pH 자극과 안전한 사용 순서를 피부과 전문의 정한미가 안내합니다.', array['비타민C', 'pH', '민감성피부', '사용순서', '자극', '항산화']::text[]),
    ('ka-QoKJHsYY', 'jeonghanmi', '마데카솔 직접 섞어 바르면 잔주름에 정말 좋은 건가요?', '마데카솔을 화장품에 섞어 바르는 것은 권하지 않습니다. 마데카솔이 피부 재생 효과가 뛰어나다 보니 잔주름에 좋다는 이야기가 나오면서 분말 팩을 만들거나 크림에 섞어 쓰는 분들이 늘고 있습니다. 하지만 마데카솔은 종류가 다양해서 일부 제품에 항생제나 스테로이드가 포함되어 있고, 잘 모르고 바르면 오히려 피부를 망가뜨릴 수 있습니다. 섞어 바르는 과정 자체도 번거롭고 위생적으로 좋지 않습니다. 안전하게 재생 효과를 누리려면 마데카솔의 핵심 성분인 병풀추출물이 들어간 화장품을 사용하시는 게 낫습니다. 성분이 검증된 시카 크림을 고르면 편리하면서도 같은 효과를 기대할 수 있으니 성분표를 꼭 확인해 보세요. 굳이 연고를 섞는 수고를 할 필요가 없습니다.', '마데카솔을 화장품에 섞어 바르면 항생제·스테로이드 부작용 위험이 있습니다. 병풀추출물 시카 크림을 안전한 대안으로 피부과 전문의 정한미가 안내합니다.', array['마데카솔', '잔주름', '병풀추출물', '시카크림', '피부재생', '스테로이드', '항생제']::text[]),
    ('ka-QoKJHsYY', 'jeonghanmi', '병풀추출물이 피부 재생에 좋다는데 근거가 있나요?', '병풀추출물은 논문으로 입증된 피부 재생·회복 성분입니다. 정식 명칭은 센텔라 아시아티카로, 오래전부터 피부 상처 치료에 사용되어 온 역사가 있습니다. 논문에 따르면 효능은 크게 네 가지로 정리됩니다. 첫째 상처 부위에 콜라겐을 합성시켜 빨리 채워 올리는 효과, 둘째 피부 염증을 줄여주는 효과, 셋째 항산화 효과, 넷째 피부 세균을 줄여주는 효과입니다. 이 네 가지가 종합적으로 작용해 망가진 피부를 빠르게 회복시키고 재생을 촉진합니다. 시카 크림이나 재생 크림을 고를 때 병풀추출물 함유 여부를 확인하시면 됩니다. 단순 마케팅이 아니라 실제 근거가 있는 성분이니 안심하고 선택하셔도 좋습니다.', '센텔라 아시아티카(병풀추출물)는 콜라겐 합성·항염·항산화·항균 네 가지 효과가 논문으로 입증된 재생 성분입니다. 작용 원리를 피부과 전문의 정한미가 정리합니다.', array['병풀추출물', '센텔라아시아티카', '콜라겐', '피부재생', '항산화', '시카크림']::text[]),
    ('ka-QoKJHsYY', 'jeonghanmi', '시카 크림에서 마데카소사이드가 왜 중요한 건가요?', '마데카소사이드는 병풀추출물 유효성분 중 가장 강력한 재생 효과를 가진 성분입니다. 병풀추출물에는 마데카소사이드, 아시아티코사이드, 마데카식애시드, 아시아틱애시드 네 가지 유효성분이 들어 있습니다. 네 가지 모두 피부 재생에 효과가 좋지만, 논문에서 마데카소사이드가 가장 강력한 효과를 나타내는 것으로 확인되었습니다. 화장품을 고를 때 병풀추출물이 들어 있는 것은 기본이고, 이 유효성분 네 가지가 성분명으로 직접 기재된 제품이 좋습니다. 특히 마데카소사이드가 포함된 제품을 선택하면 더 높은 재생 효과를 기대할 수 있습니다. 성분표에서 이 이름을 꼭 확인해 보세요. 같은 시카 크림이라도 이 성분 유무에 따라 체감 효과가 달라질 수 있습니다.', '시카 크림을 고를 때 마데카소사이드가 포함된 제품을 선택하면 재생 효과가 더 높습니다. 성분표 확인 방법을 피부과 전문의 정한미가 알려드립니다.', array['마데카소사이드', '병풀추출물', '시카크림', '피부재생', '아시아티코사이드', '성분']::text[]),
    ('ka-QoKJHsYY', 'jeonghanmi', '시카 크림 종류가 너무 많은데 어떻게 골라야 하나요?', '시카 크림은 사용 목적에 따라 데일리용, 나이트용, 집중 재생용으로 나눠 고르시면 됩니다. 데일리로 매일 쓸 제품은 점도가 가벼워 아침에 바르고 메이크업해도 부담 없는 타입을 선택하세요. 아침에 바르긴 좀 무겁지만 저녁 나이트 크림으로 적합한 제품도 있는데, 밤에 듬뿍 바르고 자면 다음 날 피부에 광이 나는 느낌을 줄 수 있습니다. 피부 장벽이 많이 깨져 있거나 레이저 시술 후 상처를 빨리 재생시켜야 할 때는 밀폐력이 높은 포마드 타입이 도움이 됩니다. 다만 어떤 제품이든 본인 피부에 먼저 테스트해 보시는 게 중요합니다. 좋다고 바로 구매하지 마시고 소량 테스트 후 맞는 제품을 고르세요. 올리브영 같은 곳에서 쉽게 시도해볼 수 있습니다.', '데일리용·나이트용·집중 재생용으로 나눠 시카 크림을 선택하는 것이 좋습니다. 레이저 시술 후 적합한 포마드 타입까지 피부과 전문의 정한미가 추천합니다.', array['시카크림', '나이트크림', '피부장벽', '피부재생', '데일리크림', '레이저시술후관리']::text[]),
    ('wFSVmqCdt5w', 'kimjongsik', '목에는 아무것도 안 바르는데 목주름 예방하려면 뭘 해야 하나요?', '얼굴에 바르는 앰플, 크림, 보습제를 목에도 그대로 발라주는 것이 가장 기본이면서 효과적인 방법입니다. 대부분 얼굴에는 좋은 제품을 열심히 바르면서도 목에는 인색하게, 남은 것을 손에 발라 없애는 경우가 많습니다. 그 아까운 것을 목에 발라주는 습관만 들여도 큰 차이를 만들 수 있습니다. 여기에 한 가지를 더하면, 주말에 보습제를 다 바른 뒤 따뜻한 물에 적신 수건을 목에 5분 정도 올려놓아 보세요. 실제로 보습이 더 잘 되는 효과가 있고, 그 위에 보습제를 톡톡 두드려 흡수시켜 주면 됩니다. 목주름은 노화뿐 아니라 구부정한 자세나 휴대폰 사용 습관 때문에도 생기므로, 평소 꾸준한 보습 관리가 예방의 첫걸음입니다. 간단하지만 지금 바로 실천해 보시길 권합니다.', '피부과 전문의 김종식이 목주름 예방을 위한 보습제 활용법과 따뜻한 수건 팩 홈케어를 안내합니다', array['목주름', '보습제', '홈케어', '주름예방', '노화', '보습', '스킨케어']::text[]),
    ('wFSVmqCdt5w', 'kimjongsik', '목 스트레칭이 목주름 예방에 진짜 도움이 되나요?', '네, 목 스트레칭은 의학적으로 목주름 예방에 도움이 됩니다. 주름은 근육의 반대 방향으로 생기는데, 목의 근육은 세로 방향이기 때문에 가로 주름이 잘 생기는 구조입니다. 따라서 반대로 고개를 위로 들어 목을 펴주는 스트레칭을 해주면 주름 예방에 효과적이에요. 방법은 턱을 위로 당겨준 뒤 왼쪽, 오른쪽으로 번갈아 움직여 주면 됩니다. 다만 스트레칭을 알려드리면 다들 하겠다고 하면서도 3일만 지나면 까먹기 쉽습니다. 습관으로 만드는 게 핵심인데, 핸드폰을 오래 사용한 뒤 보상처럼 고개를 위로 한번 들어주는 방식으로 연결하면 꾸준히 실천하기가 훨씬 수월해집니다. 지금 이 순간부터 바로 따라해 보세요.', '피부과 전문의 김종식이 목주름 예방 스트레칭의 의학적 원리와 습관 만드는 팁을 설명합니다', array['목주름', '스트레칭', '주름예방', '홈케어', '자세교정', '가로주름', '노화']::text[]),
    ('wFSVmqCdt5w', 'kimjongsik', '비타민C 앰플 목에 바르려면 아침이 좋나요, 저녁이 좋나요?', '비타민C 앰플은 아침에 바르는 것이 더 효과적입니다. 자외선에 의한 노화와 산화 반응은 낮 동안 계속 일어나기 때문에, 항산화 효과를 제대로 내려면 저녁보다 아침에 바르는 게 유리합니다. 비타민A 크림(스티바A 등)은 자극이 될 수 있으므로 저녁에 발라주시고, 아침에는 비타민C 앰플을 바르는 루틴으로 나눠 사용하시면 가장 좋습니다. 그리고 이것들을 얼굴에만 바르지 마시고 반드시 목까지 함께 발라 주세요. 선크림 역시 얼굴뿐 아니라 목까지 골고루 도포해야 하며, 저녁 세안 시에도 목까지 깨끗이 씻어 주는 것이 중요합니다. 이 세 가지 습관만 잘 지켜도 목주름 때문에 피부과에 오실 일이 크게 줄어들 수 있습니다. 인턴 때부터 꾸준히 실천해 온 습관이니 꼭 따라해 보시길 권합니다.', '피부과 전문의 김종식이 비타민C·비타민A·선크림의 올바른 사용 시간과 목 관리법을 정리합니다', array['비타민C', '비타민A', '선크림', '목주름', '홈케어', '항산화', '자외선차단', '스킨케어']::text[]),
    ('wFSVmqCdt5w', 'kimjongsik', '홈케어로도 안 없어지는 깊은 목주름은 어떻게 해야 하나요?', '홈케어로도 개선되지 않는 깊은 목 가로 주름에는 필러 시술을 가장 추천합니다. 깊은 가로 주름은 타고난 요인이 제일 크기 때문에 홈케어만으로는 한계가 있고, 필러로 간단하게 해결할 수 있어서 굳이 다른 시술을 할 필요가 없습니다. 시술 시 중요한 점은 반드시 퍼지는 성질의 필러를 사용해야 한다는 것입니다. 뭉치는 성질의 필러를 쓰면 엠보싱(울퉁불퉁한 표면)이 오래가거나 없어지지 않는 문제가 생길 수 있어요. 통증은 마취크림만 발라도 충분히 참을 수 있는 정도이며, 작은 용량으로도 볼륨이 잘 채워지는 것이 장점입니다. 논문에 따르면 효과가 1년은 물론 2년까지도 유지되는 것으로 확인됩니다. 다만 멍이나 엠보싱이 며칠에서 일주일 정도 생길 수 있으니, 목폴라로 가릴 수 있는 겨울에 시술받으시는 것을 권해 드립니다.', '피부과 전문의 김종식이 깊은 목주름 필러 시술의 효과와 필러 선택 시 주의점을 안내합니다', array['목주름', '필러', '가로주름', '시술', '엠보싱', '리프팅', '주름시술', '다운타임']::text[]),
    ('9NopfxHDdr8', 'kimjongsik', '인공눈물 얼굴에 바르면 히알루론산 화장품 안 사도 되나요?', '인공눈물에 순도 높은 저분자 히알루론산이 들어있는 건 맞지만, 그걸로 화장품을 대체하기엔 현실적으로 어렵습니다. 히알루론산 성분 인공눈물은 전문의약품이라 안과 진료를 받고 처방받아야 하는 번거로움이 있어요. 순수 히알루론산 성분만 들어있는 인공눈물을 찾기도 어렵고, 알 수 없는 부가 성분들이 포함되어 있을 수 있습니다. 이런 위험성까지 감수하면서 굳이 처방받아 바를 필요는 없다는 게 피부과 의사 입장에서의 판단이에요. 인공눈물 넣다가 눈가에 흐른 걸 톡톡 발라주는 정도는 문제없지만, 피부 보습 목적으로 따로 사서 바르는 건 추천하지 않습니다. 차라리 고분자와 저분자 히알루론산이 적절히 배합된 화장품을 고르는 게 훨씬 효율적이에요.', '인공눈물의 히알루론산을 피부에 바르는 것의 한계와 대안을 피부과 전문의 김종식이 설명합니다.', array['히알루론산', '인공눈물', '저분자히알루론산', '보습', '화장품성분', '스킨케어']::text[]),
    ('9NopfxHDdr8', 'kimjongsik', '히알루론산 바르면 진짜 피부 속까지 흡수되나요?', '저분자 히알루론산은 표피 아래쪽(약 80마이크로미터)까지 투과되지만, 고분자 히알루론산은 피부 표면을 거의 통과하지 못합니다. 피부에는 500달톤 룰이라는 게 있어서 분자량이 500달톤 이상이면 투과가 안 되는데, 히알루론산은 많게는 수백만 달톤에 달하는 큰 물질이에요. 그래서 고분자 히알루론산은 각질층을 통과하기 어렵습니다. 하지만 연구 결과를 보면 저분자 히알루론산은 500달톤보다 분자량이 크더라도 표피 깊숙이 충분히 투과하는 모습을 보여줍니다. 다만 진피 속까지 들어가지는 못하기 때문에 콜라겐 재생이나 리프팅 같은 효과를 기대하기는 어려워요. 보습과 수분 공급 정도의 현실적인 기대를 갖는 게 맞습니다.', '히알루론산의 피부 투과 원리와 고분자·저분자 차이를 피부과 전문의 김종식이 정리합니다.', array['히알루론산', '저분자히알루론산', '피부흡수', '500달톤룰', '보습', '표피투과']::text[]),
    ('9NopfxHDdr8', 'kimjongsik', '히알루론산 화장품 고를 때 저분자만 들어있는 걸 사야 하나요?', '아닙니다. 고분자와 저분자 히알루론산이 적절히 배합된 제품이 가장 좋습니다. 저분자 히알루론산이 표피 깊은 층까지 투과되는 건 맞지만, 고분자 히알루론산도 중요한 역할을 해요. 고분자 히알루론산은 피부 표면에 남아서 주변의 수분을 끌어당겨 광채 나는 효과를 만들어줍니다. 특히 아토피 피부염처럼 피부가 매우 건조하거나 각질층이 무너진 경우에는 바깥에서 수분을 잡아주는 고분자 히알루론산이 더 필요해요. 전성분표에서 소듐하이알루로네이트라고 쓰여 있으면 고분자, 하이드롤라이즈드 하이알루로닉애씨드나 포타슘하이알루로네이트가 있으면 저분자라고 보시면 됩니다. 두 가지가 함께 들어간 제품을 골라야 표면 보습과 깊은 수분 공급을 동시에 챙길 수 있어요.', '히알루론산 화장품의 전성분표 읽는 법과 고·저분자 배합의 중요성을 피부과 전문의 김종식이 안내합니다.', array['히알루론산', '고분자히알루론산', '저분자히알루론산', '전성분표', '보습', '화장품선택']::text[]),
    ('9NopfxHDdr8', 'kimjongsik', '히알루론산이 보습 말고 다른 효과도 있나요?', '네, 히알루론산에는 보습뿐 아니라 항염 효과도 있습니다. 실제 연구 결과를 보면 히알루론산이 염증을 줄여주는 작용을 하기 때문에 여드름 피부나 지루성 피부염, 아토피 피부염처럼 염증이 많은 분들에게도 도움이 돼요. 민감한 피부를 가진 분들도 이 항염 효과 덕분에 히알루론산 성분을 안심하고 사용할 수 있습니다. 다만 광고에서 흔히 말하는 콜라겐 재생이나 리프팅 효과는 바르는 히알루론산으로는 기대하기 어렵습니다. 솔직히 말하면 리프팅과 콜라겐 재생 빼고 나머지 효과는 다 있는 셈이에요. 화장품에 너무 많은 걸 기대하기보다 촉촉하고 광이 나며 염증이 진정되는 정도면 집에서 할 수 있는 케어로는 충분히 좋은 효과입니다.', '히알루론산의 보습 외 항염 효과와 기대할 수 있는 현실적 범위를 피부과 전문의 김종식이 설명합니다.', array['히알루론산', '항염효과', '여드름', '아토피피부염', '민감피부', '보습', '지루성피부염']::text[]),
    ('kVGDrxCgZnE', 'kimjongsik', 'MTS 홈케어가 SNS에서 핫한데 진짜 효과 있나요?', '네, MTS(마이크로니들 테라피 시스템) 홈케어는 그냥 화장품을 바르는 것보다 확실히 효과가 있습니다. MTS는 미세한 바늘로 피부 표면에 작은 자극을 주고, 그 위에 유효 성분을 발라 흡수율을 높이는 방식입니다. 미세한 자극이 가해지면 회복 과정에서 콜라겐이 형성되고, 모공 개선이나 탄력 향상에도 도움이 됩니다. 실제로 피부과에서도 히알루론산 같은 성분을 침투시키기 위해 MTS를 많이 활용하고 있습니다. 가정에서는 0.25mm짜리 표피용 제품을 사용하면 안전하게 홈케어에 응용할 수 있습니다. 다만 피부과 시술만큼의 깊은 침투는 어렵기 때문에, 적절한 수준에서 꾸준히 사용하시는 게 좋습니다. 피부 고민이 있지만 병원에 가기 어려운 분들에게 추천드립니다.', 'MTS는 미세 바늘로 피부에 자극을 줘 유효 성분 흡수율을 높이는 홈케어입니다. 0.25mm 제품의 효과와 원리를 피부과 전문의 김종식이 설명합니다.', array['MTS', '홈케어', '콜라겐', '마이크로니들', '피부흡수', '모공']::text[]),
    ('kVGDrxCgZnE', 'kimjongsik', '집에서 MTS 쓸 때 올바른 방법이 뭐예요?', '가정용 MTS는 인터넷에서 0.25mm짜리 제품을 구매해서 사용하시면 됩니다. 피부 위에서 가볍게 문질러 주되, 한 부위를 문지르고 다른 부위로 옮길 때 반드시 피부에서 떼어낸 뒤 옮겨야 합니다. 붙인 채로 끌면 상처가 나기 때문입니다. 표피층은 0.1mm도 안 되므로 0.25mm짜리의 반만 들어가도 충분히 자극을 줄 수 있어서 세게 누를 필요가 없습니다. 문지른 후 살짝 홍반이 생기고 따끔한 정도가 적당하며, 피가 나도록 욕심내지 마세요. MTS로 자극을 준 뒤에는 원하는 유효 성분의 앰플을 두드려 흡수시켜 주시면 됩니다. 그 다음 시카 성분이 포함된 밤 타입 보습제를 덮듯이 발라 진정시키는 것이 좋고, 마스크팩을 올려놓는 것도 괜찮지만 에센스 성분이 너무 많으면 따가울 수 있으니 주의하세요.', '가정용 MTS는 0.25mm 제품으로 가볍게 문지르고 앰플을 흡수시키는 것이 좋습니다. 올바른 사용법과 진정 케어 방법을 피부과 전문의 김종식이 안내합니다.', array['MTS', '홈케어', '사용법', '보습', '진정케어', '시카', '피부관리']::text[]),
    ('kVGDrxCgZnE', 'kimjongsik', 'MTS 하고 나서 어떤 성분을 바르면 효과가 좋아요?', '본인의 피부 고민에 맞는 유효 성분 하나를 선택해서 바르시면 됩니다. 기미나 색소 고민이 있다면 나이아신아마이드나 트라넥사믹애씨드 성분이 효과적인데, 피부과에서도 실제 시술에 많이 사용하는 성분입니다. 그냥 바르는 것보다 MTS로 살짝 자극을 준 뒤 바르면 흡수가 더 잘 됩니다. CE페룰릭 앰플도 침투율을 높이는 데 도움이 될 수 있습니다. 건조하거나 푸석한 피부가 고민이신 분들은 히알루론산 앰플을 활용해 보세요. 탄력이나 주름 개선을 원하신다면 아데노신 성분이나 펩타이드 성분을 추천드립니다. 유효 성분을 바른 뒤에는 진정 효과가 좋은 밤 타입 크림으로 마무리하시면 충분합니다.', 'MTS 후 기미엔 나이아신아마이드, 건조엔 히알루론산, 주름엔 펩타이드. 피부 고민별 추천 성분을 피부과 전문의 김종식이 정리합니다.', array['MTS', '나이아신아마이드', '트라넥사믹애씨드', '히알루론산', '아데노신', '펩타이드', '기미']::text[]),
    ('kVGDrxCgZnE', 'kimjongsik', '피부가 민감한데 집에서 MTS 홈케어 써도 괜찮을까요?', '피부가 민감하거나 트러블이 잘 생기는 분들은 MTS를 사용하지 않는 것이 좋습니다. MTS는 피부 장벽을 일부러 살짝 무너뜨렸다가 회복시키는 원리이기 때문에, 장벽이 약한 분들에게는 오히려 자극이 됩니다. 자외선에 많이 노출되어 피부 컨디션이 안 좋을 때도 피하세요. 사용 빈도는 일주일에 한 번이나 한 달에 1~2회 정도가 적당하며, 피부가 회복할 시간을 충분히 주셔야 합니다. 위생 관리도 매우 중요한데, 사용 전 알코올에 담가 소독한 뒤 완전히 건조시키고 사용하시거나 일회용 제품을 쓰는 것을 권합니다. 만약 사용 중 트러블이나 염증이 생겼다면 즉시 중단하고 피부과에서 치료를 받으시는 게 좋습니다.', '민감성 피부나 트러블 잦은 분은 MTS 사용을 피해야 합니다. 적정 사용 빈도와 소독·위생 관리 주의사항을 피부과 전문의 김종식이 안내합니다.', array['MTS', '주의사항', '민감피부', '피부장벽', '소독', '위생관리', '홈케어']::text[]),
    ('cZXZ88wUgeY', 'baejungmin', '백반증에 홍삼 먹으면 오히려 안 좋다는 게 사실인가요?', '네, 백반증은 자가면역 질환이기 때문에 면역력을 높이는 인삼이나 홍삼이 오히려 좋지 않습니다. 보통 감기에 걸리면 면역력을 올려야 한다고 생각하지만 자가면역 질환은 정반대예요. 백반증은 내 면역세포가 나의 멜라닌 세포(색소를 만드는 세포)를 침입자로 규정하고 공격해서 피부가 하얗게 변하는 병입니다. 비정상적인 자가면역 반응을 떨어뜨려야 하는 상황에서 면역력을 높이면 오히려 공격이 더 심해질 수 있어요. 관절세포를 공격하면 류마티스 관절염, 장세포를 공격하면 염증성 장질환이 되듯이 백반증도 같은 원리입니다. 그래서 백반증 환자분들은 면역 강화 건강식품을 무분별하게 복용하지 마시고, 치료 방향은 반드시 주치의와 상의하시길 권합니다.', '백반증 환자가 면역 강화 식품을 피해야 하는 이유를 피부과 전문의 배정민이 설명합니다.', array['백반증', '자가면역질환', '홍삼', '면역력', '멜라닌세포', '면역억제']::text[]),
    ('cZXZ88wUgeY', 'baejungmin', '백반증 연고 프로토픽은 얼마나 효과가 있나요?', '프로토픽 단독 사용 시 약 18%의 치료 효과가 보고되며, 얼굴 백반증의 경우 단독으로도 65%에서 효과를 보입니다. 프로토픽은 스테로이드가 들어있지 않은 면역 억제 연고로, 원래 아토피 피부염 치료제로 개발되었지만 백반증에도 널리 쓰이고 있어요. 특히 엑시머 레이저와 병행하면서 하루 2회 프로토픽을 열심히 바르면 치료 성공률을 2배가량 높이고 치료 실패율은 절반으로 줄일 수 있습니다. 치료가 종결된 뒤에도 백반증이 있던 부위에 프로토픽을 계속 바르면 재발률을 40%에서 10%까지 줄일 수 있어요. 처음 바를 때 화끈거리는 작열감이 있을 수 있지만 대부분 2주 내에 사라집니다. 모낭염이 생기면 도포를 잠시 중단하고 항생제 치료 후 다시 시작하면 됩니다.', '백반증 치료 연고 프로토픽의 효과와 엑시머 레이저 병행 전략을 피부과 전문의 배정민이 안내합니다.', array['백반증', '프로토픽', '엑시머레이저', '연고치료', '재발방지', '면역억제연고']::text[]),
    ('cZXZ88wUgeY', 'baejungmin', '백반증 연고는 하얀 부분에만 바르면 되나요?', '아닙니다. 연고는 하얀 곳만 골라 바르면 안 되고, 주변으로 넓게 도포해야 합니다. 백반증이 주변으로 퍼지는 것을 예방하고 새로운 병변이 생기는 것까지 막아야 하기 때문이에요. 특히 손끝, 손가락, 손마디, 손등에 백반증이 있는 경우에는 손 전체에 연고를 도포하는 것을 강력히 추천합니다. 출근 전에 연고를 바르기 불편하다면 도포 후 씻어내더라도 약 성분이 어느 정도 흡수되기 때문에 씻어내더라도 바르는 것이 낫습니다. 스테로이드 연고의 경우 강한 것을 단기간 쓰고 끊는 게 효과적이며, 눈 주변이나 겨드랑이처럼 피부가 연한 부위에는 부작용 위험이 있어 피하는 게 좋아요. 어떤 연고를 어디에 얼마나 바를지는 주치의와 상의하셔서 결정하시는 게 가장 안전합니다.', '백반증 연고의 올바른 도포 범위와 부위별 주의사항을 피부과 전문의 배정민이 정리합니다.', array['백반증', '연고도포', '스테로이드연고', '프로토픽', '엘리델', '손백반증']::text[]),
    ('cZXZ88wUgeY', 'baejungmin', '백반증 피부이식 수술은 아무 때나 받아도 되나요?', '아닙니다. 백반증이 충분히 안정화된 상태, 통상적으로 1년 이상 병변이 커지지 않고 새로운 병변이 생기지 않았을 때 수술을 결정합니다. 백반증이 아직 번지고 있는 상태에서 이식 수술을 해도 효과가 좋지 않기 때문이에요. 수술은 정상 피부에서 0.5~0.8mm 크기로 작은 펀치를 이용해 색소 세포를 채취한 뒤 백반증 부위에 심어주는 미세펀치 이식술이 널리 시행되고 있습니다. 심어진 색소세포가 주변으로 퍼져나가려면 수술 후에도 엑시머 레이저나 자외선 치료가 추가로 필요해요. 넓은 면적의 백반증은 세포 단위로 분리하여 한꺼번에 수술하는 방법도 있습니다. 환자의 나이, 백반증 종류, 크기, 위치에 따라 성공률과 부작용이 다르므로 경험 있는 피부과 전문의와 충분히 상의하시기 바랍니다.', '백반증 피부이식 수술의 적절한 시기와 방법을 피부과 전문의 배정민이 안내합니다.', array['백반증', '피부이식', '미세펀치이식술', '엑시머레이저', '색소세포', '수술시기']::text[]),
    ('GnzkIDdyxtc', 'kanghyunjin', '스티바A 크림 단종됐는데 대신 뭘 발라야 하나요?', '스티바A 크림의 대체제로는 디페린, 아크리프, 투앤티 크림, 그리고 비타리프트A 크림이 있습니다. 이 제품들은 모두 비타민A 유도체인 레티노이드 성분으로, 피부에 바르면 각질세포의 턴오버 주기를 빠르게 해서 피부결을 매끈하게 만들어 줍니다. 또한 모공이 막혀 생기는 여드름을 개선하고, 멜라닌 색소 생성 효소의 활성을 낮춰 기미나 색소침착 완화에도 도움이 됩니다. 꾸준히 바르면 콜라겐 합성을 유도해 피부 탄력까지 좋아지는 효과를 기대할 수 있습니다. 레티노이드는 1세대부터 4세대까지 나뉘는데, 스티바A와 투앤티는 1세대 트레티노인, 디페린은 3세대 아다팔렌, 아크리프는 4세대 트리파로텐 성분입니다. 본인 피부 타입에 맞는 대체제를 찾아 꾸준히 사용하시는 것을 권해 드립니다.', '스티바A 단종 후 디페린·아크리프·투앤티·비타리프트A가 대안입니다. 레티노이드 세대별 특징과 선택 기준을 피부과 전문의 강현진이 안내합니다.', array['스티바A', '레티노이드', '트레티노인', '안티에이징', '피부결', '콜라겐', '색소침착']::text[]),
    ('GnzkIDdyxtc', 'kanghyunjin', '지성이고 여드름 잘 나는데 디페린이 잘 맞을까요?', '디페린은 피지 분비가 많거나 여드름이 자주 생기는 분들에게 효과가 좋은 제품입니다. 3세대 레티노이드인 아다팔렌 0.1%가 주 유효성분이며, 친유성(유분기에 친화적인 성질)이 높아 지성 피부에 특히 적합합니다. 스티바A에 비해 확실히 순한 편이기 때문에 피부가 예민하신 분들도 홈케어로 시도해 보시기 좋습니다. 아직 광노화 치료제로 허가를 받지는 않았지만, 128명을 대상으로 24주간 진행한 연구에서 트레티노인과 비슷한 수준의 주름 및 색소 개선 효과가 확인되었습니다. 지성 피부라면 산뜻한 겔 타입을, 건성 피부라면 크림 타입을 선택하세요. 여드름 치료와 피부결 개선을 동시에 원하시는 분께 추천드립니다.', '디페린은 아다팔렌 성분으로 지성·여드름 피부에 특히 효과적입니다. 겔·크림 타입별 선택법과 연구 결과를 피부과 전문의 강현진이 설명합니다.', array['디페린', '아다팔렌', '여드름', '지성피부', '레티노이드', '피부결', '홈케어']::text[]),
    ('GnzkIDdyxtc', 'kanghyunjin', '4세대 레티노이드 아크리프는 뭐가 다른 건가요?', '아크리프는 가장 최근 나온 4세대 레티노이드인 트리파로텐 0.005%를 유효성분으로 한 신약입니다. 이전 세대보다 피부에서 분해되는 속도가 빠르기 때문에 얼굴뿐 아니라 가슴이나 등처럼 넓은 면적에 발라도 부작용이 덜하다는 큰 장점이 있습니다. 2019년 미국 FDA에서 9세 이상의 얼굴과 몸 여드름 치료제로 승인을 받았고, 연구에서 색소침착 개선 정도가 다른 군보다 높게 나타났습니다. 처음 사용할 때는 쌀알 크기만큼 짜서 보습제와 섞어 취침 전에 바르는 것이 좋습니다. 다만 순하다는 인식 때문에 많은 양을 한꺼번에 바르면 피부가 뒤집어질 수 있으니 소량부터 적응해 나가세요. 제형은 겔과 크림의 중간 정도로 발림성이 매끄럽고 펌핑 방식이라 양 조절이 편리합니다.', '4세대 레티노이드 아크리프는 얼굴과 몸에 모두 사용 가능하고 부작용이 적습니다. FDA 승인 성분의 특징과 사용법을 피부과 전문의 강현진이 정리합니다.', array['아크리프', '트리파로텐', '레티노이드', '여드름', '색소침착', '안티에이징', '피부결']::text[]),
    ('GnzkIDdyxtc', 'kanghyunjin', '병원 처방 없이 살 수 있는 레티노이드 제품도 있나요?', '네, 처방 없이 구매할 수 있는 레티노이드 화장품이 있습니다. 디페린, 아크리프, 투앤티 같은 연고는 전문의약품이라 병원 처방이 필요하지만, 레티날 성분의 화장품은 시중에서 바로 구매가 가능합니다. 레티날은 피부에 바르면 레티노산으로 전환되면서 레티노이드 효과를 나타내는 성분입니다. 전문의약품에 비해 자극감이 확실히 덜해서 부담 없이 사용할 수 있다는 것이 큰 장점입니다. 다양한 농도의 레티날 제품이 시중에 나와 있으며 계속 업그레이드되고 있어 앞으로도 기대되는 대체제 후보입니다. 예민한 피부이거나 스킨케어로 레티노이드를 처음 시작하시는 분들이 입문용으로 사용해 보시면 좋겠습니다.', '병원 처방 없이 살 수 있는 레티날 화장품은 자극이 적어 레티노이드 입문용으로 좋습니다. 특징과 장점을 피부과 전문의 강현진이 안내합니다.', array['레티날', '레티노이드', '레티노산', '안티에이징', '홈케어', '스킨케어', '피부결']::text[]),
    ('3WhIyPMKCKc', 'kwonsuhyun', '임신 중에 레티놀이나 스티바A 발라도 괜찮나요?', '아니요, 임신 준비 기간을 포함해 임신 중에는 바르는 레티노이드 성분을 중단하셔야 합니다. 먹는 레티노이드는 태아 기형이 증명된 Category X 약물이고, 바르는 레티노이드는 태아에 큰 문제가 없다는 연구가 있지만 위험을 감수할 이유가 없습니다. 레티놀 기능성 화장품도 임신 초기 여성 235명 대상 연구에서 태아 발달에 영향을 줄 수 있어 사용하지 않는 것이 좋습니다. 대신 레티놀을 대체할 수 있는 바쿠치올을 추천드립니다. 바쿠치올은 식물 유래 성분으로 레티놀과 유사한 기능을 하면서 자극감이 적기 때문에 임산부도 안전하게 사용할 수 있습니다. 스티바A 크림이나 디페린 연고 같은 제품은 출산 이후 다시 사용을 시작하시면 됩니다.', '피부과 전문의 권수현이 임신 중 레티놀과 레티노이드 사용 가능 여부 및 대체 성분을 안내합니다', array['임산부', '레티놀', '레티노이드', '바쿠치올', '스티바A', '디페린', '임신', '홈케어']::text[]),
    ('3WhIyPMKCKc', 'kwonsuhyun', '임신하면 기미가 심해지는데 레이저 토닝 받아도 되나요?', '임신 중 레이저 토닝은 꼭 필요한 경우가 아니라면 추천드리지 않습니다. 임산부의 절반 이상이 기미를 경험하는데, 에스트로겐과 프로게스테론 같은 여성호르몬이 증가하면서 멜라닌 색소가 늘어나기 때문입니다. 수면 질 저하와 스트레스도 기미 발생에 영향을 미칠 수 있습니다. 레이저 토닝 자체가 태아에게 직접 기형을 유발하지는 않지만, 임산부 대상 장기간 대규모 연구가 없어 권하지 않습니다. 다만 결혼식을 앞둔 경우에 한해 의사 상의 후 낮은 에너지로 받는 것은 고려해볼 수 있습니다. 기미 예방을 위해서는 무기자차 선크림을 꼼꼼히 바르시고, 가시광선까지 차단하는 틴티드 선크림도 좋은 선택입니다.', '피부과 전문의 권수현이 임신 중 기미 원인과 레이저 토닝 가능 여부를 설명합니다', array['임산부', '기미', '레이저토닝', '선크림', '무기자차', '색소침착', '임신']::text[]),
    ('3WhIyPMKCKc', 'kwonsuhyun', '임신 중 여드름 심한데 바를 수 있는 연고가 있나요?', '임산부가 사용할 수 있는 여드름 연고로는 아젤리아 연고와 클린다마이신 성분 연고를 추천드립니다. 임신하면 호르몬 불균형으로 피지 분비량이 늘어나 여드름이 생기기 쉽고, 밀가루나 단 음식 섭취 증가와 수면 질 저하도 원인이 됩니다. 먹는 약은 임신 중 복용이 불가능하므로 바르는 약을 활용하셔야 합니다. 아젤리아 연고는 약국에서 구매 가능하고, 더 심한 부위에는 클린다마이신 항생제 성분인 듀오클린, 크레오신티, 아크닌액을 사용해보실 수 있습니다. 클린다마이신은 Category B로 임산부 사용이 가능한 성분입니다. 여드름이 많이 생기거나 심하게 곪는 경우에는 피부과에서 압출 관리를 받으시는 것도 좋습니다.', '피부과 전문의 권수현이 임신 중 사용 가능한 여드름 연고와 관리법을 정리합니다', array['임산부', '여드름', '아젤리아', '클린다마이신', '연고', '압출', '임신']::text[]),
    ('3WhIyPMKCKc', 'kwonsuhyun', '웨딩 앞둔 임산부인데 받을 수 있는 피부 시술이 있나요?', '네, 임산부도 받을 수 있는 관리가 몇 가지 있습니다. 여드름이 심하면 압출 관리를 받을 수 있고, 더 심한 경우 AHA 성분인 GA필링이 가능합니다. 초음파 관리인 LDM이나 SONO 관리, 그리고 연예인 필링이라 불리는 PHA 필링도 해보실 수 있습니다. 반면 써마지나 올리지오 같은 고주파 시술은 몸에 전류를 흘려보내기 때문에 추천드리지 않습니다. 울쎄라나 슈링크 같은 초음파 시술도 마취 연고가 필요하고 통증으로 긴장하면서 태아에게 안 좋은 영향을 줄 수 있어 권하지 않습니다. 마취 연고 성분인 리도카인은 Category B 약물로 꼭 필요한 경우 국소적 사용은 가능하지만, 불필요한 시술에 무분별하게 쓰는 것은 자제하시는 게 좋겠습니다.', '피부과 전문의 권수현이 웨딩을 앞둔 임산부의 가능한 시술과 주의사항을 안내합니다', array['임산부', '웨딩', '써마지', '울쎄라', '필링', '리프팅', '시술', '마취연고']::text[]),
    ('J6-J2_y8v2E', 'kimsoohyung', '시술은 받고 싶은데 통증이 겁나요, 수면 마취 말고 방법 없나요?', '비수면 호흡 마취는 수면 마취 없이도 통증을 확실히 줄일 수 있는 좋은 선택지입니다. 졸음을 유발하는 아산화질소 가스를 마시면서 몽롱한 상태를 유지하는 방식인데, 술에 만취했을 때처럼 잠들 것 같은 느낌이 쭉 이어진다고 보시면 됩니다. 호스를 입에 물거나 마스크를 대고 호흡하며, 얼굴 전체 시술일 경우 코마개를 끼고 구강 호흡으로 진행합니다. 기계에서 아산화질소와 산소 농도를 조절하고, 손톱에 산소 포화도 측정 장치를 붙여 실시간으로 모니터링하기 때문에 안전성도 확보됩니다. 완전히 잠드는 수면 마취와 달리 의식이 유지되므로 의료진의 요청에 협조도 가능하고, 시술 후 회복도 빠른 편이에요. 아픈 건 싫은데 수면 마취까지는 부담스러운 분들에게 적합한 마취 방법입니다.', '비수면 호흡 마취의 원리와 시술 방법을 피부과 전문의 김수형이 설명합니다', array['비수면마취', '호흡마취', '아산화질소', '통증', '시술', '마취', '수면마취']::text[]),
    ('J6-J2_y8v2E', 'kimsoohyung', '비수면 마취는 금식도 필요 없다는데, 수면 마취랑 뭐가 다른 건가요?', '비수면 마취는 금식이 필요 없고 회복이 빠른 것이 수면 마취와의 가장 큰 차이입니다. 수면 마취는 혈관으로 마취제를 주입해 완전히 잠든 상태에서 시술하기 때문에 금식이 필수이고, 마취가 덜 깬 경우가 있어 당일 운전도 삼가야 합니다. 반면 비수면 마취는 더 얕은 상태로 유지되어 마취 전후 회복 속도가 훨씬 빠릅니다. 마취가 끝나면 산소를 높게 틀어 3분간 호흡하시면 대부분 정상으로 돌아오고, 병원에서 안전을 위해 15분 정도 경과를 지켜본 뒤 귀가하도록 안내드리고 있습니다. 시술 중에도 의식이 유지되므로 고개 방향을 바꾸는 등 협조가 가능하다는 것도 장점이에요. 간편하게 마취 효과를 누리면서도 일상 복귀가 빨라야 하는 분들에게 추천합니다.', '수면 마취와 비수면 마취의 차이와 장점을 피부과 전문의 김수형이 안내합니다', array['비수면마취', '수면마취', '금식', '회복', '통증', '마취', '시술']::text[]),
    ('J6-J2_y8v2E', 'kimsoohyung', '비수면 마취로 통증이 진짜 많이 줄어들어요? 근거가 있나요?', '논문 기준으로 비수면 호흡 마취는 일반 마취 주사만 맞았을 때보다 통증이 약 74% 감소합니다. 피부암 수술 환자 400명을 대상으로 통증을 0~10점으로 평가한 연구에서, 일반 마취는 4.6점이었고 비수면 마취는 1.2점을 기록했습니다. 같은 연구에서 냉찜질은 35%, 마취 연고와 진동기는 각각 22%의 진통 효과를 보여 비수면 마취가 압도적으로 우수했습니다. 이 연구는 리도카인 주사라는 비교적 아픈 상황에서 측정한 것이므로, 일반 피부과 시술에서는 진통 효과가 70% 이상 더 좋을 수 있습니다. 실제 환자분들도 마취 연고만 바를 때보다 50% 이상 통증이 줄었다고 평가하셨고, 통증이 0~1점 수준으로 거의 없었다는 분도 계십니다. 숫자로 증명된 만큼 통증 때문에 시술을 망설이시는 분들께 안심이 될 겁니다.', '비수면 호흡 마취의 통증 감소 효과를 논문 근거로 피부과 전문의 김수형이 정리합니다', array['비수면마취', '호흡마취', '통증', '진통효과', '마취연고', '냉찜질', '시술']::text[]),
    ('J6-J2_y8v2E', 'kimsoohyung', '울쎄라처럼 아프기로 유명한 시술도 비수면 마취로 버틸 수 있나요?', '네, 아프기로 유명한 울쎄라도 비수면 호흡 마취를 적용하면 통증 없이 받으실 수 있습니다. 실제로 피부 깊은 층까지 자극을 주는 울쎄라 시술을 비수면 마취 하에 진행했을 때, 시술받으신 분이 "안 아프다"고 답하셨습니다. 환자분들 후기를 보면 통증이 0~1점으로 거의 없었다는 분도 계시고, 마취 연고만 바를 때보다 50% 이상 줄었다고 느끼신 분도 많습니다. 다만 만취한 것 같은 어지러운 느낌이 불편하거나, 시술 후 약간의 울렁거림을 느끼시는 경우가 있을 수 있어요. 의사 입장에서도 환자분이 아파하지 않으니 부담 없이 시술할 수 있다는 장점이 있습니다. 울쎄라처럼 시술 시간이 긴 경우에는 호흡 마취를 함께 받으시는 것을 꼭 추천드립니다.', '울쎄라 같은 고통증 시술에서 비수면 마취 효과를 피부과 전문의 김수형이 안내합니다', array['울쎄라', '비수면마취', '호흡마취', '통증', '리프팅', '시술', '마취']::text[]),
    ('tZuO6L0Q1M0', 'jeonghanmi', '비타민C 세럼 아침에 바르면 오히려 피부에 안 좋다던데 사실인가요?', '아닙니다, 비타민C는 오히려 아침이나 낮에 바르면 더 좋은 효과를 누릴 수 있습니다. 비타민C가 빛과 열에 불안정해서 낮에 바르면 안 된다고 알고 계신 분들이 많은데, 자외선으로 피부가 손상되는 시간이 바로 낮이기 때문에 항산화 보호 효과를 제대로 발휘하려면 낮 사용이 유리합니다. 다만 비타민C를 바른 뒤 자외선에 노출되면 산화되어 본래 기능을 잃을 수 있으므로 반드시 자외선 차단제를 덧발라야 합니다. 비타민C 나이트크림 뒷면에 저녁 사용을 권하는 문구가 있어 혼란스러울 수 있지만, 핵심은 자외선 차단과 함께 사용하는 것이에요. 아침 세안 후 비타민C 세럼을 바르고 차단제까지 마무리하면 가장 효과적인 루틴이 됩니다. 낮 사용이 걱정되셨던 분들은 차단제만 잘 챙기시면 안심하고 쓰셔도 좋습니다.', '비타민C는 오히려 아침에 발라야 항산화 효과를 극대화할 수 있습니다. 자외선 차단제와 함께 쓰는 올바른 루틴을 피부과 전문의 정한미가 안내합니다.', array['비타민C', '비타민C세럼', '자외선차단제', '항산화', '스킨케어', '아침루틴', '피부보호']::text[]),
    ('tZuO6L0Q1M0', 'jeonghanmi', '비타민C 이미 먹고 있는데, 피부에 또 발라야 해요?', '먹는 비타민C와 바르는 비타민C는 작용 기전이 달라서 상호 보완은 가능하지만 대체는 불가능합니다. 먹는 비타민C는 몸 전체의 항산화력을 높여 간접적으로 피부에 도움을 주지만, 위장에서 흡수된 뒤 피부까지 충분한 양이 도달하지 않을 수 있어요. 반면 비타민C를 피부에 직접 바르면 농축된 성분이 바로 작용하기 때문에 콜라겐 생성 촉진이나 미백 효과를 더 확실히 느낄 수 있습니다. 결국 먹는 비타민C는 몸 안에서, 바르는 비타민C는 피부 표면에서 직접 작용하는 것이라 역할 자체가 다릅니다. 둘 중 하나만 해도 도움이 되지만 섭취와 도포를 함께 하면 피부 건강에 훨씬 효과적이에요. 이미 비타민C를 드시고 계시다면 세럼까지 추가해 보시길 권합니다.', '먹는 비타민C는 몸 전체에, 바르는 비타민C는 피부에 직접 작용해 역할이 다릅니다. 둘을 함께 쓰는 활용법을 피부과 전문의 정한미가 안내합니다.', array['비타민C', '먹는비타민C', '콜라겐', '미백', '항산화', '스킨케어', '비타민C세럼']::text[]),
    ('tZuO6L0Q1M0', 'jeonghanmi', '레티놀이랑 비타민C 같이 바르면 피부 망가지나요?', '레티놀과 비타민C는 함께 사용해도 되며, 두 성분을 절대 같이 쓰면 안 되는 이유는 없습니다. 다만 핵심은 자극감이 없어야 한다는 점인데, 비타민C는 따가움과 가려움을, 레티놀은 건조함과 따가움을 유발할 수 있는 성분이라 둘이 합쳐지면 자극이 더 강해질 수 있어요. 같이 사용했을 때 괜찮다면 그대로 쓰셔도 됩니다. 만약 자극감이 느껴진다면 비타민C부터 피부에 적응시킨 뒤 레티놀을 추가하는 방법을 시도해 보세요. 그래도 자극이 심하다면 비타민C는 아침에, 레티놀은 저녁에 바르거나, 요일을 나눠서 번갈아 사용하시는 것도 좋은 방법입니다. 자신의 피부 컨디션에 맞게 조절하는 것이 가장 중요하니 무작정 겁내실 필요는 없어요.', '레티놀과 비타민C는 함께 써도 되지만 자극이 느껴지면 시간대나 요일을 나눠 사용하는 것이 좋습니다. 안전한 병행법을 피부과 전문의 정한미가 정리합니다.', array['레티놀', '비타민C', '자극감', '스킨케어', '피부적응', '민감피부', '성분조합']::text[]),
    ('tZuO6L0Q1M0', 'jeonghanmi', '비타민C 앰플 색이 노래졌는데 아까워서 못 버리겠어요, 써도 되나요?', '색이 조금 변했다고 반드시 버려야 하는 것은 아니지만, 개봉 후에는 최대한 빨리 사용하시는 게 좋습니다. 비타민C 앰플이 노랗게 변했다는 것은 빛, 열, 공기에 의해 산화가 일어났다는 의미이며, 산화된 비타민C는 효과가 떨어지고 피부 자극감도 심해질 수 있어요. 유통기한이 남아 있더라도 색상 변화는 실제 변성을 나타내므로 주의가 필요합니다. 색이 심하게 변했거나 이상한 냄새가 나거나 질감이 달라졌다면 제품이 상했을 가능성이 있으니 사용을 중단하세요. 변성을 막으려면 개봉 후 서늘하고 빛이 없는 곳에 보관하시는 것이 좋습니다. 아껴 바르기보다 색이 변하기 전에 충분히 사용하는 것이 비타민C 효과를 최대로 누리는 방법이에요.', '비타민C 앰플이 노랗게 변했다면 산화가 진행된 것입니다. 효과 감소와 자극 증가 위험, 올바른 보관법을 피부과 전문의 정한미가 안내합니다.', array['비타민C', '비타민C앰플', '산화', '변성', '보관법', '스킨케어', '유통기한']::text[]),
    ('fILJTripb54', 'kimjongsik', 'VT리들샷이 피부에 구멍을 뚫는다는데, 원리가 뭔가요?', 'VT리들샷은 시카 리들이라는 바늘 모양의 미세 입자가 피부 각질층에 작은 구멍을 내서 유효 성분의 흡수를 높여주는 에센스 제형 화장품입니다. 시카 리들은 실리카와 병풀추출물로 이루어진 성분으로, 화학 명칭은 스피큘이며 피부과 해초 필링에 쓰이는 것과 같은 성분이에요. 바늘 모양 입자가 각질층에 미세한 구멍을 내면 그 구멍을 통해 에센스의 유효 성분이 흡수되고, 구멍이 난 피부는 자연스럽게 재생 과정을 거치면서 상태가 개선됩니다. 이 방식은 MTS 롤러와 원리가 비슷한데, MTS가 물리적 바늘 롤러로 직접 구멍을 내는 반면 VT리들샷은 화장품 안에 입자를 넣어 바르기만 해도 같은 효과를 내도록 만든 것이죠. 피부 재생과 성분 흡수를 동시에 기대할 수 있어 홈케어용으로 활용하기 좋은 제품입니다.', 'VT리들샷의 시카 리들 원리와 MTS와의 차이를 피부과 전문의 김종식이 설명합니다.', array['VT리들샷', '시카리들', '스피큘', '각질층', 'MTS', '홈케어', '피부재생', '해초필링']::text[]),
    ('fILJTripb54', 'kimjongsik', '화장품에 바늘 성분이 들어 있다니 피부에 남으면 위험하지 않나요?', '시카 리들의 실리카 성분은 피부의 가장 바깥 층인 각질층에만 살짝 구멍을 내는 것이라 안전성에 대해 크게 걱정하지 않으셔도 됩니다. 피부는 매일 새로운 각질을 만들어내고 기존 각질은 자연스럽게 탈락시키기 때문에, 실리카 입자도 각질과 함께 자연적으로 빠져나갑니다. 다만 매일 바를 경우 실리카가 얼굴에서 완전히 제거되는지는 정확히 알기 어려워요. 그래서 매일 사용하기보다는 가끔 바르시는 것을 권해드립니다. 실제로 바르는 순간부터 사포로 문지르는 듯한 자극감이 있고, 다음 날 아침까지 통증이 이어질 수 있습니다. 시카 리들이 피부에 남아있는 느낌은 대략 12시간 정도 지속되며 오후쯤부터 자극감이 사라지니, 사용 빈도를 조절하시는 게 좋겠습니다.', 'VT리들샷의 안전성과 사용 빈도 주의사항을 피부과 전문의 김종식이 안내합니다.', array['VT리들샷', '실리카', '안전성', '각질층', '자극감', '홈케어', '사용빈도']::text[]),
    ('fILJTripb54', 'kimjongsik', '모공 고민인데 VT리들샷 효과 볼 수 있을까요, 트러블 피부도 괜찮나요?', '피부가 비교적 튼튼하면서 모공이 고민인 분들에게 가장 효과가 좋습니다. 화장이 잘 안 먹거나 잘 뜨는 분들도 피부결이 매끈해지면서 화장이 잘 먹는 효과를 체감할 수 있어요. 반면 트러블이나 여드름, 염증이 있는 피부에는 사용을 권하기 어렵습니다. 트러블이 많은 분들 중 피부 침투형 관리를 원하시는 경우에는 골드PTT 시술을 추천드리는데, 미세 입자를 초음파 장비로 피부 깊숙이 침투시켜 피지샘까지 도달하게 하고 특정 파장의 레이저로 피지샘과 주변 염증을 함께 제거하는 원리입니다. 피부 깊숙이 확실한 효과를 내려면 피부과 시술이 필요하지만, 집에서 홈케어로 어느 정도의 모공 개선이나 피부결 관리를 하시는 데에는 VT리들샷도 충분히 도움이 됩니다.', 'VT리들샷이 잘 맞는 피부 타입과 대안 시술을 피부과 전문의 김종식이 정리합니다.', array['VT리들샷', '모공', '피부결', '트러블', '여드름', '골드PTT', '홈케어', '피부타입']::text[]),
    ('fILJTripb54', 'kimjongsik', 'VT리들샷 쓰는 날 비타민A나 비타민C도 같이 발라도 되나요?', '절대로 비추천합니다. VT리들샷 자체가 피부에 상당한 자극을 주는 제품인데, 스티바A 크림이나 비타민C처럼 따가울 수 있는 화장품까지 함께 바르면 자극이 과도해집니다. 홈케어 화장품은 항상 안전이 최우선이며, 화장품에 과도한 기대를 하시기보다는 안전하게 사용하면서 적당한 효과를 누리시는 게 바람직해요. VT리들샷을 사용하는 날에는 필링이나 비타민A, 비타민C 제품을 함께 바르지 마시고 재생크림이나 수분크림 같은 가벼운 크림류를 써주세요. 만약 이런 제품들을 같이 쓰고 싶으시다면 같은 날이 아닌 번갈아 사용하시는 방법을 권합니다. 어떤 홈케어 제품이든 내 피부에 잘 맞는지, 안전한지를 먼저 확인하신 뒤 사용하시는 것이 가장 중요합니다.', 'VT리들샷과 비타민A, 비타민C 병행 사용 주의점을 피부과 전문의 김종식이 안내합니다.', array['VT리들샷', '비타민A', '비타민C', '홈케어', '자극', '재생크림', '수분크림', '병행사용']::text[]),
    ('uRYgg7VTfzE', 'kimjongsik', '쥬베룩 맞았는데 효과를 하나도 모르겠어요, 왜 그런 건가요?', '쥬베룩은 적금형 스킨부스터이기 때문에 한 번 맞고 바로 효과를 느끼기 어렵습니다. 리쥬란이나 물광주사처럼 즉각적으로 변화가 나타나는 시술과는 결이 다른 스킨부스터예요. 쥬베룩은 콜라겐 씨앗을 심는 것과 비슷한데, 한 번 두 번 세 번 적립하듯이 맞아 주면 씨앗이 토양에서 열매를 맺듯 피부가 서서히 환해지고 콜라겐이 재생됩니다. 천천히 탄력이 생기고 주름도 개선되면서 피부가 좋아지는 방식이라 즉각적인 변화를 기대하시면 실망하기 쉽습니다. 한 달 간격으로 보통 세 번 정도 꾸준히 맞으시는 것을 추천드리고요. 바로 좋아지고 싶은 분들보다는 내 피부를 장기적으로 가꾸고 관리하고 싶으신 분들께 훨씬 더 적합한 시술입니다.', '피부과 전문의 김종식이 쥬베룩 효과를 못 느끼는 이유와 적금형 스킨부스터의 원리를 설명합니다.', array['쥬베룩', '스킨부스터', '콜라겐', '리쥬란', '피부탄력', '주름개선', '적금형시술']::text[]),
    ('uRYgg7VTfzE', 'kimjongsik', '쥬베룩 맞으면 결절 생긴다던데 정말 괜찮은 시술인가요?', '쥬베룩은 스컬트라와 구조가 다르게 설계되어 결절(피부 아래 뭉침)이 생기는 부작용이 현저히 낮습니다. 수년간 많은 쥬베룩 시술을 해왔는데, 결절처럼 동그랗게 뭉치는 현상이 생기더라도 고주파로 열을 가해 녹여주거나 손으로 마사지만 해줘도 잘 풀어지는 형태를 갖고 있어요. 쥬베룩의 작동 원리를 보면, 비어 있는 공 같은 것을 피부 안에 넣으면 그 안으로 콜라겐이 차오르고 껍질은 서서히 녹아 흡수되는 구조입니다. 피부 안에 아무것도 남지 않고 내 피부만 차올라오기 때문에 부작용도 적은 편이죠. 다만 눈가 주변은 피부가 얇아서 결절이 생기면 불편하고 오래 갈 수 있으므로 주의가 필요합니다. 입가 주변도 움직임이 많아 이물 반응이 생길 가능성이 있으니 경험 많은 전문의에게 시술받으시는 게 중요해요.', '피부과 전문의 김종식이 쥬베룩 부작용과 결절 위험성 및 해결 방법을 안내합니다.', array['쥬베룩', '부작용', '결절', '스컬트라', '콜라겐', '스킨부스터', '안전성']::text[]),
    ('uRYgg7VTfzE', 'kimjongsik', '쥬베룩이랑 리쥬란 뭐가 더 좋아요? 뭘 맞아야 하나요?', '쥬베룩과 리쥬란은 같은 스킨부스터지만 효과와 목적이 확연히 다르므로 피부 상태에 따라 선택해야 합니다. 리쥬란은 폴리뉴클레오타이드 성분으로 피부를 힐링시켜주는 효과가 있어서 상처, 염증, 여드름을 회복시키는 데 탁월합니다. 맞자마자 바로 피부가 좋아지고 속당김이나 속건조 같은 문제가 해결되는 것이 가장 큰 장점이죠. 하지만 시간이 지나면 효과가 떨어지면서 피부가 원래 상태로 되돌아가는 것이 단점이에요. 반면 쥬베룩은 콜라겐을 재생시키는 적금형 시술로, 피부가 얇고 푸석하며 잔주름이 많고 탄력이 떨어지는 분들께 추천됩니다. 리쥬란은 결혼식처럼 중요한 일정 전이나 트러블이 심할 때, 쥬베룩은 장기적으로 피부를 가꾸고 싶을 때 선택하시면 좋습니다.', '피부과 전문의 김종식이 쥬베룩과 리쥬란의 효과 차이와 추천 대상을 정리합니다.', array['쥬베룩', '리쥬란', '스킨부스터', '콜라겐', '피부재생', '속건조', '잔주름']::text[]),
    ('uRYgg7VTfzE', 'kimjongsik', '쥬베룩 볼륨은 일반 쥬베룩이랑 뭐가 다른 건가요?', '쥬베룩과 쥬베룩 볼륨의 가장 큰 차이는 입자 크기이며, 용도 자체가 다릅니다. 쥬베룩이 탁구공만 하다면 쥬베룩 볼륨은 축구공만 한 크기라고 생각하시면 됩니다. 일반 쥬베룩은 전반적인 탄력 개선과 모공 축소, 피부를 탄탄하게 만드는 데 효과적인 스킨부스터에 가까워요. 반면 쥬베룩 볼륨은 입자가 훨씬 커서 볼륨 효과가 크고, 필러 대신 옆볼이나 팔자주름, 눈 밑, 관자놀이 등 얼굴 전체의 볼륨을 채우는 데 적합합니다. 쥬베룩은 피부 질감과 탄력을 개선하는 스킨부스터 쪽이고, 쥬베룩 볼륨은 필러처럼 피부에 볼륨을 채워주는 쪽에 가깝다고 보시면 됩니다. 피부가 얇고 힘이 없는 분은 쥬베룩을, 볼륨이 꺼진 부위가 고민이신 분은 쥬베룩 볼륨을 선택해 보세요.', '피부과 전문의 김종식이 쥬베룩과 쥬베룩 볼륨의 입자 크기와 용도 차이를 설명합니다.', array['쥬베룩', '쥬베룩볼륨', '필러', '스킨부스터', '팔자주름', '콜라겐', '볼륨채움']::text[]),
    ('y1qPplWOdQ0', 'kwonsuhyun', '튼살이 갑자기 생겼는데 붉은 거랑 흰 거는 뭐가 다른 건가요?', '튼살은 피부가 급격히 늘어날 때 아래층의 콜라겐과 엘라스틴 같은 탄력 섬유가 그 속도를 따라가지 못하면서 찢어지고 변성되어 생깁니다. 급격한 체중 증가, 성장기, 임신, 스테로이드 장기 사용, 헬스로 근육이 빠르게 커진 경우 등이 대표적인 원인이에요. 초기에는 콜라겐 뼈대가 무너지면서 염증 반응이 일어나고 혈관이 넓어져 붉게 보이는 붉은 튼살 단계가 됩니다. 이 붉은 튼살을 방치하면 흉터 조직과 유사한 흰 튼살로 진행되는데, 흰 튼살은 치료 난이도가 훨씬 높아집니다. 따라서 붉은 튼살 단계에서 치료를 시작하는 것이 효과가 훨씬 좋으므로, 튼살이 처음 보이기 시작하면 빠르게 피부과 전문의와 상담하시는 것을 권합니다. 문신으로 덮는 경우도 있는데, 시간이 지나면 살 색깔이 변하거나 주변 피부와 차이가 나면서 오히려 더 도드라질 수 있어 추천드리지 않습니다.', '붉은 튼살과 흰 튼살의 차이 및 발생 원인을 피부과 전문의 권수현이 설명합니다', array['튼살', '붉은튼살', '흰튼살', '콜라겐', '탄력섬유', '엘라스틴', '임산부', '성장기']::text[]),
    ('y1qPplWOdQ0', 'kwonsuhyun', '비싼 튼살 크림 사서 발랐는데 효과가 없는 것 같아요, 정말 소용없나요?', '시중 인기 튼살 크림들은 대부분 보습 성분이 주를 이루며 특별한 치료 기능이 있다고 보기는 어렵습니다. 다섯 가지 제품을 분석한 결과 센텔라아시아티카(마데카솔 성분), 히알루론산, 세라마이드, 판테놀 등이 포함되어 있었지만 결국 보습이 주 목적인 제품들이었어요. 반면 코코아 버터, 올리브오일, 아몬드 오일은 튼살에 효과가 없다고 밝혀져 있습니다. 튼살에 효과적이라고 증명된 바르는 약제는 비타민A 제제인 스티바A 크림이나 디페린 같은 연고가 있으며, 진피까지 흡수되어 콜라겐 생성을 촉진하는 원리입니다. 다만 비타민A 제제는 자극감이 있을 수 있고 임산부의 경우 기형아 출산 위험이 있어 사용을 피해야 합니다. 화장품만으로 부족한 콜라겐을 채우기는 거의 불가능하므로, 보습 크림은 튼살 예방이나 악화 방지의 보조 수단으로 활용하세요.', '튼살 크림의 실제 효과와 성분 분석 결과를 피부과 전문의 권수현이 정리합니다', array['튼살', '튼살크림', '보습', '센텔라아시아티카', '히알루론산', '비타민A', '콜라겐']::text[]),
    ('y1qPplWOdQ0', 'kwonsuhyun', '튼살 크림 너무 비싼데 집에서 저렴하게 예방하는 방법 없나요?', '집에 있는 보습제에 바세린이나 오일을 섞어서 충분히 발라주는 것만으로도 튼살 예방에 도움이 됩니다. 튼살 전용 크림은 일반 바디 크림보다 2~3배 비싼데 성분 구성은 보습제와 거의 유사하기 때문에, 일반 보습 크림에 바세린을 섞어 바르는 방법이 경제적이면서도 효과적이에요. 여기에 마사지를 병행하면 피부 당김이 줄어들고 탄력 개선에도 도움이 됩니다. 실제 연구에서 6주간 지속적으로 마사지를 했을 때 약 36% 정도 피부 탄력도가 개선되었다는 결과가 있습니다. 다만 보습과 마사지만으로 모든 튼살을 예방하거나 치료할 수 있는 것은 아니고, 도움이 될 수 있는 수준이라는 점은 기억하셔야 해요. 꾸준한 보습과 마사지를 생활습관으로 유지하면서 튼살이 나타나면 조기에 피부과를 방문해 보세요.', '보습제와 바세린을 활용한 튼살 예방 홈케어법을 피부과 전문의 권수현이 안내합니다', array['튼살', '바세린', '보습', '마사지', '튼살예방', '홈케어', '임산부']::text[]),
    ('y1qPplWOdQ0', 'kwonsuhyun', '이미 흰 튼살이 됐는데 포기해야 하나요, 진짜 치료되긴 하나요?', '포기하지 않으셔도 됩니다. 최근 새로운 치료법들이 나오면서 흰 튼살도 개선이 가능합니다. 먼저 붉은 튼살 단계에서는 브이빔이라는 혈관 레이저로 붉은 부위를 치료하면 효과가 좋고 흰 튼살로의 진행을 막을 수 있어요. 이미 흰 튼살로 진행된 경우에는 쥬베룩 같은 콜라겐 부스터를 주사해 무너진 콜라겐 뼈대를 채워주는 방법이 있습니다. 쥬베룩은 필러와 달리 콜라겐 씨앗 역할을 해서 내 몸의 콜라겐으로 다시 채우는 원리예요. 또한 콜라겐이 부족한 부위에 적절한 양을 일정하게 투여하는 미라젯은 치료 효과와 색소침착 개선도가 좋아 각광받고 있습니다. 울트라 펄스 앙코르라는 프랙셔널 레이저 역시 표면 질감 개선과 콜라겐 생성에 도움을 주는 치료법이니, 피부과 전문의와 상의 후 본인에게 맞는 치료를 받아보세요.', '흰 튼살 치료에 효과적인 쥬베룩, 미라젯, 프랙셔널 레이저를 피부과 전문의 권수현이 안내합니다', array['튼살', '흰튼살', '쥬베룩', '콜라겐', '미라젯', '프랙셔널레이저', '브이빔', '콜라겐부스터']::text[]),
    ('LRFDz4QzM1M', 'jeonghanmi', '각질 제거 주기적으로 하면 피부가 좋아지나요?', '각질 제거를 주기적으로 하는 것은 추천드리지 않습니다. 각질은 피부 가장 바깥에서 보호막 역할을 하는 피부 장벽이기 때문에, 과도하게 벗겨내면 오히려 피부를 손상시키는 결과를 가져옵니다. 피부에 특별한 문제가 없다면 굳이 각질 제거를 하지 않아도 돼요. 중요한 일이 있는 날 어쩌다 한 번 정도는 괜찮지만, 피부를 좋아지게 하려는 목적으로 반복하는 건 좋지 않습니다. 각질이 눈에 띄게 일어난다면 그 자체가 피부 상태가 좋지 않다는 신호이므로, 건조함이나 자극의 원인을 먼저 찾아보세요. 피부 장벽을 회복시켜 줄 수 있는 클렌저나 보습 제품을 사용하시는 게 각질 제거보다 훨씬 효과적입니다.', '각질 제거를 반복하면 피부 장벽이 손상됩니다. 각질이 눈에 띄게 일어나는 원인과 보습 제품으로 해결하는 방법을 피부과 전문의 정한미가 설명합니다.', array['각질', '각질제거', '피부장벽', '필링젤', '보습', '클렌저', '홈케어']::text[]),
    ('LRFDz4QzM1M', 'jeonghanmi', '세안 후 뽀득뽀득한 느낌이 나야 잘 씻은 건가요?', '씻고 나서 뽀득뽀득한 느낌이 나는 것은 장기적으로 피부에 좋지 않습니다. 피부 표면의 기름기는 피부 장벽을 보호하는 중요한 역할을 하는데, 뽀득뽀득하다는 건 이 보호 기름까지 모두 씻겨 나갔다는 뜻이에요. 이런 세안이 반복되면 피부가 건조해지고, 심하면 가렵거나 따가운 증상이 나타날 수 있습니다. 세안 후 부드러운 사용감을 주는 약산성 클렌저가 피부 환경과 비슷하게 만들어져 있어 자극이 적습니다. 다만 피부가 매우 기름진 분이라면 약알칼리성 제품으로 유분을 제거해 주는 게 도움이 되기도 해요. 본인 피부 타입에 맞춰 약산성과 약알칼리성 제품을 필요에 따라 번갈아 사용하시면 됩니다.', '세안 후 뽀득뽀득한 느낌은 보호 기름까지 씻겨나갔다는 신호입니다. 약산성·약알칼리성 클렌저 선택 기준을 피부과 전문의 정한미가 안내합니다.', array['세안', '클렌저', '약산성', '약알칼리성', '피부장벽', '피부건조', '세안법']::text[]),
    ('LRFDz4QzM1M', 'jeonghanmi', '화장품 많이 바를수록 피부가 좋아지는 건가요?', '화장품 개수가 절대적으로 중요한 건 아닙니다. 본인 피부에 잘 맞는 제품 2~3개 정도를 발라서 건조하지 않고 불편하지 않으면 그걸로 충분해요. 피부가 안 좋을수록 여러 제품을 바르려는 경향이 있는데, 사용하는 제품이 많아지면 그중 피부에 맞지 않는 제품이 포함될 확률도 높아져 악순환이 생기기 쉽습니다. 올인원 제품 하나만 써도 불편하지 않다면 그대로 사용해도 됩니다. 트러블이 반복되는 분이라면 AHA, BHA(각질을 부드럽게 하고 피지를 줄여주는 산 성분)가 함유된 토너나 클렌저를 사용해 보세요. 또한 트러블이 잦은 분들은 논코메도제닉(과다 피지를 유발하지 않는) 인증 제품이나 민감성 피부 전용 제품을 선택하시는 게 좋습니다.', '화장품은 많이 바를수록 좋은 것이 아닙니다. 2~3개면 충분한 이유와 트러블 피부의 논코메도제닉 선택법을 피부과 전문의 정한미가 정리합니다.', array['화장품', '스킨케어', 'AHA', 'BHA', '논코메도제닉', '민감성피부', '트러블', '홈케어']::text[]),
    ('LRFDz4QzM1M', 'jeonghanmi', '트러블 자국 색소침착, 연고 발라서 없어질 수 있나요?', '트러블 후 남는 색소침착은 기본적으로 시간이 지나면 자연스럽게 좋아집니다. 하지만 트러블이 심했거나 3~4개월이 지나도 사라지지 않는 경우, 미백 기능 성분이 들어 있는 제품을 발라주면 도움이 돼요. 대표적으로 나이아신아마이드나 비타민C가 효과적인 성분으로 알려져 있습니다. 모공이 넓어지는 게 고민이라면 클렌징을 깨끗하게 해주는 것이 가장 중요해요. 피지샘에서 피지가 많이 분비되면 모공이 넓어질 수밖에 없고, 그 상태에서 세안이 부족하면 모공이 막혀 트러블로 이어지기 때문입니다. 홈케어를 꾸준히 해도 효과가 없거나 계속 악화된다면 피부과 전문의의 진료를 받아보시는 걸 권합니다.', '트러블 자국 색소침착엔 나이아신아마이드·비타민C가 효과적입니다. 모공 관리와 함께 홈케어 방법을 피부과 전문의 정한미가 안내합니다.', array['색소침착', '트러블자국', '나이아신아마이드', '비타민C', '미백', '모공', '클렌징', '홈케어']::text[]),
    ('5mA2eVFd5Bw', 'gohyerim', '인터넷에서 파는 편평사마귀 연고 바르면 없어지나요?', '시중에 나와 있는 편평사마귀 연고는 사실 효과가 없습니다. 성분을 살펴보면 병풍추출물 같은 재생 성분이나 세라마이드 같은 보습 성분, AHA 같은 각질 제거 산성분이 주를 이루는데 특별한 치료 성분은 들어있지 않아요. 이런 제품이 나온 이유는 편평사마귀가 만지거나 긁으면 더 번지는 자가접종 특성이 있어서, 피부 장벽을 보호하면 전염 예방에 어느 정도 도움이 되기 때문입니다. 그렇지만 편평사마귀를 직접 제거하는 효과는 없으니 굳이 따로 구입할 필요 없어요. 이미 세라마이드·콜레스테롤·지방산(세콜지) 성분의 보습제를 쓰고 계시다면 그 제품을 자주 충분히 발라주시는 것으로 충분합니다. 편평사마귀가 의심된다면 보습제에 의지하지 말고 피부과에서 정확한 진단과 치료를 받으시는 게 맞습니다.', '시중 편평사마귀 연고의 실제 효과와 올바른 대처법을 피부과 전문의 고혜림이 설명합니다.', array['편평사마귀', '사마귀연고', '피부장벽', '보습', '자가접종', '세라마이드']::text[]),
    ('5mA2eVFd5Bw', 'gohyerim', '편평사마귀는 어차피 재발하는데 치료해야 하나요?', '네, 편평사마귀는 재발 가능성이 있지만 치료를 안 하면 점차 번지고 가족에게도 전염될 수 있어서 반드시 치료해야 합니다. 감기도 바이러스 질환이지만 증상 완화를 위해 치료하듯이 편평사마귀도 마찬가지예요. 특히 면역력이 떨어진 임산부에서 빠르게 번지는 경우가 많고 수유하는 가슴 부위까지 번질 수 있어서 출산 후 가급적 빨리 치료하시는 걸 추천합니다. 현재로서 가장 확실한 치료법은 이산화탄소 레이저나 어붐야그 레이저로 병변을 하나하나 제거하는 방식이에요. 제거해도 눈에 안 보이던 잠복 병변이 있을 수 있어 재발은 생길 수 있지만, 반복 치료할수록 완치율이 높아지고 재발하더라도 이전보다 훨씬 적게 생깁니다. 병변이 보이면 미루지 말고 바로 피부과에 가시는 게 핵심이에요.', '편평사마귀의 재발에도 치료가 필요한 이유와 레이저 치료 전략을 피부과 전문의 고혜림이 안내합니다.', array['편평사마귀', '레이저치료', '재발', '전염', '임산부', '이산화탄소레이저', '어붐야그레이저']::text[]),
    ('5mA2eVFd5Bw', 'gohyerim', '편평사마귀 레이저 치료 후 재생테이프 꼭 붙여야 하나요?', '모든 병원에서 재생테이프를 사용하는 것은 아니며, 의사마다 시술 방법이 다릅니다. 편평사마귀는 조직학적으로 표피층의 변화만 동반되는 병변이라 깊이 깎아낼 필요가 없는 경우가 많아요. 재생테이프 없이 시술하면 물이 닿아도 되어 가벼운 세안이 가능하고, 테이프를 갈아주는 번거로움도 없습니다. 테이프 접촉피부염이 있는 분들도 이 방식으로 시술받을 수 있다는 장점이 있어요. 대신 시술 부위에 딱지가 생기는데, 딱지가 빨리 떨어지면 색소침착 위험이 높아지기 때문에 재생크림을 자주 덧바르고 세게 문지르지 않도록 주의해야 합니다. 수십 개 재생테이프를 붙인 사진에 겁먹고 치료를 미루시는 분들이 많은데, 병원마다 방법이 다르니 상담 후 결정하시면 됩니다.', '편평사마귀 레이저 시술 후 재생테이프 없이 관리하는 방법을 피부과 전문의 고혜림이 정리합니다.', array['편평사마귀', '레이저시술', '재생테이프', '색소침착', '딱지관리', '시술후관리']::text[]),
    ('5mA2eVFd5Bw', 'gohyerim', '편평사마귀 재발 안 되게 예방하는 방법이 있나요?', '면역력을 높이기 위해 스트레스를 조절하고, 적당한 운동과 균형 잡힌 식습관, 수면의 질을 높이는 노력이 재발 예방에 도움이 됩니다. 편평사마귀는 HPV 바이러스 3, 10, 28번형 감염으로 발생하는데 바이러스 자체를 레이저로 완전히 없앨 수는 없기 때문에 면역 관리가 핵심이에요. 면역력 증강에 도움이 되는 비타민이나 영양제도 예방에 도움이 될 수 있습니다. 자궁경부암 백신을 아직 안 맞은 분이라면 사마귀 예방 목적은 아니더라도 HPV 감염 예방 측면에서 남녀 모두 접종을 권고하고 있어요. 피부가 건조하거나 장벽이 무너지면 사마귀가 번지기 쉬우니 보습제를 충분히 자주 도포하는 것도 중요합니다. 무엇보다 재발이 보이면 미루지 말고 바로 피부과에 방문해서 초기에 잡는 것이 완치율을 높이는 가장 확실한 방법이에요.', '편평사마귀의 재발을 줄이는 면역 관리법과 예방 수칙을 피부과 전문의 고혜림이 안내합니다.', array['편평사마귀', '재발예방', '면역력', 'HPV', '자궁경부암백신', '보습', '피부장벽']::text[]),
    ('iXoBCDGSN5k', 'kimsoohyung', '스킨보톡스 맞으면 모공이 진짜 작아지나요?', '네, 스킨보톡스는 모공 크기를 줄이고 속광이 도는 반들반들한 피부를 만들어주는 시술입니다. 보톡스를 피부층에 얇게 주사하면 피지 분비를 효과적으로 줄여 피부의 요철이 감소하게 돼요. 실제 논문에서 62명 환자를 대상으로 시술 전과 90일 후를 비교했더니 피부 거친 정도가 7.5점에서 5점으로 약 30% 감소했고, 모공 점수도 3점에서 5점으로 개선되었습니다. 확 예뻐지는 시술은 아니지만 피부결을 좋게 해주고 환한 인상을 만들어 줍니다. 시술 시간이 5분 정도로 짧고 비용도 비교적 저렴해서 가성비가 뛰어난 편이에요. 다만 피부층에 섬세하게 주입해야 하고 농도도 1cc에 20유닛 전후로 적절해야 효과가 좋습니다. 너무 깊거나 진하게 넣으면 근육에 영향을 줘서 표정이 어색해질 수 있으니 주의하세요.', '스킨보톡스로 모공이 줄고 속광이 도는 원리와 논문 근거를 피부과 전문의 김수형이 설명합니다.', array['스킨보톡스', '모공', '피부결', '속광', '보톡스', '피지', '잔주름']::text[]),
    ('iXoBCDGSN5k', 'kimsoohyung', '스킨보톡스 3~4개월밖에 안 간다는데 맞아봐야 소용 있나요?', '단기적으로는 3~4개월이지만, 반복할수록 노화를 실제로 늦춰주기 때문에 충분히 의미 있습니다. 일란성 쌍둥이 사례가 이를 잘 보여주는데, 한 명은 13년간 연 2~3회 보톡스를 꾸준히 맞았고 다른 한 명은 13년간 단 2회만 받았어요. 그 결과 꾸준히 맞은 쪽은 이마 잔주름이 거의 없었지만, 안 맞은 쪽은 잔주름이 뚜렷하게 관찰됐습니다. 보톡스를 맞고 있는 동안에는 피부가 주름 지는 것으로부터 보호되고, 그만큼 노화가 천천히 진행되는 원리예요. 근육보톡스가 5~6개월 간격인 것에 비해 스킨보톡스는 피부층에 넣기 때문에 농도를 너무 진하게 할 수 없어 유지 기간이 짧을 수밖에 없습니다. 1년에 3번, 5분씩만 투자하면 노화를 미룰 수 있으니 장기적 관점에서 접근하시는 게 좋아요.', '스킨보톡스 3~4개월 유지 기간의 장기적 노화 방지 효과를 피부과 전문의 김수형이 정리합니다.', array['스킨보톡스', '유지기간', '노화방지', '보톡스', '잔주름', '주름예방']::text[]),
    ('iXoBCDGSN5k', 'kimsoohyung', '보톡스 자주 맞으면 내성 생겨서 안 듣는다는데 사실인가요?', '반은 맞고 반은 틀립니다. 시술 빈도가 늘어나면 내성이 생길 확률이 올라가는 건 사실이에요. 내성의 원리는 이렇습니다. 보톡스가 반복적으로 몸에 들어오면 면역세포가 이를 감지해 항체를 만들고, 항체가 보톡스를 잡아 경찰 역할의 면역세포에게 알려줘서 효과를 내기 전에 제거해 버리는 거예요. 특히 분자 크기가 큰 보톡스일수록 면역세포 눈에 잘 띄어 내성이 생기기 쉽습니다. 이를 해결하기 위해 기능 부분만 남기고 단백질을 제거한 2세대 보톡스인 제오민이 나왔고, 같은 원리로 국내산인 코어톡스도 있어요. 내성이 걱정된다면 제오민이나 코어톡스처럼 분자 크기를 줄인 제품으로 시술받는 걸 고려해 보세요.', '보톡스 내성이 생기는 원리와 내성 방지용 2세대 보톡스를 피부과 전문의 김수형이 안내합니다.', array['보톡스', '내성', '제오민', '코어톡스', '항체', '면역', '2세대보톡스']::text[]),
    ('iXoBCDGSN5k', 'kimsoohyung', '스킨보톡스 엄청 아프다던데 그래도 맞아야 하나요?', '솔직히 많이 아픈 시술이 맞습니다. 근육보톡스처럼 한두 부위가 아니라 얼굴 전체에 맞아야 하고, 근육층보다 피부층에 신경이 훨씬 많이 분포해 있어서 더 아파요. 오히려 스킨보톡스를 받는데 많이 아프지 않다면 피부층에 제대로 들어가고 있는지 의심해 봐야 합니다. 통증이 너무 걱정된다면 마취크림을 1시간 이상 바르는 걸 추천드리고, 그래도 무섭다면 수면마취나 비수면 호흡마취도 방법이에요. 부작용으로는 주사 시 멍이 생길 수 있고, 입가 근육에 작용하면 밥 먹거나 말할 때 표정이 부자연스러워질 수 있습니다. 주의할 점은 피부층에 섬세하게 주입해야 하고 잡고 싶은 잔주름 부위가 있다면 상담 시 꼭 말씀하시는 게 좋아요.', '스킨보톡스 통증 정도와 부작용 및 주의사항을 피부과 전문의 김수형이 안내합니다.', array['스킨보톡스', '통증', '부작용', '마취크림', '멍', '표정', '피부층']::text[]),
    ('ZuOad5VN0dk', 'leedoyoung', '마리오네트 주름 집에서 셀프로 예방할 수 있는 방법이 있나요?', '네, 입꼬리 내림근의 긴장을 풀어주는 간단한 습관만으로도 예방에 도움이 됩니다. 마리오네트 라인은 입꼬리 내림근이 과하게 수축하는 것과 중력으로 지방층이 처지는 것, 이 두 가지가 원인이에요. 먼저 평소에 윗 어금니와 아래 어금니 사이를 꽉 깨물지 말고 살짝 벌려 준 뒤, 입술을 여권 사진 찍듯 가볍게 다무는 연습을 해보세요. 처음엔 어색하지만 그게 정상입니다. 의식적으로 안 하면 잘 안 될 만큼 입꼬리 내림근이 경직돼 있는 분들이 많아요. 잘 안 되면 입꼬리 주변을 살살 풀어주는 스트레칭도 효과적입니다. 중력 요인은 볼살이 덜 무거우면 덜 내려오므로 적절한 볼살을 유지하시는 게 좋아요.', '마리오네트 주름(심술보) 원인과 집에서 할 수 있는 예방법을 피부과 전문의 이도영이 안내합니다.', array['마리오네트', '심술보', '입꼬리주름', '입꼬리내림근', '주름예방', '볼살', '셀프관리']::text[]),
    ('ZuOad5VN0dk', 'leedoyoung', '심술보에 울쎄라 받으면 안 되나요?', '심술보 부위에는 울쎄라를 절대 먼저 추천하지 않습니다. 울쎄라는 턱 라인 잡는 데는 좋지만 입 주변, 특히 심술보 쪽에는 신경이 지나가고 있어서 위험할 수 있어요. 울쎄라가 순간적으로 높은 열을 점으로 만드는 방식인데, 그 점이 신경에 닿으면 손상이 오는 원리입니다. 잘못하면 입이 돌아갈 수 있고, 대부분 회복은 되지만 몇 달간 양치질할 때 물이 새거나 웃을 때 입이 삐뚤어지기도 합니다. 또한 울쎄라는 지방세포를 파괴해 볼꺼짐 부작용이 생길 수도 있어요. 실제로 울쎄라 프로토콜에도 심술보 부위는 시술하지 말라고 명시되어 있으니 다른 방법을 찾으시는 게 안전합니다.', '심술보 부위에 울쎄라가 위험한 이유와 신경 손상 위험을 피부과 전문의 이도영이 설명합니다.', array['울쎄라', '마리오네트', '심술보', '신경손상', '리프팅', '볼꺼짐', '부작용']::text[]),
    ('ZuOad5VN0dk', 'leedoyoung', '실리프팅 말고 심술보에 효과 좋은 리프팅이 뭔가요?', '심술보에는 티타늄 리프팅이 효과적이고 부작용도 적습니다. 실리프팅을 처음부터 권하지 않는 이유는 피부가 탄탄해야 실이 잘 당겨지기 때문이에요. 순두부를 포크로 찍어 들어 올릴 수 없지만 찹쌀떡은 가능한 것처럼, 피부를 먼저 쫀쫀하게 만드는 게 우선입니다. 티타늄 리프팅은 원래 제모 레이저를 리프팅에 응용한 것으로, 피부 속 수분을 데워 주변 조직을 수축시켜 리프팅 효과를 냅니다. 울쎄라와 달리 서서히 열을 쌓아가는 방식이라 신경 손상이나 지방세포 파괴 걱정이 없어요. 제모보다 약한 에너지를 쓰기 때문에 안전하고, 색소와 홍조 개선까지 되어 얼굴이 화사해지는 부가 효과도 있습니다. 통증도 거의 없고 즉각적으로 좋아지는 게 장점이에요.', '심술보에 티타늄 리프팅을 추천하는 이유와 울쎄라와의 차이를 피부과 전문의 이도영이 정리합니다.', array['티타늄리프팅', '마리오네트', '심술보', '리프팅', '실리프팅', '울쎄라', '입꼬리주름']::text[]),
    ('ZuOad5VN0dk', 'leedoyoung', '입꼬리 보톡스만으로 심술보가 없어질 수 있나요?', '심술보가 아주 심하지 않고 생길락 말락 하는 분들은 입꼬리 보톡스 두 방으로도 충분히 예뻐질 수 있습니다. 입꼬리 보톡스를 맞으면 입꼬리가 살짝 올라가면서 인상이 밝아지는 효과가 있어요. 하지만 이미 심술보가 깊어진 분들은 보톡스만으로 해결이 안 될 수 있습니다. 그런 경우 티타늄 리프팅으로 피부를 탄탄하게 만든 뒤 추가 시술을 고려하는 게 좋아요. 티타늄 리프팅은 유지 기간이 조금 짧은 편이라 고주파 시술과 병합하면 시너지가 좋습니다. 고주파로 유명한 써마지는 고가이기 때문에 가성비로 병합하기 좋은 오푸스나 3DEEP 같은 고주파 시술을 함께 받으시는 걸 권해 드려요.', '입꼬리 보톡스의 심술보 개선 효과와 병합 치료 방법을 피부과 전문의 이도영이 안내합니다.', array['입꼬리보톡스', '마리오네트', '심술보', '보톡스', '티타늄리프팅', '고주파', '써마지']::text[]),
    ('6NhrPShhmvE', 'jeonghanmi', '세안 후 뽀득뽀득한 느낌이 드는데 이게 좋은 건 아닌가요?', '아닙니다. 세안 후 뽀득뽀득하고 말끔한 느낌이 든다면 오히려 피부 장벽이 망가지고 있을 수 있다는 신호예요. 클렌저에는 피부의 노폐물을 씻어내기 위한 계면활성제가 들어가 있는데, 세정력이 강한 약알칼리성 클렌저는 메이크업이나 피지를 깨끗하게 제거해 주는 대신 피부를 당기고 건조하게 만들 수 있습니다. 반대로 약산성 클렌저는 피부 장벽을 무너뜨리지 않는 순한 계면활성제가 들어 있어서 씻고 나면 미끄덩거리는 느낌이 남아요. 본인 피부가 건조하고 예민한 편이라면 순한 약산성 클렌저를 선택하고, 피부가 두껍고 유분기가 많은 분은 약알칼리성 클렌저를 가끔 사용하는 게 좋습니다. 중요한 건 무조건 강하게 씻는 게 좋은 게 아니라 내 피부 타입에 맞춰 선택해야 한다는 점이에요.', '뽀득뽀득 말끔한 느낌이 들면 피부 장벽이 망가지고 있다는 신호입니다. 약산성·약알칼리성 클렌저의 차이와 선택법을 피부과 전문의 정한미가 설명합니다.', array['클렌저', '세안', '피부장벽', '약산성', '계면활성제', '세정력', '건성피부']::text[]),
    ('6NhrPShhmvE', 'jeonghanmi', '약산성 클렌저가 순하다는데 왜 트러블이 나는 걸까요?', '약산성 클렌저가 피부에 순한 건 맞지만, 순하다고 무조건 좋은 건 아닙니다. 피부가 두껍고 모공이 크고 유분기가 많은 분이 약산성 클렌저만 쓰면 과도한 피지가 제대로 제거되지 않아 트러블이 생길 수 있어요. 이런 피부 타입은 세정력이 강한 약알칼리성 클렌저를 가끔 사용해서 피부의 유분기를 빼주는 게 필요합니다. 복합성 피부라면 볼처럼 건조한 부위는 약산성 제품, T존처럼 유분기가 많은 부위는 세정력 강한 제품으로 나눠서 쓸 수도 있어요. 또한 아침에는 순한 약산성 클렌저로 가볍게, 저녁에 메이크업을 지울 때는 세정력이 있는 제품으로 이중세안하는 식으로 상황에 따라 바꿔 쓰는 게 좋습니다. 계절별로도 겨울엔 순한 약산성, 여름엔 약알칼리성으로 조절해 보세요.', '유분 많은 피부가 약산성 클렌저만 쓰면 오히려 트러블이 생길 수 있습니다. 복합성 피부의 부위별·계절별 클렌저 선택법을 피부과 전문의 정한미가 정리합니다.', array['약산성클렌저', '트러블', '복합성피부', '세정력', '유분기', 'T존', '이중세안']::text[]),
    ('6NhrPShhmvE', 'jeonghanmi', '피부과 의사는 실제로 어떤 클렌저를 쓰나요?', '아침과 저녁 상황에 따라 제품을 나눠서 사용합니다. 아침 세안에는 제로이드 포밍 클렌저나 주닥 프로폴리스 젠틀 클렌저처럼 거품으로 나오는 순한 제품 중 손에 잡히는 걸 쓰고 있어요. 저녁에는 낮에 메이크업을 하기 때문에 이중세안을 하는데, 2차 폼클렌저로는 라로슈포제 제품을 사용합니다. 이 제품은 약산성이지만 세정력이 조금 강한 계면활성제가 들어 있어서 너무 건조하지 않으면서 적당히 씻겨요. 겨울에 피부가 많이 건조할 때는 프레쉬 소이 페이스 클렌저를 쓰는데, 다른 제품보다 미끄덩거리고 촉촉해서 건조한 계절에 잘 맞습니다. 핵심은 한 가지 제품만 고집하는 게 아니라 피부 컨디션과 계절에 맞게 바꿔가며 사용하는 거예요.', '피부과 전문의 정한미가 실제로 쓰는 제로이드·라로슈포제·프레쉬 클렌저. 아침·저녁·계절별 제품 선택 기준을 공개합니다.', array['클렌저추천', '세안', '이중세안', '약산성', '라로슈포제', '건성피부', '겨울세안']::text[]),
    ('6NhrPShhmvE', 'jeonghanmi', '클렌저 세정력이 강한지 약한지 쉽게 구별하는 방법 있나요?', '가장 간단한 방법은 클렌저 거품을 직접 내보는 겁니다. 거품이 쫀쫀하고 풍성하게 잘 나면 세정력이 강한 클렌저일 가능성이 높아요. 반면 약산성 클렌저는 강하지 않은 계면활성제를 쓰기 때문에 거품이 쫀쫀하게 나지 않아서 일부러 거품기가 달려 있는 경우가 많습니다. 거품은 잘 났는데 비벼보면 금방 없어진다면 순한 촉촉한 클렌저라고 보시면 됩니다. 추가 팁으로 여드름이 잘 나는 분은 전성분에서 BHA(살리실릭애씨드) 성분이 들어간 제품을 찾아보세요. 모공 속 피지를 줄여주고 염증도 완화해 주는 기능이 있어서 도움이 될 수 있습니다. 세안 시간은 거품 내고 마사지하는 시간을 30초, 길어도 60초 안에 끝내고 손바닥이 아닌 손가락으로 부드럽게 씻어주세요.', '거품이 쫀쫀하면 세정력 강한 클렌저, 금방 꺼지면 순한 클렌저입니다. 세정력 판별법과 BHA 클렌저 활용 팁을 피부과 전문의 정한미가 안내합니다.', array['클렌저', '거품', '세정력', 'BHA', '여드름', '세안법', '약산성']::text[]),
    ('49t9ToD-9zQ', 'jeonghanmi', '선크림만 발랐는데도 이중세안 꼭 해야 하나요?', '대부분의 선크림은 폼클렌저만으로 깨끗하게 지워지지 않기 때문에 이중세안이 필요합니다. 자외선 차단제는 기름 성분이 많이 들어가 있고, 특히 물리적 차단제(무기자차)는 바르면 백탁이 일어날 정도로 밀착되어 있어요. 손등에 선크림을 바르고 폼클렌저로 씻어보면 언뜻 씻긴 것 같아도 잔주름 사이사이로 선크림이 남아 있는 걸 확인할 수 있습니다. 클렌징 오일로 1차 클렌징한 뒤 폼클렌저로 2차 세안을 하면 깨끗하게 지워져요. 다만 이지워시 타입이라고 적혀 있거나 물리적 차단제가 전혀 없는 가벼운 제형의 선크림이라면 폼클렌저 한 번만으로도 충분할 수 있습니다. 확인이 어려우면 직접 손등 테스트를 해보시는 게 가장 확실해요.', '선크림은 기름 성분이 많아 폼클렌저만으로 다 지워지지 않습니다. 이중세안이 필요한 이유와 예외 상황을 피부과 전문의 정한미가 정리합니다.', array['선크림', '이중세안', '클렌징오일', '자외선차단제', '무기자차', '폼클렌저', '세안']::text[]),
    ('49t9ToD-9zQ', 'jeonghanmi', '클렌징 오일 쓰는데 자꾸 좁쌀 여드름이 나요. 왜 그런 건가요?', '클렌징 오일 후 좁쌀 여드름이 나는 이유는 크게 두 가지입니다. 첫째, 유화 과정을 제대로 안 해서 오일이 깨끗하게 씻기지 않은 경우예요. 클렌징 오일은 반드시 물기 없는 손에 덜어 롤링한 뒤, 손가락 끝에 물을 묻혀 다시 문질러서 하얗게 유화시켜야 합니다. 오일을 바르고 바로 물로 헹구면 하나도 안 씻기거든요. 둘째, 피부에 맞지 않는 오일 제형을 쓰고 있을 수 있어요. 피부가 지성이거나 모공이 크고 여드름이 잘 나는 분은 오일이 모공에 남아 트러블을 유발하기 쉽습니다. 이런 피부라면 오일 대신 클렌징 밀크나 클렌징 워터 같은 다른 제형을 찾아보시는 게 좋아요. 반면 건조한 피부는 오일 사용 후 수분막이 생겨서 오히려 잘 맞습니다.', '클렌징 오일 후 좁쌀 여드름은 유화 미흡이나 피부 타입 불일치가 원인입니다. 올바른 유화 방법과 대체 제형을 피부과 전문의 정한미가 안내합니다.', array['클렌징오일', '좁쌀여드름', '유화', '트러블', '지성피부', '모공', '세안']::text[]),
    ('49t9ToD-9zQ', 'jeonghanmi', '클렌징 워터가 산뜻해서 좋은데 피부가 예민해져요. 계속 써도 될까요?', '피부가 예민하고 얇고 홍조가 있는 분이라면 클렌징 워터는 안 쓰시는 게 좋습니다. 클렌징 워터를 쓸 때 화장솜에 적셔서 닦아내게 되는데, 이 닦아내는 동작 자체가 민감한 피부에는 자극이 되기 때문이에요. 특히 메이크업을 지울 때는 힘을 줘서 닦게 되니 더 문제가 됩니다. 클렌징 워터는 90% 이상이 물로 되어 있어 사용감은 산뜻하지만, 세정력이 오일에 비해 약해서 가벼운 메이크업이나 선크림 정도만 발랐을 때 쓰기 적합해요. 피부 장벽이 튼튼한 분한테는 좋을 수 있습니다. 클렌징 워터를 포기하기 어렵다면 화장솜 대신 거품 용기에 넣어서 거품으로 만들어 사용하는 방법도 있어요.', '클렌징 워터는 화장솜으로 닦는 동작 자체가 민감한 피부에 자극이 됩니다. 예민한 피부를 위한 대안 사용법을 피부과 전문의 정한미가 설명합니다.', array['클렌징워터', '민감성피부', '홍조', '자극', '화장솜', '피부장벽', '클렌징']::text[]),
    ('49t9ToD-9zQ', 'jeonghanmi', '클렌징 오일이랑 밤이랑 뭐가 다른 건가요?', '클렌징 밤은 사실 클렌징 오일과 거의 같다고 보시면 됩니다. 프라이팬에 묻은 기름을 안 닦고 두면 하얗게 굳는 것처럼, 상온에서 고체가 되는 오일들을 모아 만든 게 클렌징 밤이에요. 고체처럼 보이지만 피부에 올려서 문지르면 체온 때문에 녹아서 부드러워지므로 원리는 동일합니다. 그래서 클렌징 밤도 오일과 마찬가지로 물기 없는 손으로 사용해야 하고 유화 과정이 꼭 필요해요. 피부 타입별로 정리하면, 건조하고 예민한 피부는 클렌징 밀크나 크림이 좋고, 지성이고 피부가 두꺼우며 유분이 많은 분은 클렌징 오일이나 밤으로 확실하게 씻어주는 게 맞습니다. 한 제품만 고집하기보다 메이크업 정도와 피부 상태에 따라 바꿔 쓰세요.', '클렌징 밤과 오일의 차이점 및 피부 타입별 1차 클렌저 선택법을 피부과 전문의 정한미가 정리합니다.', array['클렌징밤', '클렌징오일', '유화', '건성피부', '지성피부', '클렌징밀크', '1차세안']::text[]),
    ('4DdDRwsNibc', 'leedoyoung', '써마지나 울쎄라 말고 얼굴 처짐 막을 방법이 있나요?', '네, 얼굴 근육 운동만 꾸준히 해도 처짐 예방에 큰 도움이 됩니다. 써마지, 울쎄라, 쥬베룩, 리쥬란 같은 시술들은 좋지만 대부분 근육까지 영향을 주지 못해요. 나이가 들면 피부와 지방층뿐 아니라 근육도 늘어지고 힘을 잃는데, 특히 중안면(앞광대 포함 부위)의 큰광대근이 힘을 잃으면 처짐이 심해집니다. 이게 소위 말하는 얼굴의 근손실이에요. 큰광대근을 강화하는 방법은 집에서도 가능합니다. 입을 살짝 벌리고 어금니가 닿지 않게 한 뒤, 혀로 입천장을 밀어주는 느낌을 주면서 활짝 웃어 보세요. 처음엔 광대 쪽이 떨리고 뻐근할 수 있는데 안 쓰던 근육을 쓰면 당연한 반응입니다. 꾸준히 하면 5년, 10년 젊어질 수 있는 얼굴을 만들 수 있어요.', '큰광대근을 강화하면 시술 없이도 얼굴 처짐을 예방할 수 있습니다. 집에서 할 수 있는 구체적인 운동 방법을 피부과 전문의 이도영이 안내합니다.', array['얼굴근육운동', '리프팅', '큰광대근', '처짐', '노화방지', '중안면', '동안']::text[]),
    ('4DdDRwsNibc', 'leedoyoung', '얼굴 근육 운동하면 근육이 울퉁불퉁해지지 않나요?', '아닙니다. 얼굴 근육 운동은 등척성 운동(철봉 매달리기처럼 힘을 유지하는 방식)이라서 벌크업이 되는 게 아니라 자연스럽게 근육의 힘만 늘어납니다. 두 번째 운동인 입꼬리 당김근 강화도 같은 원리예요. 입을 살짝 벌리고 어금니가 닿지 않게 한 상태에서 편안하게 미소를 지으며 입꼬리를 당겨주고, 손가락을 떼고도 긴장을 유지하는 겁니다. 평소에 덜 쓰던 근육을 강화시키면 자연스럽게 예쁜 표정이 나와요. 시간이 없으면 큰광대근 운동과 입꼬리 당김근 운동을 묶어서 동시에 해도 됩니다. 처음엔 잘 안 되는 게 정상이고, 헬스장에서 처음 운동할 때 무게 못 드는 것과 같은 이치예요. 꾸준히 하면 표정이 좋아지고 점점 어려 보이게 됩니다.', '얼굴 근육 운동은 등척성 운동이라 벌크업 걱정이 없습니다. 입꼬리 당김근 강화와 자연스러운 표정 만드는 방법을 피부과 전문의 이도영이 설명합니다.', array['얼굴근육운동', '등척성운동', '입꼬리당김근', '큰광대근', '동안', '표정', '리프팅']::text[]),
    ('4DdDRwsNibc', 'leedoyoung', '얼굴 홈트가 잘 안 되면 피부과에서 도움받을 수 있나요?', '네, 얼굴 근육을 풀어주는 레비나스와 근력 운동을 대신해 주는 엠페이스, 이 두 가지 프로그램으로 도움을 받을 수 있습니다. 레비나스는 체외 충격파 장비로 일종의 경락과 비슷한 역할을 해요. 뭉쳐 있는 얼굴 근육을 풀어주고 붓기도 빠지게 해서 얼굴이 작아지는 느낌을 줍니다. 엠페이스는 근육에 전기적 자극을 줘서 근육이 자발적으로 수축하게 만드는 장비예요. 큰광대근과 입꼬리 당김근을 타겟으로 고주파 열 자극과 EMS 자극을 동시에 줘서 근육을 효과적으로 강화시킵니다. 레비나스로 스트레칭하고 엠페이스로 근력을 키우면 처져 있던 지방층이 리프팅되면서 부족했던 볼륨이 자연스럽게 채워져요. 다만 정확한 근육을 제대로 자극해야 효과가 확실하므로 숙련된 의사에게 받으시길 권합니다.', '홈트가 어렵다면 레비나스로 근육을 풀고 엠페이스로 근력을 키우는 시술 조합이 효과적입니다. 원리와 효과를 피부과 전문의 이도영이 정리합니다.', array['엠페이스', '레비나스', '얼굴근육', '리프팅', '경락', 'EMS', '큰광대근']::text[]),
    ('4DdDRwsNibc', 'leedoyoung', '요즘 갑자기 확 늙은 것 같은데 왜 그런 건가요?', '나이가 들면서 피부, 지방층, 근육이 동시에 흘러내리기 때문입니다. 하루하루 망가지고 없어지는데 그만큼 채워 넣지 못하면 얼굴이 폭삭 무너지는 거예요. 특히 중안면 부위, 앞광대를 포함한 얼굴 중간 부분이 중요한데, 이곳의 지방이 빠지고 큰광대근이 힘을 잃으면 처짐이 눈에 띄게 심해집니다. 사람 얼굴을 볼 때 가장 튀어나온 앞광대 쪽에 시선이 먼저 가는데, 여기가 꺼지면 급격히 늙어 보여요. 젊은 분들도 이런 느낌을 받는 경우가 상당히 많습니다. 해결의 핵심은 얼굴 근육을 운동해서 힘을 키워주는 건데, 몸 운동과 마찬가지로 꾸준함이 가장 중요합니다. 집에서 매일 5분씩 큰광대근과 입꼬리 당김근을 자극해 보세요.', '피부·지방·근육이 동시에 처지면 얼굴이 갑자기 늙어 보입니다. 중안면 볼륨 손실 원인과 매일 5분 얼굴 근육 운동의 중요성을 피부과 전문의 이도영이 설명합니다.', array['노화', '얼굴처짐', '중안면', '큰광대근', '앞광대', '동안', '얼굴근육운동']::text[]),
    ('uPa-DvAheIo', 'kimsoohyung', 'SPF 50 바르고 있는데 왜 기미가 안 옅어지는 걸까요?', 'SPF가 높아도 기미를 악화시키는 주범인 자외선 A와 블루라이트를 막지 못하면 소용이 없습니다. SPF는 자외선 B(UVB) 차단 지수일 뿐인데, 자외선 B는 유리창을 통과하지 못해서 실내 생활이 많은 분에게는 큰 위협이 아닙니다. 반면 자외선 A(UVA)와 블루라이트는 유리를 뚫고 들어와 피부 깊숙이 침투해 기미를 악화시킵니다. 실제로 활성산소를 일으키는 빛의 비율을 보면 자외선 B가 4%, 자외선 A가 46%, 블루라이트가 50%를 차지해요. 그래서 기미 고민이 있으신 분들은 SPF 수치보다 PA 지수가 ++++인지, 블루라이트 차단이 되는지를 먼저 확인하셔야 합니다. PA는 자외선 A 차단력을 나타내는 지표로 플러스가 많을수록 효과가 큽니다. 기미 관리의 핵심은 SPF 숫자가 아니라 어떤 파장을 막아주느냐에 달려 있다고 보시면 됩니다.', 'SPF만 높여도 기미가 안 줄어드는 이유와 진짜 봐야 할 차단 지수를 피부과 전문의 김수형이 설명합니다.', array['선크림', '기미', 'SPF', 'PA', '자외선A', '블루라이트', '활성산소']::text[]),
    ('uPa-DvAheIo', 'kimsoohyung', '블루라이트가 기미에 영향 준다는데 선크림으로 막을 수 있나요?', '산화철 성분이 들어간 선크림이나 비비크림을 바르면 블루라이트를 효과적으로 차단할 수 있습니다. 햇빛 속 블루라이트는 전자기기에서 나오는 양의 10배나 되고, 피부에 활성산소를 만들어 콜라겐을 분해하고 기미와 노화를 촉진시킵니다. 문제는 블루라이트 차단 수치가 선크림에 따로 표기되어 있지 않다는 점이에요. 대신 성분표에서 적색산화철, 황색산화철, 흑색산화철이 포함됐는지 확인하시면 됩니다. 산화철은 공식 자외선 차단 성분은 아니지만 피부색을 내기 위해 들어가는 성분으로, 블루라이트를 막아주는 효과가 입증되어 있어요. 톤업 선크림에도 산화철이 포함된 경우가 많으니 색감 있는 제품을 고르시는 것도 방법입니다. 만약 지금 쓰는 선크림에 산화철이 없다면, 그 위에 비비크림이나 파운데이션을 한 겹 덧바르는 것만으로도 충분히 차단 가능합니다.', '블루라이트를 막는 산화철 성분 선크림 고르는 법을 피부과 전문의 김수형이 안내합니다.', array['블루라이트', '산화철', '선크림', '기미', '톤업선크림', '자외선차단']::text[]),
    ('uPa-DvAheIo', 'kimsoohyung', '민감성 피부인데 유기자차 쓰면 눈이 시린 건 왜 그런 거예요?', '유기자차는 피부에 흡수되어 화학적으로 자외선을 열로 전환하는 방식이라 민감성 피부에 자극을 줄 수 있습니다. 화학 성분이 피부 안으로 들어가기 때문에 눈 시림이나 따가움이 생기는 분들이 있어요. 반면 무기자차(무기 자외선 차단제)는 피부 위에 하얀 막을 형성해 자외선을 물리적으로 반사시키는 원리여서 자극이 적습니다. 단점은 발랐을 때 백탁현상이 있을 수 있다는 건데, 최근 제품들은 백탁이 거의 없으면서 자연스러운 톤 보정 효과를 주는 것도 많아요. 그래서 민감성 피부이신 분들은 유기자차보다 무기자차를 선택하시는 게 안전합니다. 발림감이 나한테 안 맞거나 눈이 시리면 아무리 좋은 성분이어도 꾸준히 바르기 어렵기 때문에, 자극 없이 편하게 쓸 수 있는 제품을 찾는 게 가장 중요합니다. 무기자차 중에서 PA++++인 제품을 고르시면 차단력과 저자극을 동시에 잡을 수 있어요.', '민감성 피부에 유기자차가 자극을 주는 이유와 무기자차 선택법을 피부과 전문의 김수형이 정리합니다.', array['무기자차', '유기자차', '민감성피부', '선크림', '눈시림', '백탁현상', '자외선차단제']::text[]),
    ('uPa-DvAheIo', 'kimsoohyung', '톤업 선크림 싫은데 기미 막으려면 어떤 제품을 써야 하나요?', '톤업이 부담스러운 분들은 맥소릴 400 성분이 들어간 선크림을 선택하시면 색감 없이도 자외선 A를 강력하게 차단할 수 있습니다. 대부분의 자외선 A 차단 성분은 피부에 가장 깊이 들어오는 긴 파장대의 UVA1까지는 막지 못하는 경우가 많아요. 그런데 맥소릴 400이라는 성분은 기존의 멕소릴 SX, XL 성분과 합쳐져서 UVB부터 UVA까지 모든 파장을 차단합니다. 라로슈포제 안뗄리오스 UV 뮨 400 같은 제품이 이 성분을 포함하고 있어서, 산화철 없이도 자외선 A 방어력이 뛰어나요. 톤업 효과를 원하지 않으면서 기미 관리를 하고 싶은 분들에게 좋은 대안이 됩니다. 햇빛을 많이 쬐는 날에는 선크림을 여러 번 덧발라야 하는데, 색감 없는 제품이라 덧바르기에도 부담이 없어요. 다만 블루라이트 차단까지 원하신다면 이 위에 파운데이션이나 비비를 한 겹 덧바르시는 걸 추천드립니다.', '톤업 없이 기미를 막는 UVA 차단 선크림 선택법을 피부과 전문의 김수형이 안내합니다.', array['선크림', '기미', '자외선A', '맥소릴400', '라로슈포제', 'UVA차단', '톤업']::text[]),
    ('_OzrE2BwSU8', 'parkhyojin', '기미도 잡티도 없는데 얼굴이 칙칙해 보이는 이유가 뭔가요?', '얼굴에 솜털이 많으면 기미나 잡티 없이도 피부가 어둡고 칙칙해 보일 수 있습니다. 솜털이 빛을 산란시키면서 피부 톤이 탁해 보이고, 화장을 해도 매끄럽지 않거나 시간이 지나면 금방 뜨는 현상이 생깁니다. 거울을 가까이 대고 들여다보면 본인 얼굴에 솜털이 얼마나 많은지조차 모르는 분들이 대부분이에요. 이런 경우 얼굴 전체 제모 레이저를 받으면 다음 날 세안할 때부터 얼굴이 매끈해지고 광택이 나는 걸 느낄 수 있습니다. 왁싱이나 더마플래닝(피부샵에서 털을 깎아내는 시술)은 털만 깎거나 뽑는 거라 효과가 오래가지 못하고 오히려 트러블이나 인그로운 헤어가 생기기 쉬워요. 반면 제모 레이저는 털집 자체를 파괴하기 때문에 몇 번만 받아도 효과가 오래 지속되고 반영구적 제모로 갈 수도 있습니다. 웨딩이나 중요한 일을 앞두고 계신 분이라면 꼭 한 번 고려해 보세요.', '솜털 때문에 얼굴이 칙칙해 보이는 원인과 제모 레이저 효과를 피부과 전문의 박효진이 설명합니다.', array['얼굴제모', '솜털', '레이저제모', '톤업', '칙칙한피부', '더마플래닝', '왁싱']::text[]),
    ('_OzrE2BwSU8', 'parkhyojin', '코 주변 블랙헤드가 사실은 털일 수도 있다는 게 진짜인가요?', '네, 코와 나비존에 까맣게 올라온 것들이 블랙헤드가 아니라 털인 경우가 실제로 많습니다. 이걸 소극성 속모증이라고 하는데, 모공 안에 짧은 털이 자라나면서 블랙헤드처럼 보이는 겁니다. 말 그대로 털이기 때문에 제모 레이저 시술을 받으면 쉽게 해결할 수 있어요. 진짜 블랙헤드는 피지선에서 피지가 과다 분비된 뒤 구멍이 열린 채로 막혀 있는 상태를 말합니다. 피부에 털이 존재하는 곳에는 마치 바늘과 실처럼 피지선이 붙어 다니기 때문에, 제모 레이저로 털밭을 없애주면 피지 분비 자체도 줄어드는 효과가 있습니다. 블랙헤드와 화이트헤드에 여드름균이 감염되면 붉은 여드름으로 터지는 것이므로, 근본적으로 털과 피지선을 관리하는 게 핵심이에요. 단순히 짜내거나 팩으로 해결하려 하기보다 피부과에서 정확한 원인 진단을 받아보시길 권합니다.', '코 주변 블랙헤드가 실은 털(소극성 속모증)일 수 있는 이유와 제모 레이저 효과를 피부과 전문의 박효진이 안내합니다.', array['블랙헤드', '소극성속모증', '제모레이저', '피지선', '모공', '코블랙헤드', '여드름']::text[]),
    ('_OzrE2BwSU8', 'parkhyojin', '얼굴 제모 레이저가 모낭염이랑 홍조에도 효과가 있나요?', '네, 여드름과 모낭염, 홍조 모두 털과 그 옆에 붙어 있는 피지선에서 기인하는 것이라 제모 레이저로 털밭을 없애주면 증상이 좋아질 수 있습니다. 얼굴에 홍조가 있는 분들의 피부를 확대해 보면 모낭 주위에 염증 세포가 몰려 있고 혈관이 늘어나 있는 게 보입니다. 이 모낭 주위 염증 때문에 컨디션에 따라 얼굴이 울긋불긋해졌다가 덜해졌다가 하는 거예요. 제모 레이저로 모낭 자체를 파괴하면 염증의 근원이 줄어들어 홍조와 모낭염이 함께 개선됩니다. 실제로 모낭염과 홍조로 스트레스를 받던 환자가 5회 시술 후 만족해서 10회까지 연장하고 더 좋아진 사례도 있어요. 다만 초반에 드물게 일시적 모낭염이 생길 수 있는데, 횟수가 거듭될수록 줄어들고 예방 약도 함께 처방하니 크게 걱정하지 않으셔도 됩니다. 최소 4주 간격으로 5회 정도 시술하면 만족감을 느끼실 수 있어요.', '얼굴 제모 레이저가 모낭염과 홍조까지 개선하는 원리를 피부과 전문의 박효진이 정리합니다.', array['모낭염', '홍조', '제모레이저', '여드름', '피지선', '얼굴제모', '염증']::text[]),
    ('_OzrE2BwSU8', 'parkhyojin', '얼굴 솜털 제거하면 피부가 더 예민해지지 않나요?', '머리카락이나 눈썹, 코털과 달리 얼굴 솜털은 거의 기능을 하지 않아서 제거해도 피부가 더 예민해진다는 객관적 자료는 입증된 바가 없습니다. 다만 부작용이 전혀 없는 건 아닌데, 제모 레이저의 원리가 멜라닌 세포를 타겟으로 하기 때문에 얼굴이 까무잡잡하거나 어두운 분은 너무 강하게 시술하면 화상이나 딱지가 생길 수 있어요. 기미가 있는 분들은 오히려 기미가 더 심해질 가능성도 있습니다. 반대로 너무 약하게 하면 효과가 없어 돈만 낭비하게 되니, 반드시 경험이 많은 피부과 전문의에게 상담 후 시술을 받으셔야 합니다. 시술 자체는 여성분이라면 마취크림 없이도 받을 수 있을 정도로 통증이 적고, 시술 후 10분 정도 진정 팩만 올리면 바로 일상생활이 가능해요. 남성분들은 턱과 인중, V라인 쪽 굵은 털 부위가 많이 아프지만, 횟수가 거듭될수록 모가 얇아지면서 통증도 함께 줄어듭니다.', '얼굴 솜털 제모 후 예민해지는지 여부와 부작용 주의점을 피부과 전문의 박효진이 안내합니다.', array['얼굴제모', '솜털', '부작용', '통증', '멜라닌', '기미', '레이저제모']::text[]),
    ('NXJcg3O86GA', 'kimjongsik', '여드름 자국 색소침착에 멜라토닝크림 바르면 진짜 효과 있나요?', '네, 상처나 여드름 후에 생긴 갈색이나 검정색에 가까운 색소침착에는 멜라토닝크림을 꾸준히 바르면 분명히 효과가 있습니다. 멜라토닝크림 안에 들어있는 하이드로퀴논이라는 성분이 색소를 만드는 과정 자체를 억제하기 때문이에요. 다만 반드시 저녁에만 바르셔야 합니다. 하이드로퀴논을 바르고 자외선에 노출되면 오히려 색소침착이 더 생기는 부작용이 있기 때문이에요. 스킨케어 마지막 단계에서 신경 쓰이는 부위에만 하루 한 번 바르시고, 다음 날 외출 전에는 반드시 자외선 차단제를 발라주셔야 합니다. 하루 만에 좋아지진 않지만 안 바르는 것보다는 확실히 도움이 되니, 피부과에서 레이저토닝 받으러 오시기 전에 먼저 시도해 보시는 걸 추천드려요. 단, 색깔이 아직 붉은 단계라면 멜라토닝크림보다는 노스카나겔 같은 흉터 연고가 더 적합합니다.', '여드름 후 색소침착에 멜라토닝크림이 효과 있는 이유와 올바른 사용법을 피부과 전문의 김종식이 설명합니다.', array['색소침착', '멜라토닝크림', '하이드로퀴논', '여드름자국', '잡티', '홈케어', '자외선차단']::text[]),
    ('NXJcg3O86GA', 'kimjongsik', '팔꿈치랑 무릎이 까만데 멜라토닝크림 발라도 소용없나요?', '팔꿈치나 무릎, 복숭아뼈처럼 피부가 두꺼워져서 생기는 색소침착에는 멜라토닝크림이 효과가 없으니 바르지 마세요. 이 부위들은 잦은 마찰 때문에 피부가 두꺼워진 상태라 색소를 억제하는 연고로는 해결이 안 됩니다. 대신 유리아크림이나 투앤티크림 같은 레티노이드 제품이나 유리아 성분이 들어간 제품을 사용하시는 게 좋아요. 이런 연고들은 각질 탈락 주기를 빠르게 해서 두꺼운 각질을 벗겨내고, 마치 새살이 돋아나듯 부드럽고 하얗게 만들어주는 효과가 있습니다. 사용법은 간단하게 크림을 짜서 해당 부위에 넓게 펴 발라주시면 됩니다. 색소침착은 부위와 원인에 따라 홈케어 방법이 완전히 다르기 때문에, 무조건 같은 연고 하나로 해결하려 하면 안 돼요. 팔꿈치와 무릎은 각질 관리가 핵심이라는 점 기억해 주세요.', '팔꿈치와 무릎 색소침착에 맞는 연고 선택법을 피부과 전문의 김종식이 안내합니다.', array['색소침착', '팔꿈치', '무릎', '유리아크림', '투앤티크림', '레티노이드', '각질']::text[]),
    ('NXJcg3O86GA', 'kimjongsik', '아토피 때문에 생긴 색소침착에는 뭘 발라야 하나요?', '아토피 피부염으로 인한 색소침착에는 연고보다 보습제를 하루에 5번, 10번 자주 발라주시는 게 가장 좋습니다. 목이나 팔 오금, 무릎 오금처럼 아토피가 자주 생기는 부위에 멜라토닝크림이나 유리아크림을 바르면 오히려 피부에 자극을 줘서 아토피 피부염을 악화시킬 수 있어요. 아토피 피부염은 염증이 반복되면서 그 자리에 까맣게 색소가 남는 건데, 이때 자극이 되는 성분을 바르면 역효과가 납니다. 보습제는 하루에 여러 번 발라도 상관없으니, 집이나 사무실 여기저기에 두고 습관적으로 자주 바르시는 걸 추천드립니다. 단, 목에 생긴 색소침착이라도 아토피와 관련 없는 경우가 있을 수 있어서 정확한 진단은 필요합니다. 본인이 아토피 때문에 색소침착이 생긴 게 확실하다면 연고 대신 보습 위주로 관리하시는 게 안전해요. 자극 없는 보습만으로도 피부가 회복되면서 색소가 서서히 옅어질 수 있습니다.', '아토피 피부염으로 생긴 색소침착에 연고 대신 보습제를 써야 하는 이유를 피부과 전문의 김종식이 정리합니다.', array['아토피', '색소침착', '보습제', '아토피피부염', '목색소침착', '홈케어', '팔오금']::text[]),
    ('NXJcg3O86GA', 'kimjongsik', '여드름 흉터가 아직 붉은데 멜라토닝크림 바르면 안 되나요?', '색깔이 아직 붉은 단계의 여드름 자국에는 멜라토닝크림보다 노스카나겔 같은 흉터 연고가 더 도움이 됩니다. 색소침착을 개선하는 연고는 이미 갈색이나 검정색으로 변한 자국에 효과적인 것이고, 붉은 기가 남아 있을 때는 아직 색소가 아닌 염증 반응이 진행 중인 거예요. 흉터 연고는 하루에 다섯 번, 여섯 번 수시로 발라주시는 게 좋습니다. 그렇게 관리하다가 붉은 자국이 까매졌다면, 그때부터 멜라토닝크림으로 바꿔 바르시면 됩니다. 만약 색소침착이 너무 깊고 오래돼서 홈케어로 잘 안 되는 경우라면 피부과의 레이저토닝을 고려해 볼 수 있어요. 레이저토닝은 색소를 잘게 부수는 시술로, 1~2회가 아니라 10번에서 20번, 30번까지도 반복해서 조금씩 밝아지게 하는 방법입니다. 시술부터 바로 받기보다는 상태에 맞는 홈케어를 먼저 시도해 보시는 걸 추천드려요.', '붉은 여드름 자국에 맞는 연고 선택과 레이저토닝 시기를 피부과 전문의 김종식이 안내합니다.', array['여드름흉터', '노스카나겔', '붉은자국', '색소침착', '레이저토닝', '멜라토닝크림', '홈케어']::text[]),
    ('SgJAZC_KNM8', 'jeonghanmi', '등드름이 계속 나는데 집에서 뭘 바르면 좋아질 수 있나요?', '살리실릭 애시드(BHA) 성분이 들어간 폼클렌저로 등드름 부위를 씻되, 바로 헹구지 말고 5분 정도 시간을 두면 효과가 훨씬 좋습니다. BHA는 모공 속 피지를 청소해 주고, 모공을 막는 각질을 탈락시키며, 염증까지 줄여주는 세 가지 역할을 합니다. 집에 있는 폼클렌저 전성분을 검색해서 살리실릭 애시드가 있으면 그걸 그대로 쓰시면 돼요. 만약 그 성분이 없다면, 세정력이 강한 약알칼리성 클렌저로 등과 가슴 부위를 씻어주시는 것도 방법입니다. 등과 앞가슴은 우리 몸에서 피지가 가장 많은 부위인 데다 땀도 많이 나고 머리카락도 닿아서 구조적으로 여드름이 날 수밖에 없어요. 얼굴에 쓸 때 건조해서 안 쓰던 클렌저라도 등이나 가슴에는 오히려 적합할 수 있으니 한번 활용해 보세요. 홈케어만 잘해줘도 등드름과 가드름은 진짜 많이 좋아질 수 있습니다.', '등드름에 효과적인 BHA 클렌저 사용법과 5분 팁을 피부과 전문의 정한미가 안내합니다.', array['등드름', '가드름', 'BHA', '살리실릭애시드', '폼클렌저', '홈케어', '여드름']::text[]),
    ('SgJAZC_KNM8', 'jeonghanmi', '닦토가 피부에 안 좋다면서 등드름엔 왜 하라는 건가요?', '건조하고 예민한 얼굴 피부에는 닦토를 피해야 하지만, 피지가 많아서 문제인 등과 앞가슴에는 각질 토너로 닦아주는 게 오히려 효과적입니다. AHA나 BHA 같은 산 성분이 들어가 있는 각질 토너나 각질 패드로 닦토를 해주면 등드름과 가드름이 굉장히 많이 좋아지는 걸 경험할 수 있어요. 집에 있는 토너 중 각질 정리 기능이 표시된 제품이 있다면 그걸 사용하시면 됩니다. 스트라이덱스 토너 패드처럼 살리실릭 애시드 0.5%가 들어간 제품이나, 디오디너리 글리콜릭 애시드 토너처럼 AHA 성분이 든 제품이 대표적이에요. 굳이 이 제품이 아니더라도 AHA나 BHA가 포함된 토너라면 아무거나 쓰셔도 괜찮습니다. 새로 사고 싶다면 AHA, BHA, PHA, RHA가 모두 포함된 바디워시를 선택하시는 것도 좋은 방법이에요. 핵심은 닦토의 각질 제거 효과를 피지 많은 부위에 집중적으로 활용하는 겁니다.', '등드름 부위에 닦토가 효과적인 이유와 추천 각질 토너를 피부과 전문의 정한미가 정리합니다.', array['닦토', '등드름', 'AHA', 'BHA', '각질토너', '각질패드', '가드름', '바디워시']::text[]),
    ('SgJAZC_KNM8', 'jeonghanmi', '약국에서 살 수 있는 등드름 약이 있다던데 뭔가요?', '클리어틴이라는 일반의약품으로, 처방전 없이 약국에서 바로 구입할 수 있는 살리실릭 애시드 2% 약입니다. 화장품이나 클렌저에 들어갈 수 있는 살리실릭 애시드 최대 농도가 0.5%인 반면, 클리어틴은 의약품이라 4배 높은 2%가 들어가 있어서 효과가 더 강합니다. 클렌저나 토너를 써봤는데 효과가 없는 분들이 다음 단계로 시도해 볼 만한 제품이에요. 사용법은 여드름이 나는 부위에 톡톡 찍어서 바르면 되는데, 농도가 높기 때문에 넓게 펴 바르면 피부가 뒤집어질 수 있어 주의가 필요합니다. 그리고 등드름이 났을 때 손으로 뜯으면 색소침착이 심하게 남으니, 여드름 패치를 붙여서 만지지 않도록 하는 것도 중요해요. 패치를 붙이면 자국이 훨씬 덜 남고 덜 오래 갑니다. 이런 홈케어를 다 해봤는데도 안 좋아지면, 여드름이 아니라 모낭염이나 곰팡이균 감염일 수 있으니 피부과를 방문하세요.', '약국에서 살 수 있는 등드름 약 클리어틴의 효과와 사용 주의점을 피부과 전문의 정한미가 설명합니다.', array['클리어틴', '등드름', '살리실릭애시드', '약국', '여드름패치', '모낭염', '홈케어']::text[]),
    ('SgJAZC_KNM8', 'jeonghanmi', '등드름 자국 색소침착이 안 사라지는데 뭘 바르면 되나요?', '나이아신아마이드가 색소침착을 줄여주면서 염증과 붉은기를 가라앉히고, 피지까지 줄여주기 때문에 등드름 자국에 가장 적합한 성분입니다. 디오디너리 나이아신아마이드처럼 성분 함량이 높고 용량 대비 가격이 저렴한 제품이 넓은 등이나 앞가슴에 바르기 좋아요. 집에 레티놀이 있다면 등드름이 가라앉고 난 자리에 발라 보시는 것도 추천드립니다. 레티놀은 각질을 빨리 탈락시켜서 거기에 묻어 있는 색소를 떨어뜨리는 효과가 있어요. 레티놀이 없으면 일부러 새로 사실 필요는 없고, 있으면 활용해 보세요. 그리고 등드름을 예방하려면 샤워 순서도 중요합니다. 반드시 머리를 먼저 감고 몸을 나중에 씻어야 해요. 헤어 제품에 들어있는 실리콘이나 오일 성분이 피부에 남으면 모공을 막고 여드름을 유발하기 때문입니다. 등드름이 많이 나는 분은 머리 감을 때 몸을 숙여서 제품이 등에 닿지 않게 하는 게 가장 좋습니다.', '등드름 자국 색소침착에 효과적인 성분과 샤워 순서 팁을 피부과 전문의 정한미가 안내합니다.', array['등드름', '색소침착', '나이아신아마이드', '레티놀', '샤워순서', '가드름', '여드름자국']::text[]),
    ('Xm8HiMrS9QA', 'kimsoohyung', '선크림 바르고 폼클렌징으로만 씻으면 안 되나요?', '선크림을 바른 날에는 폼클렌징만으로 절대 충분하지 않고, 반드시 이중세안을 해야 합니다. 50배율 확대경으로 실험해 본 결과, 무기자차 선크림을 폼클렌징으로만 씻었을 때 각질 사이사이에 선크림이 그대로 남아 있는 게 확인됐어요. 무기자차의 원료는 돌을 아주 잘게 빻은 돌가루인데, 발림성을 위해 여기에 실리콘과 오일을 넣어 만든 것이 선크림입니다. 이 돌가루와 오일 성분을 제대로 씻어내지 않으면 모공을 막아서 피지와 땀이 배출되지 않고 트러블의 원인이 됩니다. 오일 성분은 물에 녹지 않아서 프라이팬 기름때처럼 기름으로 지워내야 해요. 그래서 1차 세안은 클렌징 오일이나 밀크로 유분기를 녹여내고, 2차 세안은 폼클렌징으로 남은 잔여물을 마무리하시는 게 올바른 순서입니다. 자외선 카메라로 찍어봐도 이중세안을 해야만 잔여물이 완전히 제거되는 걸 확인할 수 있어요.', '선크림 이중세안이 필수인 이유와 올바른 세안 순서를 피부과 전문의 김수형이 설명합니다.', array['이중세안', '선크림', '무기자차', '클렌징오일', '폼클렌징', '모공', '트러블']::text[]),
    ('Xm8HiMrS9QA', 'kimsoohyung', '무기자차 선크림이 순하다는데 대충 씻어도 괜찮지 않나요?', '무기자차가 순한 건 맞지만, 순하다고 대충 씻어도 되는 건 절대 아닙니다. 무기자차는 피부에 흡수되지 않고 막을 만들어 자외선을 차단하는 방식이라 민감성 피부나 영유아에게 적합해요. 하지만 바로 그 특성 때문에 돌가루 성분이 각질 사이에 끼어 모공을 막고 피부 트러블을 유발할 수 있습니다. 실험을 해보면 폼클렌징만으로는 선크림이 다 지워지지 않고, 클렌징 오일과 폼클렌징으로 이중세안을 해야 말끔해지는 걸 확인할 수 있어요. 세안 방법은 먼저 클렌징 오일을 바르고 충분히 롤링한 다음, 손에 물기가 있는 상태에서 유화를 시켜 뿌옇게 만들어주세요. 물로 헹군 후 폼클렌징을 할 때는 반드시 충분한 거품을 만든 상태에서 롤링해야 합니다. 거품 없이 하면 아무리 순한 제품이라도 피부에 자극이 가서 피부염이 생길 수 있어요.', '무기자차 선크림의 올바른 이중세안 방법과 유화 팁을 피부과 전문의 김수형이 안내합니다.', array['무기자차', '이중세안', '클렌징오일', '세안법', '민감성피부', '유화', '거품']::text[]),
    ('Xm8HiMrS9QA', 'kimsoohyung', '아이한테 이중세안이 너무 힘든데 좋은 방법 없나요?', '이중세안이 어려운 아이들에게는 이지워시 타입 선크림을 사용하시면 폼클렌징 한 번만으로도 말끔히 씻겨냅니다. 이지워시는 선크림 성분에 수용성 코팅을 하거나 유화제를 첨가해서 1차 세안만으로도 잘 지워지도록 만든 제품이에요. 로션 제형이라 수분감 있게 발리고, 아이들이 얼굴을 움직여도 쉽게 발리는 장점이 있습니다. 실제로 바른 후 폼클렌징으로만 씻어봤을 때 선크림이 말끔히 지워지는 걸 확인했어요. 다만 이지워시 제품들은 대부분 SPF가 32 정도로 낮은 편이라, 야외 활동을 많이 하는 아이들에게는 자주 덧발라 주시는 게 좋습니다. 실내 활동이 많은 민감성 피부에게도 적합한 선택이에요. 선크림을 바른 날에는 무조건 이중세안이 원칙이지만, 이지워시 제품이라면 아이들도 부담 없이 선크림을 쓸 수 있습니다.', '이중세안이 어려운 아이를 위한 이지워시 선크림의 장단점을 피부과 전문의 김수형이 정리합니다.', array['이지워시', '어린이선크림', '이중세안', '민감성피부', '선크림', '유아', 'SPF']::text[]),
    ('Xm8HiMrS9QA', 'kimsoohyung', '선크림 바르면 여드름이 더 올라오는데 어떤 걸 써야 하나요?', '여드름 피부라면 유분기가 적은 수분감 많은 선크림을 쓰거나, 잘 씻기는 이지워시 제품을 사용하시는 게 좋습니다. 선크림을 발랐을 때 여드름이 더 올라오는 이유는 선크림의 오일 성분이 모공을 막기 때문이에요. 유분기가 많은 선크림을 제대로 씻어내지 않으면 잔여물이 모공을 막고 결국 여드름을 유발하게 됩니다. 반면 수분감이 많은 선크림은 오일 성분이 적게 남아서 모공을 막을 확률이 줄어들어요. 민감성 피부이면서 이중세안이 부담스러운 분들은 1차 클렌징 밀크로 유분기를 제거하고, 2차 클렌징 젤로 잔여물을 마무리하시면 자극 적고 수분감 있게 끝낼 수 있습니다. 클렌징 밀크와 클렌징 젤 조합으로도 선크림이 말끔히 씻기는 게 실험으로 확인됐어요. 피부장벽이 약한 분도 이 조합이라면 매일 부담 없이 이중세안을 하실 수 있습니다.', '여드름 피부에 맞는 선크림 선택과 자극 적은 이중세안 조합을 피부과 전문의 김수형이 안내합니다.', array['여드름', '선크림', '이중세안', '클렌징밀크', '클렌징젤', '민감성피부', '모공']::text[]),
    ('hIFc2zY_vNs', 'kimjongsik', '뜨거운 물로 모공 열고 찬물로 닫는 세안법 진짜 효과 있나요?', '아니요, 뜨거운 물로 열었다가 찬물로 조이는 세안법은 오히려 모공을 더 자극해서 도드라져 보이게 만들 수 있으니 지금 당장 중단하셔야 합니다. 모공을 자꾸 열었다 닫았다 반복하면 자극이 누적되면서 모공이 더 벌어지는 현상이 생길 수 있어요. 코팩이나 각질팩처럼 물리적으로 피지를 뜯어내는 방법도 마찬가지로 모공을 늘어지게 만드는 원인이 됩니다. 묵은 피지와 각질은 클렌징 오일이나 클렌징 밀크로 기름때를 살살 녹여서 제거하는 게 훨씬 안전해요. 이때 바로 물로 씻지 말고 물을 묻혀 롤링하는 유화 과정을 거친 뒤 씻어내셔야 합니다. 그 다음 클렌징 폼으로 한번 더 마무리 세안을 해주세요. 아무리 좋은 제품을 열 가지 바르더라도 이런 나쁜 습관 한두 가지를 안 하는 게 모공 관리에서는 더 중요합니다.', '뜨거운물-찬물 세안법과 코팩이 모공에 해로운 이유를 피부과 전문의 김종식이 설명합니다.', array['모공', '세안법', '클렌징오일', '유화', '코팩', '각질팩', '홈케어']::text[]),
    ('hIFc2zY_vNs', 'kimjongsik', '모공이 넓은 지성 피부인데 여름에 뭘 발라야 하나요?', '피지 분비가 왕성한 지성 피부는 여름에 살리실산이 들어있는 토너로 가볍게 필링해주는 게 가장 효과적입니다. 피지를 말려주는 세안제로 한 번 더 세안한 뒤, 살리실산 토너를 T존 위주로 발라주시면 모공 속 노폐물이 정리되면서 모공이 덜 벌어져 보여요. 여름에는 오히려 꾸덕한 크림류를 아예 바르지 않는 것도 방법입니다. 스킨이나 토너만 바르고 아무것도 안 바르는 게 나을 때도 있어요. 모공 발달이 많은 분들은 레티놀 제품이나 스티바 같은 연고를 매일 사용해 피부 재생을 도와주는 것도 좋습니다. 다만 여러 제품을 한꺼번에 섞어 바르면 자극이 생길 수 있으니, 하루에 한 가지만 쓰거나 번갈아 사용하시는 게 안전해요. 내 피부가 피지형인지 노화형인지 먼저 파악하고 제품을 선택하는 게 핵심입니다.', '지성 피부의 여름철 모공 관리에 효과적인 홈케어 제품을 피부과 전문의 김종식이 안내합니다.', array['모공', '지성피부', '살리실산', '레티놀', '피지', '여름스킨케어', '홈케어']::text[]),
    ('hIFc2zY_vNs', 'kimjongsik', '나이 들면서 세로로 늘어나는 모공은 왜 생기는 건가요?', '세로 모공은 피지가 아닌 노화로 인해 모공 자체의 탄력이 떨어지면서 아래로 늘어져 생기는 현상입니다. 얼굴이 기름지지 않고 오히려 건조한 분들, 어릴 때는 모공이 거의 안 보였는데 나이 들면서 슬슬 늘어지기 시작한 분들에게 많이 나타나요. 모공이 비교적 적게 발달한 피부도 나이가 들면 세로 모공이 생길 수 있습니다. 이런 노화성 모공에는 비타민C 제품이 효과가 있어요. 여름에는 CE페룰릭 같은 비타민C 앰플을 양 볼 위주로 바르고, 겨울에는 비타민C 사용을 줄이고 레티놀 제품을 쓰는 식으로 계절에 따라 바꿔주는 게 좋습니다. 피지형 모공과 노화형 모공은 관리법이 완전히 다르기 때문에 자기 모공 타입을 먼저 정확히 알아야 합니다. 잘 모르겠으면 제품을 많이 쓰는 것보다 하나씩 번갈아 사용하시는 게 안전합니다.', '노화로 생기는 세로 모공의 원인과 계절별 홈케어 방법을 피부과 전문의 김종식이 정리합니다.', array['세로모공', '노화', '비타민C', '탄력', '모공관리', 'CE페룰릭', '레티놀']::text[]),
    ('hIFc2zY_vNs', 'kimjongsik', '울쎄라가 리프팅 말고 모공 축소에도 효과 있나요?', '네, 울쎄라의 얕은 팁으로 모공 주변에 집중 시술하면 모공이 좁아지고 리프팅되는 효과를 기대할 수 있습니다. 울쎄라는 리프팅 장비로 알려져 있지만, 다양한 깊이의 팁이 있어서 깊은 팁은 근막 자극으로 리프팅에 쓰고 얕은 팁은 모공 타이트닝에 활용됩니다. 일반 리프팅 울쎄라는 시술 후 1-2달이 지나야 효과가 나타나는 반면, 모공 팁은 1-2주만에 바로 차이를 느끼실 수 있어요. 실제로 울쎄라 모공 팁 시술 후 2주 뒤에 모공이 눈에 띄게 줄어든 케이스가 많습니다. 비슷한 원리인 슈링크 장비로도 팁만 잘 선택하면 좋은 결과를 얻을 수 있어요. 다만 피지 분비가 왕성한 귤껍질 모공 타입은 골드PTT나 니들RF 같은 피지 억제 시술이 더 적합합니다. 노화로 늘어진 세로 모공이라면 울쎄라가 가장 잘 맞는 선택이 될 수 있어요.', '울쎄라 얕은 팁을 활용한 모공 축소 시술의 효과와 원리를 피부과 전문의 김종식이 설명합니다.', array['울쎄라', '모공', '리프팅', '슈링크', '골드PTT', '니들RF', '세로모공']::text[]),
    ('RT1T05Ns1AY', 'gohyerim', '데오드란트가 사실 땀을 막아주는 게 아니라는 말이 진짜인가요?', '네, 데오드란트의 원래 용도는 땀 억제가 아니라 땀 냄새 제거입니다. 물론 요즘 제품에는 겨드랑이 땀을 줄이는 성분이 대부분 들어가 있지만, 땀이 많은 분들의 겨터파크를 막기에는 효과가 부족할 수 있어요. 데오드란트에는 냄새를 잡기 위해 항균 성분인 트리클로산과 향료가 들어있는 경우가 많은데, 트리클로산은 갑상선이나 생식 호르몬 불균형을 일으킬 수 있다는 유해성 논란이 있어 사용을 줄이는 추세입니다. 향료 역시 알레르기 접촉 피부염을 가장 많이 일으키는 원인으로 보고되고 있어요. 가렵고 따가워서 긁으면 그 부위에 거뭇거뭇한 색소침착까지 생길 수 있습니다. 실제로 데오드란트 사용 후 접촉 피부염과 색소침착 때문에 상담 오시는 분들이 꽤 많아요. 땀이 심하지 않고 냄새만 신경 쓰이는 정도라면 데오드란트로 충분하지만, 심한 겨땀에는 다른 방법을 고려해야 합니다.', '데오드란트의 실제 기능과 향료·트리클로산의 부작용 위험을 피부과 전문의 고혜림이 설명합니다.', array['데오드란트', '겨드랑이', '땀', '트리클로산', '향료', '접촉피부염', '색소침착']::text[]),
    ('RT1T05Ns1AY', 'gohyerim', '피부과 의사가 직접 쓰는 데오드란트는 어떤 제품인가요?', '트리클로산과 향료가 빠진 크리스탈 데오드란트 스틱형이 민감한 피부에 가장 안전한 선택입니다. 스틱형은 암모늄알룸 단일 성분으로만 되어 있어서 땀 발생을 억제하면서도 무향이고 끈적임이 없어요. 샤워 후 물기를 대충 닦고 바로 바르면 따로 물을 묻힐 필요 없이 간편하게 사용할 수 있습니다. 롤온형은 포타슘알룸과 소듐바이카보네이트 등 총 6개 성분이 들어있어 항균 항염 작용까지 해주지만, 액체가 마르는 데 시간이 걸려 좀 불편할 수 있어요. 피부가 민감한 분이라면 성분 수가 적은 스틱형을 선택하시는 게 낫습니다. 다만 기본 성분 자체가 알루미늄 화합물이라 자극이 있을 수 있으니 외출 후 돌아오면 꼭 바로 씻어내 주세요. 2주간 직접 사용해본 결과 특별한 자극 없이 무난하게 쓸 수 있었습니다.', '민감 피부에 안전한 크리스탈 데오드란트 스틱형 사용 후기를 피부과 전문의 고혜림이 안내합니다.', array['크리스탈데오드란트', '암모늄알룸', '겨드랑이', '땀억제', '민감피부', '무향', '스틱형']::text[]),
    ('RT1T05Ns1AY', 'gohyerim', '약국에서 파는 겨땀 억제제는 어떤 원리로 효과가 있는 건가요?', '약국 겨땀 억제제의 핵심 성분인 염화알루미늄은 땀과 만나 화학 반응으로 침전물을 만들어 땀샘을 물리적으로 막아주는 원리입니다. 쉽게 말해 땀샘에 모자를 씌운다고 생각하시면 돼요. 염화알루미늄 농도 20% 제품에는 드리클로, 노스엣, 스웨클로, 데오클렌이 있고, 12% 제품에는 노스엣센스와 스웨티브센스가 있습니다. 드리클로와 노스엣은 알코올이 들어있어 빨리 마르지만 자극이 있을 수 있고, 스웨클로와 데오클렌은 알코올이 없어 자극은 덜하지만 건조에 시간이 걸립니다. 처음 사용하거나 민감한 피부라면 12% 제품부터 시작하시는 게 안전해요. 반드시 물기를 완전히 말린 후 밤에 바르셔야 하는데, 염화알루미늄이 물과 만나면 염산이 생성되어 피부가 화끈거릴 수 있기 때문입니다. 제모 직후에는 12시간 이상 간격을 두고 사용해주세요.', '약국 겨땀 억제제의 작용 원리와 농도별 제품 비교를 피부과 전문의 고혜림이 정리합니다.', array['염화알루미늄', '드리클로', '겨땀', '약국템', '땀억제', '노스엣', '스웨클로']::text[]),
    ('RT1T05Ns1AY', 'gohyerim', '데오드란트도 약국템도 안 통하면 겨드랑이 보톡스밖에 답이 없나요?', '네, 데오드란트와 약국템으로 땀 억제가 역부족이거나 자극·알레르기로 사용이 불가능하다면 겨드랑이 보톡스 시술을 고려해볼 수 있습니다. 보톡스는 보통 4개월에서 길면 6개월까지 효과가 지속되기 때문에 1년에 한 번 정도 5-6월에 맞으면 여름 내내 뽀송하게 지낼 수 있어요. 단계별로 정리하면 땀이 심하지 않고 냄새만 신경 쓰이는 분은 데오드란트, 겨터파크가 열릴 만큼 땀이 많은 분은 염화알루미늄 약국템, 그마저도 부족하거나 쓸 수 없는 분은 보톡스 시술 순서로 접근하시면 됩니다. 약국템을 쓸 때는 물기를 완전히 말리고 밤에 바르는 게 핵심이고, 상처나 제모 직후에는 쓰면 안 됩니다. 아침에 일어나서 겨드랑이를 잘 닦아줘야 옷 변색도 방지할 수 있어요. 본인 피부에 문제가 생기지 않는 선에서 단계적으로 시도해보시는 게 가장 현명한 방법입니다.', '겨드랑이 보톡스 시술의 효과 지속 기간과 단계별 겨땀 관리법을 피부과 전문의 고혜림이 안내합니다.', array['겨드랑이보톡스', '보톡스', '겨땀', '다한증', '데오드란트', '염화알루미늄', '땀억제']::text[]),
    ('PhkRbs0d8gA', 'kimjongsik', '눈밑 꺼짐에 콜라겐 크림 열심히 바르면 효과 있나요?', '결론부터 말씀드리면 콜라겐 크림으로는 눈밑 꺼짐을 개선할 수 없습니다. 눈밑이 꺼져 보이는 건 피부 표면이 아닌 피부 안쪽 구조물의 문제이기 때문에 바르는 제품으로는 해결이 안 돼요. 눈밑 꺼짐에는 크게 두 가지 유형이 있는데, 하나는 눈밑을 지지하는 인대가 노화로 힘이 떨어지면서 지방이 불룩하게 돌출되는 형태이고, 다른 하나는 눈 주변 뼈가 선천적으로 발달이 미약해 앞볼 쪽이 안으로 꺼져 보이는 형태입니다. 선천적 꺼짐은 나이와 관계없이 젊을 때부터 나타나며, 다크서클이 있거나 퀭해 보인다고 느끼시는 분들이 이 경우에 해당할 수 있어요. 실제로는 눈바로 밑이 아니라 그보다 아래쪽인 앞볼이 꺼져서 전체가 퀭해 보이는 경우가 많습니다. 내 상태가 어떤 유형인지 정확히 파악하는 게 시술 선택의 첫 단계이니, 무작정 유명한 시술을 찾기보다 원인부터 확인해보세요.', '콜라겐 크림이 눈밑 꺼짐에 효과 없는 이유와 꺼짐의 두 가지 유형을 피부과 전문의 김종식이 설명합니다.', array['눈밑꺼짐', '콜라겐', '다크서클', '노화', '눈밑지방', '앞볼', '인대']::text[]),
    ('PhkRbs0d8gA', 'kimjongsik', '눈밑 꺼짐에 쥬베룩 볼륨 맞으면 채워지지 않나요?', '쥬베룩 볼륨은 콜라겐 부스터로서 효과 자체는 좋지만, 눈밑에는 추천하지 않는 시술입니다. 첫째로 쥬베룩 볼륨은 한 번으로 끝나지 않고 최소 한 달 간격으로 세 번 이상 시술해야 하는데, 콜라겐이 얼마나 차오를지 정확히 예측할 수 없어요. 눈밑은 아주 좁은 위치에 작은 포인트만 정밀하게 채워야 하는 까다로운 부위인데, 원하는 양보다 적거나 많은 콜라겐이 생성되면 인상 자체가 크게 달라질 수 있습니다. 눈밑은 조금만 변해도 전체 인상에 큰 영향을 미치는 곳이에요. 또한 눈밑 피부가 매우 얇기 때문에 시술 후 작은 결절이라도 생기면 피부에 비쳐 보이는 부작용이 생길 수 있습니다. 발생 빈도는 낮지만 한번 생기면 상당히 골치 아픈 문제가 됩니다. 그래서 눈밑 꺼짐 교정에는 볼륨을 정밀하게 조절할 수 있는 다른 방법을 고려하시는 게 좋아요.', '눈밑에 쥬베룩 볼륨을 추천하지 않는 이유와 부작용 위험을 피부과 전문의 김종식이 안내합니다.', array['쥬베룩', '눈밑꺼짐', '콜라겐', '결절', '볼륨시술', '부작용', '콜라겐부스터']::text[]),
    ('PhkRbs0d8gA', 'kimjongsik', '눈밑 꺼짐에는 필러가 제일 낫다는 게 사실인가요?', '네, 선천적으로 앞볼이 꺼져서 생기는 눈밑 꺼짐에는 필러가 가장 효과적인 시술입니다. 필러에 거부감을 가지신 분들이 많지만 이 부위는 들어가는 양 자체가 워낙 적기 때문에 필러가 이동하거나 녹아서 부자연스러워지는 부작용이 거의 없어요. 아주 소량만으로도 교정 효과가 좋다는 게 큰 장점입니다. 다만 반드시 알아야 할 점이 있는데, 눈바로 밑이 아니라 그보다 아래쪽인 앞광대나 앞볼 쪽에 시술하는 게 훨씬 자연스럽고 예쁘게 교정됩니다. 또 하나 중요한 건 1cc를 꼭 다 넣을 필요 없이 딱 필요한 만큼만 소량으로 넣어 모양을 교정하는 거예요. 과한 양을 넣으면 얼굴이 어색해질 수 있으니, 소량으로 교정하고 부족하면 나중에 다시 소량 추가하는 방식이 안전합니다. 시술 위치와 양 조절, 이 두 가지가 눈밑 필러의 핵심이에요.', '눈밑 꺼짐에 필러가 효과적인 이유와 시술 시 핵심 주의사항을 피부과 전문의 김종식이 정리합니다.', array['필러', '눈밑꺼짐', '앞볼', '소량교정', '앞광대', '다크서클', '볼륨']::text[]),
    ('PhkRbs0d8gA', 'kimjongsik', '눈밑이 퀭한데 울쎄라나 써마지로 좋아질 수 있나요?', '울쎄라와 써마지는 인대가 약해져서 눈밑 지방이 불룩하게 돌출되는 유형에는 효과가 좋지만, 선천적으로 앞볼이 꺼진 유형에는 적합하지 않습니다. 눈밑을 지지하는 인대에 힘이 없어지면서 지방이 튀어나오는 경우라면, 울쎄라나 써마지가 인대에 힘을 보강해줄 수 있어 단연 좋은 선택이에요. 반면 뼈 자체가 선천적으로 발달이 덜 돼서 앞볼이 쑥 꺼져 보이는 분들은 리프팅 장비로는 해결이 되지 않습니다. 이 경우에는 볼륨감을 채워주는 필러 시술이 가장 적합해요. 핵심은 내 눈밑이 진짜 꺼진 건지, 지방이 불룩한 건지, 아니면 꺼진 위치가 눈 밑이 아니라 그 아래쪽인지를 정확히 구분하는 데 있습니다. 유명하다는 이유만으로 시술을 고르기보다 자신의 상태에 맞는 시술을 선택하시는 게 훨씬 중요합니다.', '눈밑 꺼짐 유형별로 울쎄라·써마지와 필러 중 적합한 시술을 피부과 전문의 김종식이 안내합니다.', array['울쎄라', '써마지', '눈밑꺼짐', '리프팅', '필러', '눈밑지방', '인대']::text[]),
    ('ub0dxrymg7o', 'gohyerim', '순수 비타민C랑 비타민C 유도체 뭐가 다른 건가요?', '순수 비타민C(아스코빅애씨드)는 항산화, 미백, 콜라겐 생성에 직접적으로 효과가 강하지만, pH가 낮아 피부 자극이 크고 빛과 열에 쉽게 산화되는 단점이 있습니다. 개봉 후 3-4개월만 지나도 노랗게 변색될 정도로 안정성이 낮아요. 반면 비타민C 유도체는 이런 단점을 보완한 형태라서 빛과 열에 안정적이고 피부 자극도 적어 민감한 피부에 사용하기 수월합니다. 다만 피부에 흡수된 후 비타민C로 전환되는 과정이 필요하기 때문에 순수 비타민C보다 효과는 다소 떨어질 수 있어요. 성분표에서 구분하는 방법도 다른데, 순수 비타민C는 아스코빅애씨드로, 유도체는 에칠아스코빌에텔처럼 이름 중간에 아스코빌이 들어있는지 확인하시면 됩니다. 피부가 예민하신 분이라면 유도체 제품부터 시작하는 게 안전한 선택입니다.', '순수 비타민C와 비타민C 유도체의 차이와 민감 피부에 적합한 선택을 피부과 전문의 고혜림이 정리합니다.', array['비타민C', '아스코빅애씨드', '비타민C유도체', '민감피부', '항산화', '미백', '에칠아스코빌에텔']::text[]),
    ('ub0dxrymg7o', 'gohyerim', '피부 예민한데 순수 비타민C 앰플 쓰고 싶으면 어떻게 해야 하나요?', '따가움이 느껴져도 바로 중단하지 말고, 크림에 한두 방울 섞어서 바르는 것부터 시작해보세요. 처음부터 맨 얼굴에 바르면 따갑고 붉어질 수 있는데, 크림에 섞으면 자극이 완화되면서도 피부가 점차 적응할 수 있습니다. 사용량을 조금씩 늘려 나중에는 4-5방울까지 섞어 써도 괜찮아지는 경우가 많아요. 사용 빈도도 처음에는 3일에 한 번 저녁에만 쓰다가, 2-3주 후 이상이 없으면 이틀에 한 번으로 늘리시면 됩니다. 낮은 농도의 제품부터 시작해 서서히 농도를 올리는 것도 핵심이에요. 기미가 있으신 분은 기미 부위를 피해 먼저 테스트한 후 자극이 없을 때 전체에 사용하세요. 비타민A 제품과는 같은 시간대에 같이 쓰지 말고 아침 비타민C, 저녁 비타민A로 나누거나 격일로 사용하시는 게 안전합니다.', '예민한 피부가 순수 비타민C 앰플에 적응하는 단계별 방법을 피부과 전문의 고혜림이 안내합니다.', array['비타민C', '민감피부', '순수비타민C', '기미', '비타민A', '앰플', '스킨케어루틴']::text[]),
    ('ub0dxrymg7o', 'gohyerim', '아토피 있는 민감 피부도 비타민C 유도체 앰플 쓸 수 있나요?', '네, 알레르기 유발 성분과 향료가 없는 비타민C 유도체 제품이라면 아토피가 있는 민감 피부도 사용할 수 있습니다. 비타민C 유도체는 순수 비타민C보다 자극이 적고 안정성이 높아서 예민한 피부에도 수월하게 쓸 수 있어요. 에칠아스코빌에텔이 들어있는 제품 중에서도 나이아신아마이드, 판테놀, 병풀 추출물처럼 진정과 재생에 도움이 되는 성분이 함께 들어있으면 더 좋습니다. 다만 나이아신아마이드가 10% 이상 고함량으로 들어있는 제품은 예민한 날 따끔거리거나 붉어질 수 있으니 주의하세요. 건조한 피부라면 히알루론산이 함께 들어있는 제품을 선택하면 보습까지 동시에 챙길 수 있어요. 피부 상태가 안 좋은 날에는 모든 활성 성분을 중단하고 판테놀이나 세라마이드 보습제로 장벽을 회복시킨 뒤 다시 루틴으로 돌아가는 게 핵심입니다.', '아토피 민감 피부의 비타민C 유도체 사용법과 제품 선택 기준을 피부과 전문의 고혜림이 설명합니다.', array['아토피', '민감피부', '비타민C유도체', '나이아신아마이드', '판테놀', '히알루론산', '피부장벽']::text[]),
    ('ub0dxrymg7o', 'gohyerim', '피부과 의사는 비타민C를 어떤 루틴으로 바르고 있나요?', '매일 아침에는 비타민C 유도체 앰플을 바르고, 이틀에 한 번 저녁에만 순수 비타민C 앰플을 사용하는 방식으로 루틴을 유지하고 있습니다. 순수 비타민C를 쓰지 않는 저녁에는 비타민A가 들어있는 제품을 바르고 있어요. 처음에는 비타민C를 맨 얼굴에 바르면 따갑고 붉어졌기 때문에 크림에 섞어서 시작했고, 점차 적응하면서 지금은 피부 상태 좋은 날에는 세안 직후에도 사용할 수 있게 되었습니다. 하지만 피부 컨디션이 안 좋은 날에는 비타민C와 비타민A 모두 중단하고 판테놀 앰플이나 세라마이드 보습제만 사용해 피부 장벽을 회복시켜요. 건강해졌다고 느껴지면 다시 원래 루틴으로 돌아가는 유연한 방식입니다. 예민한 피부일수록 매일 같은 루틴을 고집하기보다 그날 피부 상태에 맞춰 조절하시는 게 중요합니다.', '민감 피부 피부과 의사의 실제 비타민C 사용 루틴과 컨디션별 대처법을 피부과 전문의 고혜림이 공유합니다.', array['비타민C', '스킨케어루틴', '비타민A', '민감피부', '판테놀', '피부장벽', '순수비타민C']::text[]),
    ('3URwM6zw35I', 'parkhyojin', '수부지인데 보습 안 하면 오히려 기름이 더 나온다는 게 사실인가요?', '네, 수딩젤이나 앰플만 쓰고 보습을 전혀 안 해주면 오히려 수분 부족으로 피부가 유분을 더 많이 만들어냅니다. 핵심은 피부 장벽을 보호할 수 있게 보습은 어느 정도 해주면서 기름기는 잡아주는 제품을 간단히 쓰고, 모공을 막는 제품은 모두 피하는 것이에요. 기름이 많은 피부는 바르는 행위 자체를 최소화해야 하지만 그렇다고 아예 안 바르면 악순환이 됩니다. 실제로 보습력 좋기로 유명한 무거운 로션을 발랐다가 유분이 폭발하고 트러블이 난 경험도 있어요. 건성이나 아토피 환자분들이 쓰는 무거운 제품을 절대 쓰시면 안 되고, 기름은 잡으면서 보습감은 주는 가벼운 로션 하나만 선택하시면 됩니다. 이렇게 단순한 루틴으로도 2-3일만 따라해도 기름이 줄어드는 걸 느끼는 분들이 많아요.', '수부지 피부가 보습을 해야 기름이 줄어드는 원리와 제품 선택 기준을 피부과 전문의 박효진이 설명합니다.', array['수부지', '보습', '유분', '피부장벽', '홈케어', '지성피부', '로션']::text[]),
    ('3URwM6zw35I', 'parkhyojin', '기름 많은 피부인데 클렌징 오일 쓰면 안 되나요?', '기름이 많은 피부에 클렌징 오일을 쓰면 모공을 더 막고 잘 씻겨나가지 않아서 오히려 트러블을 유발할 수 있습니다. 실제로 오일로 세안하면 손톱으로 긁었을 때 그대로 잔여물이 긁혀 나올 만큼 깨끗이 씻어내기 어려워요. 2차 세안을 한다 해도 완전히 제거하지 못해 문제가 생길 가능성이 높습니다. 클렌징 밀크도 같은 이유로 권하지 않고, 클렌징 워터를 사용하시는 게 낫습니다. 유분이 많은 분이라면 분홍색 뚜껑이 아닌 연두색 뚜껑 제품을 선택하시고, 닦아낼 때 박박 문지르지 말고 부드럽게 닦아내는 게 포인트예요. 워터로 1차 클렌징 후에는 BHA나 RHA 같은 필링 성분이 포함된 약알칼리성 세안제로 2차 세안해 피지와 각질을 제거해주시면 됩니다. 다만 피부 장벽이 무너져 있다면 약산성 제품으로만 부드럽게 세안하셔야 해요.', '기름 많은 피부에 클렌징 오일이 맞지 않는 이유와 올바른 세안법을 피부과 전문의 박효진이 안내합니다.', array['클렌징오일', '지성피부', '클렌징워터', '이중세안', '모공', '트러블', 'BHA']::text[]),
    ('3URwM6zw35I', 'parkhyojin', '수부지 피부 스킨케어는 뭘 얼마나 발라야 하나요?', '기름이 많은 수부지 피부는 토너 하나와 로션 하나, 딱 두 가지만으로 기본 스킨케어를 끝내는 게 가장 이상적입니다. 번들거림 없이 수분을 충분히 공급하면서 결을 정리해주는 토너를 바른 뒤, 기름은 잡으면서 피부 깊숙이 보습감을 주는 로션 하나만 바르면 돼요. 기름이 많은 피부든 예민한 피부든 최소한으로 발라야 하기 때문입니다. 그래도 미백이나 항노화가 아쉽다면 아침에 로션 바르기 전 비타민C 세럼을 추가하고, 저녁에는 로션 바른 후 디페린 겔을 코, 이마, 나비존에 소량만 바르는 정도로 조합해볼 수 있어요. 디페린 겔은 기름기를 잡으면서 노화를 막아주는데 처방이 필요한 전문 의약품이니 피부과 상담 후 사용하세요. 피부가 현재 붉고 따갑고 건조하다면 비타민C와 디페린 겔 모두 피부 장벽이 회복된 후에 천천히 추가하셔야 합니다.', '수부지 피부의 최소한 스킨케어 루틴과 추가 제품 조합법을 피부과 전문의 박효진이 정리합니다.', array['수부지', '스킨케어', '비타민C', '디페린', '토너', '로션', '항노화']::text[]),
    ('3URwM6zw35I', 'parkhyojin', '기름 많은 피부에 매트 선크림 바르면 화장 안 해도 되나요?', '매트한 무기자차 선크림을 바르면 적당한 백탁 현상으로 톤이 환해지면서 막을 형성해 기름이 덜 올라오기 때문에, 특별한 약속이 없는 날에는 선크림 하나로 톤업 화장을 끝내고 외출할 수 있습니다. 기름 있는 피부는 화장을 안 하면 오후에 기름이 더 번들번들 올라오는데, 선크림으로 한번 막을 쳐주면 하루 종일 뽀송뽀송 화사함을 유지할 수 있어요. 문제는 대부분의 선크림이 유분기가 많아서 화장하기도 전에 이미 번들거린다는 건데, 이럴 때 매트 타입의 무기자차를 선택하시면 됩니다. 선크림만 바른 날 저녁에는 클렌저 밤 하나만으로도 세안이 가능해서 세안 부담도 줄어들어요. 이 단순한 루틴을 2주만 따라해보시면 기름이 줄고 피부가 건강해지는 변화를 느끼실 수 있습니다. 효과가 빠른 분은 2-3일 만에도 차이를 체감하는 경우가 많습니다.', '기름 많은 피부에 매트 무기자차 선크림 하나로 화장을 대체하는 방법을 피부과 전문의 박효진이 안내합니다.', array['선크림', '수부지', '매트선크림', '무기자차', '톤업', '유분', '지성피부']::text[]),
    ('0yPA_qnzUuQ', 'jeonghanmi', '한국 사람들은 진짜 체취가 안 나는 편인가요?', '네, 한국인은 유전적으로 체취가 거의 나지 않는 편입니다. 체취를 결정하는 유전자에 A타입과 G타입 두 가지가 있는데, A타입이면 체취가 거의 안 나고 G타입이면 심하게 납니다. 논문에 따르면 한국인은 거의 100%에 가까울 정도로 A타입 유전자를 갖고 있어요. 반면 흑인, 백인, 유럽인은 G타입이 월등히 많아서 겨드랑이 냄새가 한국인보다 훨씬 강합니다. 재밌는 건 이 유전자가 귀지 형태도 결정한다는 점이에요. A타입은 귀지가 바스라질 정도로 마르고, G타입은 끈적끈적하게 젖어 있습니다. 가족 중에 귀지가 끈적한 분이 있다면 G타입일 가능성이 높으니 겨드랑이 관리에 더 신경 쓰시는 게 좋습니다. 유전자 타입을 바꿀 수는 없지만 관리법으로 충분히 줄일 수 있으니 걱정하지 마세요.', '한국인의 체취가 적은 유전적 이유와 귀지 형태의 연관성을 피부과 전문의 정한미가 설명합니다.', array['체취', '유전자', '겨드랑이냄새', '귀지', '아포크린', '한국인', '땀냄새']::text[]),
    ('0yPA_qnzUuQ', 'jeonghanmi', '겨드랑이 냄새가 유독 지독한 이유가 뭐예요?', '겨드랑이에 분포한 아포크린 땀샘에서 나오는 땀이 다른 부위보다 진하고 탁하기 때문입니다. 우리 피부에는 에크린 땀샘과 아포크린 땀샘 두 종류가 있는데, 에크린은 전신에 고르게 있고 더울 때 나는 일반적인 땀을 분비해요. 반면 아포크린 땀샘은 겨드랑이처럼 특정 부위에만 집중되어 있습니다. 여기서 나오는 땀 성분이 피부 세균에 의해 분해되면 일반 땀보다 훨씬 지독한 냄새가 발생합니다. 원래 땀 자체는 냄새가 없지만, 세균이 땀을 분해하는 과정에서 비로소 냄새가 만들어지는 거예요. 개인마다 땀 성분, 보유 세균, 식습관, 스트레스가 다르기 때문에 체취의 정도도 사람마다 달라집니다. 겨드랑이는 아포크린 땀샘의 대표 부위이니 다른 곳보다 특별히 관리가 필요합니다.', '겨드랑이 냄새가 유독 심한 원인인 아포크린 땀샘의 원리를 피부과 전문의 정한미가 정리합니다.', array['아포크린', '에크린', '땀샘', '겨드랑이냄새', '체취', '세균', '땀']::text[]),
    ('0yPA_qnzUuQ', 'jeonghanmi', '먹는 음식에 따라 진짜 체취가 달라지나요?', '네, 먹는 음식이 땀 냄새에 직접적인 영향을 줍니다. 박찬호 선수가 미국 마이너리그 시절 마늘 냄새 때문에 동료에게 껌을 던져 맞은 적이 있을 정도예요. 마늘을 하나만 먹어도 땀을 흘리면 바로 마늘 냄새가 나서, 결국 한국 음식을 포기하고 치즈와 햄버거만 먹었더니 아무도 냄새 지적을 안 했다고 합니다. 마늘, 양파, 술처럼 냄새가 강한 음식은 체취를 강하게 만드니 줄이시는 게 좋습니다. 반대로 녹차, 파슬리, 과일은 체취를 줄여주는 음식으로 알려져 있어요. 물도 많이 마셔서 노폐물을 빨리 배출하는 것이 도움이 됩니다. 체취가 신경 쓰이신다면 식단부터 점검해 보세요.', '음식이 체취에 미치는 영향과 냄새를 줄이는 식단을 피부과 전문의 정한미가 안내합니다.', array['체취', '식습관', '마늘냄새', '녹차', '땀냄새', '음식', '노폐물']::text[]),
    ('0yPA_qnzUuQ', 'jeonghanmi', '체취 줄이려면 일상에서 뭘 어떻게 해야 하나요?', '규칙적인 샤워로 몸의 분비물을 씻어내는 것이 가장 기본입니다. 특히 아포크린 땀샘이 많은 겨드랑이는 더 꼼꼼히 씻어야 하고, 털이 많다면 제모를 하는 것도 효과적이에요. 털에 땀이 묻으면 세균 번식이 활발해져 냄새가 더 심해지기 때문입니다. 겨드랑이 냄새가 느껴진다면 데오드란트를 사용하시는 것도 좋습니다. 옷에도 피지와 땀이 묻어서 냄새가 나기 때문에 자주 갈아입는 습관이 중요하고요. 스트레스가 심해지면 냄새도 강해지므로 스트레스 관리까지 신경 쓰셔야 합니다. 이렇게 일상 속 작은 습관들만 지켜도 체취는 충분히 줄일 수 있어요.', '일상에서 체취를 줄이는 구체적인 관리법 5가지를 피부과 전문의 정한미가 정리합니다.', array['체취관리', '제모', '데오드란트', '겨드랑이', '스트레스', '샤워', '땀냄새']::text[]),
    ('Asc74WD0VRM', 'leedoyoung', '여드름 짜도 되는 거예요, 안 되는 거예요?', '여드름은 짜는 게 좋습니다. 다만 잘 짜야 합니다. 핵심은 농이 노랗게 올라와 있느냐인데, 만졌을 때 아프든 안 아프든 농이 노랗게 맺혀 있으면 집에서 짜셔도 됩니다. 이른바 잘 익은 여드름이죠. 방법은 약국에서 일회용 알코올 스왑과 멸균 면봉을 사서, 손을 깨끗이 씻고 여드름 주위를 소독한 뒤 멸균 면봉 두 개로 눌러 짜면 됩니다. 짠 후에는 감염 방지를 위해 여드름 패치를 붙이거나 연고를 발라주세요. 반면 피부 속 깊이 있어서 살짝만 건드려도 아픈 여드름은 절대 손으로 짜면 안 됩니다. 잘못 건드리면 더 큰 염증으로 번질 수 있으니 이런 경우 반드시 피부과를 방문하세요.', '농이 노랗게 올라온 여드름은 집에서 짜도 됩니다. 멸균 면봉을 이용한 올바른 압출법과 짜면 안 되는 여드름을 피부과 전문의 이도영이 안내합니다.', array['여드름', '압출', '멸균면봉', '여드름패치', '농', '염증', '피부과']::text[]),
    ('Asc74WD0VRM', 'leedoyoung', '여드름 빨리 안 없애면 진짜 흉터 남나요?', '네, 염증을 빨리 해결하지 않으면 100% 흉터가 남습니다. 이것을 연구한 논문에 따르면 염증이 아무리 심해도 빨리 해결하면 흉터가 남지 않고, 반대로 염증이 별로 심하지 않더라도 오래 방치하면 흉터가 많이 남는다고 합니다. 여드름이 난 것은 불이 난 것과 같다고 생각하시면 되는데, 불을 빨리 진압해야 후유증이 안 남는 것처럼 여드름도 최대한 빨리 해결해야 합니다. 피부과에서는 염증 주사로 염증을 바로 가라앉힌 뒤 스케일링이나 레이저 등으로 후속 관리를 도와드릴 수 있어요. 집에서 혼자 해보다가 흉터가 생겨서 더 큰 비용이 드는 경우를 많이 보았습니다. 여드름의 골든타임을 놓치지 않는 것이 가장 중요합니다.', '여드름 염증을 빨리 해결하지 않으면 흉터가 남습니다. 골든타임을 놓치지 않는 치료 원칙과 염증 주사 활용법을 피부과 전문의 이도영이 설명합니다.', array['여드름흉터', '염증', '골든타임', '압출', '염증주사', '스케일링', '피부과']::text[]),
    ('Asc74WD0VRM', 'leedoyoung', '여드름 예방하려면 어떤 음식을 피해야 하나요?', '혈당지수가 높은 음식을 멀리하는 게 가장 효과적입니다. 하얀빵, 흰쌀밥, 국수, 케이크, 쿠키, 사탕, 초콜릿 같은 정제 탄수화물과 설탕이 많은 디저트가 대표적이에요. 혈당이 빠르게 상승하면 인슐린과 IGF-1(인슐린유사성장인자)이 분비되면서 피지와 안드로겐 호르몬 분비가 증가해 결국 여드름을 일으킵니다. 술도 마찬가지인데, 맥주나 하이볼, 막걸리는 혈당지수가 높은 편이에요. 술을 완전히 끊기 어렵다면 와인, 소주, 보드카, 위스키처럼 혈당을 덜 올리는 종류로 적당량만 드시는 게 낫습니다. 달달한 탄산음료 대신 제로 음료를 선택하는 것도 좋은 방법이에요. 음식을 먹고 여드름이 반복된다면 혈당지수를 체크해 보시길 권합니다.', '흰빵·쿠키·맥주 같은 고혈당 음식이 피지 분비를 늘려 여드름을 유발합니다. 혈당지수 기준으로 안전한 대안 식품을 피부과 전문의 이도영이 정리합니다.', array['여드름', '혈당지수', '인슐린', '피지', '식습관', '술', '정제탄수화물']::text[]),
    ('Asc74WD0VRM', 'leedoyoung', '피부 예민한데 여드름이 자꾸 나면 어떤 관리를 받아야 하나요?', '피부가 예민하고 민감해서 여드름이 반복된다면 소노라임이나 LDM 같은 고밀도 초음파 관리가 적합합니다. 일반적인 스케일링은 자극이 될 수 있는 반면, 초음파 치료는 아주 미세한 진동을 피부에 전달하는 방식이에요. 이 잔떨림이 일어나면 피부는 장벽이 손상됐다고 인식해서 재생에 필요한 지질을 스스로 많이 만들어냅니다. 그래서 피부 장벽이 개선되면서 동시에 염증도 빠져나가는 효과가 있습니다. 집에서는 BHA 성분이 들어간 클렌저를 사용하면 면포를 녹이고 피지 분비도 줄여줘서 여드름 완화에 도움이 됩니다. 충분한 수면과 스트레스 관리도 성인형 여드름 예방에 중요하니 생활 습관 교정도 함께 해주세요.', '예민한 피부엔 소노라임·LDM 같은 초음파 관리가 적합합니다. 피부 장벽을 개선하면서 염증을 빼는 시술과 BHA 홈케어를 피부과 전문의 이도영이 안내합니다.', array['민감성피부', '여드름', '초음파', '소노라임', 'LDM', 'BHA', '피부장벽']::text[]),
    ('wusUx3hPsi8', 'leedoyoung', '30대 초반인데 갑자기 확 늙은 느낌이 드는 게 정상인가요?', '네, 30대 초반에 노화가 확 느껴지는 건 실제로 근거가 있습니다. 노화와 관련된 단백질 발현이 32~34세쯤 한 번 피크를 찍는다는 논문이 있어요. 이 시기를 경험한 분들은 대부분 얼굴이 훅 처진 느낌이 든다거나 꺾이는 느낌이 든다고 표현합니다. 잔주름이 갑자기 생기거나 피부가 푸석푸석해졌다고 느끼는 것도 같은 맥락이에요. 이럴 때 가장 도움이 되는 시술이 고주파 시술인데, 피부에 전기를 흘려 열을 발생시키면 오래된 콜라겐과 엘라스틴이 파괴되고 우리 몸이 새 콜라겐을 만들어냅니다. 1년에 한 번씩 꾸준히 받으면 어느 순간 동년배보다 훨씬 어려 보인다는 소리를 들을 수 있습니다. 노화는 365일 진행되니 커피 한 잔 값 정도의 투자로 미리 예방하시는 게 현명합니다.', '30대 초반 노화 피크의 과학적 근거와 고주파 시술의 원리를 피부과 전문의 이도영이 설명합니다.', array['노화', '고주파', '써마지', '콜라겐', '리프팅', '30대', '탄력']::text[]),
    ('wusUx3hPsi8', 'leedoyoung', '써마지 600샷 맞았는데 효과 모르겠다는 말이 사실인가요?', '써마지 효과를 제대로 보려면 샷수를 충분히 하거나 다른 시술을 병합해야 합니다. 시술 효과가 나타나려면 피부 온도를 40~42도 이상까지 올려야 하는데, 체온 36.5도에서 42도까지 올리는 데 비싼 써마지 샷을 소진하면 아까운 거예요. 그래서 써마지 전에 티타늄 리프팅이나 오푸스 같은 시술로 온도를 먼저 올려놓으면 써마지 한 샷 한 샷의 효율이 극대화됩니다. 600샷으로 효과를 못 느꼈다는 분들은 대부분 예열 없이 써마지만 단독으로 받은 경우가 많아요. 샷수가 적더라도 병합 시술과 함께라면 훨씬 좋은 결과를 기대할 수 있습니다. 비용 대비 효과를 최대화하려면 병합 전략을 상담받아 보시는 것을 추천드립니다.', '써마지 효과를 극대화하는 샷수 전략과 병합 시술 팁을 피부과 전문의 이도영이 안내합니다.', array['써마지', '샷수', '고주파', '병합시술', '피부온도', '티타늄리프팅', '오푸스']::text[]),
    ('wusUx3hPsi8', 'leedoyoung', '써마지 아프다는데 덜 아프게 받을 수 있는 방법 있나요?', '써마지가 아프신 분들은 세르프나 덴서티 하이 같은 대체 장비를 고려해 보세요. 이 장비들은 써마지보다 통증은 줄어들면서 효과는 상당히 좋은 고주파 시술기입니다. 써마지는 원래 아픈 시술에 속하지만, 지금은 K뷰티 덕분에 선택지가 엄청나게 많아졌어요. 대표적인 고주파 시술로 써마지 외에 올리지오, 텐서마, 댄서티, 세르프 등이 있습니다. 고주파의 원리는 동일하게 열을 이용해 오래된 콜라겐을 새것으로 교체하는 것이라 어떤 장비든 탄력, 잔주름, 모공, 피부결, 피부톤 개선 효과를 기대할 수 있어요. 처음 입문하시는 분이라면 통증이 적은 장비부터 시작해서 피부 반응을 보시는 게 부담이 덜합니다.', '써마지 통증이 걱정될 때 선택할 수 있는 대안 고주파 장비를 피부과 전문의 이도영이 정리합니다.', array['써마지', '통증', '세르프', '덴서티', '고주파', '올리지오', '입문']::text[]),
    ('wusUx3hPsi8', 'leedoyoung', '고주파 시술이랑 같이 받으면 좋은 시술이 뭐예요?', '고주파 시술 후 새 콜라겐이 더 잘 만들어지는 환경을 만들어주는 스킨부스터를 함께 받으시면 좋습니다. 대표적으로 쥬베룩이나 리쥬란 같은 스킨부스터가 도움이 됩니다. 볼살이나 턱살이 축 늘어져서 처짐이 심한 분들은 SMAS(근막)를 리프팅시키는 울쎄라가 적합하고요. 근육 자체를 강화시켜주는 엠페이스라는 시술도 있습니다. 고주파가 피부를 건강하게 만들어주는 시술이라면, 울쎄라나 엠페이스는 구조적인 처짐을 잡아주는 역할이라 서로 보완이 잘 돼요. 고주파를 1~2년 꾸준히 받으면서 본인 상태에 맞는 병합 시술을 더하면 동안 유지에 확실한 격차가 벌어집니다.', '고주파와 함께 받으면 효과 배가되는 병합 시술 조합을 피부과 전문의 이도영이 안내합니다.', array['고주파', '스킨부스터', '쥬베룩', '리쥬란', '울쎄라', '엠페이스', '병합시술']::text[]),
    ('sLsi7wWwMe4', 'jeonghanmi', '레티놀이 진짜 주름을 없애주는 성분인가요?', '네, 레티놀은 피부 노화를 예방하고 이미 진행된 노화를 되돌리는 효과가 과학적으로 입증된 성분입니다. 원래 여드름 치료 연고로 개발된 트레티노인을 꾸준히 바른 환자들이 주름까지 사라졌다고 보고하면서 항노화 효과가 발견됐어요. 1986년 논문에서 트레티노인이 광노화를 되돌린다는 사실이 밝혀졌고, 1995년 미국 FDA가 광노화 치료제로 정식 승인까지 했습니다. 레티놀은 이 트레티노인과 비슷한 효과를 내면서 부작용이 적도록 개량한 화장품 성분이에요. 피부톤이 밝아지고, 잔주름이 줄고, 탄탄해지는 등 화장품에 바라는 거의 모든 효과를 가지고 있습니다. 한두 번 발라서 바로 효과가 나타나진 않으니 본인에게 맞는 제품을 오랜 시간 꾸준히 바르는 게 가장 중요합니다.', '레티놀의 항노화 효과가 FDA 승인까지 받게 된 과학적 배경을 피부과 전문의 정한미가 설명합니다.', array['레티놀', '트레티노인', '주름', '광노화', 'FDA', '안티에이징', '비타민A']::text[]),
    ('sLsi7wWwMe4', 'jeonghanmi', '레티놀 부작용이 무섭다는데 처음 쓸 때 어떻게 시작해야 하나요?', '레티놀 초보라면 농도 0.01% 정도의 가장 낮은 제품부터 시작하시는 게 안전합니다. 레티놀은 트레티노인과 뿌리가 같은 성분이라 농도가 높으면 피부가 빨개지고, 각질이 일어나고, 찢어질 듯 건조해지는 부작용이 나타날 수 있어요. 처음에는 얼굴 전체에 바르지 말고 소량만 테스트해 보시고, 매일 바르지 말고 2~3일에 한 번씩 피부 반응을 살피며 사용하세요. 비타민C나 AHA, BHA처럼 자극을 줄 수 있는 성분과 동시에 쓰는 것도 조심해야 합니다. 레티놀을 바르면 피부가 자외선에 민감해질 수 있기 때문에 낮에는 반드시 자외선 차단제를 발라주셔야 해요. 적응이 된 후에야 농도를 0.1%, 0.5%로 단계적으로 올리시는 게 바람직합니다.', '레티놀 초보자의 단계별 사용법과 부작용 예방 수칙을 피부과 전문의 정한미가 안내합니다.', array['레티놀', '부작용', '농도', '자외선차단제', '각질', '초보', '사용법']::text[]),
    ('sLsi7wWwMe4', 'jeonghanmi', '레티놀이 원래 여드름 약이었다는 게 사실인가요?', '네, 레티놀의 뿌리인 트레티노인은 원래 여드름 치료 연고로 개발된 성분입니다. 1960년대 미국 필라델피아 대학교 피부과의 클리그만 교수가 비타민A 유도체 중 레티노익 애씨드가 피지를 줄이고 각질을 탈락시키는 기능을 발견했어요. 이걸로 여드름 환자에게 임상시험을 했더니 드라마틱하게 좋아져서 ''레틴A''라는 연고로 상업화했습니다. 날개 돋친 듯 팔렸고, 우리나라에서는 스티바A 크림이라는 이름으로 최근까지 판매됐어요. 그런데 이 연고를 꾸준히 바른 환자들이 "여드름도 나았는데 주름도 없어졌어요"라고 보고하면서 항노화 효과가 발견된 겁니다. 여드름 약을 개발했는데 알고 보니 젊어지게 하는 마법의 약이었던 셈이죠.', '여드름 치료제에서 항노화 성분으로 변신한 레티놀의 탄생 과정을 피부과 전문의 정한미가 정리합니다.', array['레티놀', '트레티노인', '여드름', '레틴A', '스티바A', '비타민A', '클리그만']::text[]),
    ('sLsi7wWwMe4', 'jeonghanmi', '레티놀 바를 때 목에도 꼭 발라야 하나요?', '네, 레티놀은 얼굴뿐 아니라 목에도 함께 발라주시는 게 좋습니다. 목에도 주름이 생기기 때문에 얼굴만 관리하면 얼굴과 목의 피부 나이 차이가 점점 벌어지게 됩니다. 얼굴에서 목까지 편하게 펴 바를 수 있는 가벼운 제형이 꾸준히 쓰기에 유리해요. 너무 끈적한 제형은 바르기 귀찮아서 오래 쓰지 못하게 되거든요. 피부 재생에 좋은 판테놀이 함께 들어간 제품이면 자극을 줄이면서 보습까지 챙길 수 있습니다. 레티놀의 핵심은 한두 번이 아니라 오랜 기간 꾸준히 바르는 것이니, 본인이 부담 없이 매일 쓸 수 있는 제형과 농도를 선택하시는 게 가장 중요합니다. 적응된 후에 농도를 점차 올려가는 단계적 접근을 추천드립니다.', '레티놀을 목까지 발라야 하는 이유와 꾸준히 쓰기 좋은 제품 선택법을 피부과 전문의 정한미가 설명합니다.', array['레티놀', '목주름', '판테놀', '사용법', '제형', '안티에이징', '홈케어']::text[]),
    ('TDZ_GV4CvQU', 'kimsoohyung', '문신 지우려면 몇 번이나 받아야 하고 색깔마다 다른가요?', '문신은 한 번에 다 지워지지 않고, 잉크 색과 양에 따라 횟수가 달라집니다. 검정색은 입자 크기가 작은 편이라 비교적 빨리 지워지고, 보라색이나 남색도 비교적 잘 지워지는 편이에요. 반면 빨간색과 노란색은 잘 안 지워지는 색에 속합니다. 실선과 그라데이션만으로 이루어진 도안은 잉크 양이 적어서 적은 횟수로도 제거가 가능하고요. 피부가 하얀 경우에는 문신과 피부색의 대비가 커서 레이저가 더 잘 먹히고, 시술 후 색소침착도 덜 오는 편입니다. 문신을 한 지 오래됐을수록 더 빨리 지워지기도 해요. 정확한 횟수는 크기, 색깔, 잉크 양에 따라 달라지니 병원에서 직접 상담받으시는 게 좋습니다.', '검정 문신은 빨리 지워지지만 빨간색·노란색은 난이도가 높습니다. 색깔·잉크량·피부색에 따른 제거 횟수 차이를 피부과 전문의 김수형이 정리합니다.', array['문신제거', '피코레이저', '잉크색', '검정문신', '빨간문신', '색소침착', '시술횟수']::text[]),
    ('TDZ_GV4CvQU', 'kimsoohyung', '문신 지울 때 진짜 엄청 아프다는데 어떻게 견디나요?', '문신을 지우는 건 새기는 것보다 훨씬 아프지만, 요즘은 마취 방법이 다양해서 걱정을 많이 안 하셔도 됩니다. 기본적으로 마취 크림을 바르고 시술하며, 부위가 작으면 주사 마취를 추가하기도 합니다. 부위가 넓다면 비수면 마취나 수면 마취까지 하는 경우도 있어요. 다행히 문신 제거는 치료 회차가 쌓일수록 통증이 점점 덜해져서 초반만 넘기면 다들 훨씬 편하게 받으시더라고요. 다만 문신 제거는 여러 번 시술해야 하기 때문에 시간과 비용이 만만치 않게 소요됩니다. 그래서 문신을 할 때 충분히 고민하고 결정하시는 게 가장 좋고, 꼭 지우고 싶다면 겁먹지 마시고 빨리 병원에 내원하시는 것이 효율적입니다.', '문신 제거는 마취 크림·주사·수면 마취까지 다양한 통증 관리법이 있습니다. 회차가 쌓일수록 통증이 줄어드는 이유도 피부과 전문의 김수형이 안내합니다.', array['문신제거', '통증', '마취', '피코레이저', '수면마취', '비용', '시술횟수']::text[]),
    ('TDZ_GV4CvQU', 'kimsoohyung', '커플 문신 후회하는 사람 많다던데 실제로도 그런가요?', '네, 피부과에 커플 문신 지우러 오시는 분들이 꽤 많습니다. 최근에는 17살 여학생이 남자친구와 사귀면서 팔뚝에 이름을 영어로 새겼다가 헤어진 뒤 엄마 손을 잡고 제거하러 온 경우도 있었어요. 사실 문신은 하는 순간에 잘 지워질지 아닐지가 결정됩니다. 어떤 색 잉크를 썼는지, 잉크가 얼마나 들어갔는지에 따라 제거 난이도가 갈리기 때문이에요. 그 학생의 경우 잉크량이 적은 편이어서 6~7번 정도면 다 지울 수 있을 것으로 보입니다. 요즘은 피코레이저가 발달해서 깨끗하게 지울 수 있지만, 시간과 비용과 통증이 모두 수반되는 만큼 문신은 충분히 고민 후에 결정하시길 권합니다.', '커플 문신 후회로 피부과를 찾는 분이 많습니다. 실제 제거 사례와 잉크량에 따른 시술 횟수 차이를 피부과 전문의 김수형이 설명합니다.', array['커플문신', '문신제거', '피코레이저', '잉크량', '후회', '시술횟수', '타투']::text[]),
    ('TDZ_GV4CvQU', 'kimsoohyung', '문신은 원래 언제부터 시작됐고 왜 했던 건가요?', '문신의 역사는 무려 5300년 전까지 거슬러 올라갑니다. 그 시대 미라의 몸에서 문신이 발견됐는데, 허리나 무릎에 있었기 때문에 통증 치료 목적이었을 것으로 추정합니다. 고대 이집트에서는 여성이 풍요와 다산을 기원하며 배에 평행선 문신을 했고, 일본에서는 수호전 영웅을 따라한 전신 문신이 유행했어요. 당시에는 마취 크림도 없이 하나하나 새겨야 해서 전신 문신에 2년이나 걸렸다고 합니다. 조선시대에도 사랑하는 연인의 이름을 가슴이나 팔뚝에 새기는 ''연비''라는 커플 문신 풍습이 있었어요. 어우동이 연인들 이름을 몸에 새긴 것이 증거가 되어 결국 교수형에 처해진 유명한 사례도 있습니다. 문신은 치료, 주술, 사랑 표현 등 시대마다 목적은 달랐지만 몸에 소중한 것을 새기려는 인간의 본능인 셈이죠.', '문신의 역사는 5300년 전 미라까지 거슬러 올라갑니다. 고대 이집트·일본·조선시대의 문신 문화와 의미를 피부과 전문의 김수형이 정리합니다.', array['문신역사', '이레즈미', '연비', '어우동', '타투', '조선시대', '고대문신']::text[]),
    ('7H8g6bbY_ZE', 'jeonghanmi', '위고비 맞으면 진짜 15kg까지 빠질 수 있나요?', '임상시험 결과 68주(약 17개월) 투약 시 평균 약 15%의 체중 감량 효과가 확인되었습니다. 100kg인 분은 85kg, 70kg인 분은 60kg까지 감량이 가능한 수치예요. 기존에 많이 쓰이던 삭센다의 감량 효과가 7~8%였던 것과 비교하면 거의 2배에 달하는 수준입니다. 위고비의 주성분인 세마글루타이드가 GLP-1 호르몬과 유사하게 작용해서 뇌의 포만감 중추를 자극하고, 음식이 위에 머무르는 시간을 늘려 자연스럽게 식사량이 줄어드는 원리예요. 삭센다는 매일 주사해야 했지만 위고비는 일주일에 한 번 복부나 허벅지에 자가 주사하면 되니 편의성도 크게 좋아졌습니다. 다만 약물만으로는 체중 감량을 유지할 수 없으므로 규칙적인 운동과 식습관 개선이 반드시 병행돼야 합니다. 마법의 약이 아니라 생활 습관 교정을 도와주는 보조 수단으로 접근하시는 게 좋습니다.', '위고비는 68주 투약 시 평균 15% 체중 감량이 가능합니다. 세마글루타이드의 포만감 작용 원리와 삭센다 대비 장점을 피부과 전문의 정한미가 정리합니다.', array['위고비', '비만치료제', '세마글루타이드', 'GLP-1', '체중감량', '삭센다', '다이어트']::text[]),
    ('7H8g6bbY_ZE', 'jeonghanmi', '위고비 부작용이 심하다는데 어떤 게 있나요?', '가장 흔한 부작용은 구역감, 구토, 설사, 변비 같은 소화기 증상이며 두통과 피로도 나타날 수 있습니다. 다행히 이런 증상 대부분은 일시적이어서 2~3일 정도면 호전되는 경우가 많다고 해요. 하지만 당뇨병 환자에게는 저혈당이나 당뇨병성 망막병증이 생길 수 있고, 췌장염, 위염, 담석증 같은 부작용도 유발할 수 있어 주의가 필요합니다. 아예 사용할 수 없는 경우도 있는데요, 췌장염이나 갑상선 수질암, 다발성 내분비종양증의 병력 또는 가족력이 있으면 금기이고 임산부와 수유부도 사용이 불가합니다. 위고비는 건강보험 적용이 안 돼서 한 달 비용이 약 80만~100만 원 정도로 예상되고 있어요. 효과가 뛰어난 만큼 반드시 의사와 상담 후 본인에게 적합한지 확인하고 처방받으시길 권합니다.', '위고비의 흔한 부작용은 구역감·구토·설사이며 췌장염 이력이 있으면 금기입니다. 부작용 종류와 비용까지 피부과 전문의 정한미가 안내합니다.', array['위고비', '부작용', '구역감', '췌장염', '비만치료제', '금기', '처방']::text[]),
    ('7H8g6bbY_ZE', 'jeonghanmi', '위고비로 체중 감량 후 끊으면 요요 온다는데 사실인가요?', '네, 요요현상이 올 수 있습니다. 실제 연구 결과에 따르면 위고비로 체중을 감량한 뒤 약을 중단하고 1년이 지났을 때 환자의 3분의 2가 다시 원래 체중으로 돌아갔다고 해요. 꽤 높은 수치죠. 위고비가 식욕 억제와 포만감 유지를 도와주는 약이기 때문에 중단하면 다시 식욕이 돌아오면서 체중이 증가할 수 있는 겁니다. 그래서 약물 치료만 믿고 생활 습관을 바꾸지 않으면 장기적으로는 효과를 유지하기 어렵습니다. 규칙적인 운동과 건강한 식습관 개선을 꼭 병행해야 약을 줄이거나 중단한 뒤에도 감량 체중을 유지할 수 있어요. 위고비를 시작하실 때부터 생활 습관 교정을 함께 계획하시는 게 현명한 접근입니다.', '위고비 중단 1년 후 3분의 2가 원래 체중으로 돌아갔다는 연구 결과가 있습니다. 요요를 막는 생활습관 병행법을 피부과 전문의 정한미가 설명합니다.', array['위고비', '요요현상', '체중감량', '비만치료제', '식습관', '운동', '다이어트']::text[]),
    ('7H8g6bbY_ZE', 'jeonghanmi', '위고비랑 내년에 나온다는 마운자로 뭐가 더 좋아요?', '위고비의 체중 감량 효과가 약 15%인 반면, 내년 출시 예정인 마운자로는 약 22%의 감량 효과를 보여준다고 합니다. 체중의 5분의 1 이상을 줄여주는 셈이라 수치상으로는 마운자로가 더 강력해요. 마운자로는 미국 일라이릴리에서 개발한 약인데, 위고비를 만든 덴마크 노보노디스크와 치열한 경쟁 구도에 있습니다. 다만 효과가 더 크다고 무조건 좋은 건 아닐 수 있어요. 약으로 10kg 이상 감량이 가능하다면 그 이상의 효과보다는 가격, 편의성, 부작용 같은 요소가 더 중요할 수도 있습니다. 앞으로 주사제 외에 먹는 약 형태의 비만치료제도 개발되고 있어서 선택지가 더 다양해질 전망이에요. 비만 치료제의 새로운 시대가 이제 막 시작된 만큼, 자신에게 맞는 약을 의사와 충분히 상담해 결정하시길 권합니다.', '위고비 15% vs 마운자로 22%, 차세대 비만치료제의 감량 효과 차이와 먹는 약 형태까지 비만치료의 전망을 피부과 전문의 정한미가 정리합니다.', array['위고비', '마운자로', '비만치료제', '체중감량', '세마글루타이드', 'GLP-1', '비교']::text[]),
    ('LKMHCgogWao', 'parkhyojin', '스트레스 받으면 피부가 진짜 나빠지는 건가요?', '네, 스트레스는 피부를 직접적으로 악화시킵니다. 스트레스를 받으면 뇌에서 코티졸이라는 스트레스 호르몬이 분비되는데, 이 코티졸이 피부에서 염증 물질을 마구 내보내고 피부 장벽까지 무너뜨려요. 그 결과 아토피, 건선, 여드름 같은 피부 질환의 스위치를 켜버리게 됩니다. 실제로 피부과에서 치료를 열심히 해도 반응이 더딘 환자분들에게 극심한 스트레스가 있는지 물어보면 대부분 그렇다고 답하시는 경우가 많아요. 만성 두드러기 환자분들도 스트레스 원인이 사라지면 거짓말처럼 증상이 낫는 경우가 있습니다. 더 놀라운 건 코티졸이 단순히 염증만 유발하는 게 아니라 콜라겐 생성까지 저하시켜서 노화를 앞당긴다는 점이에요. 마음고생이 심하면 실제 나이보다 더 늙어 보일 수 있는 거죠.', '스트레스가 피부를 악화시키는 과학적 원리를 피부과 전문의 박효진이 설명합니다.', array['스트레스', '코티졸', '피부장벽', '아토피', '건선', '여드름', '콜라겐', '노화']::text[]),
    ('LKMHCgogWao', 'parkhyojin', '피부과에서 항우울제를 처방한다는 게 사실인가요?', '네, 드물지만 피부과에서도 항우울제를 처방하는 경우가 있습니다. 만성 피부 질환 중 적절한 치료를 해도 반응이 더딘 환자분들에게 마음 상태와 스트레스가 피부를 악화시킨다고 판단되면 항우울제를 병행 처방하기도 해요. 특히 홍조 환자분들에게 레이저나 먹는 약으로 치료해도 반응이 느릴 때 항우울제를 함께 처방하면 경과가 훨씬 좋아지는 경우가 있습니다. 항우울제가 피부로 분포되는 신경에서 나오는 전달물질을 차단해서 염증이 감소하고 피부 증상이 개선되는 원리예요. 물론 메인 치료제로 쓰는 건 아니고 보조적으로 사용하는 것이며, 모든 환자에게 해당되는 건 아닙니다. 피부 질환이 오래 낫지 않고 스트레스가 심하다면 담당 피부과 선생님께 마음 상태에 대해서도 솔직히 말씀드려 보세요.', '피부과에서 항우울제를 처방하는 이유와 효과를 피부과 전문의 박효진이 안내합니다.', array['항우울제', '홍조', '스트레스', '피부과치료', '만성피부질환', '염증', '신경전달물질']::text[]),
    ('LKMHCgogWao', 'parkhyojin', '잠만 잘 자도 피부가 좋아진다는 말이 진짜예요?', '네, 수면은 피부 건강에 결정적인 영향을 줍니다. 잠만 잘 자도 피부과 오는 환자의 반이 줄 거라고 할 정도로 수면이 중요해요. 일정 시간이 넘어가면 우리 몸에서 스트레스 호르몬이 더 많이 분비되고, 이것들이 피부 장벽을 무너뜨려서 푸석푸석하고 건조한 피부를 만듭니다. 그래서 성인도 가능하면 밤 11시 전에 잠자리에 드는 게 좋아요. 어릴 때 성장 호르몬 분비를 위해 일찍 자라고 했던 것처럼, 성인에게도 일정 시간 이전에 자는 게 피부 회복에 도움이 됩니다. 또한 잠 잘 자고 밥 잘 먹고 걱정할 게 없으면 피부 트러블이 진짜 안 나거든요. 몸과 마음의 신호가 그대로 피부로 드러나기 때문에 수면 관리를 피부 관리의 첫 단계로 생각하시는 게 맞습니다.', '수면이 피부 건강에 미치는 영향과 적정 취침 시간을 피부과 전문의 박효진이 정리합니다.', array['수면', '피부장벽', '스트레스호르몬', '피부관리', '건조', '코티졸', '생활습관']::text[]),
    ('LKMHCgogWao', 'parkhyojin', 'SNS 많이 보면 피부도 안 좋아질 수 있나요?', '네, SNS 과다 사용이 스트레스를 유발해 피부를 악화시킬 수 있습니다. SNS에 노출될수록 남들과 비교하게 되고 상대적 박탈감을 느끼면서 오는 스트레스가 상당히 커요. 이런 비교 스트레스가 코티졸 분비를 촉진하고, 코티졸이 피부 장벽을 무너뜨리며 염증 반응을 일으키고 콜라겐 생성까지 저하시킵니다. 그래서 하루에 10분, 20분이라도 SNS 보는 시간을 줄여나가는 디지털 디톡스를 시작해 보세요. 처음엔 어려워도 조금씩 줄이다 보면 긍정적인 변화를 느낄 수 있습니다. 외적인 것을 자꾸 비교하기보다 나 자신의 내면을 들여다보는 시간을 갖는 게 중요해요. 행복과 자기 만족이 결국 가장 좋은 화장품이자 가장 좋은 시술이라고 할 수 있습니다.', 'SNS가 피부에 미치는 악영향과 디지털 디톡스 방법을 피부과 전문의 박효진이 설명합니다.', array['SNS', '디지털디톡스', '스트레스', '코티졸', '피부장벽', '비교심리', '이너뷰티']::text[]),
    ('8A78c7XN-cA', 'kimsoohyung', '제모를 인류가 언제부터 했는지 궁금해요, 고대 이집트부터인가요?', '제모의 역사는 고대 이집트까지 거슬러 올라갑니다. 이집트에서는 남녀 구분 없이 두피, 눈썹, 수염, 몸 안의 털까지 전체 제모를 했어요. 모래 폭풍이 많은 기후 특성상 털에 모래가 붙는 걸 비위생적이고 불결하게 여겼기 때문입니다. 클레오파트라의 상징인 단발머리도 사실 가발이었고, 상류층 이집트인들은 아침에 머리를 밀고 눈썹을 왁싱으로 제거한 뒤 납 성분 크림으로 눈썹과 아이라인을 그렸어요. 당시에는 청동 면도기나 뾰족한 조개껍질로 면도하고, 설탕과 레몬즙을 섞은 슈가 왁스로 눈썹을 제모했는데 이게 오늘날 슈가링 왁스의 원조입니다. 재미있는 건 이집트에서 수염을 기를 수 있는 사람은 파라오뿐이었다는 점이에요. 수염이 곧 권력의 상징이었던 거죠.', '클레오파트라도 전신 제모를 했습니다. 슈가링 왁스의 원조인 고대 이집트 제모 문화와 방법을 피부과 전문의 김수형이 정리합니다.', array['제모', '이집트', '슈가링왁스', '제모역사', '클레오파트라', '왁싱', '면도']::text[]),
    ('8A78c7XN-cA', 'kimsoohyung', '겨드랑이 제모가 원래 필수가 아니었다면서요?', '맞아요, 여성 겨드랑이 제모 문화는 20세기 초에야 시작됐습니다. 1908년부터 여성 잡지에 겨드랑이 제모를 해야 한다는 인식을 심어주는 광고가 등장하기 시작했어요. 미국 상류층 대상 패션 잡지 하퍼스 바자에 제모크림 광고가 실리면서 사람들이 겨드랑이 제모를 인식하게 된 거죠. 이걸 본 질레트가 1915년에 최초의 여성용 면도기 ''마이 레이디''를 출시했는데 이게 대박이 났습니다. 면도기 시장이 순식간에 2배로 커졌어요. 당시 패션 변화도 영향을 미쳤는데, 치마와 소매가 짧아지면서 깔끔한 피부가 더 중요해졌고 다리털 제모도 시작됐습니다. 결국 제모 문화는 위생보다는 광고와 패션 트렌드가 만들어낸 측면이 큰 셈이에요.', '여성 겨드랑이 제모는 1908년 잡지 광고에서 시작됐습니다. 질레트 여성용 면도기 탄생 배경과 제모 문화의 확산 과정을 피부과 전문의 김수형이 안내합니다.', array['겨드랑이제모', '제모문화', '질레트', '여성용면도기', '패션', '제모역사', '왁싱']::text[]),
    ('8A78c7XN-cA', 'kimsoohyung', '레이저 제모 나오기 전에는 어떻게 영구 제모했어요?', '레이저 이전에는 전기 분해법이라는 방식으로 영구 제모를 했습니다. 1875년 안과의사 찰스 미셸이 눈을 찌르는 내향성 속눈썹 치료를 위해 얇은 바늘을 모낭에 넣고 전류를 흘렸더니 털이 다시 나지 않는다는 걸 발견한 게 시작이에요. 이 방법을 제모에 응용해서 1900년대 초반부터 사용했는데, 문제는 털이 난 구멍 하나하나에 바늘을 찔러야 해서 통증이 극심했다는 겁니다. 다리 제모 한 번에 5시간에서 10시간까지 걸렸다고 해요. 그러다 1990년대에 빛을 이용해 선택적으로 모낭을 파괴하는 레이저 제모가 도입되면서 상황이 완전히 달라졌습니다. 1995년 정식 승인 이후 현재 가장 널리 사용되는 제모 방법이 됐어요. 덕분에 아프고 오래 걸렸던 제모가 몇 분 만에 가능해진 거죠.', '1875년 안과의사가 발견한 전기 분해법은 다리 제모에 10시간이나 걸렸습니다. 레이저 제모 등장까지의 발전 과정을 피부과 전문의 김수형이 설명합니다.', array['레이저제모', '전기분해법', '영구제모', '모낭', '찰스미셸', '제모역사', '제모시술']::text[]),
    ('8A78c7XN-cA', 'kimsoohyung', '로마 시대에도 제모를 했다는 게 진짜예요?', '네, 로마에서는 이집트보다 더 발달한 제모 문화가 있었습니다. 로마 시내에는 ''테르메''라는 공중 목욕탕이 900개나 있었는데, 거기에 온탕, 냉탕, 일광욕, 마사지샵, 제모샵이 모두 한 곳에 있었어요. 사람들이 목욕하면서 제모를 받았고, 저녁 약속을 잡거나 파티를 하기도 했습니다. 제모샵에는 ''알리필라스''라는 제모 전문 노예들이 족집게를 사용해 털을 뽑았는데, 시인 세네카의 편지에 보면 알리필라스가 털을 뽑을 때마다 사람들이 소리를 너무 질러서 시끄러웠다는 기록이 남아 있어요. 실제로 영국 배스 지역의 로마 유적지에서 청동 족집게가 50개나 발견되기도 했습니다. 이후 중세에는 금욕주의 때문에 제모가 사라졌다가 르네상스 시대에 넓은 이마를 만들기 위한 헤어라인 제모로 다시 등장했어요.', '로마에는 900개의 공중목욕탕에 제모샵이 있었습니다. 족집게로 털을 뽑던 로마 시대부터 르네상스까지 제모 문화 변천을 피부과 전문의 김수형이 정리합니다.', array['제모역사', '로마', '테르메', '공중목욕탕', '왁싱', '족집게', '르네상스']::text[]),
    ('nkBnj2I3p_Q', 'parkhyojin', '울쎄라 맞으면 턱선·볼살 정리돼서 얼굴이 진짜 갸름해져요?', '네, 울쎄라 시술 후 얼굴 면적이 눈에 띄게 줄어드는 효과가 있습니다. 직접 시술을 받은 후 거울을 보며 ''내가 이렇게 갸름했나, 얼굴 면적이 날아간 것 같다''고 느낄 정도였어요. 울쎄라는 초음파로 피부 깊은 근막층까지 에너지를 전달해 지방 감소와 피부 수축을 동시에 일으킵니다. 시술 전에는 환자분들이 좋다고 할 때 플라시보 효과도 있겠거니 했는데, 직접 경험해 보니 꾸준히 받으려고 하는 이유를 알겠더라고요. 특히 살이 통통하게 있어서 밀려서 팔자주름이 짙어 보이는 분들이나, 얼굴 면적이 넓어서 날렵하게 만들고 싶은 분들에게 효과가 뚜렷합니다. 안면비대칭이 심한 경우에는 한쪽만 집중 시술해서 대칭을 맞추는 것도 가능해요. 다만 시술 후 효과가 바로 나타나는 게 아니라 붓기가 빠지면서 점차 드러나는 점을 참고하세요.', '울쎄라 시술 후 얼굴 면적이 눈에 띄게 줄어듭니다. 초음파 근막층 자극 원리와 팔자주름·안면비대칭 개선 효과를 피부과 전문의 박효진이 정리합니다.', array['울쎄라', '리프팅', '얼굴축소', '팔자주름', '안면비대칭', '초음파', '근막층']::text[]),
    ('nkBnj2I3p_Q', 'parkhyojin', '울쎄라 시술 후 2주나 붓는다는데 괜찮은 건가요?', '붓기가 크다는 건 오히려 근막층이나 지방층에서 염증 반응이 활발하게 일어나고 있다는 반증이에요. 근막층까지 타겟으로 해서 250~300샷의 많은 에너지가 깊게 들어가면 그만큼 붓기가 오래 지속될 수 있습니다. 직접 경험했을 때 다음 날 얼굴이 눈에 띄게 부어서 보는 사람마다 뭐 했냐고 물었고, 2~3일이면 빠지겠지 했는데 2주까지 지속됐어요. 그런데 신기하게 붓기가 싹 빠지니까 얼굴이 엄청 날렵해져 보였습니다. 그렇다고 붓기가 없으면 효과가 없는 건 아니에요. 사람마다 피부 두께가 달라서 깊게 들어가지 않아도 되는 분들은 붓기가 상대적으로 적습니다. 다만 얼마나 부을지 예측이 어려우므로 울쎄라 시술 후 2~3주 정도는 중요한 약속을 잡지 않는 게 안전합니다.', '울쎄라 후 붓기가 2주까지 지속될 수 있습니다. 근막층 에너지 반응과 붓기 빠진 뒤 리프팅 효과, 다운타임 일정 관리법을 피부과 전문의 박효진이 안내합니다.', array['울쎄라', '붓기', '부작용', '근막층', '다운타임', '리프팅', '시술후관리']::text[]),
    ('nkBnj2I3p_Q', 'parkhyojin', '울쎄라 맞고 신경 손상이 올 수 있다는데 위험한 건가요?', '울쎄라 후 신경 손상은 드물지만 올 수 있는 부작용입니다. 직접 겪었을 때 시술 후 식사하는데 입에서 음식이 새고, 양치할 때 양칫물이 흘러내려서 거울을 보니 입술이 마음대로 안 움직여졌어요. 이때 울쎄라 후 운동신경 손상이 온 걸 알게 됐습니다. 다행히 신경 손상은 일시적이에요. 보통 2~3주 정도면 운동신경이 거의 돌아오고, 처음에만 어색할 뿐 남들은 거의 못 알아보는 정도입니다. 본인만 아는 수준으로 조금 불편하다가 자연 회복됩니다. 그래서 울쎄라 시술 전에 2~3주 후까지 중요한 일정이 없는지 꼭 확인하는 게 좋아요. 붓기든 신경 손상이든 시간이 지나면 회복되니 너무 걱정하실 필요는 없지만 사전에 알고 가시는 게 마음이 편합니다.', '울쎄라 후 드물게 운동신경 손상이 올 수 있지만 2~3주면 자연 회복됩니다. 실제 경험 기반 증상과 회복 과정을 피부과 전문의 박효진이 설명합니다.', array['울쎄라', '신경손상', '부작용', '운동신경', '회복기간', '리프팅', '다운타임']::text[]),
    ('nkBnj2I3p_Q', 'parkhyojin', '울쎄라 시술이 엄청 아프다던데 어떻게 참아요?', '솔직히 안 아프다고 하면 거짓말이에요. 울쎄라는 통증이 있는 시술이 맞습니다. 시술 중 호흡 마취를 했는데도 아프다고 느껴서 마취를 해달라고 요청할 정도였어요. 특히 1.5팁보다 깊은 3.0팁이나 4.5팁이 들어갈 때 통증이 더 강합니다. 시술하는 선생님들도 통증과의 싸움을 많이 하기 때문에 마취크림을 40~50분 이상 오래 바르기도 하고, 수면 마취를 하는 병원도 있어요. 비수면 호흡 마취를 적극적으로 활용하는 곳도 있습니다. 통증에 민감한 분들은 시술 전에 마취 방법을 선생님과 충분히 상의하시는 게 좋아요. 아프지만 시술 받고 나면 효과가 정말 좋으니까 그래도 꾸준히 받게 되는 시술이에요.', '울쎄라는 통증이 있는 시술이지만 마취 크림·호흡 마취·수면 마취 등 다양한 방법으로 관리할 수 있습니다. 팁별 통증 차이와 대처법을 피부과 전문의 박효진이 안내합니다.', array['울쎄라', '통증', '마취', '호흡마취', '수면마취', '리프팅', '시술과정']::text[]),
    ('VMsll3EJg8c', 'jeonghanmi', '피부과 리프팅이 초음파·고주파·레이저로 나뉜다는데 뭐가 다른 거예요?', '피부과 리프팅은 크게 초음파, 고주파, 레이저 세 가지로 나뉘며 모두 피부 속에 열을 주는 게 핵심입니다. 차이는 열이 도달하는 깊이예요. 초음파(대표: 울쎄라)는 가장 깊은 근막층까지 들어가서 처진 피부를 달라붙게 만들고, 고주파(대표: 써마지)는 반대로 위쪽 진피층의 콜라겐을 자극해 피부를 탄탄하게 해줍니다. 레이저(대표: 티타늄)는 세 종류의 빛이 한꺼번에 나와서 표피부터 일부 지방층까지 골고루 열을 줘요. 피부층을 쉽게 이해하자면 맨 위 진피층은 콜라겐이 풍부한 돼지껍데기, 그 밑이 지방층, 가장 아래가 근육을 싸는 근막층입니다. 초음파는 돋보기로 햇빛을 모아 종이를 태우듯 초음파를 한 점에 집속시켜 깊은 층을 익히는 원리예요. 본인에게 뭐가 필요한지에 따라 선택이 달라지므로 피부과 전문의 진단을 받아보시는 게 가장 정확합니다.', '초음파·고주파·레이저 리프팅의 원리와 차이를 피부과 전문의 정한미가 정리합니다.', array['리프팅', '울쎄라', '써마지', '티타늄', '초음파', '고주파', '레이저', '근막층']::text[]),
    ('VMsll3EJg8c', 'jeonghanmi', '울쎄라랑 써마지 중에 나한테 맞는 걸 어떻게 알 수 있어요?', '간단하게 본인이 직접 판단할 수 있는 방법이 있습니다. 손가락 두 개로 팔자주름 옆 살과 턱 밑 살을 집어보세요. 두 군데가 두둑하게 많이 잡히는 분들은 처짐이 심한 것이라 울쎄라 같은 초음파 시술이 적합합니다. 반대로 잡히는 게 별로 없고 눈가나 입가 잔주름이 많거나 모공이 늘어져 있는 분들은 피부 탄력이 필요한 상태라 써마지 같은 고주파가 더 효과적이에요. 울쎄라는 깊은 근막층을 수축시켜 처진 피부를 올려주는 역할을 하고, 써마지는 진피층 콜라겐을 재생해서 피부를 쫀쫀하게 만들어 줍니다. 물론 두 가지를 병행하면 더 좋은 결과를 얻을 수 있고요, 정확한 진단은 피부과 선생님이 직접 보시고 판단해주시는 게 가장 좋습니다. 셀프 테스트로 대략적인 방향을 잡아보세요.', '울쎄라와 써마지 중 본인에게 맞는 시술을 판단하는 법을 피부과 전문의 정한미가 안내합니다.', array['울쎄라', '써마지', '리프팅', '처짐', '탄력', '팔자주름', '고주파', '초음파']::text[]),
    ('VMsll3EJg8c', 'jeonghanmi', '티타늄 레이저가 효과 바로 보인다는데 울쎄라보다 좋은 건가요?', '티타늄의 가장 큰 장점은 효과가 즉시 나타난다는 점입니다. 한쪽 얼굴에 먼저 시술하고 거울을 보면 바로 차이가 보여요. 울쎄라나 써마지는 콜라겐 재생이 진행되면서 한 달 정도까지는 눈에 띄는 변화가 잘 안 보이거든요. 그래서 당장 내일 중요한 일이 있거나 연예인분들이 촬영 전에 받기도 합니다. 또 하나 중요한 차이가 있는데, 심술보(턱 아래 양옆) 살이 많은 분들은 울쎄라로 시술할 수 없어요. 그 부위에 신경이 지나가서 신경 손상 위험이 있기 때문인데, 티타늄은 그 부위도 시술이 가능합니다. 다만 두 장비는 작용하는 깊이와 원리가 달라서 단순 비교보다는 본인 피부 상태에 따라 선택하시는 게 맞아요. 심술보 처짐이나 실리프팅이 싫은 분들에게 티타늄이 좋은 대안이 될 수 있습니다.', '티타늄 레이저의 즉시 효과와 울쎄라와의 차이점을 피부과 전문의 정한미가 설명합니다.', array['티타늄', '리프팅', '레이저', '울쎄라', '즉시효과', '심술보', '턱살']::text[]),
    ('VMsll3EJg8c', 'jeonghanmi', '울쎄라·써마지 너무 비싼데 저렴한 국산 장비도 효과 있나요?', '국산 장비들도 충분히 좋은 대안이 될 수 있습니다. 우리나라 회사들의 기술력이 좋아서 비슷한 원리로 만든 장비가 많이 출시돼 있어요. 고주파 계열에는 올리지오, 덴서티, 텐서마, 볼뉴머 등이 있고, 초음파 계열에는 리니어지, 슈링크, 텐쎄라, 더블로 같은 장비들이 있습니다. 다만 오리지널 장비는 오리지널이라는 생각이 있어요. 커피에 비유하면 스타벅스가 맛과 질이 항상 보장되듯, 울쎄라나 써마지는 가장 오래됐고 효과가 가장 많이 입증된 브랜드입니다. 예산이 충분하고 확실한 효과를 원한다면 오리지널을 추천드리지만, 국산 장비들도 계속 기술이 업그레이드되고 있고 시술자에 따라 충분히 좋은 효과를 낼 수 있어요. 비용 대비 효과를 따져서 선택하시면 됩니다.', '국산 리프팅 장비의 종류와 오리지널 대비 효과 차이를 피부과 전문의 정한미가 안내합니다.', array['리프팅', '울쎄라', '써마지', '슈링크', '국산장비', '올리지오', '비용', '더블로']::text[]),
    ('heotGQCv6Rc', 'gohyerim', '갑자기 생긴 점이 피부암일 수도 있나요?', '대부분의 점은 문제가 없지만, 점처럼 보이면서 흑색종이라는 피부암인 경우가 있어 주의가 필요합니다. 흑색종은 초기에 발견하면 대부분 완치되지만 늦게 발견하면 치사율이 75%까지 이르는 무서운 질환이에요. 갑자기 점이 생겨서 걱정되는 마음에 병원을 찾는 분들이 많은데, 실제로는 그냥 두거나 미용 목적으로 제거하는 경우가 대부분입니다. 하지만 제거 시기를 놓치면 사망에 이를 수 있는 점도 있기 때문에 ABCDE 법칙으로 자가 점검을 해보시는 게 좋아요. 비대칭, 불규칙한 경계, 불균일한 색, 6mm 이상의 직경, 갑작스러운 변화 중 해당되는 특징이 있다면 피부과를 방문하세요. 의심스러운 소견이 있을 때는 조직검사로 정확히 진단할 수 있습니다. 조기 발견과 치료가 무엇보다 중요하니 점의 변화를 평소에 관찰해두시길 권합니다.', '갑자기 생긴 점이 흑색종(피부암)인지 구별하는 ABCDE 법칙을 피부과 전문의 고혜림이 설명합니다.', array['흑색종', '피부암', '점', 'ABCDE법칙', '조직검사', '피부과검진', '조기발견']::text[]),
    ('heotGQCv6Rc', 'gohyerim', '손바닥이나 발바닥에 점이 있으면 무조건 빼야 하나요?', '아니요, 손바닥이나 발바닥에 점이 있다고 무조건 제거할 필요는 없습니다. 피부 3대 암 중 기저세포암과 편평세포암은 햇빛 노출 부위에 주로 생기고 치사율도 낮은 편이에요. 반면 흑색종은 서양에서는 햇빛 노출 부위에 잘 생기지만, 동양인은 손바닥이나 발바닥, 발가락에 생기는 경향이 있습니다. 손발에 가해지는 물리적 자극이나 압력이 영향을 준다고 보고 있어서 이런 이야기가 나온 거예요. 그렇다고 해서 손바닥 점이 모두 위험한 것은 아니니 ABCDE 법칙으로 점검해보시면 됩니다. 비대칭이거나 경계가 울퉁불퉁하거나 여러 색이 섞여 있거나 6mm 이상이거나 갑자기 변화가 있다면 피부과에서 확인받으세요. 불안하다면 전문의 진료를 통해 안심하시는 것도 좋은 방법입니다.', '손바닥·발바닥 점이 위험한지, 동양인에게 흑색종이 잘 생기는 부위를 피부과 전문의 고혜림이 안내합니다.', array['손바닥점', '발바닥점', '흑색종', '피부암', '동양인', 'ABCDE법칙', '점제거']::text[]),
    ('heotGQCv6Rc', 'gohyerim', '튀어나온 점이나 털 난 점도 그냥 둬도 괜찮은 건가요?', '네, 튀어나온 점이나 털이 난 점도 꼭 제거할 필요는 없습니다. 다만 미용적인 이유로 제거를 원하시는 분들이 많은데, 특히 털이 난 점은 주변 털보다 굵고 빨리 자라서 불편할 수 있어요. 이런 점들은 주로 복합 모반이나 진피내모반인 경우가 많아서 일반 평평한 점보다 훨씬 깊이 자리하고 있습니다. 레이저로 제거할 경우 한 번에 되지 않고 여러 번에 걸쳐야 하며, 수술적 방법으로 제거하기도 해요. 깊이 있는 점이다 보니 다른 점보다 제거 후 흉터가 남을 확률이 높다는 점을 미리 알아두셔야 합니다. 건강상 위험한 것은 아니니 불편하지 않다면 굳이 제거하지 않아도 되고, 미용적으로 신경 쓰인다면 피부과에서 상담 후 결정하시면 됩니다.', '튀어나온 점이나 털 난 점의 정체와 제거 시 주의사항을 피부과 전문의 고혜림이 정리합니다.', array['튀어나온점', '털난점', '진피내모반', '복합모반', '점제거', '레이저', '흉터']::text[]),
    ('heotGQCv6Rc', 'gohyerim', '얼굴에 있는 점을 매력 포인트로 살려도 괜찮을까요?', '네, 요즘은 점을 개성과 매력의 상징으로 보는 경우가 많아져서 충분히 살려도 좋습니다. 과거 서양에서는 점을 마녀의 표식으로 부정적으로 봤지만, 17세기 프랑스 궁정에서 인조점이 유행하면서 패션의 일부가 됐어요. 동양에서는 관상학적으로 눈 밑 점은 지혜, 입 주변은 언변, 코 주변은 재물운을 나타낸다고 해서 좋은 의미로 받아들여졌습니다. 아이브 장원영씨도 어릴 때 눈물 점을 여러 번 뺐는데 안 없어져서 포기했다가 지금은 자기 최애 점이 됐다고 하죠. 가수 비비는 원래 없던 점을 일부러 찍어서 트레이드 마크로 만들기도 했어요. 이렇게 점이 자신을 표현하는 방법 중 하나가 된 시대이니, 의심스러운 특징만 없다면 매력점으로 남겨두시는 것도 좋은 선택입니다.', '점을 매력 포인트로 살려도 되는지, 점에 대한 인식 변화를 피부과 전문의 고혜림이 안내합니다.', array['매력점', '점', '관상', '미인점', '개성', '장원영', '점제거']::text[]),
    ('5noTgaqr7Nc', 'gohyerim', '팔이랑 볼에 닭살처럼 오돌토돌한 게 여드름인가요?', '여드름이 아니라 모공각화증일 가능성이 높습니다. 모공각화증은 오래된 피부세포가 정상적으로 탈락하지 못하고 모공을 막아서 피부가 거칠고 오돌토돌하게 보이는 상태예요. 주로 팔 상완 바깥쪽, 허벅지, 엉덩이에 잘 생기지만 때로는 얼굴 볼에도 나타날 수 있습니다. 어린아이 볼에 여드름처럼 보이는 것도 실제로는 모공각화증인 경우가 많아요. 일시적으로 소름이 돋는 닭살과는 달리 모공각화증은 계속 없어지지 않고 지속된다는 차이가 있습니다. 대부분 유전이 원인이라서 부모님 중 한 분이 있으면 자녀에게 발생할 확률이 50% 정도 됩니다. 대개 20세까지 심해지다가 나이가 들면서 완화되기도 하니 너무 걱정하지 마세요.', '팔·볼에 오돌토돌한 돌기는 여드름이 아니라 모공각화증일 수 있습니다. 유전적 원인과 닭살과의 차이, 호발 부위를 피부과 전문의 고혜림이 설명합니다.', array['모공각화증', '닭살', '여드름', '각질', '팔', '유전', '피부질환']::text[]),
    ('5noTgaqr7Nc', 'gohyerim', '모공각화증은 각질 제거하면 완전히 없어지나요?', '아니요, 각질 제거만으로 모공각화증을 완벽히 해결할 수는 없습니다. 일시적으로 좋아질 수는 있지만 대부분 유전적 요인이 원인이기 때문에 근본적으로 없애기는 어려워요. 다만 꾸준히 관리하면 충분히 개선될 수 있습니다. 각질 제거는 일주일에 1-2회 정도 AHA나 BHA 같은 산 성분으로 부드럽게 하는 것이 좋고, 알갱이 큰 스크럽으로 물리적으로 긁는 방식은 피해야 합니다. 너무 자주 하거나 강하게 하면 오히려 피부를 자극해서 증상이 악화될 수 있어요. 또 모공각화증 부위를 손으로 긁거나 뜯으면 붉어지고 색소침착이 생겨서 더 안 좋아집니다. 각질 제거 후에는 반드시 충분한 보습을 해주셔야 하고, 보습제는 하루에도 여러 번 발라 피부를 촉촉하게 유지하세요.', '모공각화증은 각질 제거만으로 완치되지 않습니다. AHA·BHA를 활용한 올바른 각질 관리법과 보습 병행 원칙을 피부과 전문의 고혜림이 안내합니다.', array['모공각화증', '각질제거', 'AHA', 'BHA', '보습', '피부관리', '닭살']::text[]),
    ('5noTgaqr7Nc', 'gohyerim', '모공각화증에 우레아 크림이 효과 있다던데 어떤 제품을 써야 하나요?', '우레아 성분이 들어간 크림은 각질을 연화시키고 수분을 끌어당기는 효과가 있어서 모공각화증 관리에 도움이 됩니다. 약국에서 살 수 있는 의약품은 우레아 20%가 들어간 유리아 크림이 대표적이고, 일반 화장품은 10% 정도까지 함유돼 있어요. 의약품은 계속 사용하면 자극이 있고 미끌거리는 느낌이 있어 매일 바르기 불편할 수 있습니다. 일상용으로는 제로이드 리케닉 크림이 우레아 10%에 세라마이드, 히알루론산, 판테놀 같은 보습·재생 성분이 함께 들어 있어 큰 자극 없이 사용할 수 있어요. 스킨피디아 유리아텐도 우레아 10%에 비슷한 보습·재생 성분이 들어 있고 흡수가 빠르고 발림성이 좋습니다. 우레아 농도가 높은 크림은 민감한 피부에 자극이 될 수 있으니, 처음에는 바디크림에 섞어 바르거나 2-3일에 한 번 사용하면서 피부 상태를 살펴보세요.', '우레아 크림은 각질 연화와 보습에 효과적입니다. 유리아 크림·제로이드·스킨피디아 등 농도별 추천 제품과 사용법을 피부과 전문의 고혜림이 정리합니다.', array['모공각화증', '우레아', '보습', '유리아크림', '제로이드', '스킨피디아', '각질연화']::text[]),
    ('5noTgaqr7Nc', 'gohyerim', '모공각화증이 심한데 피부과 치료를 받아야 하나요?', '홈케어로 잘 해결되지 않는다면 피부과에서 비타민A 외용제를 처방받거나 필링, 레이저 시술을 해볼 수 있습니다. 다만 이런 치료도 재발을 완전히 막지는 못하기 때문에 치료 후 좋아진 피부를 유지하려면 일상적인 관리가 꼭 필요해요. 가장 중요한 건 건조함을 피하는 것인데, 가습기로 실내 습도를 유지하고 물을 많이 마시는 것이 좋습니다. 뜨거운 물로 오래 샤워하거나 때를 미는 등 강한 자극은 증상을 악화시키니 피해야 해요. 샤워 후에는 물기가 마르기 전에 바로 보습제를 바르고, 하루에도 여러 번 보습제를 도포해서 촉촉한 상태를 유지하세요. 모공각화증은 완치보다 관리의 개념으로 접근하시는 게 맞고, 꾸준히 관리하면 충분히 매끄러운 피부를 유지할 수 있습니다.', '심한 모공각화증은 비타민A 외용제·필링·레이저로 치료할 수 있습니다. 피부과 치료 옵션과 재발 방지를 위한 보습 관리법을 피부과 전문의 고혜림이 설명합니다.', array['모공각화증', '피부과치료', '필링', '레이저', '비타민A', '보습', '피부장벽']::text[]),
    ('sLiwrTPMDc8', 'kimsoohyung', '겨울에 건조한데 각질 제거를 해도 괜찮은 건가요?', '네, 충분히 보습했는데도 피부가 답답하고 각질이 뜬다면 부드럽게 각질 제거를 해주는 게 오히려 좋습니다. 건강한 피부는 오래된 각질이 저절로 떨어지는 턴오버가 일어나는데, 20대는 4주면 새로워지지만 40대가 되면 6-8주까지 늘어나거든요. 턴오버가 느려져서 각질이 쌓이면 피부가 칙칙해 보이고 결이 안 좋아지며 잔주름이 두드러져요. 겨울에는 피부가 건조해지면서 각질끼리 뭉쳐서 눈에 더 잘 보이기도 합니다. 이럴 때 효소 세안제를 사용하면 스크럽처럼 피부를 긁지 않고 각질을 살살 녹여 제거해줘서 자극이 적어요. 사용할 때 팁은 T존 포함 얼굴 중앙부는 꼼꼼히, 가장자리는 힘을 빼고 가볍게 해주는 겁니다. 가장자리는 피부가 얇아서 세게 하면 접촉 피부염이 올 수 있기 때문이에요.', '겨울철 각질 제거를 해도 되는지, 효소 세안제 사용법을 피부과 전문의 김수형이 안내합니다.', array['각질제거', '효소세안제', '겨울피부', '턴오버', '건성', '피부결', 'T존']::text[]),
    ('sLiwrTPMDc8', 'kimsoohyung', '효소 세안제 추천받고 싶은데 피부 타입별로 뭘 쓰면 좋나요?', '각질 제거력을 원하면 스킨피디아 엔자임 파우더 워시, 민감하고 당김이 심하면 주닥 효소 클렌저가 잘 맞습니다. 스킨피디아 제품은 각질 제거와 피지 제거 효과가 가장 좋았고 보습 효과도 있어서 각질을 제거한 뒤에도 당기는 느낌보다 촉촉한 느낌이 들어요. 파우더 형태라 바로 피부에 올리면 안 되고 물과 섞어서 거품을 낸 후 부드럽게 마사지하듯 문지르고 미온수로 씻어내시면 됩니다. 건성이면 겨울철에 1-2주에 한 번, 지성이면 주 1-2회 정도 사용하세요. 주닥 효소 클렌저는 보습에 포인트가 맞춰져 있어서 자극이 거의 없고 순하면서 촉촉한 느낌을 받을 수 있어요. 히터 바람에도 얼굴이 빨개지고 당김이 심한 민감성 피부분들에게 더 잘 맞습니다. 어떤 제품이든 쓰다가 빨개지거나 가려우면 바로 사용을 중단하시고 보습을 해주세요.', '피부 타입별 효소 세안제 추천과 사용 빈도를 피부과 전문의 김수형이 정리합니다.', array['효소세안제', '스킨피디아', '주닥', '각질제거', '민감성피부', '건성', '지성']::text[]),
    ('sLiwrTPMDc8', 'kimsoohyung', '겨울 보습제 고를 때 꼭 들어가야 하는 성분이 뭔가요?', '세콜지, 즉 세라마이드·콜레스테롤·지방산 이 세 가지가 겨울 보습의 핵심입니다. 이 세 가지가 모이면 벽돌과 시멘트처럼 피부에 튼튼한 장벽을 만들어줘서 수분이 빠져나가지 않고 촉촉한 상태를 유지해요. 겨울에는 차갑고 건조한 바람 때문에 피부 장벽이 쉽게 망가지니까 보습제로 세콜지를 보완해주는 게 좋습니다. 제로이드 인텐시브 크림은 세콜지에 글리세린, 스쿠알란, 올리브오일, 항산화 성분까지 들어 있어서 가을·겨울에 쓰기 좋아요. 외출 후 찢어질 것처럼 건조하고 따가울 때는 같은 라인의 제로이드 인텐시브 리치 크림을 섞어 바르면 판테놀과 마데카소사이드의 재생·진정 효과까지 받을 수 있습니다. 리치 크림은 질감이 꾸덕해서 아침보다 밤에 사용하시는 게 화장 밀림 없이 좋아요.', '겨울 보습제 필수 성분 세콜지(세라마이드·콜레스테롤·지방산)를 피부과 전문의 김수형이 설명합니다.', array['세콜지', '세라마이드', '콜레스테롤', '지방산', '피부장벽', '겨울보습', '제로이드']::text[]),
    ('sLiwrTPMDc8', 'kimsoohyung', '지성 피부인데 겨울에 건조하면 어떤 보습제를 써야 하나요?', '지성 피부에는 바이오더마 세비엄 하이드라가 수분은 채워주면서 마무리감이 산뜻해서 잘 맞습니다. 아무리 지성 피부라도 겨울철 차갑고 건조한 바람에는 피부 장벽이 망가질 수 있거든요. 이 제품은 세라마이드가 들어가서 피부 장벽을 회복시켜주고 글리세린으로 보습 효과를 줘요. 거기에 항염 작용을 하는 감초 성분도 들어 있어서 예민해진 피부를 진정시켜줍니다. 발라보면 수분이 쏙 흡수되면서도 기름지지 않고 산뜻하게 마무리되는 게 지성 피부분들에게 가장 좋은 점이에요. 건성 피부용 꾸덕한 크림을 쓰면 기름이 과해져서 트러블이 날 수 있으니 자기 피부 타입에 맞는 제형을 선택하는 게 중요합니다. 효소 세안제로 각질 제거 후 이런 보습제를 잘 조합하면 윤광 나고 화장 잘 먹는 겨울 피부를 만들 수 있어요.', '지성 피부의 겨울철 보습제 선택법과 추천 제품을 피부과 전문의 김수형이 안내합니다.', array['지성피부', '겨울보습', '바이오더마', '세라마이드', '피부장벽', '속건조', '보습제']::text[]),
    ('3sy7L-BwCIY', 'kimsoohyung', '속건조에 홍조까지 있는데 자극 없는 피부과 시술이 있나요?', 'LDM이 민감성이면서 속건조와 홍조가 있는 분들에게 잘 맞는 시술입니다. 전용 초음파 겔을 바르고 두 가지 파장으로 각각 3분씩 총 12분 관리를 진행하는데요, 초음파가 손상된 콜라겐과 엘라스틴을 자극해서 수분 가득한 피부로 만들어줘요. 콜라겐과 엘라스틴은 피부에서 댐 같은 역할을 하는데, 이게 튼튼해지니까 수분이 빠져나가지 않아서 속건조가 해결됩니다. 피부 장벽이 강화되면서 염증이 줄어드니까 홍조도 개선돼요. 실제로 1주 간격 4번 받고 홍조와 수분 손실이 줄었다는 논문도 있습니다. 효과를 더 높이려면 이온토코메드 팩을 같이 하면 좋은데, 코코넛에서 추출한 천연 소재로 일반 하이드로겔 마스크보다 진정·수분 흡수 능력이 10배 정도 좋아요. 지성 피부분에게도 수분 젤을 사용하므로 트러블 걱정 없이 받을 수 있습니다.', '속건조와 홍조에 효과적인 LDM 시술의 원리와 장점을 피부과 전문의 김수형이 설명합니다.', array['LDM', '속건조', '홍조', '민감성피부', '피부장벽', '초음파', '콜라겐']::text[]),
    ('3sy7L-BwCIY', 'kimsoohyung', 'PHA 필링이 물광 보톡스라고 불리는 이유가 뭔가요?', 'PHA(폴리하이드록시산) 성분이 피부 속에서 물주머니처럼 수분을 끌어모아 물방울 맺힌 듯한 광채를 만들어주기 때문입니다. PHA 필링은 부드럽게 각질을 제거하면서 동시에 수분을 끌어당기는 성질이 있어서, 시술 후 피부가 물을 잔뜩 머금은 것처럼 반짝반짝 빛이 나요. 기존 필링제인 AHA나 BHA보다 자극이 적어서 예민하거나 민감한 피부도 받을 수 있는 시술입니다. 시술할 때는 AHA로 표면 각질을 먼저 정리하고 PHA 토너, 트리트먼트, 마사지 크림, 블루 벨벳 진정 팩까지 마무리해요. 시술 직후 멘솔 성분 때문에 화한 느낌이나 당기는 느낌이 날 수 있는데, 이는 건조해서가 아니라 하이드라 필름이라는 투명한 수분막이 생기면서 나타나는 현상이에요. 이 수분막 덕분에 물광이 오래 유지되니 걱정하실 필요 없습니다.', 'PHA 필링이 물광을 만드는 원리와 시술 과정을 피부과 전문의 김수형이 안내합니다.', array['PHA필링', '물광', '각질제거', '민감성피부', '물톡스', '보습', '톤업']::text[]),
    ('3sy7L-BwCIY', 'kimsoohyung', '통증 없이 탄력까지 좋아지는 시술이 정말 있나요?', '네, 코레지는 통증이 전혀 없으면서 속건조 개선과 탄력·리프팅 효과까지 주는 시술입니다. 16개의 고주파 파장으로 게을러진 피부 세포를 자극해서 깨워주는 원리인데, 건조한 게 사라지고 피부 탄력이 좋아지면서 턱 라인까지 정리돼요. 먼저 얼굴에 크림을 바르고 세라믹 핸드피스로 10분 정도 고주파 에너지를 전달한 뒤, 고주파가 흐르는 특수 장갑으로 10분 정도 얼굴 굴곡을 만져줍니다. 약간 따뜻한 느낌만 나서 마음 편하게 받을 수 있고, 시술 직후 전후 차이가 바로 보이는 게 장점이에요. 피부가 얇고 건조하신 분들에게 효과가 제일 좋고, 건성 피부에 특히 추천드립니다. 다만 크림을 사용하는 시술이라 드물게 지성 피부에서 트러블이 날 수 있어서, 지성분에게는 LDM이 더 적합할 수 있어요.', '통증 없이 탄력과 리프팅 효과를 주는 코레지 시술을 피부과 전문의 김수형이 설명합니다.', array['코레지', '고주파', '리프팅', '탄력', '속건조', '무통증', '턱라인']::text[]),
    ('3sy7L-BwCIY', 'kimsoohyung', '리쥬란은 언제부터 맞으면 좋고 얼마나 넣어야 하나요?', '20대 후반에서 30대 초반부터 진피층이 얇아지기 시작하니 피부가 얇은 분은 그때부터 시작하면 효과가 좋습니다. 리쥬란은 연어에서 추출한 성분으로 콜라겐이 모여 있는 진피층을 튼튼하게 해주는 데 가장 효과적이에요. 진피층이 튼튼해지니까 미세한 잔주름과 속건조가 개선됩니다. 주사량은 속건조 정도에 따라 달라지는데, 찢어질 것처럼 심하면 4cc, 약간 당기는 정도라면 2cc가 적당해요. 마취 크림을 바른 뒤 의사가 직접 한 땀 한 땀 진피층에 주사하는 방식이라 멍이 들 수 있고 아프기로 유명한 시술이기도 합니다. 통증이 걱정되신다면 미라젯으로 주입하거나 비수면 호흡 마취를 함께 할 수 있어요. 피부 재생에서는 리쥬란만 한 게 없어서 확실한 속건조 개선을 원하시면 추천드립니다.', '리쥬란의 적정 시작 시기와 주사량 기준을 피부과 전문의 김수형이 정리합니다.', array['리쥬란', '속건조', '진피층', '잔주름', '피부재생', '콜라겐', '주사시술']::text[]),
    ('Wvp8YqoZeHA', 'parkhyojin', '남자 수염 제모가 성형수술급이라는 말이 사실인가요?', '네, 거뭇거뭇한 수염 자국이 얼굴에 주는 영향이 굉장히 커서 제모만으로도 인상이 확 달라집니다. 남성분들 얼굴 톤이 어둡고 칙칙해 보이는 이유가 대부분 수염 자국 때문인데, 제모를 하면서 이 자국들이 없어지니까 얼굴이 밝아지고 깔끔해지며 동안으로 보이게 돼요. 실제로 제모 받은 남성들이 면도 안 해도 되는 편리함, 모낭염 같은 트러블 감소, 얼굴 톤업 효과를 가장 크게 느낀다고 합니다. 수염 라인에만 계속 트러블이 나던 분들도 제모 횟수가 쌓이면 모낭이 파괴되면서 증상이 점점 줄어요. 매일 면도해도 저녁이면 수염 자국이 보여서 불편했던 분들이 제모 후에는 출근 준비 시간이 10분 이상 줄었다고 할 정도입니다. 주변에서 피부 좋아졌다, 젊어 보인다는 말을 들으니 한 사람이 받으면 주변 10명이 따라 하는 입소문 시술이에요.', '남성 수염 제모의 효과와 만족도가 높은 이유를 피부과 전문의 박효진이 설명합니다.', array['수염제모', '남성제모', '톤업', '모낭염', '면도', '동안', '피부관리']::text[]),
    ('Wvp8YqoZeHA', 'parkhyojin', '남자 수염 제모 몇 회나 받아야 효과가 보이나요?', '보통 4주 간격으로 5회 정도만 받아도 거뭇거뭇한 수염 자국이 거의 없어져서 깔끔한 인상을 느낄 수 있습니다. 그때부터 이미 얼굴 톤이 밝아지는 걸 스스로 체감하고, 평상시 면도도 거의 안 하게 돼요. 10회차쯤 되면 털이 듬성듬성 솜털처럼 나고, 15회 이상 넘어가면 80% 이상 털이 사라져서 영구 제모 상태라고 볼 수 있습니다. 다만 사람마다 털 굵기, 밀도, 색 차이가 있기 때문에 정확한 횟수는 조금씩 차이가 날 수 있어요. 시술 시간 자체는 약 1분 정도로 매우 짧은데, 통증은 솔직히 상당합니다. 번개 맞은 것처럼 아프지만 금방 지나가고 결과에 너무 만족하니까 계속 오시는 거예요. 통증에 취약한 분들도 효과를 경험하고 나면 스스로 다음 예약을 잡을 정도입니다.', '남성 수염 제모의 회차별 효과와 영구 제모까지 걸리는 기간을 피부과 전문의 박효진이 안내합니다.', array['수염제모', '제모횟수', '영구제모', '남성제모', '통증', '시술시간', '효과']::text[]),
    ('Wvp8YqoZeHA', 'parkhyojin', '40대 넘으면 수염 제모가 안 된다는 게 사실인가요?', '네, 제모 레이저의 원리상 검은 털에만 반응하기 때문에 흰 수염이 나기 시작하면 제모 효과를 볼 수 없습니다. 남성분들도 40대가 넘어가면 흰 수염이 슬슬 나기 시작하는데, 그때부터는 몇 번을 해도 제모가 되지 않아요. 그래서 피부과에 오는 40대 남성분들에게는 지금이 마지막 기회라고 빨리 시작하시라고 권하는 편입니다. 처음에는 갸우뚱하시던 분들도 한두 번 받아보시고 나면 바로 감사하다, 이렇게 편한 줄 몰랐다고 말씀하세요. 사람들이 제모한 것을 알아봐주고 거울 볼 때마다 본인도 변화를 느끼게 됩니다. 아직 수염이 검은색일 때 시작해야 효과를 제대로 볼 수 있으니, 제모를 고민 중이시라면 미루지 말고 빨리 시작하시는 게 유리해요.', '40대 이후 수염 제모가 어려워지는 이유와 적정 시작 시기를 피부과 전문의 박효진이 설명합니다.', array['수염제모', '40대', '흰수염', '레이저제모', '남성제모', '데드라인', '제모원리']::text[]),
    ('Wvp8YqoZeHA', 'parkhyojin', '남자 수염 제모 부작용이 걱정되는데 안전한가요?', '가장 주의해야 할 부작용은 화상인데, 피부색에 맞게 에너지를 조절하면 거의 발생하지 않습니다. 화상은 주로 얼굴 색이 짙은 어두운 피부톤의 분들에게 강한 에너지가 들어갔을 때 생길 수 있어요. 에너지를 낮추면 화상 위험은 줄지만 그만큼 효과도 떨어지기 때문에, 피부 타입에 따라 안전하면서도 효과 있는 선을 찾는 게 숙련된 전문가의 역할입니다. 1-2회차에는 시술 후 모낭염이 생기는 분들도 있지만 이건 오히려 횟수가 쌓이면 모낭이 파괴되면서 줄어들어요. 수염 라인에 계속 트러블이 나시는 분들은 제모를 하면 그 증상이 점점 개선됩니다. 제모 효과가 잘 안 느껴지거나 털이 느리게 빠진다면 에너지가 너무 낮게 설정된 것일 수 있으니 시술자와 상의해보세요. 통증은 확실히 있지만 시술 시간이 1분 정도로 짧아서 충분히 참을 만합니다.', '남성 수염 제모의 부작용과 안전하게 받는 방법을 피부과 전문의 박효진이 정리합니다.', array['수염제모', '부작용', '화상', '모낭염', '안전성', '레이저', '에너지조절']::text[]),
    ('t8_d6wo4c8I', 'jeonghanmi', '예뻐지려고 피부과 시술 받는 게 진짜 자신감에 도움이 되나요?', '네, 피부과 시술은 단순히 외모를 바꾸는 게 아니라 본연의 아름다움을 되찾으면서 자신감을 회복하는 과정입니다. 예를 들어 기미가 신경 쓰이던 분이 치료 후 피부가 깨끗해지면, 깨끗해진 사실 자체보다 그로 인해 자신감을 갖게 되는 게 더 큰 변화예요. 다이어트도 마찬가지로, 5kg을 빼면 주변은 별 차이를 못 느끼지만 본인 스스로 더 멋져졌다고 느끼면서 사람들을 더 당당하게 대하게 됩니다. 실제로 중년 여성분들이 어느 날 거울을 봤을 때 너무 나이 들어 보여서 직장에서 위축됐다고 호소하시는 경우가 많아요. 리프팅 시술로 탄력이 돌아오면 말씀하시는 톤부터 밝아지시거든요. 결국 시술이란 몇 cm를 끌어올리는 게 아니라, 본인의 아름다움을 더 자신 있게 표현할 수 있게 해주는 자기효능감의 회복입니다. 매력은 자신을 사랑하는 데서 나온다는 점을 기억해 주세요.', '피부과 시술이 외모뿐 아니라 자신감과 자존감 회복에 미치는 영향을 피부과 전문의 정한미가 설명합니다.', array['자신감', '피부과시술', '리프팅', '자존감', '자기효능감', '매력']::text[]),
    ('t8_d6wo4c8I', 'jeonghanmi', '얼굴 대칭이 예쁨의 기준이라는데, 미의 기준은 정해져 있나요?', '대칭이 예쁘게 보이는 건 맞지만, 미의 기준이 그것 하나로 정해져 있지는 않습니다. 연구에 따르면 어떤 사람이 아름다운가를 판단할 때 개인의 취향이 절반 정도를 차지한다고 해요. 심지어 유전자가 똑같은 일란성 쌍둥이도 이성의 매력을 평가할 때 각자 기준이 다르다는 연구가 있습니다. 문화권마다 선호하는 얼굴도 달라서, 동아시아는 갸름한 V라인을, 서양은 광대뼈가 도드라진 입체감 있는 얼굴을 좋아해요. 물론 좌우반전 챌린지처럼 대칭일수록 더 예쁘게 보인다는 연구도 있긴 합니다. 하지만 옛말처럼 아름다움은 보는 사람의 눈에 달려 있다는 말에도 과학적 근거가 있는 셈이죠. 사람마다 각자의 심미안이 존재하니, 누군가를 따라하기보다 본인만의 매력을 찾는 게 더 중요합니다.', '얼굴 대칭과 미의 기준에 대한 연구 결과와 개인 취향의 역할을 피부과 전문의 정한미가 정리합니다.', array['미의기준', '얼굴대칭', 'V라인', '광대', '매력', '좌우반전', '개인차']::text[]),
    ('t8_d6wo4c8I', 'jeonghanmi', '셀카가 남이 찍어준 사진보다 더 예쁘게 나오는 이유가 뭔가요?', '셀카를 찍을 때 본인이 가장 편하고 자연스러운 상태가 되기 때문에 매력적인 표정이 나옵니다. 실제로 본인이 찍은 셀카에서 더 매력적인 표정이 나온다는 연구 결과가 있어요. 그 이유는 셀카를 찍을 때 남의 시선을 신경 쓰지 않고, 스스로 가장 예쁜 척도 멋있는 척도 하면서 굉장히 자신감 있는 상태가 되기 때문입니다. 차은우 같은 배우도 카메라 앞에서 당당하게 표정이나 포즈를 취할 때 더 매력적으로 보이는 것과 같은 원리예요. 만약 그런 외모라도 무대에서 쭈뼛거리고 자신감이 없으면 그렇게 매력적으로 보이지 않을 겁니다. 결국 자신감 있을 때 자연스럽고 예쁜 표정이 나온다는 거죠. 사진 잘 나오고 싶다면 편안하고 당당한 마음으로 찍어보세요.', '셀카가 더 예쁘게 나오는 과학적 이유와 자신감의 관계를 피부과 전문의 정한미가 안내합니다.', array['셀카', '자신감', '표정', '매력', '사진', '자연스러움']::text[]),
    ('t8_d6wo4c8I', 'jeonghanmi', '피부과 전문의가 생각하는 진짜 예뻐지는 방법이 뭔가요?', '외모가 완벽한 누군가를 따라하는 게 아니라, 그 사람만의 고유한 아름다움을 살려주면서 컴플렉스를 자연스럽게 보완하는 것이 진짜 예뻐지는 방법입니다. 사람마다 이목구비도, 피부톤도, 분위기도 모두 다르잖아요. 정샘물 메이크업 아티스트의 철학처럼 각자가 지닌 고유의 컬러와 빛, 개성을 살려 매력을 돋보이게 하는 접근이 중요합니다. 트렌드를 쫓기보다 있는 그대로의 나를 받아들이면서 나다움을 잃지 않고 아름다워지는 게 핵심이에요. 외모가 첫인상에 영향을 미치는 건 맞지만, 지속적인 매력은 자신감과 진정성에서 나옵니다. 피부과 시술도 그런 내추럴 뷰티를 찾아주고 자존감을 높여주는 여정이라고 생각하시면 돼요. 자기 자신을 사랑하는 게 가장 강력한 매력 비결입니다.', '고유한 아름다움을 살리는 피부과 시술 철학과 자존감의 관계를 피부과 전문의 정한미가 설명합니다.', array['내추럴뷰티', '자존감', '피부과시술', '개성', '매력', '정샘물', '아름다움']::text[]),
    ('GQBb1sYzxmo', 'jeonghanmi', '멜라토닌이 기미에도 효과가 있다는 게 사실인가요?', '네, 멜라토닌이 기미 개선에 도움이 될 수 있다는 연구 결과들이 나오고 있습니다. 기미가 있는 사람들의 혈액 속 멜라토닌 수치를 측정해 봤더니 기미가 없는 사람들에 비해 낮게 나왔어요. 실제로 기미가 있는 사람들에게 멜라토닌을 3달 동안 복용하게 했더니 기미 넓이도 줄어들고 색깔도 옅어졌다는 연구가 있습니다. 멜라토닌이 기미에 도움이 되는 이유는 두 가지예요. 첫째, 강력한 항산화 물질로서 기미를 유발하는 산화 스트레스(활성산소)를 줄여줍니다. 둘째, 멜라닌(피부 색소) 합성을 직접적으로 억제하는 역할도 해요. 다만 아직 대규모 임상시험 결과가 없고 장기 복용 문제점도 있을 수 있어서, 기미 때문에 무조건 복용하기엔 이른 단계입니다. 희망적이지만 의사와 상담 후 판단하시는 게 안전해요.', '멜라토닌이 기미 개선에 도움이 되는 원리와 연구 결과를 피부과 전문의 정한미가 정리합니다.', array['멜라토닌', '기미', '항산화', '멜라닌', '산화스트레스', '색소침착', '피부미백']::text[]),
    ('GQBb1sYzxmo', 'jeonghanmi', '멜라토닌이 그냥 잠 오게 하는 영양제 아닌가요?', '아닙니다. 멜라토닌은 영양제가 아니라 우리 몸의 생체 시계를 조절하는 호르몬이에요. 해가 지면 멜라토닌 분비가 시작돼서 점점 졸리게 하고, 해가 뜨면 분비가 줄어 아침에 일어나게 하는 역할을 합니다. 신생아가 처음 3~4개월간 낮밤을 구분 못하다가 이후 구분하기 시작하는 것도 멜라토닌을 스스로 만들기 시작해서예요. 문제는 요즘 늦게까지 핸드폰이나 TV의 블루라이트를 보면 멜라토닌 분비가 줄어들어 불면증이 생길 수 있다는 겁니다. 한국에서는 전문의약품으로 분류돼 있어 의사 처방이 있어야 복용할 수 있는 약이기도 해요. 젊은 분들은 대부분 멜라토닌 분비가 왕성하게 잘 되기 때문에 보충해도 효과가 없을 수 있습니다. 50대 이상 수면장애가 있거나 교대근무로 수면 패턴이 깨진 분들에게 도움이 됩니다.', '멜라토닌이 영양제가 아닌 호르몬인 이유와 올바른 복용 대상을 피부과 전문의 정한미가 안내합니다.', array['멜라토닌', '수면', '호르몬', '블루라이트', '불면증', '생체시계', '전문의약품']::text[]),
    ('GQBb1sYzxmo', 'jeonghanmi', '멜라토닌이 피부 노화도 늦춰줄 수 있나요?', '이론상으로는 가능합니다. 멜라토닌의 항산화 효과가 피부 노화를 막아주는 역할을 해요. 활성산소가 피부에 쌓이면 콜라겐이나 엘라스틴 같은 좋은 성분을 파괴하고 심지어 피부 세포 DNA까지 손상시킬 수 있는데, 멜라토닌이 이 활성산소가 쌓이는 것을 막아줍니다. 놀라운 건 멜라토닌이 비타민C나 비타민E보다도 항산화 효과가 뛰어나다는 연구 결과가 있다는 점이에요. 또한 면역력을 높여주고 심지어 암 예방 효과까지 있다는 연구들도 나오고 있습니다. 야간 근무를 장기간 하신 분들은 멜라토닌 분비가 엉망이 되면서 유방암 발생 위험이 일반인보다 높았다는 통계도 있어요. 다만 나이가 들수록 멜라토닌이 줄어드는데, 부작용 우려가 있어 단순히 영양제처럼 복용하면 안 됩니다. 멜라토닌이 든 크림을 피부에 직접 바르면 주름 감소와 탄력 개선 효과가 있었다는 연구도 참고해 보세요.', '멜라토닌의 항산화 효과와 피부 노화 방지 가능성에 대해 피부과 전문의 정한미가 설명합니다.', array['멜라토닌', '피부노화', '항산화', '콜라겐', '활성산소', '비타민C', '엘라스틴']::text[]),
    ('GQBb1sYzxmo', 'jeonghanmi', '수면 부족하면 얼굴 기미가 진해질 수 있나요?', '네, 수면 부족은 기미를 악화시킬 수 있습니다. 잠을 잘 못 자면 멜라토닌 분비가 줄어드는데, 멜라토닌은 피부에 쌓이는 산화 스트레스(활성산소 등 해로운 부산물)를 청소부처럼 쓸어내는 역할을 해요. 이 청소 역할이 줄어들면 노폐물과 활성산소가 쌓여서 기미를 유발하게 됩니다. 특히 핸드폰이나 TV에서 나오는 블루라이트를 밤에 보면 멜라토닌 분비가 줄어들어요. 전등 불빛이 없던 옛날에는 해가 뜨면 일어나고 밤에 자는 게 자연스러웠지만, 요즘은 전자기기 때문에 생체 리듬이 깨지기 쉽습니다. 나이가 들수록 멜라토닌 자체도 줄어들어서 잠도 안 오고 피부 노화도 가속화되는 원인이 될 수 있어요. 기미가 신경 쓰이신다면 잠자기 전 블루라이트 노출을 줄이고 규칙적인 수면 습관을 가지시는 게 좋습니다.', '수면 부족이 기미를 악화시키는 원리와 예방법을 피부과 전문의 정한미가 안내합니다.', array['수면부족', '기미', '멜라토닌', '블루라이트', '산화스트레스', '피부관리', '수면습관']::text[]),
    ('ZH6ZfRghZmo', 'jeonghanmi', '위고비 맞으면 진짜 10kg 이상 빠지나요? 부작용은 없어요?', '위고비는 일주일에 한 번 주사를 맞으면 평균 15% 체중 감량 효과가 있는 혁신적인 비만 치료제입니다. 100kg이던 사람이 85kg으로, 70kg이던 사람이 60kg까지 빠질 수 있어요. 하지만 효과가 좋다고 누구나 안전하게 쓸 수 있는 약은 아닙니다. 가장 흔한 부작용은 소화기계 증상으로, 위의 운동이 느려져 속이 울렁거리는 구역감이 44%, 구토가 20% 정도 나타났어요. 다만 이런 증상은 대부분 투약 초기 1~2달에 생겼다가 서서히 사라집니다. 그래서 용량을 한 번에 올리지 않고 수 개월에 걸쳐 천천히 증량하는 거예요. 실제로 4년간 맞다가 급성 췌장염으로 사망한 사례도 있었으므로, 반드시 의사와 꼼꼼한 상담 후 본인에게 이득과 위험을 잘 파악하고 사용해야 합니다.', '위고비의 체중 감량 효과와 주요 부작용 및 주의사항을 피부과 전문의 정한미가 정리합니다.', array['위고비', '비만치료제', '부작용', '체중감량', '구역감', '췌장염', 'GLP-1']::text[]),
    ('ZH6ZfRghZmo', 'jeonghanmi', '위고비 맞으면 안 되는 사람도 있나요?', '네, 위고비를 절대 사용하면 안 되는 금기 대상이 있습니다. 갑상선 수질암 병력이나 가족력이 있는 경우, 제2형 다발성 내분비 종양증후군 병력이나 가족력이 있는 경우, 그리고 세마글루타이드에 과민반응이 있는 경우가 해당돼요. 사용 시 주의해야 할 사항도 여러 가지입니다. 급성 췌장염이 의심되면 즉시 투약을 중단해야 하고, 담석증 의심 시 검사가 필요합니다. 당뇨 환자는 저혈당 위험이 있고, 급성 신장 손상이 발생할 수 있어요. 심박수가 올라갈 수 있어 정기적 체크가 필요하며, 자살 행동이나 자살 사고에도 주의가 필요합니다. 특히 빨리 빼겠다고 처음부터 높은 용량으로 맞으면 절대 안 되고, 가장 낮은 용량부터 시작해 4주간 관찰 후 천천히 증량하셔야 합니다.', '위고비를 절대 사용하면 안 되는 대상과 주의사항을 피부과 전문의 정한미가 안내합니다.', array['위고비', '금기', '갑상선수질암', '췌장염', '부작용', '비만치료제', '세마글루타이드']::text[]),
    ('ZH6ZfRghZmo', 'jeonghanmi', '위고비가 살만 빼주는 약이 아니라는데 정말인가요?', '맞습니다. 위고비는 단순 다이어트 약이 아니라 비만과 관련된 여러 질환도 개선시켜 주는 치료제예요. 17,600명을 대상으로 3년 넘게 관찰한 대규모 연구에서, 위고비를 맞은 그룹이 심근경색이나 뇌졸중 같은 심혈관 질환 위험이 20% 감소했습니다. 심장질환으로 인한 사망도 15% 더 낮았고, 심부전으로 인한 사망도 18% 더 낮았어요. 또한 당뇨와 만성신장질환이 있는 환자들에게 3년 이상 투약했을 때 신부전(콩팥 기능 저하) 발생 위험이 24%나 낮게 나타났습니다. 심장 건강이 좋아지고 혈압도 내려간다는 결과도 있어요. 그래서 단순히 날씬해지고 싶은 분이 아닌, BMI 30 이상이거나 27 이상이면서 고혈압, 당뇨, 고지혈증 같은 비만 관련 질환이 있는 분들에게 적합한 치료제입니다.', '위고비의 체중 감량 외 심혈관 질환 개선 효과와 적응증을 피부과 전문의 정한미가 설명합니다.', array['위고비', '심혈관질환', '비만치료제', '체중감량', '당뇨', '심부전', 'BMI']::text[]),
    ('ZH6ZfRghZmo', 'jeonghanmi', '위고비 맞다가 이런 증상 나타나면 바로 병원 가야 하나요?', '네, 특정 증상이 나타나면 즉시 병원에 가야 합니다. 심한 복통이 지속될 때, 등 쪽으로 퍼지는 통증이 있을 때, 심한 구토가 멈추지 않을 때, 며칠째 음식을 못 먹을 때, 갑자기 어지럽고 맥박이 빨라질 때가 위험 신호예요. 실제 사례에서 한 고도비만 남성분이 4년간 위고비를 맞다가 용량을 0.5mg으로 올렸을 때 심한 구토와 메스꺼움이 나타났고, 4주 후 급성 췌장염이 발생해 사망하셨습니다. 보통 위고비 관련 급성 췌장염은 투약 초기에 생기는 경우가 많지만, 이 사례처럼 나중에도 늦게 생길 수 있어요. 부작용이 나타나면 괜찮겠지 넘기지 마시고 담당 의사에게 바로 알리셔야 합니다. 약을 쓰는 동안 정기적으로 심박수도 체크하시는 게 좋습니다.', '위고비 투약 중 즉시 병원을 방문해야 하는 위험 증상들을 피부과 전문의 정한미가 정리합니다.', array['위고비', '부작용', '췌장염', '응급증상', '복통', '구토', '비만치료제']::text[]),
    ('piajMmEONTo', 'parkhyojin', '피부과 시술 아픈 게 무서운데, 수면마취 말고 다른 방법 없나요?', '비수면 호흡마취라는 방법이 있습니다. 잠들지 않으면서도 통증을 거의 못 느끼게 해주는 마취 방식이에요. 아산화질소와 산소를 동시에 호스로 들이쉬면서 편하게 쉬다 보면 점점 편안해지고, 평소 느끼던 통증이 10이었다면 1~2로 확 줄어드는 원리입니다. 정확히 말하면 통증을 차단하는 게 아니라 의식을 다른 데로 빼돌려서 통증을 못 느끼게 해주는 거예요. 술에 취하면 넘어지거나 부딪혀도 고통을 잘 못 느끼는 것과 비슷한 원리라고 보시면 됩니다. 수면마취처럼 8시간 금식이나 시술 전 감기 제한도 없고, 끝나고 마취 깨는 데 오래 걸리지도 않아요. 이미 많은 병원에서 시행하고 있는데 환자분들이 아직 잘 모르실 뿐이니, 통증이 걱정되시면 호흡마취 가능 여부를 문의해 보세요.', '수면마취 대신 통증을 줄여주는 비수면 호흡마취의 원리와 장점을 피부과 전문의 박효진이 설명합니다.', array['호흡마취', '비수면마취', '아산화질소', '통증', '피부과시술', '수면마취', '웃음가스']::text[]),
    ('piajMmEONTo', 'parkhyojin', '호흡마취하면 의식이 없어지는 건 아닌 거죠?', '맞아요, 호흡마취는 의식이 완전히 있는 상태입니다. 대화도 가능하고 주변 소리도 다 들려요. 본인은 취한 것 같은 느낌이지만 의식이 있고, 구구단도 할 수 있을 정도로 맨정신인데 아프지는 않은 그런 상태가 됩니다. 이게 호흡마취의 가장 큰 장점 중 하나예요. 수면마취는 완전히 의식을 잠재워서 자발 호흡까지 없어질 수 있고, 혀가 뒤로 말려 들어가면서 기도가 막히는 응급 상황이 올 수도 있거든요. 반면 호흡마취는 그런 위험 상황 자체가 없어서 훨씬 안전합니다. 시술하는 의사 입장에서도 환자 산소포화도나 호흡 상태를 계속 의식하지 않아도 돼서 시술에 더 집중할 수 있어요. 내가 인지할 수 있는 상황에서 시술받고 싶은 분들에게 특히 좋은 방법입니다.', '호흡마취 중 의식 상태와 수면마취 대비 안전성 차이를 피부과 전문의 박효진이 안내합니다.', array['호흡마취', '의식', '수면마취', '안전성', '자발호흡', '통증관리', '피부과시술']::text[]),
    ('piajMmEONTo', 'parkhyojin', '호흡마취 효과가 사람마다 다르다는데, 술 못 마시는 사람이 더 잘 듣나요?', '네, 호흡마취는 술이 세고 약한 것과 관련이 있어서 사람마다 차이가 있습니다. 술을 잘 못 마시는 이른바 알쓰인 분들은 거의 기억이 안 날 정도로 통증이 0에 가깝게 느껴져요. 반면 술이 세신 분들은 통증이 10점에서 1~2점으로 감소하기는 하지만, 아예 기억이 안 나는 수준은 아닙니다. 주변 소리 다 들리고 상황 인지도 되며 충분히 기억도 나는 상태예요. 그래도 모든 분께 통증 감소 효과는 확실히 있습니다. 마취 효과를 더 좋게 받으려면 마음을 편안하게 가지고 숨을 천천히 들이쉬고 내쉬는 게 중요해요. 유토피아에 갔다 온다는 생각으로 가장 행복했던 여행지를 떠올리시면 훨씬 마취가 잘 된다고 합니다.', '호흡마취 효과의 개인차와 더 잘 받는 방법을 피부과 전문의 박효진이 정리합니다.', array['호흡마취', '알쓰', '통증', '개인차', '마취효과', '비수면마취', '호흡법']::text[]),
    ('piajMmEONTo', 'parkhyojin', '호흡마취 끝나고 어지럽거나 울렁거리지 않나요?', '호흡마취 후 약간 어지럽거나 울렁거림이 있을 수 있지만, 끝나고 산소를 5분간 충분히 들이마시면 그런 증상도 금방 좋아집니다. 수면마취처럼 깨는 데 오래 걸리지 않아서 바로 일상생활이 가능해요. 수면마취는 8시간 금식도 해야 하고 시술 2주 전까지 감기가 걸리면 일정을 다 바꿔야 하며, 끝나고도 마취 깨는 데 오래 걸리고 운전도 못 하잖아요. 호흡마취는 그런 번거로움이 전혀 없고 굉장히 간편하게 받을 수 있습니다. 소아치과에서 아이들에게 웃음가스로 마취하는 것과 같은 원리이기도 해요. 다만 산소를 충분히 마시지 않고 바로 일어나면 머리가 아프거나 울렁거릴 수 있으니, 끝난 후 5분간 산소 흡입 시간을 꼭 지키시는 게 중요합니다.', '호흡마취 후 회복 시간과 부작용 관리법을 피부과 전문의 박효진이 설명합니다.', array['호흡마취', '회복', '어지러움', '산소흡입', '수면마취', '웃음가스', '부작용']::text[]),
    ('mzTZV2c5noU', 'jeonghanmi', '온다 리프팅이 울쎄라나 써마지랑 뭐가 다른 건가요?', '온다는 울쎄라(초음파)나 써마지(고주파)와 달리 극초단파라는 파장을 사용하는 리프팅 장비입니다. 원리가 전자레인지와 비슷한데, 물 분자를 빠르게 진동시켜 빨리 데워주는 방식이에요. 핵심 차이는 표피를 거의 데우지 않고 안쪽만 빨리 데워준다는 점이라서 통증이 굉장히 적다는 장점이 있습니다. 핸드피스가 두 가지로 나뉘는데, 7mm 핸드피스는 피부 깊은 곳까지 들어가 리프팅 효과와 바디 리프팅도 가능하고요. 3mm 핸드피스는 얕은 층을 타겟해서 피부 타이트닝 효과를 줄 수 있습니다. 리프팅의 양대산맥이 울쎄라와 써마지였는데, 온다는 통증이 적으면서도 효과를 낼 수 있는 새로운 패러다임의 장비로 주목받고 있어요. 시술 부위와 목적에 따라 핸드피스를 선택할 수 있다는 점도 장점입니다.', '온다 리프팅의 원리와 울쎄라, 써마지와의 차이점을 피부과 전문의 정한미가 설명합니다.', array['온다', '리프팅', '울쎄라', '써마지', '극초단파', '타이트닝', '통증']::text[]),
    ('mzTZV2c5noU', 'jeonghanmi', '모공 줄이는 데 특화된 스킨부스터가 있다던데 뭔가요?', '포젤란이라는 새로 나온 스킨부스터가 모공 개선에 특화되어 있습니다. 기존 스킨부스터들이 수분이나 피부결 개선이 주 목적이라면, 포젤란은 PCL이라는 성분이 들어 있어서 모공과 피부결에 특히 효과적이에요. PCL 성분의 분자 크기가 굉장히 작아서 모공 속으로 흡수가 잘 된다고 합니다. 일반적인 스킨부스터에 들어있는 아미노산이나 비타민 같은 성분에 PCL이 더해진 구성이에요. 제형이 액상으로 나와 있어서 바로 사용하기도 편하다는 특징이 있습니다. 실제로 환자분들 중에 모공이 좋아졌다, 결이 좋아졌다는 후기가 다른 부스터에 비해 많은 편이라고 해요. 포젤란은 독일어로 도자기라는 뜻인데, 도자기 같은 피부를 만들어준다는 의미를 담고 있습니다.', '모공 개선에 특화된 스킨부스터 포젤란의 특징과 성분을 피부과 전문의 정한미가 안내합니다.', array['포젤란', '스킨부스터', '모공', 'PCL', '피부결', '모공축소', '피부관리']::text[]),
    ('mzTZV2c5noU', 'jeonghanmi', '자기장으로 얼굴 리프팅하는 장비도 있나요?', '네, 코어스컬프라는 장비가 자기장을 이용한 피부 관리 기기입니다. 자기장이 피부 깊이 들어가는데, 지방층이나 근막층보다 더 깊은 근육층까지 도달할 수 있다고 해요. 타이트닝과 리프팅 효과가 있고, 얼굴이 부었을 때 붓기를 빼주거나 염증을 줄여주는 효과도 두루 있습니다. 사용 방식은 누워서 얼굴을 장비에 대고 쬐는 형태예요. 원래는 배나 엉덩이 같은 바디용 기계였는데, 얼굴에도 쓸 수 있게 새롭게 출시된 장비입니다. 철가루를 대보면 자기장에 의해 흔들리는 게 보일 정도로 에너지가 전달되는 것을 눈으로 확인할 수 있어요. 아직 새로 나온 장비라서 임상 데이터가 쌓여봐야 하겠지만, 다양한 효과를 기대할 수 있는 흥미로운 기술입니다.', '자기장을 이용한 리프팅 장비 코어스컬프의 원리와 효과를 피부과 전문의 정한미가 정리합니다.', array['코어스컬프', '자기장', '리프팅', '타이트닝', '붓기', '근육층', '바디관리']::text[]),
    ('mzTZV2c5noU', 'jeonghanmi', '피부를 깎지 않고도 흉터나 모공 치료가 가능한 레이저가 있나요?', '네, 레드터치 프로라는 레이저가 피부를 깎아내지 않으면서 흉터와 모공을 치료할 수 있는 프랙셔널 방식의 장비입니다. 이탈리아 회사에서 만든 제품으로 유럽과 캐나다에서 굉장히 인기가 있고, 한국에 들어온 지 얼마 안 됐어요. 피부가 밝아지면서 피부결, 모공, 탄력까지 동시에 좋아지는 효과가 있다고 합니다. 프랙셔널 빔이 들어갈 때 굉장히 뜨거울 수 있는데, 핸드피스 앞쪽에서 쿨링을 해줘서 통증이 적은 편이에요. 가장 큰 장점은 피부를 깎아내는 방식이 아니기 때문에 시술 후 바로 일상생활을 할 수 있다는 점입니다. 기존 프락셀은 다운타임이 부담스러웠다면, 이 장비는 일상에 지장 없이 흉터와 모공을 관리하고 싶은 분들에게 좋은 선택지가 될 수 있어요.', '다운타임 없이 흉터와 모공을 치료하는 레드터치 프로 레이저를 피부과 전문의 정한미가 소개합니다.', array['레드터치프로', '프랙셔널', '흉터', '모공', '레이저', '다운타임', '피부결']::text[]),
    ('o8EincXgG2A', 'jeonghanmi', '눈가 보톡스 맞으면 웃을 때 표정이 어색해지나요?', '네, 눈가 보톡스를 꼼꼼하게 많이 놓으면 웃을 때 표정이 부자연스러워질 수 있습니다. 눈 주변에 팬더처럼 동그랗게 있는 근육에 보톡스를 놔서 그 근육이 움직이지 않게 해야 눈 주름이 안 생기기 때문이에요. 주름을 확실히 펴려고 꼼꼼하게 놓을수록 웃을 때도 근육이 움직이지 않아 어색할 수밖에 없습니다. 반대로 적당히 놓으면 주름이 완전히 펴지지 않죠. 결국 주름이 잘 펴지는 게 중요한지, 표정이 자연스러운 게 더 중요한지 본인의 우선순위를 먼저 정하셔야 합니다. 시술 전에 담당 선생님과 이 부분을 충분히 상의하시면 본인에게 맞는 용량을 찾는 데 도움이 돼요. 주름 제거와 자연스러운 표정, 둘 다 100% 만족시키기는 어렵다는 점을 미리 알고 가시는 게 좋습니다.', '눈가 보톡스 후 표정이 어색해지는 이유와 자연스러운 시술을 위한 팁을 피부과 전문의 정한미가 설명합니다.', array['보톡스', '눈가주름', '표정', '눈가보톡스', '자연스러움', '주름개선']::text[]),
    ('o8EincXgG2A', 'jeonghanmi', '상대방이 진짜 웃는 건지 가짜 웃는 건지 구별할 수 있나요?', '눈가와 입꼬리를 함께 보면 진심 어린 미소인지 알 수 있습니다. 진짜 행복할 때는 입꼬리뿐 아니라 눈 주변 근육도 같이 수축해서 눈이 반달처럼 되고 눈가에 주름이 생기는데, 이걸 뒤셴 스마일이라고 해요. 연구에 따르면 사람들은 이런 표정을 볼 때 상대방이 더 진실되고 따뜻하며 신뢰할 수 있다고 느낀다고 합니다. 연습을 통해 의도적으로 뒤셴 스마일을 만들 수는 있지만, 진짜 행복해서 짓는 미소와 의도적 미소는 미세하게 다르다고 해요. 사진으로 포착하기는 어려워도 사람들은 그 차이를 무의식적으로 알아챈답니다. 그래서 손님을 상대하는 직업을 가진 분들은 눈가 보톡스를 맞을 때 특히 신중해야 합니다. 눈 주변 근육이 움직이지 않으면 뒤셴 스마일 자체가 불가능해지기 때문이에요.', '진짜 미소와 가짜 미소를 구별하는 뒤셴 스마일의 원리와 보톡스와의 관계를 피부과 전문의 정한미가 정리합니다.', array['뒤셴스마일', '표정', '눈가주름', '보톡스', '미소', '신뢰감', '눈웃음']::text[]),
    ('o8EincXgG2A', 'jeonghanmi', '안면홍조가 너무 심한데 치료할 수 있나요?', '네, 안면홍조 때문에 레이저 치료를 받으러 오시는 분들이 실제로 꽤 많습니다. 온도 변화가 미세하게 있거나 작은 감정 변화만으로도 얼굴이 쉽게 빨개지는 분들이 있는데, 긴장하거나 부끄러울 때 본인의 감정이 그대로 드러나기 때문에 사회생활에서 불편감을 많이 느끼세요. 사람의 피부는 감정을 표현하는 중요한 역할을 하는데, 얼굴이 붉어지면 부끄럽거나 화가 났다는 걸 드러내고 창백해지면 겁을 먹었다는 신호가 됩니다. 인간은 진화 과정에서 털이 줄어들면서 피부가 감정 표현의 도구가 된 거예요. 그래서 홍조가 심한 분들은 원치 않는 감정 노출로 스트레스를 받게 되는 겁니다. 피부과에서 레이저 치료를 통해 홍조를 개선할 수 있으니 일상생활에 지장이 있다면 상담받아 보시는 걸 추천드립니다.', '안면홍조의 원인과 레이저 치료 가능성을 피부과 전문의 정한미가 안내합니다.', array['안면홍조', '레이저치료', '홍조', '감정표현', '피부', '사회생활']::text[]),
    ('o8EincXgG2A', 'jeonghanmi', '피부관리 방법이 너무 많은데 뭐가 제일 중요해요?', '깨끗하게 씻고, 보습하고, 자외선 차단하는 기본 관리만 잘해도 피부 건강의 90%는 해결됩니다. 요즘 피부 관리법이 너무 많아서 헷갈리시겠지만, 뭐든 기본에 충실한 게 핵심이에요. 피부가 깨끗하고 건강하면 다른 사람에게 좋은 인상을 주고, 본인이 건강하고 활력 있다는 걸 자연스럽게 보여주게 됩니다. 피부 상태는 그 사람의 건강과 컨디션을 드러내는 신호이기 때문에, 피부관리는 단순히 예뻐 보이기 위한 것만은 아니에요. 또한 건강한 피부만큼이나 건강한 표정도 중요합니다. 아무리 피부가 좋아도 늘 찡그리고 있으면 좋은 인상을 줄 수가 없죠. 피부과 의사로서 가장 이상적이라고 생각하는 건 완벽하게 주름 없는 피부가 아니라, 건강하게 빛나면서 자연스러운 감정을 담을 수 있는 얼굴입니다.', '피부관리의 핵심 기본 3단계와 건강한 피부의 의미를 피부과 전문의 정한미가 정리합니다.', array['피부관리', '기초케어', '세안', '보습', '자외선차단', '동안', '건강한피부']::text[]),
    ('zVRtKm2ORUM', 'jeonghanmi', '대변 이식으로 여드름이 치료된다는 게 사실인가요?', '네, 여드름 환자에게 선별된 장내 미생물을 이식했더니 여드름이 40% 개선되었다는 연구 결과가 실제로 있습니다. 대변 미생물 이식술(FMT)은 건강한 사람의 대변에서 유익한 미생물만 정제해서 환자의 장에 이식하는 치료법이에요. 장내 미생물이 우리 몸 면역력의 70~80%를 담당하기 때문에 장 환경이 개선되면 피부 질환에도 영향을 줄 수 있는 겁니다. 여드름뿐 아니라 아토피, 건선 같은 피부 질환에서도 가능성이 확인되고 있어요. 다만 아직 연구가 초기 단계여서 어떤 사람에게 어떤 기증자의 어떤 미생물이 필요한지, 최적의 투여 방법이 뭔지 등 더 많은 임상시험이 필요합니다. 만성 여드름으로 고생하시는 분들에게는 희소식이지만, 당장 임상에서 활용되기까지는 시간이 더 걸릴 것으로 보입니다.', '대변 미생물 이식술의 여드름 개선 효과와 피부 질환 치료 가능성을 피부과 전문의 정한미가 설명합니다.', array['대변이식술', '여드름', '장내미생물', 'FMT', '아토피', '건선', '면역력']::text[]),
    ('zVRtKm2ORUM', 'jeonghanmi', '대변 이식술이 정말 효과 있는 병이 뭐예요?', '클로스트리디움 디피실(Clostridium difficile)이라는 균이 일으키는 중증 장염에서 90% 이상의 치료율을 보여줍니다. 이 장염은 항생제로 치료를 해도 장 속 유익균까지 같이 죽어서 재발이 굉장히 흔한 질환이에요. 대변 이식술은 건강한 사람의 장내 미생물을 환자의 장에 이식해서 장 환경을 다시 건강하게 복원하는 원리입니다. 2023년 11월에는 대변에서 추출한 유익균을 알약에 담은 Rebyota라는 약이 미국 FDA 승인을 받아 실제로 처방되고 있어요. 영국, 네덜란드, 호주에서도 활용되고 있고, 한국에서는 일부 대학병원에서 연구 목적으로 제한적으로 사용 중입니다. 장염 외에도 자폐 스펙트럼 장애, 우울증, 비만, 당뇨병, 심지어 흑색종 같은 피부암 치료에서도 효과가 확인되고 있어요. 면역항암제에 반응이 없던 흑색종 환자 중 65%가 대변 이식 후 항암제 효과가 좋아졌다는 결과도 있습니다.', '대변 미생물 이식술의 주요 치료 효과와 FDA 승인 현황을 피부과 전문의 정한미가 안내합니다.', array['대변이식술', 'FMT', '장염', '흑색종', '면역항암제', '장내미생물', 'FDA']::text[]),
    ('zVRtKm2ORUM', 'jeonghanmi', '대변 미생물 이식술은 실제로 어떻게 진행하는 거예요?', '크게 세 가지 방법이 있는데, 내시경으로 항문에 직접 주입하거나, 코에 관을 넣어 장에 주입하거나, 캡슐 형태로 먹는 방법입니다. 실제로 이식되는 건 대변 그 자체가 아니라 여러 단계의 정제 과정을 거쳐 불순물을 제거하고 유익한 미생물만 분리한 깨끗한 상태예요. 기증자 선정도 굉장히 까다로운데, 기본 건강검진은 물론 여러 감염질환이나 자가면역질환 유무를 철저히 체크하고 생활습관이나 식습관, 최근 복용 약물까지 꼼꼼하게 확인합니다. 부작용은 대체로 안전한 편으로, 가장 흔한 건 일시적인 복부 불편감이나 설사인데 대부분 며칠 안에 해결된다고 해요. 다만 면역력이 많이 떨어진 환자에게는 좀 더 신중하게 접근해야 합니다. 건강한 사람의 대변을 모아두는 대변 은행도 생기고 있어서, 제대혈 은행처럼 필요할 때 바로 사용할 수 있게 보관하는 시스템이 갖춰지고 있습니다.', '대변 미생물 이식술의 구체적 시술 방법과 안전성을 피부과 전문의 정한미가 정리합니다.', array['대변이식술', 'FMT', '장내미생물', '대변은행', '기증자', '부작용', '캡슐']::text[]),
    ('zVRtKm2ORUM', 'jeonghanmi', '장내 미생물이 면역력에 왜 그렇게 중요한 거예요?', '우리 몸속 100조 개가 넘는 미생물 중 대부분이 장에 살면서 면역력의 70~80%를 담당하고 있습니다. 단순히 음식을 소화시키는 역할만 하는 게 아니라 대사나 신경계 기능에도 핵심적인 영향을 미쳐요. 4세기 중국 역사서에 이미 대변을 이용한 설사 치료 기록이 있을 만큼 오래된 개념이지만, 현대의학에서 주목받기 시작한 건 2013년 NEJM이라는 세계 최고 권위 의학 저널에 획기적인 연구가 발표되면서부터입니다. 장내 미생물 균형이 무너지면 장염뿐 아니라 정신과 질환, 비만, 당뇨, 심지어 암 치료 효과에까지 영향을 준다는 연구들이 속속 나오고 있어요. 미래에는 개인의 장내 미생물 상태를 분석해서 맞춤형 치료가 가능해질 수도 있습니다. 건강한 장내 환경을 유지하는 것이 전신 건강의 핵심이라 해도 과언이 아닌 시대가 오고 있는 겁니다.', '장내 미생물이 면역력과 전신 건강에 미치는 영향을 피부과 전문의 정한미가 설명합니다.', array['장내미생물', '면역력', '마이크로바이옴', 'FMT', '대사', '건강', '장건강']::text[]),
    ('2z-zBNyzkqs', 'jeonghanmi', '피부과 의사도 직접 써마지 받나요?', '네, 저는 다른 건 몰라도 써마지 시술만큼은 1년에 한 번 꼭 받고 있고 벌써 6년째 꾸준히 하고 있습니다. 매년 연말에 건강검진하듯 써마지를 받는 게 루틴이에요. 혼자 하기엔 아프고 시간도 오래 걸려서 원장님들끼리 짝지어 서로 해주고 받고 있습니다. 시술할 때마다 "올해도 얼굴에 방부제 칩시다"라고 얘기할 정도로, 써마지는 피부 노화를 미루는 보험 같은 시술이에요. 의사들이 다 이과생이라 증명 안 된 건 안 믿는데, 써마지는 효과가 다 증명돼 있으니까 안 받을 이유가 없는 거죠. 병원에 오시는 70대 분들 중 피부가 정말 좋으신 분들께 여쭤보면 써마지를 꾸준히 받았다고 하시는 경우가 꽤 있어요. 지금 당장 큰 차이를 못 느끼더라도 5년, 10년 쌓이면 확실한 차이가 납니다.', '피부과 의사가 직접 써마지를 꾸준히 받는 이유와 장기적 효과를 피부과 전문의 정한미가 안내합니다.', array['써마지', '리프팅', '콜라겐', '노화방지', '피부탄력', '고주파', '피부관리']::text[]),
    ('2z-zBNyzkqs', 'jeonghanmi', '써마지 받아도 효과를 못 느끼겠다는 사람도 있던데 왜 그래요?', '원래 피부 컨디션이 좋은 분들은 단기적으로 확 좋아지는 걸 못 느낄 수 있지만, 건조하고 푸석거리는 분들은 효과를 바로 체감합니다. 써마지는 피부 속에 열을 넣어 콜라겐을 재생시키는 시술인데, 콜라겐이 만들어지려면 시간이 필요해서 보통 2~3개월 뒤에 효과를 느끼게 돼요. 피부가 얇거나 푸석한 분들은 시술 직후에도 쫀쫀해졌다고 느끼시기도 합니다. 제 경우엔 원래 건성이어서 매년 가을쯤 되면 건조해지며 각질이 뜨곤 했는데, 써마지를 꾸준히 받으면서 그런 건조증이 사라졌어요. 또 피부가 얇은 편인데도 아직 잔주름 없이 잘 유지하고 있는 것도 써마지 덕이라고 생각합니다. 효과가 아예 없는 게 아니라 사람마다 체감하는 정도가 다른 것이니, 장기적 관점에서 노화 방지 보험이라고 생각하시면 됩니다.', '써마지 효과를 체감하기 어려운 이유와 장기적 피부 개선 원리를 피부과 전문의 정한미가 설명합니다.', array['써마지', '효과', '콜라겐', '피부탄력', '건성피부', '노화방지', '리프팅']::text[]),
    ('2z-zBNyzkqs', 'jeonghanmi', '써마지가 비싸서 부담되는데 가성비 좋은 대안이 있나요?', '올리지오, 세르프, 볼류머, 덴서티, 텐서마 같은 국산 고주파 장비들이 써마지와 비슷한 원리로 작동하면서 더 합리적인 가격대를 제공합니다. 기본적으로 단극성 고주파라는 점은 써마지와 똑같은데 각 장비마다 자랑하는 특성이 조금씩 달라요. 써마지를 스타벅스에 비유하면, 어느 매장을 가든 맛과 품질이 일정하고 가장 많은 연구 데이터가 쌓여 있어서 가장 믿을 수 있는 브랜드인 겁니다. 예산이 충분하고 가장 확실한 걸 원하면 써마지를 선택하시면 되고, 무리되지 않는 선에서 꾸준히 관리하고 싶다면 국산 장비들도 좋은 옵션이 됩니다. 중요한 건 고민하다 아무것도 안 하는 것보다 뭐라도 하는 게 낫다는 거예요. 젊음을 지키는 건 마라톤이지 단거리 스퍼트가 아니니까, 각자 사정에 맞게 선택해서 꾸준히 유지하시는 게 가장 중요합니다.', '써마지의 가성비 대안 고주파 장비들과 선택 기준을 피부과 전문의 정한미가 정리합니다.', array['써마지', '고주파', '올리지오', '세르프', '덴서티', '텐서마', '가성비', '리프팅']::text[]),
    ('2z-zBNyzkqs', 'jeonghanmi', '써마지가 얼굴 처진 볼살·턱선도 끌어올려 주나요?', '아니요, 써마지는 처진 걸 끌어올려주는 시술이 아니라 피부 탄력을 주는 시술입니다. 이미 많이 처진 경우에는 써마지 말고 다른 시술이 필요할 수 있어요. 써마지의 원리는 피부 속에 열을 넣어서 콜라겐을 재생시키는 건데, 피부 겉에는 화상을 입히지 않으면서 속에만 열을 전달하는 기술이 핵심이에요. 그래서 써마지의 효과는 탱탱해지고 쫀쫀해지는 탄력 개선이지, 축 처진 살을 물리적으로 올리는 건 아닙니다. 써마지가 좀 아픈 시술이긴 해서 보통 마취크림을 두껍게 바르고 시술하고, 병원에 따라 수면마취나 비수면 호흡마취를 하기도 합니다. 하루 커피값으로 젊음을 살 수 있다고 생각하면 나쁘지 않은 투자이니, 탄력 관리 목적으로 접근하시면 만족도가 높을 거예요.', '써마지의 정확한 효과 범위와 처짐 개선의 한계를 피부과 전문의 정한미가 안내합니다.', array['써마지', '리프팅', '피부탄력', '콜라겐', '처짐', '고주파', '마취']::text[]),
    ('8KUbNkEHaQo', 'leedoyoung', '리프팅 시술 종류가 너무 많은데 나한테 맞는 걸 어떻게 골라요?', '요즘은 리프팅도 맞춤형 시대라서 얼굴형, 살성, 고민 포인트에 따라 다른 장비를 선택해야 합니다. 같은 30대 여성이라도 피부가 얇은 분, 땅콩형 얼굴로 굴곡이 있는 분, 처짐이 심한 분, 잔주름이 많은 분, 살이 많은 분 등 고민이 전부 다르거든요. 써마지가 제일 좋다고 무조건 추천하면 요즘 환자분들도 이상하게 보실 정도로, 장비마다 고유의 특장점이 다 달라요. 피부 진단기로 촬영을 먼저 하고 환자 얼굴을 보면서 어떤 시술을 조합하면 좋을지 고민해서 추천드리는 게 제대로 된 상담입니다. 본인 얼굴형에 맞게 받아야지 유명하다고 막 정하시면 안 돼요. 볼살 처짐과 광대 밑 꺼짐이 있다면 볼륨 이동이 가능한 세르프가 좋고, 피부가 얇고 탄력만 원하면 써마지가 적합합니다.', '얼굴형과 고민별 맞춤 고주파 리프팅 장비 선택법을 피부과 전문의 이도영이 안내합니다.', array['리프팅', '고주파', '써마지', '세르프', '덴서티', '텐써마', '맞춤형시술', '얼굴형']::text[]),
    ('8KUbNkEHaQo', 'leedoyoung', '세르프가 써마지보다 좋은 거 아니에요?', '세르프는 써마지와 다른 고유 장점이 있지만, 써마지가 가장 오랫동안 검증된 오리지널 장비로 만족도 1위라는 점에서 단순 비교는 어렵습니다. 세르프의 가장 큰 특징은 팁이 써마지보다 훨씬 커서 더 깊게 더 많은 에너지를 전달할 수 있으면서도 안 아프다는 거예요. 마취 연고 안 바르고도 시술 가능할 정도로 편안하고, 깊은 층/중간 층/얕은 층으로 깊이 조절이 가능해서 환자 맞춤형 조합의 경우의 수가 엄청 많습니다. 특히 살집 있는 분이나 땅콩형 얼굴로 광대 밑이 꺼진 분들에게 세르프가 효과적인데, 볼륨을 이동시켜서 움푹 들어간 곳을 채워주는 느낌이 있어요. 다만 써마지는 가장 오래되고 연구 데이터가 풍부해서 보장된 장비이고, 세르프는 그 사이에 위치하는 아는 사람만 아는 꿀 장비라고 보시면 됩니다.', '세르프와 써마지의 차이점과 각각 적합한 피부 타입을 피부과 전문의 이도영이 설명합니다.', array['세르프', '써마지', '고주파', '리프팅', '땅콩형얼굴', '통증', '볼륨이동']::text[]),
    ('8KUbNkEHaQo', 'leedoyoung', '눈가 잔주름이랑 모공 고민엔 어떤 리프팅이 좋아요?', '눈가, 입가의 자글자글한 잔주름이나 모공, 피부결, 홍조처럼 얕은 층 문제에는 덴서티 하이팁이 정말 효과적입니다. 덴서티는 팁 모양이 써마지의 네모와 달리 11자 형태로, 좀 더 섬세한 작업이 가능하고 에너지 침투 깊이가 상대적으로 얕은 편이에요. 얕다는 게 꼭 단점은 아닌 게, 피부 얕은 층에 있는 문제를 해결하는 데는 오히려 더 특화되어 있기 때문입니다. 깊은 층에는 별로 관심 없고 피부가 얇으면서 잔주름과 모공을 개선하고 싶은 분들에게 추천드려요. 만약 덴서티 효과에 더해서 깊은 층까지 관리하고 싶다면 티타늄 리프팅 같은 걸 섞어서 받으시면 라인 관리와 주름 개선을 동시에 할 수 있습니다. 각 장비가 잘하는 영역이 다르니까 조합해서 받는 게 핵심이에요.', '잔주름과 모공 개선에 특화된 덴서티 하이팁의 장점을 피부과 전문의 이도영이 정리합니다.', array['덴서티', '잔주름', '모공', '눈가주름', '고주파', '리프팅', '피부결', '홍조']::text[]),
    ('8KUbNkEHaQo', 'leedoyoung', '고주파 리프팅 효과를 극대화하는 꿀팁이 있나요?', '가장 중요한 건 한 번 받을 때 최대한 많은 유효샷을 쓰는 겁니다. 컵라면에 끓는 물을 부어도 3분을 기다려야 면이 익듯이, 피부도 일정 온도까지 먼저 올려야 하고 그 온도를 유지시켜야 콜라겐이 재생됩니다. 온도를 올리는 데 쓰이는 샷은 사실상 버려지는 거라서, 써마지 300샷 중 100샷이 온도 높이는 데 쓰이면 유효샷은 200샷밖에 안 돼요. 600샷을 선택하면 유효샷이 확실히 많아져서 효과가 크게 올라갑니다. 두 번째로 이마보다는 중안면과 하안면에 샷을 집중하는 게 좋은데, 다들 가장 고민하는 부위가 그쪽이기 때문이에요. 마지막으로 초음파나 티타늄 같은 레이저 리프팅, 리쥬란이나 쥬베룩 같은 스킨부스터를 병합하면 더 좋은 결과를 볼 수 있습니다. 특히 티타늄 리프팅으로 먼저 온도를 올려놓으면 써마지의 유효샷을 더 늘릴 수 있어요.', '고주파 리프팅 효과를 높이는 유효샷 원리와 병합 시술 팁을 피부과 전문의 이도영이 안내합니다.', array['써마지', '유효샷', '고주파', '리프팅', '콜라겐', '리쥬란', '쥬베룩', '스킨부스터']::text[]),
    ('tOdt2ddTlYs', 'leedoyoung', '김성령처럼 나이 들어도 피부 좋으려면 뭘 해야 하나요?', '써마지 같은 고주파 시술을 1년에 최소 한두 번 꾸준히 받는 것이 핵심입니다. 김성령 씨를 피부과 학회에서 직접 봤는데 50대인데도 피부가 40대 느낌으로 엄청 탱탱하고 뽀얘서, 적금 들고 보험 드는 것처럼 꾸준히 고주파 시술을 받아온 결과라고 생각해요. 당장 엄청난 차이는 못 느낄 수 있지만, 5년 10년이 지나면 확실한 차이가 나타납니다. 써마지의 효과는 울쎄라처럼 라인을 잡아주는 게 아니라, 피부를 탄탄하고 쫀쫀하게 만들어주는 탄력 관리와 톤 관리에요. 매년 꾸준히 시술받은 사람과 안 받은 사람의 격차는 시간이 갈수록 벌어집니다. 동창회에서 "너는 왜 안 늙었냐"는 소리를 듣고 싶다면 지금부터라도 시작하시는 게 좋습니다.', '나이 들어도 탱탱한 피부를 유지하는 고주파 시술의 장기적 효과를 피부과 전문의 이도영이 설명합니다.', array['써마지', '동안', '피부탄력', '고주파', '리프팅', '콜라겐', '노화방지']::text[]),
    ('tOdt2ddTlYs', 'leedoyoung', '세르프가 진짜 안 아프다는 게 사실이에요?', '네, 마취 연고 안 바르고도 시술할 수 있을 정도로 세르프는 통증이 거의 없습니다. 직접 시술받아 봤는데 입 근처가 원래 되게 아픈 부위임에도 하나도 안 아팠어요. 열감은 느껴지지만 아프지 않아서 정말 깜짝 놀랐습니다. 세르프의 팁은 써마지보다 1.5배 정도 훨씬 큰데, 팁이 크면 피부 깊게 들어가고 에너지가 많이 전달되면서도 통증이 없는 게 핵심 장점이에요. 깊은 층, 중간 층, 얕은 층으로 깊이 조절이 가능하고 효과까지 좋습니다. 6주 전에 데모하며 치료해드린 분을 다시 만났는데 얼굴에서 광이 나고 모공까지 개선되어서 손을 붙잡으며 감사하다고 하시더라고요. 써마지가 아프다는 이유로 망설이셨던 분들에게 세르프는 좋은 대안이 됩니다.', '세르프의 무통증 시술 경험과 실제 효과를 피부과 전문의 이도영이 안내합니다.', array['세르프', '통증', '고주파', '리프팅', '써마지', '모공', '피부탄력']::text[]),
    ('tOdt2ddTlYs', 'leedoyoung', '포젤란 스킨부스터가 다른 것보다 뭐가 좋은 거예요?', '포젤란은 다른 스킨부스터에 비해 모공 개선과 피부결이 좋아졌다고 말씀하시는 빈도가 확실히 더 높습니다. 실제로 시술받은 분이 피부가 반짝반짝 도자기처럼 된다고 표현할 정도로, 광택과 결 개선 효과가 뚜렷해요. 6주 전에 시술해드린 남자분을 다시 만났을 때 얼굴에서 광이 나면서 모공도 개선되어 있어서 저도 깜짝 놀랐습니다. 남자분인데도 모공이 개선되고 피부에서 광이 나더라고요. 포젤란이라는 이름 자체가 도자기(porcelain)에서 따온 건데, 그만큼 매끈하고 빛나는 피부를 만들어주는 데 특화된 제품이에요. 모공이 신경 쓰이거나 피부결을 개선하고 싶은 분들이라면 한번 고려해 보시기 좋습니다.', '포젤란 스킨부스터의 모공 개선과 피부결 효과를 피부과 전문의 이도영이 정리합니다.', array['포젤란', '스킨부스터', '모공', '피부결', '광택', '도자기피부']::text[]),
    ('tOdt2ddTlYs', 'leedoyoung', '티타늄 리프팅은 써마지랑 뭐가 달라요?', '티타늄 리프팅은 울쎄라의 라인 잡아주는 효과와 써마지의 탄탄하고 쫀쫀해지는 탄력 관리, 그리고 톤 관리까지 한 번에 해줄 수 있는 장비입니다. 써마지가 고주파로 피부 속에 열을 넣어 콜라겐을 재생하는 방식이라면, 티타늄은 레이저 기반으로 라인과 탄력을 동시에 잡아주는 차이가 있어요. 고주파 시술의 효과를 높이는 데에도 티타늄을 병합하면 좋은데, 써마지 전에 티타늄으로 먼저 피부 온도를 올려놓으면 써마지의 유효샷이 더 늘어나서 효과를 극대화할 수 있습니다. 한국 피부과 전문의들이 이런 조합 시술에 굉장히 우수한 노하우를 갖고 있어요. 라인도 잡고 싶고 탄력도 원한다면 써마지 단독보다 티타늄과 병합하는 걸 추천드립니다. 보통 1년에 한두 번 정도 시술받으시면 유지 관리에 충분합니다.', '티타늄 리프팅과 써마지의 차이점 및 병합 시술의 장점을 피부과 전문의 이도영이 설명합니다.', array['티타늄리프팅', '써마지', '울쎄라', '리프팅', '라인관리', '피부탄력', '병합시술']::text[]),
    ('Ah3eRV4U784', 'jeonghanmi', '울쎄라랑 써마지 번갈아 받으면 진짜 시너지 효과가 나나요?', '네, 울쎄라와 써마지를 번갈아 시술하면 피부 각 층마다 탄력을 줄 수 있어 시너지 효과를 기대할 수 있습니다. 써마지는 진피층을 타겟으로 콜라겐을 자극해 피부 탄력을 높이는 시술이고, 울쎄라는 그보다 더 깊은 근막층까지 들어가 피부를 찰싹 달라붙게 해주는 리프팅 효과를 냅니다. 최화정 씨처럼 1년에 한 번씩 두 시술을 꾸준히 받으면 얕은 층과 깊은 층 모두를 케어할 수 있죠. 중요한 건 과도하게 시술받기보다 자연스러운 노화를 받아들이면서 적절하게 관리하는 마인드예요. 이런 접근법을 요즘은 슬로우 에이징이라고 부릅니다. 울쎄라는 시술 후 며칠 정도 부을 수 있지만, 써마지는 받고 나서도 거의 티가 나지 않아 바로 일상생활이 가능합니다. 스케줄이 없는 시기를 골라 정기적으로 받으시는 게 좋습니다.', '울쎄라와 써마지를 번갈아 시술했을 때 시너지 효과와 슬로우 에이징을 피부과 전문의 정한미가 설명합니다.', array['울쎄라', '써마지', '리프팅', '콜라겐', '슬로우에이징', '탄력', '근막층']::text[]),
    ('Ah3eRV4U784', 'jeonghanmi', '스킨보톡스(더모톡신)랑 엑소좀을 같이 받으면 어떤 효과가 있나요?', '더모톡신(스킨보톡스)은 피부결을 매끄럽게, 엑소좀은 피부 재생 효과를 줘서 함께 받으면 전반적으로 맨들맨들한 피부를 만들 수 있습니다. 더모톡신은 잔주름을 없애주고 모공도 줄여주며, 피지가 많은 분들은 피지도 줄여주는 역할을 해요. 엑소좀은 피부에 좋은 영양분을 공급해주는 재생 시술이죠. 한예슬 씨처럼 매년 초에 울쎄라, 더모톡신, 엑소좀을 한꺼번에 받고 써마지를 6개월에 한 번씩 받는 체계적 관리법이 효과적입니다. 다만 세 가지 시술을 마취크림만 바르고 받기엔 통증이 상당하기 때문에 수면마취나 비수면호흡마취를 병행하는 경우가 많아요. 촬영 일정이 잡히면 한 달 전부터 관리를 계획하는 것처럼 본인 스케줄에 맞춰 시술을 짜는 게 포인트입니다.', '더모톡신(스킨보톡스)과 엑소좀의 효과 및 병행 시술법을 피부과 전문의 정한미가 안내합니다.', array['더모톡신', '스킨보톡스', '엑소좀', '울쎄라', '피부재생', '모공', '잔주름']::text[]),
    ('Ah3eRV4U784', 'jeonghanmi', '홍조나 잡티가 고민인데 레이저 토닝이랑 IPL 중 뭘 받아야 하나요?', '잡티 위주라면 IPL, 홍조 위주라면 브이빔이 더 적합하고, 둘 다 고민이면 IPL로 두루두루 효과를 볼 수 있습니다. IPL은 여러 가지 파장의 빛이 한꺼번에 나와서 주근깨나 잡티 제거, 피부 톤 환하게 하기, 홍조 개선까지 여러 효과를 동시에 내줘요. 브이빔은 피부 속 혈관을 줄여주는 전문 시술이라 홍조에 특히 효과가 좋습니다. 강민경 씨처럼 조명이 센 무대에서 일하는 분들은 레이저 토닝으로 잡티를 꾸준히 관리하고, 홍조 관리용으로 브이빔과 IPL을 병행하시더라고요. 이런 시술들은 받고 나서 거의 티가 나지 않아 바로 화장도 가능하다는 장점이 있어요. 피부 톤을 고르게 유지하고 싶은 분들에게 부담 없이 정기적으로 받을 수 있는 시술입니다.', '홍조와 잡티 고민에 IPL과 브이빔 중 어떤 시술을 선택할지 피부과 전문의 정한미가 정리합니다.', array['IPL', '브이빔', '레이저토닝', '홍조', '잡티', '주근깨', '피부톤']::text[]),
    ('Ah3eRV4U784', 'jeonghanmi', '리프팅 시술 없이 꾸준히 받을 수 있는 피부 관리가 있을까요?', 'LDM이나 코레지 셀핏 같은 스킨케어 관리는 통증 없이 편안하게 받으면서 보습, 재생, 미세 리프팅 효과까지 기대할 수 있습니다. 이 관리들은 시술이 아니라 스킨케어여서 아픈 게 하나도 없고 마사지 받는 느낌으로 받을 수 있어요. 안소희 씨도 큰 시술보다 1~2주에 한 번씩 꾸준히 받는 걸 선호한다고 했죠. 물론 울쎄라나 써마지처럼 한 번에 확 효과가 나타나진 않습니다. 하지만 꾸준히 받으면 차근차근 피부가 좋아지고 미세하게 리프팅이 되는 효과도 있어요. 피부가 빨개지거나 붓는 게 없어서 위클리 케어로 부담 없이 받을 수 있다는 점이 가장 큰 장점이에요. 각자에게 잘 맞는 방법을 찾아서 꾸준하게 관리하는 게 핵심입니다.', '통증 없이 꾸준히 받을 수 있는 LDM, 코레지 셀핏 관리의 효과를 피부과 전문의 정한미가 안내합니다.', array['LDM', '코레지셀핏', '스킨케어', '보습', '피부재생', '리프팅', '위클리케어']::text[]),
    ('1wtAvzoqHbw', 'kwonsuhyun', '이중턱 없애려고 윤곽주사 맞았는데 효과가 없으면 어떡하죠?', '윤곽주사만으로 이중턱이 해결되지 않는 경우가 많고, 원인에 따라 다른 접근이 필요합니다. 윤곽주사는 가볍게 쁘띠 시술 정도로 시도해볼 수 있는 방법이지만, 지방이 많거나 피부가 처진 경우에는 효과가 미미할 수 있어요. 이중턱의 원인이 지방 축적이라면 브이올렛처럼 지방 세포를 직접 파괴하는 시술이 효과적이고, 살이 빠졌는데도 피부가 늘어져 있다면 울쎄라 같은 리프팅이 필요합니다. 또한 턱이 짧아서 이중턱이 도드라져 보이는 경우에는 턱 필러로 턱 라인을 만들어주면 이중턱이 덜 보이기도 해요. 중요한 건 본인의 이중턱 원인이 지방인지, 처짐인지, 골격인지를 먼저 파악하는 것입니다. 하나의 시술로 해결되지 않을 수 있으니 단계적으로 접근하시는 게 좋습니다.', '윤곽주사로 효과 없는 이중턱의 원인별 시술 선택법을 피부과 전문의 권수현이 설명합니다.', array['이중턱', '윤곽주사', '브이올렛', '울쎄라', '턱필러', '리프팅', '지방분해']::text[]),
    ('1wtAvzoqHbw', 'kwonsuhyun', '브이올렛이 일반 지방분해주사랑 뭐가 다른 거예요?', '브이올렛은 정식 허가를 받은 단일 성분(데옥시콜산)으로, 병원마다 제각각인 일반 지방분해주사와 달리 효과와 안정성이 표준화되어 있습니다. 일반 지방분해주사는 병원마다 조제 방식이 다르고 표준화가 되어 있지 않아 결과를 예측하기 어렵습니다. 반면 브이올렛의 데옥시콜산은 우리 체내에서도 지방을 분해하는 성분으로 나오는 물질이에요. 다만 맞는 순간부터 부어오르기 시작하고 약 2주 동안 붓기가 지속될 수 있습니다. 이건 지방을 파괴하면서 생기는 염증 반응으로 정상적인 과정이에요. 지방이 많았던 부분은 여러 번 맞고 나서 꽤 효과를 볼 수 있지만, 이중턱을 오래 달고 살아서 피부가 늘어진 경우에는 추가로 리프팅 시술이 필요할 수도 있습니다.', '브이올렛과 일반 지방분해주사의 차이점 및 시술 후 경과를 피부과 전문의 권수현이 안내합니다.', array['브이올렛', '지방분해주사', '데옥시콜산', '이중턱', '지방파괴', '붓기', '턱살']::text[]),
    ('1wtAvzoqHbw', 'kwonsuhyun', '턱 밑에 울룩불룩한 게 지방이 아니라 침샘일 수도 있다는데 사실인가요?', '네, 턱 밑의 불룩한 부분이 지방이 아니라 비대해진 침샘인 경우가 의외로 많고, 이건 침샘 보톡스로 쉽게 줄일 수 있습니다. 침샘은 리프팅 시술이나 지방 제거로는 절대 없어지지 않기 때문에 정확한 원인 파악이 중요해요. 본인이 침샘 비대인지 확인하는 방법은 간단합니다. 혀로 입천장 끝을 대면 턱 밑에 튀어나오는 부분이 만져지는데, 이게 크게 느껴지면 침샘이 비대된 거예요. 과식, 야식, 흡연, 음주가 침샘을 과도하게 자극해 커지게 만들 수 있습니다. 침샘 보톡스는 시술 시간이 짧고 가성비가 좋으며, 맞은 지 2~3일부터 효과가 나타나 2주면 확실히 보입니다. 보통 4~6개월 간격으로 맞으면 되고, 꾸준히 정기적으로 맞다 보면 시술 간격을 점점 늘릴 수 있어요.', '이중턱으로 오해하기 쉬운 침샘 비대의 확인법과 보톡스 치료를 피부과 전문의 권수현이 설명합니다.', array['침샘보톡스', '이중턱', '침샘비대', '보톡스', '턱밑', '턱선', '가성비시술']::text[]),
    ('1wtAvzoqHbw', 'kwonsuhyun', '침샘 보톡스 맞으면 침이 부족해지거나 부작용은 없나요?', '우리 몸 곳곳에 침샘이 여러 개 있기 때문에 턱 밑 침샘을 줄인다고 해서 침이 말라 일상생활에 영향을 주지는 않습니다. 침샘 보톡스의 효과는 개인차가 있지만 보통 4~6개월 정도 유지돼요. 꾸준히 정기적으로 맞다 보면 침샘 크기 자체가 많이 줄어서 시술 간격을 점점 늘릴 수 있습니다. 실제로 6개월 간격으로 맞고 있을 정도로 유지가 잘 되는 편이에요. 이중턱의 원인은 사람마다 다르기 때문에 각자에 맞는 시술을 선택하는 게 중요합니다. 지방이 너무 많으면 브이올렛, 피부가 처졌으면 울쎄라, 턱 밑이 울룩불룩하면 침샘 보톡스 이렇게 원인별로 접근하세요. 하나의 시술로 모든 이중턱이 해결되는 건 아니니 전문의와 상담 후 단계적으로 진행하시는 게 좋습니다.', '침샘 보톡스의 부작용 여부와 유지 기간, 이중턱 원인별 시술법을 피부과 전문의 권수현이 정리합니다.', array['침샘보톡스', '이중턱', '부작용', '보톡스유지기간', '브이올렛', '울쎄라', '턱살']::text[]),
    ('n1dSF5i9pGc', 'kimjongsik', '겨울에 피부 건조하면 건성 피부인 건가요, 건조증인 건가요?', '건성 피부와 건조증은 다릅니다. 건성 피부는 원래 쉽게 건조해지는 피부 타입이고, 건조증은 겨울 같은 날씨 때문에 피부가 건조해져서 생기는 불편한 증상을 말해요. 건조증의 대표 증상은 각질이 많이 생기고, 따갑고, 가렵기도 한 거예요. 많은 분들이 건성 피부인데 겨울에 건조증까지 겹치는 경우가 많습니다. 관리의 기본은 당연히 보습인데, 세안이나 샤워 후 물기가 마르기 전에 빨리 보습해주는 게 가장 중요해요. 화장품 바를 때 한꺼번에 듬뿍 많이 바르는 것보다 얇게 여러 번 자주 바르는 게 더 효과적입니다. 피부에 수분감이 떨어지면 탄력도 떨어져 보이기 때문에 나중에 더 나이 들어 보이게 될 수 있어요.', '건성 피부와 건조증은 원인이 다릅니다. 겨울철 각질·가려움을 줄이는 올바른 보습 타이밍과 보습제 사용법을 피부과 전문의 김종식이 설명합니다.', array['건성피부', '건조증', '겨울보습', '세안후보습', '각질', '피부탄력', '보습제']::text[]),
    ('n1dSF5i9pGc', 'kimjongsik', '겨울철 피부에 각질이 심하면 건선인 건가요?', '아닙니다. 건선이라고 착각하고 피부과에 오시는 분들 대부분은 건조증이나 건성 피부인 경우가 훨씬 많습니다. 건선은 면역체계 이상 때문에 피부가 두꺼워지고 붉어지고 각질이 생기는 만성 염증성 피부 질환으로, 건조해서 생기는 건조증과는 아예 다른 병이에요. 100명 중 한두 명 정도 생길 정도로 생각보다 흔하긴 하지만, 평생 관리가 필요한 질환입니다. 건선 치료는 연고 도포가 기본이고, 자외선 치료나 엑시머 레이저로 병변만 타겟해서 치료하기도 해요. 심한 경우에는 먹는 약이나 한두 달에 한 번 생물학적 제제 주사를 맞기도 합니다. 건선이 있는 분도 보습제는 꼭 발라주시고, 42도 이하 미온수로 가볍게 씻으며, 과도한 피부 자극과 스트레스를 피하는 게 중요합니다.', '각질이 심하다고 건선은 아닙니다. 건선과 건조증의 차이점, 엑시머 레이저·생물학적 제제 등 건선 치료법을 피부과 전문의 김종식이 안내합니다.', array['건선', '건조증', '만성피부질환', '엑시머레이저', '면역질환', '각질', '피부과치료']::text[]),
    ('n1dSF5i9pGc', 'kimjongsik', '홍조 올라올 때 얼음찜질하면 안 된다는 게 사실인가요?', '네, 얼굴이 달아올랐을 때 얼음찜질을 하면 오히려 홍조가 더 심해질 수 있어 절대 하면 안 됩니다. 피부가 너무 차갑다가 뜨겁다가를 반복하면 피부에 자극이 가중되어 안면 홍조가 악화되는 원리예요. 특히 마스크를 썼다가 벗었을 때 홍조가 더 심해지는 분들이 많은데, 이때도 얼음찜질은 독이 됩니다. 홍조를 유발하는 대표적인 행동으로는 음주, 매운 음식 섭취가 있고, 겨울에도 자외선이 눈이나 아스팔트에 반사되어 피부에 자극을 주기 때문에 자외선 차단제를 꼭 바르셔야 해요. 이런 생활습관 개선만으로도 일시적 홍조는 좋아질 수 있습니다. 생활습관을 바꿔도 개선되지 않는다면 피부과에서 정확한 진단을 받고 본인에게 맞는 치료를 하시는 게 중요합니다.', '홍조에 얼음찜질을 하면 오히려 악화됩니다. 온도 변화가 혈관을 자극하는 원리와 음주·매운 음식 등 홍조 유발 요인을 피부과 전문의 김종식이 정리합니다.', array['안면홍조', '얼음찜질', '겨울피부', '자외선차단', '혈관확장', '피부자극', '마스크']::text[]),
    ('n1dSF5i9pGc', 'kimjongsik', '안면 홍조 치료하려면 피부과에서 어떤 시술을 받아야 하나요?', '안면 홍조 치료는 크게 혈관 레이저와 피부 장벽 강화 치료 두 가지로 접근합니다. 첫 번째는 젠틀맥스, 브이빔, M22 같은 혈관 레이저로 확장된 혈관 자체를 잡아주는 치료예요. 두 번째는 피부 장벽을 튼튼하게 만드는 치료인데, 고주파 치료나 리쥬란, 쥬베룩 같은 주사제 치료, 시크릿이나 더블타이트 같은 바늘 고주파 시술, LDM이나 더미오케어 같은 피부 관리가 있습니다. 피부 장벽이 무너진 분, 혈관이 확장된 분, 둘 다 해당하는 분이 각각 있어서 치료 방향이 달라지게 돼요. 일시적 현상인지 질환인지에 따라서도 접근법이 다릅니다. 정확한 진단 없이 본인 마음대로 관리하면 별것 아니었던 문제를 키울 수 있으니, 전문의에게 먼저 진단을 받아보세요.', '안면 홍조 치료는 브이빔·젠틀맥스 혈관 레이저와 리쥬란·쥬베룩 피부 장벽 강화 두 가지로 접근합니다. 유형별 치료 전략을 피부과 전문의 김종식이 정리합니다.', array['안면홍조', '브이빔', '혈관레이저', '리쥬란', '쥬베룩', '피부장벽', '고주파']::text[]),
    ('bA7b_xLi3_U', 'parkhyojin', '기미를 한 번에 없앨 수 있다는 광고가 있던데 사실인가요?', '아닙니다. 기미를 한 번에 없앨 수 있다는 광고는 거짓말이고, 그렇게 한 번에 없애려다가 돌아올 수 없는 강을 건널 수도 있습니다. 기미라고 진단되는 순간 완전히 없앤다는 목표가 아니라 많이 연해지게 한다는 목표를 잡아야 해요. 기미는 피부과에서 당뇨나 고혈압 같은 만성질환으로 분류하는데, 호르몬이나 자외선에 의해 계속 진해지고 심해질 수 있기 때문입니다. 치료를 중단하면 몇 개월 지나 다시 생기거나 더 진해질 수 있어 유지치료가 꼭 필요해요. 반면 주근깨는 한두 번만 치료해도 충분히 좋아질 수 있습니다. 겉으로 비슷한 갈색 반점이라도 기미, 주근깨, 흑자 등 진단이 다양하기 때문에 정확한 진단 없이 치료하면 오히려 더 심해질 수 있어요.', '기미를 한 번에 없앨 수 없는 이유와 올바른 치료 목표를 피부과 전문의 박효진이 설명합니다.', array['기미', '잡티', '색소치료', '주근깨', '유지치료', '만성질환', '레이저']::text[]),
    ('bA7b_xLi3_U', 'parkhyojin', '색소 치료 결과가 사람마다 다른 이유가 뭔가요?', '같은 갈색 반점이라도 실제 진단이 기미인지, 주근깨인지, 흑자인지에 따라 치료법과 결과가 완전히 달라지기 때문입니다. 심지어 이 모든 걸 동시에 갖고 있는 환자분들도 있어요. 거기에 동양인 중에는 얼굴에 밝은색과 어두운색 피부의 경계선이 있는데, 이 선의 모양에 따라 치료가 잘 되기도, 잘 안 되기도 예측할 수 있습니다. 이런 색소선은 육안으로 보이지 않아 피부 진단기가 필요해요. 또한 민감성 피부인지, 색소침착이 잘 남는 피부인지 같은 개인 차이도 치료 결과에 영향을 미칩니다. 의사마다도 보수적으로 천천히 옅게 하는 법, 적극적으로 딱지를 만들어 빠르게 치료하는 법 등 고유의 치료법이 달라요. 빠른 치료가 최선이 아니라 정확하고 확실한 치료가 최선입니다.', '색소 치료 결과가 사람마다 다른 이유를 피부 진단과 개인 차이 관점에서 피부과 전문의 박효진이 안내합니다.', array['색소치료', '기미', '주근깨', '흑자', '피부진단기', '색소침착', '맞춤치료']::text[]),
    ('bA7b_xLi3_U', 'parkhyojin', '기미 치료받으러 피부과 갈 때 꼭 체크해야 할 게 있을까요?', '네, 피부과 선택 시 세 가지를 체크하시면 됩니다. 첫째, UV 모드가 있는 피부 진단기나 우드등으로 색소를 정확히 진단하는 곳인지 확인하세요. 둘째, 색소 치료를 할 수 있는 레이저 장비를 고루고루 갖추고 있는지 보는 것도 중요합니다. 아무리 실력이 좋아도 장비가 다양하지 않으면 맞춤 치료가 어렵거든요. 셋째, 단순히 레이저만 권유하는 곳이 아니라 피부 장벽 상태 확인, 필요시 먹는 약 처방, 집에서 홈케어 방법까지 안내해주는 곳인지 체크하세요. 색소를 전반적으로 케어해줄 수 있는 곳이 좋습니다. 그리고 가장 중요한 건 한 번에 다 없애드린다는 곳은 거르시면 돼요. 한 번에 없앨 수 있는 부위, 횟수가 필요한 부위, 완전히 못 없애는 부위를 정확히 구분해서 설명해주는 곳이 신뢰할 수 있습니다.', '기미와 잡티 치료를 위한 피부과 선택 시 필수 체크사항을 피부과 전문의 박효진이 정리합니다.', array['색소치료', '피부진단기', '기미', '레이저장비', '피부장벽', '홈케어', '피부과선택']::text[]),
    ('bA7b_xLi3_U', 'parkhyojin', '기미·잡티 색소 치료는 보통 몇 회, 얼마나 걸리나요?', '주근깨만 있는 20~30대 분들은 한 번에 바로 없앨 수 있지만, 복합 색소가 있으면 최소 1~2주 간격으로 10회 정도 치료를 먼저 받아보시길 권합니다. 총 기간으로 따지면 약 3~4개월 정도 걸리는 셈이에요. 10회 치료 후 얼마나 개선됐는지 체크해보시고 추가 치료 여부를 결정하시면 됩니다. 실제로 딱지가 생기게 해서 한 번에 없앨 수 있는 색소들만 있는 경우가 거의 없기 때문에 시간이 필요해요. 특히 기미는 아무리 잘 치료해도 재발할 수 있어서 유지치료가 필수입니다. 색소치료는 너무 서두르지 말고 정확한 진단 후 개선 목표치를 전문의와 충분히 상담해서 진행하세요. 빠른 치료가 최선이 아니라 정확하고 확실한 치료가 최선이라는 점 꼭 기억하시기 바랍니다.', '색소 치료에 필요한 기간과 횟수, 유지치료의 중요성을 피부과 전문의 박효진이 안내합니다.', array['색소치료기간', '기미', '주근깨', '레이저치료', '유지치료', '피코토닝', '색소제거']::text[]),
    ('9y9A7DHVrFc', 'parkhyojin', '30대인데 피부가 푸석푸석하고 생기가 없으면 뭘 받아야 하나요?', '피부가 푸석푸석하고 생기가 없을 때 해주면 좋은 시술이 바로 쥬베룩입니다. 쥬베룩은 피부에 콜라겐이 스스로 생성될 수 있도록 자극시키는 가루를 넣는 시술이에요. 피부가 탱탱할지 푸석푸석할지를 결정하는 건 진피의 콜라겐과 엘라스틴인데, 본인이 못 느낄 뿐이지 20대부터 이미 노화가 진행되면서 이것들이 줄어들고 있습니다. 바르는 것만으로 노화를 방지할 수 있다면 항노화, 리프팅, 레이저 같은 시술이 존재할 이유가 없겠죠. 쥬베룩은 스킨부스터의 한 종류로 회복력과 재생력에 좋고, 콜라겐 생성을 통한 볼류마이징 효과까지 있어 항노화의 끝판왕이라는 별명이 붙기도 해요. 지금부터라도 꾸준히 관리하면 빛을 볼 수 있으니 전혀 안 늦었습니다.', '30대부터 시작하면 좋은 쥬베룩의 콜라겐 촉진 원리와 효과를 피부과 전문의 박효진이 설명합니다.', array['쥬베룩', '콜라겐', '스킨부스터', '항노화', '피부재생', '볼류마이징', '30대피부']::text[]),
    ('9y9A7DHVrFc', 'parkhyojin', '쥬베룩이랑 스컬트라 뭐가 다른 거예요?', '쥬베룩, 쥬베룩 볼륨, 스컬트라 모두 콜라겐 생성을 촉진시키지만 입자 모양과 크기가 달라 쓰임새가 다릅니다. 스컬트라는 입자가 뾰족뾰족해서 콜라겐 생성 유도 자체는 더 잘 되지만 그만큼 결절 이슈가 조금 더 있었어요. 그래서 입자를 동글동글하게 만든 것이 쥬베룩과 쥬베룩 볼륨입니다. 이 둘의 차이는 입자 크기인데, 입자가 클수록 콜라겐 생성이 잘 되지만 바늘로 주입하기 어려워요. 볼류마이징 목적이면 입자가 큰 스컬트라나 쥬베룩 볼륨을 주로 쓰고, 모공 축소나 여드름 흉터처럼 피부 얕은 층에 직접 콜라겐 씨앗을 뿌려야 할 때는 작은 입자의 쥬베룩을 바늘로 직접 주사하는 게 더 효과적입니다. 이런 면에서 쥬베룩을 대체할 수 있는 스킨부스터는 아직 없어요.', '쥬베룩과 스컬트라의 입자 차이와 용도별 선택법을 피부과 전문의 박효진이 정리합니다.', array['쥬베룩', '스컬트라', '쥬베룩볼륨', '콜라겐', '결절', '볼류마이징', '스킨부스터']::text[]),
    ('9y9A7DHVrFc', 'parkhyojin', '얼굴에 쥬베룩 한 번만 맞아도 콜라겐 효과가 있나요?', '쥬베룩은 콜라겐 생성이 3주 뒤부터 나타나기 시작하는데, 1회만으로는 눈에 띄는 변화를 보기 어렵습니다. 그래서 4주 간격으로 3회 정도 먼저 받아보시면서 효과를 체감하시고, 이후에는 18~24개월 주기로 꾸준히 받으시길 권합니다. 노화는 계속 진행되기 때문에 콜라겐이 없어질 만하면 다시 자극시켜주는 반복이 필요해요. 부작용으로는 결절이 있을 수 있는데, 요즘은 표준화된 희석 프로토콜이 나와서 거의 드물다고 보시면 됩니다. 쥬베룩의 동그란 입자 안은 스펀지처럼 텅 비어 있는 구조라 결절이 생겼더라도 쉽게 해결할 수 있어요. 기본적으로 약간의 멍이나 3일 정도 불편함은 있을 수 있지만 심각한 부작용은 드뭅니다.', '쥬베룩의 권장 시술 횟수와 주기, 결절 부작용에 대해 피부과 전문의 박효진이 안내합니다.', array['쥬베룩', '콜라겐생성', '시술주기', '결절', '스킨부스터', '부작용', '항노화']::text[]),
    ('9y9A7DHVrFc', 'parkhyojin', '피부가 민감한데 쥬베룩 받아도 괜찮을까요?', '오히려 민감한 분들에게 쥬베룩이 더 좋습니다. 민감한 피부는 레이저 같은 시술을 받다가 자극이 더 심해지는 경우가 있는데, 쥬베룩은 콜라겐 씨앗을 피부 속에 심어 피부 안쪽에서부터 변화가 나타나기 때문이에요. 피부 장벽이 무너져 있는 분들에게도 굉장히 좋고, 피부과에서 예뻐지는 시술을 하고 싶은데 피부가 너무 예민한 분들이 제일 먼저 시도해볼 수 있는 시술이기도 합니다. 다만 콜라겐 생성까지 시간이 걸리기 때문에 주사 맞자마자 즉각적인 효과를 원하시는 분께는 권하지 않아요. 통증이 걱정되시면 호흡마취를 하면 주사 시술의 통증을 거의 못 느낄 정도입니다. 직접 손주사로 넣는 방식 외에 바늘 고주파로 밀어넣는 방법도 있어 통증 부담을 줄일 수 있어요.', '민감한 피부에 쥬베룩이 적합한 이유와 통증 관리 방법을 피부과 전문의 박효진이 설명합니다.', array['쥬베룩', '민감성피부', '피부장벽', '콜라겐', '스킨부스터', '호흡마취', '통증']::text[]),
    ('yzruxX_RvEk', 'parkhyojin', '레이저 토닝 10번 했는데 기미가 안 사라지는 이유가 뭔가요?', '기미는 레이저 토닝만으로는 치료가 안 되기 때문입니다. 기미는 멜라닌을 만드는 기계가 일시적으로 한 번 작동한 잡티와 달리, 색소를 계속 만들어내는 상태예요. 더 중요한 건 피부 장벽이 무너지면 외부 자극이 쉽게 들어와 이 기계들이 더 민감하게 반응한다는 점입니다. 그래서 단순히 색소를 깨부수는 토닝만 해서는 효과가 제한적이에요. 피부 장벽을 재생시켜주는 관리와 과민해진 색소 기계를 진정시키는 치료를 복합적으로 해야 합니다. LDM 같은 피부 재생 관리, 콜라겐 부스터 주사, 고주파 치료 같은 것들이 함께 필요해요. 비싼 치료를 권하는 게 호구 잡는 게 아니라, 본인 피부 상태에 복합 치료가 필요한 거라고 이해하시는 게 맞습니다.', '레이저 토닝만으로 기미가 안 빠지는 원인과 복합 치료의 필요성을 피부과 전문의 박효진이 설명합니다.', array['기미', '레이저토닝', '피부장벽', '색소치료', 'LDM', '콜라겐', '복합치료']::text[]),
    ('yzruxX_RvEk', 'parkhyojin', '기미랑 애브넘 어떻게 구분하나요? 치료법이 완전 다르다던데', '색깔로 구분합니다. 기미는 갈색이고 넓게 퍼져 있는 반면, 애브넘은 회색빛이나 푸른빛을 띠며 광대 부위에 동글동글하게 모여 있어요. 애브넘의 정식 명칭은 수천성 양측성 오타모반인데, 동양인 여성에게 특히 많이 생깁니다. 기미라고 생각하고 치료하면 아무리 해도 사라지지 않는 이유가 바로 이 때문이에요. 애브넘은 색소 덩이가 깊은 곳에 있어서 완전히 깨부셔주는 강력한 에너지가 필요하거든요. 그래서 피코 레이저나 피코 토닝으로 따로 치료하며, 최소 20~30회는 시술해야 합니다. 쉽게 비유하면 기미는 물고기가 연못에 넓게 퍼진 것, 애브넘은 깊은 곳에 동글동글 모여 있는 것이라고 생각하시면 됩니다.', '기미와 애브넘의 구분법과 각각의 치료 방식 차이를 피부과 전문의 박효진이 정리합니다.', array['애브넘', '기미', '피코레이저', '색소', '오타모반', '피코토닝', '동양인']::text[]),
    ('yzruxX_RvEk', 'parkhyojin', '주근깨랑 흑자는 뭐가 다른 건가요? 같은 거 아니에요?', '주근깨와 흑자는 모양도, 치료 난이도도 완전히 다릅니다. 주근깨는 주로 어릴 때부터 햇빛 노출 부위에 생기는 작은 갈색 반점이고, 레이저 1~2회만으로 제거되는 난이도 별 1개짜리예요. 반면 흑자는 크기가 더 크고 경계가 뚜렷하며, 특히 40대 분들이 골프 치고 나서 생겼다며 오시는 경우가 많습니다. 흑자에는 햇빛에 오래 노출돼 생기는 일광흑자와 유전적으로 양측 대칭으로 생기는 흑자증 두 가지가 있어요. 치료는 먼저 딱지를 만들어 제거하는 방식으로 시도하지만, 이후 염증 후 색소침착이 생기는 경우가 꽤 있어서 그걸 다시 빼주는 작업까지 필요합니다. 그래서 치료 난이도가 별 3개로, 주근깨보다 시간과 노력이 더 드는 색소입니다.', '주근깨와 흑자의 차이점 및 각각의 치료 난이도를 피부과 전문의 박효진이 안내합니다.', array['주근깨', '흑자', '일광흑자', '색소침착', '레이저', '잡티', '색소치료']::text[]),
    ('yzruxX_RvEk', 'parkhyojin', '같은 병원인데 왜 나한테만 비싼 치료를 권하는 건가요?', '비싼 치료를 권하는 건 호구를 잡으려는 게 아니라, 피부 상태에 따라 필요한 치료 범위가 다르기 때문입니다. 단순히 색소를 없애는 치료만 필요한 사람이 있고, 피부 장벽을 튼튼히 하거나 콜라겐을 채워주는 복합 치료까지 필요한 사람이 있어요. 추가 치료가 들어가면 당연히 가격이 올라갈 수밖에 없습니다. 색소치료는 등산에 비유할 수 있는데, 정상에 가는 방법은 여러 가지지만 체력과 상황에 맞는 등산로를 골라야 안전한 것처럼 나에게 맞는 치료법을 찾는 게 중요해요. 피부는 본인이 평생 가지고 온 역사이기 때문에 한 번에 생긴 게 아니듯 한 번에 없앨 수도 없습니다. 색소치료는 100m 달리기가 아니라 마라톤이니, 내 페이스를 유지하며 꾸준히 접근하시는 게 가장 좋습니다.', '색소치료 가격 차이의 진짜 이유와 올바른 치료 마인드를 피부과 전문의 박효진이 설명합니다.', array['색소치료', '피부장벽', '콜라겐', '기미치료', '레이저토닝', '유지치료']::text[]),
    ('bZqrA80ESnE', 'kimsoohyung', '다이소 레티놀 세럼 진짜 써도 괜찮은 건가요?', '입문용으로 충분히 괜찮은 제품입니다. 토니모리와 다이소가 콜라보한 본셉 레티놀 500 IU 세럼인데, 농도가 0.05%라 처음 레티놀을 시작하는 분들에게 적절해요. 레티놀 외에도 세라마이드, 히알루론산, 병풀추출물 같은 진정과 보습 성분이 함께 들어 있어서 자극을 최소화하면서 피부 재생을 기대할 수 있습니다. 다만 주의할 점이 있는데, 얼굴에 바르기 전 팔 안쪽이나 귀 뒤에 소량 테스트를 먼저 해보세요. 낮에 바르면 자외선에 의해 레티놀이 분해되기 때문에 반드시 자기 전에 완두콩 하나만큼만 소량 사용하셔야 합니다. 처음에는 일주일에 두세 번만 쓰다가 피부가 적응되면 매일로 늘리시고, 레티놀 사용 중에는 낮에 선크림을 꼭 챙겨 바르셔야 해요.', '다이소 레티놀 세럼은 0.05% 농도로 입문용에 적합합니다. 세라마이드·히알루론산 함유 성분 분석과 올바른 사용법을 피부과 전문의 김수형이 안내합니다.', array['레티놀', '다이소', '세럼', '세라마이드', '히알루론산', '병풀추출물', '피부재생']::text[]),
    ('bZqrA80ESnE', 'kimsoohyung', '갑자기 트러블 올라올 때 바르는 스팟 제품 추천해주세요', '어성초 칼라민 진정콕 스팟이 가성비 좋은 선택입니다. 3,000원짜리인데 주성분인 칼라민 9%가 가려움을 진정시키고 염증을 줄여주며, 어성초가 피부를 가라앉히는 역할을 해요. 피곤하거나 생리 전에 이마나 입가에 트러블 1~2개씩 올라올 때 딱 좋습니다. 사용법은 흔들지 말고, 자기 전 면봉으로 1층 칼라민 부분만 톡 찍어 바른 뒤 아침에 세안하면 됩니다. 논코메도제닉 테스트와 피부 자극 테스트를 거쳐서 여드름 피부도 안전하게 쓸 수 있어요. 다만 각질 제거 성분인 BHA가 들어 있어 약간 화한 느낌이 있을 수 있고, 천연 오일이 포함돼 있어서 오일 알러지가 있는 분들은 주의가 필요합니다.', '갑자기 올라온 트러블엔 칼라민 9% 스팟 제품이 효과적입니다. 어성초 칼라민 진정콕 사용법과 주의사항을 피부과 전문의 김수형이 안내합니다.', array['어성초', '칼라민', '트러블', '스팟', '여드름', 'BHA', '진정']::text[]),
    ('bZqrA80ESnE', 'kimsoohyung', '겨울에 손발이 갈라지는데 보습제 어떻게 발라야 효과 있나요?', '핵심은 물에 닿을 때마다 바르는 것입니다. 손은 물에 닿았다가 마를 때 건조해지는데, 설거지를 10분 한 번 하는 것보다 1분씩 10번 하는 게 훨씬 안 좋아요. 물에 닿는 횟수가 많을수록 피부가 상하기 때문입니다. 니베아 크림처럼 글리세린이 들어 있어 수분 막을 잘 씌워주는 제품을 팔다리에 아낌없이 바르시는 게 좋고, 핸드크림은 아트릭스처럼 실리콘 성분이 있어 끈적임이 적은 제품이 편해요. 발꿈치 각질이 심한 분은 우레아 10% 들어간 풋크림을 추천드리는데, 우레아가 각질을 분해하고 피부 단백질과 결합해 수분을 잡아줍니다. 히터를 틀면 손발에 가까운 팔다리부터 건조해지니, 이유 없이 팔다리가 가렵다면 보습 상태를 꼭 확인해보세요.', '손은 물에 닿을 때마다 보습해야 갈라짐을 막을 수 있습니다. 니베아·아트릭스·우레아 풋크림 등 부위별 보습제 선택법을 피부과 전문의 김수형이 정리합니다.', array['겨울보습', '핸드크림', '우레아', '니베아', '건조', '주부습진', '풋크림', '각질']::text[]),
    ('bZqrA80ESnE', 'kimsoohyung', '건성인데 씻고 나면 너무 당기는데 클렌징젤로 바꿔도 되나요?', '네, 건성 피부라면 클렌징젤이 클렌징 폼보다 훨씬 순합니다. 클렌징젤은 수분감이 많아 씻을 때 자극이 덜하고 당김도 적어요. 다이소에도 클렌징젤이 있는데, 성분을 보면 다이소듐코코일글루타메이트 같은 약한 세정제가 들어 있어서 씻고 나서 덜 건조합니다. 살리실릭애씨드도 약간 포함돼 각질 제거를 도와주기 때문에 건조하면서 여드름이 나는 피부에도 괜찮아요. 다만 살리실릭애씨드와 향료 성분 때문에 피부가 매우 예민한 분은 주의가 필요합니다. 건조함이 심하신 분들은 이렇게 저렴하지만 성분 괜찮은 제품을 구매해서 듬뿍 바르시는 것도 좋은 방법이에요. 겨울엔 히터로 실내가 더 건조해지니 세정력이 너무 강하지 않은 제품을 선택하시는 게 핵심입니다.', '건성 피부는 클렌징 폼보다 클렌징젤이 순하고 당김이 적습니다. 다이소 클렌징젤 성분 분석과 겨울철 세안 제품 선택법을 피부과 전문의 김수형이 안내합니다.', array['클렌징젤', '건성', '세안', '다이소', '살리실릭애씨드', '세정제', '보습']::text[]),
    ('5u9kLL_PZ7M', 'kimjongsik', '스컬트라랑 레디어스 뭐가 다른 거예요? 콜라겐 부스터 다 비슷한 거 아닌가요?', '레디어스는 피부를 구성하는 다섯 가지 성분을 모두 만들어낼 수 있다는 점에서 특별합니다. 다른 콜라겐 부스터들이 피부 구성 성분의 일부만 생성하는 반면, 레디어스는 집의 기둥 역할인 1형 콜라겐, 벽체 역할인 3형 콜라겐, 쿠션제처럼 탄력을 주는 엘라스틴, 단열재처럼 수분을 잡아주는 프로테오글리칸, 배관 시스템인 신생혈관까지 다섯 가지를 동시에 만들어줍니다. 기존 시술들이 특정 부위에 볼륨을 채워주는 데 포커스가 있었다면, 레디어스는 전반적으로 피부 자체가 좋아지는 느낌을 주는 시술이에요. 우리 몸에 원래 있는 칼슘 하이드록시아파타이트 성분을 사용해서 친화력이 높고 부작용이 적습니다. FDA에서 승인받은 지 벌써 20년이 지났고, 전 세계 1,500만 케이스 이상 시술된 검증된 제품이에요.', '레디어스가 다른 콜라겐 부스터와 다른 점을 피부과 전문의 김종식이 설명합니다.', array['레디어스', '스컬트라', '콜라겐', '엘라스틴', '칼슘하이드록시아파타이트', '리프팅', '콜라겐부스터']::text[]),
    ('5u9kLL_PZ7M', 'kimjongsik', '목주름이랑 손등 주름에도 레디어스가 효과 있나요?', '네, 목주름과 손등 주름에 특히 효과가 좋습니다. 목이나 손등은 피부가 매우 얇아서 기존 필러나 보톡스로 시술하면 부자연스러워 보이는 경우가 있었거든요. 레디어스는 특정 부위에 볼륨을 세우는 게 아니라 전반적으로 피부 자체를 두껍게 만들어주는 시술이라 얇은 피부에 딱 맞습니다. 시술 직후부터 볼륨감이 생기고, 시간이 지나면서 콜라겐이 차오르며 피부가 탄탄해지는 효과를 볼 수 있어요. 한 달 간격으로 두 번 정도 시술하면 6개월에서 1년까지 지속적으로 좋아집니다. 효과는 보통 6개월에서 1년 정도 가고, 사람에 따라 1~2년까지 지속되기도 해요. 시술 권장 주기는 1년에 한 번 정도이지만 상태에 따라 2~3년 뒤에 오셔도 됩니다.', '목주름과 손등 주름에 레디어스가 효과적인 이유를 피부과 전문의 김종식이 안내합니다.', array['목주름', '손등주름', '레디어스', '콜라겐부스터', '필러', '피부두께', '리프팅']::text[]),
    ('5u9kLL_PZ7M', 'kimjongsik', '피부가 종잇장처럼 얇은데 레디어스 받아도 되나요?', '오히려 그런 피부에 가장 효과가 좋은 시술입니다. 기존 볼륨 시술인 필러나 스컬트라, 쥬베룩 볼륨은 앞볼, 옆볼, 관자놀이처럼 특정 꺼진 부위를 채우는 데 초점이 맞춰져 있어요. 반면 레디어스는 피부 자체를 살짝 두껍게 만들어주는 시술이라, 종잇장처럼 얇아서 쉽게 푸석해지고 잔주름이 많이 생기는 피부에 딱입니다. 특히 팔자주름과 아랫볼 입가 주변처럼 피부가 쪼글쪼글해지는 부위에 전반적으로 볼륨을 채워주는 데 효과가 탁월해요. 써마지나 울쎄라 같은 리프팅을 받아도 탄력이 완전히 회복되지 않는 분들에게도 레디어스로 탄력을 확 채워주면 아주 좋습니다. 마치 메마른 땅에 영양분을 공급하듯이 피부 구성 성분을 고르게 채워 근본적으로 건강하게 만들어주는 시술이에요.', '피부가 얇고 잔주름 많은 분에게 레디어스가 적합한 이유를 피부과 전문의 김종식이 정리합니다.', array['레디어스', '얇은피부', '잔주름', '팔자주름', '리프팅', '써마지', '울쎄라', '탄력']::text[]),
    ('5u9kLL_PZ7M', 'kimjongsik', '레디어스 맞고 나서 주의사항이 뭔가요? 부작용은 없어요?', '일반적인 시술 주의사항과 크게 다르지 않습니다. 시술 후 과한 세안, 격한 운동, 사우나처럼 붓기가 올라올 수 있는 행동은 줄이시면 좋아요. 주사 바늘로 살짝 구멍을 내는 과정에서 멍이 생기거나, 캐뉼라로 전반적으로 시술하면서 약간 붓기가 있을 수 있지만 보통 며칠 내에 가라앉습니다. 아스피린 같은 혈전제를 드시는 분은 멍이 오래 갈 수 있으니 시술 일주일 전부터 끊을 수 있으면 끊으시고, 시술 전후 음주도 피해주세요. 레디어스는 전반적으로 영양분을 공급해 피부가 자라나게 만드는 시술이라, 필러처럼 어디를 절대 누르면 안 된다는 주의사항은 없습니다. 안전하게 시술하기 위해 기본적으로 희석을 많이 해서 사용하며, 시술 후 자외선 차단과 보습 관리를 잘 해주시면 됩니다.', '레디어스 시술 후 주의사항과 부작용 가능성을 피부과 전문의 김종식이 안내합니다.', array['레디어스', '부작용', '시술후관리', '멍', '붓기', '콜라겐부스터', '결절']::text[]),
    ('wRTdq73ZEEY', 'gohyerim', '대상포진이랑 입술 물집은 같은 병 아닌가요?', '완전히 다른 질환입니다. 대상포진은 수두 바이러스가 원인이고, 입술에 자주 재발하는 단순포진은 헤르페스 심플렉스 바이러스가 원인이에요. 대상포진은 어린 시절 걸렸던 수두바이러스가 신경절에 숨어 있다가 면역력이 떨어지면 다시 나타나는 건데, 신경을 따라 발생하기 때문에 몸 한쪽으로 띠 모양의 물집이 생깁니다. 가장 큰 차이는 통증의 정도예요. 대상포진은 옷깃만 스쳐도 아프고 칼로 찌르는 것 같다고 표현할 만큼 극심한 반면, 단순포진은 따끔거리고 간지러운 정도입니다. 또 대상포진은 평생 보통 한 번만 걸리지만, 입술포진은 피곤할 때마다 훨씬 자주 재발하죠. 대상포진은 예방접종이 있어 예방이 가능하지만, 단순포진은 예방접종이 없어서 컨디션 관리만이 방법입니다.', '대상포진은 수두 바이러스, 입술포진은 헤르페스 바이러스가 원인으로 전혀 다른 질환입니다. 통증 정도와 재발 패턴의 차이를 피부과 전문의 고혜림이 설명합니다.', array['대상포진', '단순포진', '수두바이러스', '헤르페스', '물집', '면역력', '신경통']::text[]),
    ('wRTdq73ZEEY', 'gohyerim', '대상포진 치료 늦으면 진짜 평생 아플 수 있나요?', '네, 치료 시기를 놓치면 수개월에서 수년 이상 극심한 통증이 지속되는 대상포진 후 신경통이 생길 수 있습니다. 이게 정말 고통스러운 합병증인데, 고령이거나 초기 통증과 수포가 심한 경우 발생 위험이 높아요. 피부 병변이 생긴 후 72시간 이내에 항바이러스제를 복용해야 통증 발생과 신경통을 줄일 수 있습니다. 특히 바이러스가 얼굴 신경을 공격하면 귀 주변에 물집이 생기고 얼굴 근육이 마비되는 람세이헌트 증후군까지 올 수 있어요. 얼굴 마비 후 3일 안에 치료하면 거의 완치되지만, 7일이 지나면 겨우 22%만 완치됐다는 연구가 있습니다. 심지어 치료를 제대로 안 하면 치매 위험이 1.3배 높아지고, 반대로 항바이러스제로 잘 치료한 분들은 치매 위험이 25% 낮아졌다는 연구도 있습니다.', '대상포진은 72시간 내 항바이러스제를 복용해야 신경통을 예방할 수 있습니다. 람세이헌트 증후군 등 치료 지연 시 합병증을 피부과 전문의 고혜림이 정리합니다.', array['대상포진', '신경통', '합병증', '항바이러스제', '람세이헌트', '치매', '72시간']::text[]),
    ('wRTdq73ZEEY', 'gohyerim', '대상포진 백신 한 번만 맞으면 되는 건가요? 효과가 얼마나 가요?', '2회 접종하는 사백신이 90% 이상 예방 효과로 훨씬 좋습니다. 예전에 나온 1회 접종 생백신은 편하긴 하지만 맞아도 10명 중 4명은 대상포진에 걸렸고, 7년 지나면 예방 효과가 30%까지 떨어졌어요. 반면 2~6개월 간격으로 2회 접종하는 사백신은 접종 10년 후에도 80% 이상 예방 효과가 유지됩니다. 두 번 맞아야 하고 가격이 다소 비싸다는 단점은 있지만, 50세 이상이라면 꼭 고려해보시는 게 좋아요. 대상포진 백신이 예방뿐 아니라 치매 예방에도 효과가 있다는 논문도 있고요. 혹시 백신을 맞고도 대상포진에 걸리더라도 가볍게 지나갈 수 있으니 안 맞을 이유가 없습니다.', '대상포진 백신은 2회 접종 사백신이 90% 이상 예방 효과로 가장 좋습니다. 생백신과 사백신의 효과·지속 기간 차이를 피부과 전문의 고혜림이 안내합니다.', array['대상포진', '백신', '예방접종', '사백신', '생백신', '50대', '치매예방']::text[]),
    ('wRTdq73ZEEY', 'gohyerim', '젊은데 대상포진 걸릴 수도 있나요? 나이 든 사람만 걸리는 거 아니에요?', '아닙니다. 스트레스와 과로로 인해 20~30대도 충분히 걸릴 수 있어요. 블랙핑크 로제도 20대에 스트레스로 대상포진이 왔다고 할 만큼, 면역력이 떨어지면 나이와 상관없이 발생합니다. 대상포진은 3명 중 1명이 살면서 한 번은 겪을 정도로 흔한 질환이에요. 수포가 생기기 전 통증만 있을 때는 심장질환이나 소화기 질환으로 오해해서 내과에서 피검사, 심전도, 위내시경까지 받고 오시는 분도 꽤 있습니다. 몸 한쪽에 띠 모양으로 극심한 통증이 생기거나 물집이 보이면 72시간 안에 반드시 병원에 가셔야 해요. 평소에 충분한 영양 섭취, 규칙적인 수면, 스트레스 관리를 해서 면역력을 유지하는 게 가장 중요한 예방법입니다.', '20~30대도 스트레스와 과로로 대상포진에 걸릴 수 있습니다. 3명 중 1명이 겪는 대상포진의 초기 증상 구별법과 72시간 골든타임을 피부과 전문의 고혜림이 안내합니다.', array['대상포진', '젊은층', '면역력', '스트레스', '수포', '통증', '예방']::text[]),
    ('9xAhofPhJ7E', 'jeonghanmi', '겨울철 건조할 때 아침에 물 세안만 해도 정말 괜찮나요?', '아니요, 아침에도 클렌저를 써주는 게 좋습니다. 잠자는 동안 베개나 이불에 묻어있던 먼지와 노폐물이 피부에 닿고, 자는 동안 피지나 땀 같은 기름 성분이 배출되거든요. 이런 성분들은 물만으로는 씻겨 나가지 않습니다. 다만 너무 세정력이 강한 클렌저를 반복적으로 쓰면 피부 장벽에 손상을 줄 수 있기 때문에 아침에는 순한 약산성 클렌저 정도면 충분해요. 거품기가 달린 제품을 쓰면 아침에 바쁠 때 거품 안 내고 바로 쓸 수 있어서 편합니다. 세정력이 적당하면서 사용감이 촉촉한 제품을 골라야 아침 세안 후 당기지 않아요. 겨울엔 피부가 더 건조해지니까 세정력보다 순한 사용감을 우선으로 선택하시는 게 맞습니다.', '아침에도 클렌저를 써야 밤사이 쌓인 피지와 노폐물이 제거됩니다. 겨울철 순한 약산성 클렌저 선택법과 아침 세안 요령을 피부과 전문의 정한미가 설명합니다.', array['물세안', '클렌저', '약산성', '아침세안', '피부장벽', '건성', '세정력']::text[]),
    ('9xAhofPhJ7E', 'jeonghanmi', '선크림 바르면 너무 답답한데 가벼운 자외선 차단제 있나요?', '선 앰플이나 선 에센스 제형을 써보시면 크림의 답답함 없이 자외선 차단이 가능합니다. 크림 위에 또 크림 타입 선크림을 바르면 피부가 무겁고 답답해질 수 있는데, 묽은 제형의 자외선 차단제가 요즘 많이 나오고 있어요. 촉촉하면서도 가볍기 때문에 건성 피부가 메이크업 전에 바르기에도 부담이 없습니다. 다만 이런 제품들은 대부분 화학적 차단제(유기자차)만 들어 있어서 유기자차에 예민한 피부는 주의가 필요할 수 있어요. 병풀추출물, 판테놀, 히알루론산 같은 보습 진정 성분도 포함되어 있는 제품이 많아서 너무 예민한 피부가 아니라면 괜찮습니다. 입술도 자외선 차단이 필요한데, SPF 50 이상 들어간 립밤을 아침에 바르면 입술 색소침착 예방에 도움이 돼요.', '선 앰플·선 에센스 제형은 크림보다 가볍고 답답하지 않습니다. 건성 피부를 위한 자외선 차단제 선택법과 SPF 립밤 활용법을 피부과 전문의 정한미가 안내합니다.', array['선크림', '자외선차단제', '선앰플', '건성', '유기자차', '립밤', 'SPF']::text[]),
    ('9xAhofPhJ7E', 'jeonghanmi', '클렌저 하나만 고집하면 안 되나요? 여러 개 쓰는 게 진짜 좋아요?', '피부 상태에 따라 클렌저를 바꿔주는 게 피부를 훨씬 좋게 만들 수 있습니다. 오케스트라 지휘자가 된 느낌으로 그때그때 다른 클렌저를 쓰면 피부 상태가 확 좋아져요. 예를 들어 평소에는 순한 약산성 클렌저를 쓰되, 피지가 많아 기름 낀 느낌이 들 때는 세정력이 강한 제품으로, 피부 컨디션이 떨어지고 각질이 올라올 때는 클렌징 밀크로 바꿔주는 식입니다. 여드름이 나니까 무조건 강한 클렌저, 건조하니까 무조건 순한 클렌저 이렇게 한 가지만 고집하지 마세요. 클렌징 밀크는 예민하고 건조한 피부에 좋아서 씻고 나서도 촉촉하고, 세정력 강한 제품은 pH가 약산성이어도 계면활성제가 강해서 깔끔하게 씻깁니다. 클렌저만 잘 바꿔줘도 피부 상태가 정말 많이 달라질 수 있어요.', '클렌저 한 가지만 고집할 필요가 없습니다. 피지 많을 때·건조할 때·각질 올라올 때 상태별로 클렌저를 바꾸는 전략을 피부과 전문의 정한미가 정리합니다.', array['클렌저', '클렌징밀크', '약산성', '세정력', '이중세안', '피부장벽', '건성']::text[]),
    ('9xAhofPhJ7E', 'jeonghanmi', '피부과 원장님은 레티날을 어떻게 바르나요? 매일 발라도 되나요?', '매일 바르면 각질이 너무 올라오고 붉어질 수 있어서 2~3일에 한 번 바르고 있습니다. 레티날은 레티놀의 활성 성분으로 피부 노화를 막고 이미 진행된 노화를 되돌려주는 효과가 있어요. 부위별로 농도를 다르게 쓰는 게 포인트인데, 눈가나 입가처럼 예민한 곳은 0.05%의 약한 제품을, 얼굴 전체와 목에는 0.15% 제품을 사용합니다. 눈가 입가에 강한 농도를 쓰면 각질이 지저분하게 올라오고 피부가 뒤집어질 수 있거든요. 레티날을 바르고 피부가 뒤집어지면서 각질이 올라왔을 때는 바이오셀룰로스 마스크팩으로 진정시키는 것도 좋은 방법이에요. 입술에도 레티날이 들어간 립밤을 자기 전에 발라주면 입술 노화 관리에 도움이 됩니다.', '레티날은 매일 바르면 각질이 올라올 수 있어 2~3일에 한 번이 적당합니다. 눈가·얼굴 부위별 농도 조절법과 진정 팁을 피부과 전문의 정한미가 안내합니다.', array['레티날', '레티놀', '노화방지', '주름', '각질', '눈가', '농도']::text[]),
    ('cT3mvmpLiVY', 'jeonghanmi', '비싼 크림 발라도 건조한데 장벽크림에 꼭 들어있어야 할 성분이 뭔가요?', '세라마이드, 콜레스테롤, 지방산 세 가지가 반드시 함께 들어있어야 합니다. 이 세 성분의 앞글자를 따서 ''세콜지''라고 부르는데, 피부장벽이 무너졌을 때 이 셋이 조화를 이뤄야 제대로 회복 효과를 볼 수 있어요. 1970년대 피터 엘리아스 교수가 아토피 환자 연구 중 각질층에서 이 성분들로 채워진 정교한 보호막 구조를 발견했거든요. 세라마이드만 단독으로 넣으면 오히려 회복이 느려지고, 세 가지가 특정 비율로 있을 때 효과가 극대화됩니다. 핵심은 셋 중 하나가 나머지보다 3배 많은 황금비율인데, 예를 들어 3:1:1이나 1:3:1처럼 구성되면 피부 회복 속도가 빨라져요. 그래서 단순히 세라마이드가 들어있다는 문구만 보고 구매하지 마시고, 콜레스테롤과 지방산까지 포함됐는지 꼭 확인하세요. 피부장벽이 망가진 상태에서는 비싼 제품이어도 이 세 성분 없이는 효과를 기대하기 어렵습니다.', '피부장벽 회복에 필수인 세라마이드·콜레스테롤·지방산 황금비율을 피부과 전문의 정한미가 설명합니다.', array['피부장벽', '세라마이드', '콜레스테롤', '지방산', '장벽크림', '건성', '보습']::text[]),
    ('cT3mvmpLiVY', 'jeonghanmi', '지성인데 피부장벽도 안 좋으면 어떤 크림을 골라야 하나요?', '지방산 비율이 높은 장벽크림을 선택하면 피지 조절과 장벽 개선을 동시에 할 수 있습니다. 닥터디퍼런트 113크림처럼 지방산 중 리놀렌산을 강화한 제품이 좋은데, 리놀렌산이 피부에 부족하면 모공 입구가 막혀서 블랙헤드 같은 피지가 잘 끼거든요. 여기에 나이아신아마이드까지 들어있으면 피지 분비를 조절하면서 장벽도 회복시켜 줍니다. 반면 민감성 피부는 세라마이드가 3배 많은 311 타입이 적합하고, 나이 들면서 건조해지는 피부는 콜레스테롤이 3배 많은 131 타입이 효과적이에요. 피부 노화가 진행될수록 콜레스테롤 합성이 현저히 감소하기 때문에 외부에서 보충해 주는 게 중요합니다. 이처럼 같은 세콜지 크림이라도 본인 피부 타입에 따라 비율이 다른 제품을 고르는 게 핵심이에요. pH까지 약산성으로 맞춘 제품이면 더 좋습니다.', '지성 피부의 장벽 회복에 적합한 크림 선택법을 피부과 전문의 정한미가 안내합니다.', array['지성피부', '피부장벽', '리놀렌산', '나이아신아마이드', '모공', '블랙헤드', '피지조절']::text[]),
    ('cT3mvmpLiVY', 'jeonghanmi', '가성비 좋은 장벽크림 찾는데 1만 원대도 효과 있나요?', '네, 가격이 착해도 세콜지 성분이 제대로 들어있으면 충분히 효과를 볼 수 있습니다. 일리윤 세라마이드 아토 집중 크림은 150ML에 1만 원대인데, 세라마이드와 세라마이드 전구체, 콜레스테롤, 다양한 종류의 지방산이 잘 포함돼 있어요. 세라마이드를 캡슐 형태로 전달하는 기술이 적용되어 바르고 가볍게 두드려 주면 금방 흡수되고 끈적거림이 적습니다. 얼굴뿐 아니라 목, 손등, 몸 어디든 장벽이 깨져 있을 때 아끼지 않고 듬뿍 바를 수 있는 게 큰 장점이에요. 비슷한 가격대로 아토팜 MLE 크림도 있는데, 실제 피부장벽 지질과 유사한 구조로 만들어져 흡수력이 좋고 히알루론산·판테놀·시어버터까지 포함돼 있습니다. 온 가족이 건조한 겨울에 부담 없이 쓸 수 있는 제품들이니 집에 있는 보습제 성분표부터 한번 확인해 보세요.', '1만 원대 가성비 장벽크림의 성분과 효과를 피부과 전문의 정한미가 정리합니다.', array['장벽크림', '가성비', '일리윤', '아토팜', '세라마이드', '겨울보습', '보습제']::text[]),
    ('cT3mvmpLiVY', 'jeonghanmi', '나이 들면서 피부가 급격히 건조해지는데 안티에이징 크림으로 뭐가 좋나요?', '콜레스테롤 비율이 높은 장벽크림이 노화 피부 건조함 해결에 가장 효과적입니다. 나이가 들수록 피부장벽의 기름 성분이 줄어드는데, 그중에서도 콜레스테롤 합성이 현저히 감소하거든요. 스킨수티컬즈 트리플리피드 2:4:2 크림은 세라마이드 2%, 콜레스테롤 4%, 지방산 2%로 콜레스테롤 비율을 의도적으로 높게 설계한 제품이에요. 노화된 피부에서 콜레스테롤이 많을 때 장벽이 잘 개선된다는 연구 결과를 반영한 거죠. 밤에 스킨케어 마지막 단계로 듬뿍 발라주면 다음 날 아침 피부가 한결 건강해진 느낌을 받을 수 있습니다. 다만 이 제품이 부담스러우면 닥터디퍼런트 131크림이 같은 원리로 콜레스테롤을 3배 넣어놓은 가성비 좋은 대안이 될 수 있어요. 어떤 제품이든 최소 2주는 꾸준히 발라야 차이를 느끼실 수 있습니다.', '노화로 건조해진 피부에 콜레스테롤 강화 크림이 효과적인 이유를 피부과 전문의 정한미가 설명합니다.', array['안티에이징', '콜레스테롤', '피부노화', '장벽크림', '스킨수티컬즈', '건조피부', '보습']::text[]),
    ('PDU8BZCLFSs', 'jeonghanmi', '속건조 심한데 리쥬란 맞으면 진짜 효과 있나요?', '네, 속건조가 심해서 비싼 크림을 발라도 흡수가 안 되는 분들에게 리쥬란은 매우 효과적인 시술입니다. 리쥬란 성분은 폴리뉴클레오타이드(연어 DNA 추출 성분)인데, 피부 재생을 촉진하고 콜라겐 재생, 염증 감소, 히알루론산을 통한 수분 공급까지 해줘요. 분자 크기가 커서 바르는 것으로는 피부 속에 흡수가 안 되기 때문에 반드시 주사로 맞아야 합니다. 속건조 외에도 피부가 푸석푸석하고 생기 없을 때, 눈가·입가 잔주름이 신경 쓰일 때, 소개팅이나 강의처럼 중요한 일 앞두고 피부 광을 내고 싶을 때 효과가 좋아요. 다만 시술 후 주사 자국이나 붓기가 보통 일주일 정도 남기 때문에 중요한 일정 최소 일주일 전에는 맞아야 합니다. 한 달에 1번씩 3-4회 정도 받는 걸 추천드려요.', '속건조에 리쥬란이 효과적인 이유와 적정 시술 시기를 피부과 전문의 정한미가 안내합니다.', array['리쥬란', '속건조', '폴리뉴클레오타이드', '피부재생', '잔주름', '콜라겐', '스킨부스터']::text[]),
    ('PDU8BZCLFSs', 'jeonghanmi', '리쥬란 맞으면 안 되는 사람도 있다는데 누가 피해야 하나요?', '피부가 극도로 예민한 상태이거나 이미 피부 컨디션이 충분히 좋은 분은 리쥬란을 피하는 게 좋습니다. 아무리 성분이 좋아도 주사를 놓는 시술이기 때문에 피부 상태가 너무 안 좋을 때는 주사 자체가 자극이 되고, 마취크림 때문에 피부가 뒤집어지기도 해요. 아무것도 안 했는데 피부가 달아오르고 따갑고 간지러운 상태라면 장벽부터 먼저 회복시킨 뒤에 고려하세요. 반대로 피부 결도 좋고 탄력도 좋고 속건조도 없는 분이 맞으면 나쁠 건 없지만 크게 효과를 못 느낄 수 있습니다. 또한 모공, 홍조, 여드름처럼 뚜렷한 트러블 해결 목적으로 리쥬란을 맞겠다고 하면 기대만큼 효과가 없을 수 있어요. 이런 경우엔 해당 증상에 맞는 레이저 시술이 더 효과적이고, 리쥬란은 보조적으로 병행하면 시너지를 낼 수 있습니다. 지금 내 피부 상태가 리쥬란에 적합한지 피부과 선생님과 상의해 보시는 게 가장 정확해요.', '리쥬란 시술을 피해야 하는 피부 상태와 적합한 대상을 피부과 전문의 정한미가 설명합니다.', array['리쥬란', '민감성피부', '피부장벽', '홍조', '모공', '시술주의사항', '피부재생']::text[]),
    ('PDU8BZCLFSs', 'jeonghanmi', '눈가 주름에 아이 리쥬란이 일반 리쥬란보다 좋은 이유가 뭔가요?', '아이 리쥬란은 일반 리쥬란보다 점성이 훨씬 묽어서 얇고 예민한 눈가 피부에 빠르게 흡수되고 붓기도 금방 빠집니다. 일반 리쥬란은 점성이 꽤 있어서 눈가에 맞으면 올록볼록한 게 오래 가는 단점이 있거든요. 눈가 잔주름이나 눈 밑 피부 탄력이 걱정되는 분들에게 아이 리쥬란이 특히 효과적이에요. 많은 분들이 다른 얼굴 부위에는 일반 리쥬란을, 눈가에는 아이 리쥬란을 함께 맞는 방식으로 시술받고 있습니다. 눈가는 보톡스로도 잔주름 해결이 잘 안 되는 부위라서 리쥬란이 좋은 대안이 될 수 있어요. 다만 리쥬란 시술 자체가 꽤 아픈 편이라 통증이 걱정되시면 마취 성분이 포함된 리쥬란 HB를 선택하면 훨씬 덜 아프게 받으실 수 있습니다. 오리지널은 마취크림을 오래 발라도 아프지만 HB는 마취크림만으로도 충분히 견딜 만해요.', '눈가 전용 아이 리쥬란의 장점과 통증 줄인 리쥬란 HB를 피부과 전문의 정한미가 소개합니다.', array['리쥬란', '아이리쥬란', '눈가주름', '잔주름', '리쥬란HB', '눈밑탄력', '피부재생']::text[]),
    ('PDU8BZCLFSs', 'jeonghanmi', '리쥬란 맞고 홍조나 모공이 좋아졌다는 후기가 많은데 진짜인가요?', '리쥬란이 모공이나 홍조를 직접 개선시키는 시술은 아니지만, 피부 재생 과정에서 전반적으로 건강해지면서 덤으로 개선되는 효과는 있을 수 있습니다. 즉 모공이나 홍조를 좋아지게 하려는 목적으로 리쥬란을 맞으면 기대만큼 효과가 없을 수 있어요. 이런 분들은 해당 증상에 맞는 레이저 같은 시술을 받는 게 더 효과적입니다. 다만 여드름이나 홍조 치료를 위해 레이저를 받고 있는 분이라도, 지금 피부 상태가 리쥬란이 필요한 상태라면 레이저와 리쥬란을 병행했을 때 시너지가 날 수 있어요. 리쥬란은 피부 재생과 회복을 돕는 영양 주사 같은 개념이라서 다른 치료의 효과를 끌어올리는 역할을 하는 거죠. 헷갈리면 피부과 선생님과 상의해서 지금 내 피부에 리쥬란이 필요한 상태인지 확인받는 게 가장 좋습니다. 무조건 맞는다고 다 좋은 건 아니에요.', '리쥬란이 모공·홍조에 직접 효과가 있는지 여부를 피부과 전문의 정한미가 정리합니다.', array['리쥬란', '홍조', '모공', '피부재생', '레이저', '시너지효과', '시술선택']::text[]),
    ('L0pu2ZMf76I', 'leedoyoung', '턱 밑이 두꺼비처럼 볼록한데 살이 아니라 침샘이라고요?', '네, 턱 밑 볼록한 부분은 살이 아니라 턱밑샘이라는 침샘인 경우가 많고, 침샘 보톡스로 간단히 해결됩니다. 많은 분들이 이걸 살로 착각하고 다이어트를 하시는데 다이어트로는 절대 빠지지 않는 부위예요. 침샘에 보톡스를 넣으면 침샘 자체가 줄어들면서 튀어나온 부분도 줄어들고 라인이 깔끔하게 개선됩니다. 특히 술을 좋아하시는 분들은 침샘이 커져 있는 경우가 많아서 효과를 확실히 보실 수 있어요. 침샘이 마비되면 침이 안 나오지 않을까 걱정하실 수 있는데, 우리 몸에는 침샘이 여러 곳에 있어서 일상 기능에는 거의 지장이 없습니다. 다만 턱밑샘은 쉬고 있을 때 침 분비를 담당하기 때문에 과하게 건들면 구강건조증이 생길 수 있어요. 그래서 시술 후 물을 충분히 마시면 됩니다.', '턱 밑 볼록함의 원인인 침샘과 보톡스 해결법을 피부과 전문의 이도영이 설명합니다.', array['침샘보톡스', '보톡스', '턱밑샘', '얼굴윤곽', '갸름', '리프팅', '구강건조']::text[]),
    ('L0pu2ZMf76I', 'leedoyoung', '입꼬리가 처져서 항상 울상인데 보톡스로 올릴 수 있나요?', '네, 입꼬리 내림근에 보톡스를 놓으면 입꼬리가 자연스럽게 살짝 올라가서 편안한 인상을 만들 수 있습니다. 표정을 안 짓고 있어도 입꼬리가 밑으로 처지는 분들은 입꼬리를 내리는 근육이 강하게 작용하는 경우거든요. 여기에 중력까지 더해지면 무표정일 때도 울상으로 보이게 됩니다. 입꼬리 내림근은 바깥쪽의 얕은 부위에 위치하고 있어서 정확한 위치에 정확한 용량을 놓으면 다른 근육에 영향 없이 자연스러운 미소를 만들 수 있어요. 부작용을 걱정하실 수 있지만, 정확한 해부학적 지식을 바탕으로 올바른 자리에 놓으면 일상생활에 전혀 지장 없습니다. 효과는 보통 4-6개월 정도 지속되고, 시술 후 3-4일 후에 서서히 나타나기 시작해서 1-2주 정도면 완전히 자리를 잡아요. 반복 시술하면 근육이 자연스럽게 작아져서 맞는 간격이 점점 길어질 수도 있습니다.', '입꼬리 처짐을 보톡스로 자연스럽게 교정하는 원리를 피부과 전문의 이도영이 안내합니다.', array['입꼬리보톡스', '보톡스', '입꼬리처짐', '울상', '표정주름', '얼굴윤곽', '마리오네트']::text[]),
    ('L0pu2ZMf76I', 'leedoyoung', '자갈턱 보톡스라는 게 있다는데 무턱에도 효과 있나요?', '네, 자갈턱 보톡스는 무턱이거나 턱이 뒤로 빠진 분, U라인 턱을 가진 분들에게 필러 맞은 것처럼 턱이 앞으로 자연스럽게 나오는 효과를 줍니다. 턱 끝에 있는 턱끝근이 과하게 수축하면 턱이 쭈글쭈글해지고 뒤로 빠져 보이는데, 여기에 보톡스 네 방을 놓으면 근육이 부드러워지면서 턱선이 세련되게 변해요. 놀라운 건 한 번도 안 맞은 분은 있어도 한 번만 맞은 분은 없다는 점입니다. 100이면 100 다시 오셔서 또 놔달라고 할 정도로 만족도가 높은 시술이에요. 옆에서 봤을 때 턱선이 예뻐지고 전체적인 인상이 세련되게 바뀌기 때문이죠. 다만 이 시술을 아는 분이 많지 않아서 직접 요청하기보다는 다른 시술을 받다가 추천받는 경우가 대부분이에요. 효과는 4-6개월 정도 유지됩니다.', '무턱·U라인에 효과적인 자갈턱 보톡스의 원리와 만족도를 피부과 전문의 이도영이 설명합니다.', array['자갈턱보톡스', '보톡스', '무턱', '턱선', '얼굴윤곽', 'V라인', '턱끝근']::text[]),
    ('L0pu2ZMf76I', 'leedoyoung', '보톡스 자주 맞으면 내성 생긴다는데 정말인가요?', '내성이 생길 수는 있지만, 요즘은 내성이 덜 생기는 제품들이 나와서 크게 걱정하지 않으셔도 됩니다. 보툴리눔 톡신은 순수 톡신 부분과 주변부 단백질로 구성되어 있는데, 이 주변 단백질에 대해 항체가 생기면서 내성이 발생하는 경우가 있어요. 내성이 생기더라도 미용적으로 효과가 없어지는 것 외에 건강상 크게 걱정할 사항은 아니고, 시간이 지나면 항체가 줄어들면서 효과가 다시 나타나기도 합니다. 제오민이나 코어톡스 같은 신제품은 주변 단백질을 제거하고 순수 톡신 성분만 사용해서 내성이 덜 생기도록 만들어졌어요. 특히 사각턱, 침샘, 승모근, 종아리처럼 고용량을 맞아야 하는 부위에는 이런 제품으로 시술받으면 내성 걱정을 거의 안 하셔도 됩니다. 일반 보톡스를 맞다가 효과가 떨어지는 느낌이 들면 제품을 바꿔보는 것도 방법이에요.', '보톡스 내성이 생기는 원리와 내성 걱정 없는 신제품을 피부과 전문의 이도영이 안내합니다.', array['보톡스', '내성', '제오민', '코어톡스', '보툴리눔톡신', '항체', '사각턱']::text[]),
    ('HmNviBaQSnU', 'gohyerim', '립스틱 테스터 입술에 발라봤는데 진짜 위험한 건가요?', '네, 립스틱 테스터를 입술에 직접 바르는 건 헤르페스 바이러스 감염 위험이 있어서 피하셔야 합니다. 2017년 미국에서 한 여성이 캘리포니아 화장품 매장에서 립스틱 테스터를 입술에 바른 뒤 단순포진에 감염되어 2,800만 원 소송을 건 사례가 실제로 있었어요. 한 연구에서 화장품 매장 테스터 립스틱을 검사했더니 헤르페스 바이러스 DNA가 발견됐고, 이 바이러스가 립스틱에서 최대 일주일까지 살아있었다고 합니다. 손등에 해보는 것도 사실 추천하지 않는데, 한국 화장품 매장 테스터를 조사한 연구에서 대장균, 폐렴균, 황색포도상구균까지 발견됐거든요. 발색 테스트를 하고 싶으면 피부에 직접 바르지 말고 매장에 있는 티슈나 면봉에 해보는 게 안전합니다. 잠깐의 편의 때문에 평생 후회할 수 있으니 일회용 도구를 꼭 사용하세요.', '립스틱 테스터의 헤르페스 감염 위험성과 안전한 사용법을 피부과 전문의 고혜림이 안내합니다.', array['헤르페스', '단순포진', '립스틱테스터', '바이러스감염', '수포', '피부감염', '위생']::text[]),
    ('HmNviBaQSnU', 'gohyerim', '입술 물집이 한 번 생기면 평생 재발한다는 게 사실인가요?', '네, 헤르페스 바이러스는 한 번 감염되면 신경절에 잠복해 있다가 면역이 떨어질 때마다 재발하는 평생 동거 바이러스입니다. 헤르페스 심플렉스 바이러스가 피부와 점막에 감염을 일으켜 주로 입술에 수포를 만드는데, 사실 몸 어디에라도 발생할 수 있어요. 피곤하거나 스트레스받거나 면역이 저하되면 잠복해 있던 바이러스가 다시 활동해서 증상을 일으킵니다. 전 세계적으로 성인 헤르페스 감염률은 90%에 달한다는 보고도 있을 정도로 매우 흔해요. 증상이 없거나 진단되지 않은 상태로 있는 경우가 많아서 실제 감염률은 더 높을 것으로 추정됩니다. 입술 문신 같은 미용 시술 후에 재발하는 경우도 많고, 수포가 입술 주변으로 번지면 딱지가 떨어진 뒤에도 흉터나 색소침착이 생길 가능성이 높아요. 감염 경로는 어릴 때 뽀뽀나 음식 같이 먹기, 전골 숟가락 공유 등 일상에서도 쉽게 옮을 수 있습니다.', '헤르페스 바이러스의 잠복·재발 메커니즘과 감염 경로를 피부과 전문의 고혜림이 설명합니다.', array['헤르페스', '단순포진', '입술물집', '바이러스', '재발', '신경절', '면역저하']::text[]),
    ('HmNviBaQSnU', 'gohyerim', '입술이 따끔거리기 시작하면 24시간이 골든타임이라는데 왜요?', '수포가 올라오기 전 입술이 간질간질하고 따끔거리는 시점에 24시간 내 먹는 항바이러스제를 처방받으면 치료 기간과 흉터 발생을 크게 줄일 수 있습니다. 이미 물집이 생긴 후에는 바르는 항바이러스 연고는 효과가 거의 없고, 먹는 약도 효과가 떨어지거든요. 보통 물집이 생기고 딱지가 되어 좋아지기까지 2주 정도나 걸리는데, 초기에 대응하면 이 기간을 상당히 단축할 수 있어요. 특히 수포가 입술 주변으로 번지면 딱지가 떨어진 뒤에도 흉터나 색소침착이 생길 가능성이 높기 때문에 빠른 치료가 중요합니다. 그래서 몸 컨디션이 안 좋으면서 입술이 간질간질해지는 느낌이 들면 바로 병원에 가시는 게 좋아요. 수포가 생긴 후에는 음식을 개인 접시에 덜어먹고, 수건도 따로 쓰고, 뽀뽀도 잠시 참아야 합니다. 아토피나 습진이 있는 분은 전신으로 퍼질 위험이 있으니 더욱 조심하세요.', '헤르페스 초기 24시간 골든타임 치료의 중요성을 피부과 전문의 고혜림이 안내합니다.', array['헤르페스', '단순포진', '골든타임', '항바이러스제', '수포', '입술물집', '색소침착']::text[]),
    ('HmNviBaQSnU', 'gohyerim', '아토피 있으면 헤르페스가 더 위험하다는 게 사실인가요?', '네, 아토피처럼 피부 장벽이 손상된 경우 헤르페스 바이러스가 전신으로 퍼지는 포진상 습진이 발생할 수 있어서 각별히 조심해야 합니다. 보통 헤르페스 감염은 입술 주변처럼 국소적으로 나타나지만, 피부 장벽이 취약한 분들은 바이러스에 대한 감염 자체가 취약해져요. 포진상 습진이 발생하면 수포와 농포, 딱지가 넓게 퍼져나가면서 발열, 가려움, 설사, 임파선 비대까지 동반될 수 있습니다. 더 무서운 건 눈에 감염되면 각막염이나 결막염이 발생하고 심하면 시력 저하까지 올 수 있다는 점이에요. 그래서 아토피나 습진이 있는 분은 수포가 생겼을 때 개인 위생을 더 철저히 하고, 눈 주변에 증상이 나타나면 즉시 안과에 가셔야 합니다. 가족 중에 입술 수포가 있는 사람이 있으면 음식, 수건을 철저히 따로 쓰고 스킨십도 피해 주세요. 특히 아이들에게 뽀뽀를 통한 전파가 흔하니 주의가 필요합니다.', '아토피 환자가 헤르페스에 더 취약한 이유와 대처법을 피부과 전문의 고혜림이 정리합니다.', array['헤르페스', '아토피', '포진상습진', '피부장벽', '각막염', '전신감염', '면역저하']::text[]),
    ('jDiAZpv8jg4', 'jeonghanmi', '내 피부 타입을 정확히 알려면 피부과를 가야 하나요?', '아니요, 피부 타입은 피부과에 가서 알려주시는 게 아니라 세안 후 2시간 관찰로 스스로 판단할 수 있습니다. 세안하고 아무것도 바르지 않은 채 2시간 뒤 피부 상태를 체크해 보세요. 굉장히 당기고 각질이 일어나면 건성인데, 건성은 보통 2시간도 못 버티고 씻자마자 건조해집니다. 얼굴 전체가 기름기가 있고 번들거리면 지성이고, T존만 기름지고 볼은 괜찮으면 복합성이에요. 전체적으로 건조하고 당기는데 기름은 도는 경우가 흔히 말하는 수분 부족형 지성 피부고요. 2시간 지났는데 특별히 불편한 게 없으면 건강한 보통 피부입니다. 여기에 화장품을 바꿀 때 쉽게 붉어지고 따갑고 뒤집어진다면 민감성을 추가로 생각할 수 있어요. 다만 피부 타입은 절대적인 게 아니라 계절이나 컨디션에 따라 바뀔 수 있으니 상황에 맞게 스킨케어를 조절하시는 게 중요합니다.', '세안 후 2시간 관찰로 피부 타입을 스스로 판단하는 방법을 피부과 전문의 정한미가 설명합니다.', array['피부타입', '건성', '지성', '복합성', '민감성피부', '스킨케어', '세안']::text[]),
    ('jDiAZpv8jg4', 'jeonghanmi', '스킨케어 바르는 순서가 헷갈리는데 정확한 규칙이 뭔가요?', '가장 물 같은 제형부터 발라서 점점 되직해지는 순으로 바르면 됩니다. 토너가 가장 묽으니 먼저 바르고, 세럼이나 에센스, 그다음 로션, 크림, 마지막이 밤 순서예요. 이렇게 하는 이유는 되직한 걸 먼저 바르면 피부에 막이 쳐져서 그다음 바르는 성분이 흡수가 안 되기 때문입니다. 로션과 크림을 꼭 둘 다 발라야 하는 건 아니고 큰 틀에서 둘 다 보습제 개념이에요. 로션만 발라도 피부가 편안하고 당기지 않으면 거기서 끝내도 되고, 부족하면 크림을 추가하면 됩니다. 5-6가지를 반드시 챙겨 발라야 한다는 건 정해진 게 아니라 본인 피부가 편안하면 최소한의 개수로 충분해요. 발랐을 때 트러블이 나지 않고 피부가 과하지 않은 조합을 찾으시는 게 핵심입니다.', '스킨케어 바르는 순서의 정확한 규칙과 최소 루틴을 피부과 전문의 정한미가 안내합니다.', array['스킨케어순서', '토너', '세럼', '로션', '크림', '보습제', '레이어링']::text[]),
    ('jDiAZpv8jg4', 'jeonghanmi', '비타민C랑 레티놀 같이 바르면 안 된다는데 사실인가요?', '화장품끼리 절대 같이 못 쓰는 상극 조합은 사실 없지만, 자극이 있는 성분끼리 합치면 자극감이 심해질 수 있어서 조심은 필요합니다. 비타민C, 레티놀, 레티날, AHA, BHA 같은 성분은 단독으로 발라도 피부에 자극을 줄 수 있는 것들이라 함께 쓰면 따갑거나 뒤집어질 수 있거든요. 하지만 피부가 건강한 분은 비타민C와 레티놀을 같이 발라도 아무 문제 없습니다. 핵심은 본인 피부 반응을 보는 거예요. 두 개 같이 발라도 증상이 없으면 계속 같이 써도 되고, 민감하거나 뒤집어지는 것 같으면 하나는 아침에, 하나는 저녁에 나눠 바르세요. 아니면 하나는 월·수·금, 하나는 화·목·토 이렇게 교차하는 방법도 있습니다. 피부 컨디션이 좋을 때는 괜찮다가도 건조하거나 안 좋을 때는 하나만 발라도 따가울 수 있으니 상태에 맞게 조절하시면 됩니다.', '비타민C와 레티놀 병용 가능 여부와 자극 줄이는 방법을 피부과 전문의 정한미가 정리합니다.', array['비타민C', '레티놀', '화장품상극', '민감성피부', 'AHA', 'BHA', '스킨케어']::text[]),
    ('jDiAZpv8jg4', 'jeonghanmi', '크림 바르면 때처럼 밀리는데 안 맞는 건가요?', '안 맞아서 쓰면 안 된다는 건 아니고, 밀리는 원인을 찾아서 해결하면 됩니다. 제품이 밀린다는 건 좋은 성분이 피부에 흡수되지 못하고 뭉쳐지는 거라 효과를 제대로 못 보는 상태예요. 가장 흔한 원인은 먼저 바른 제품과 다음 제품의 베이스가 안 맞는 경우인데, 실리콘 베이스 위에 수분 베이스를 바르면 뭉칠 수 있거든요. 두 번째는 레이어링할 때 흡수 시간을 충분히 안 주는 경우로, 하나 바르고 1-2분 정도 흡수시킨 다음 다음 제품을 바르면 해결되는 경우가 많아요. 세 번째는 단순히 양을 너무 많이 발랐을 때고, 네 번째는 피부에 각질이 많이 쌓여 있어서 같이 밀리는 경우입니다. 피부에 해를 주거나 위험한 건 아니지만 흡수가 안 되면 화장품 효과를 못 보니까 원인별로 하나씩 체크해 보세요. 특히 각질이 많지 않은지 확인하고, 바르는 시간 간격을 조절하는 것부터 시도해 보시는 걸 추천드립니다.', '크림 바를 때 때처럼 밀리는 원인 네 가지와 해결법을 피부과 전문의 정한미가 안내합니다.', array['화장품밀림', '뭉침', '스킨케어', '각질', '레이어링', '실리콘', '흡수']::text[]),
    ('HFZyhJjGGT4', 'kwonsuhyun', '피부과 의사도 비타민C 화장품 바르면 진짜 톤 밝아져요?', '네, 비타민C는 지성 피부에도 효과가 확실한 몇 안 되는 성분입니다. 피부가 두껍고 모공이 넓은 지성 피부는 다른 기능성 화장품을 발라도 번들거리고 트러블만 올라오는 경우가 많은데, 비타민C 제품은 피부톤을 화사하게 하고 피부결을 매끈하게 만들어주는 효과를 체감할 수 있어요. 처음 바를 때 따가울 수 있으니 소량으로 시작하거나 보습제와 섞어 바르면 자극감을 줄일 수 있습니다. 비타민C와 보습제 두 가지만 꾸준히 발라도 충분히 차이를 느낄 수 있고, 임신 중처럼 시술이 제한되는 시기에도 안전하게 사용할 수 있는 장점이 있어요. 피부가 예민해서 비타민C가 맞지 않는 분들은 세라마이드, 콜레스테롤, 지방산이 포함된 보습제로 피부 장벽을 먼저 강화해보세요. 장벽이 튼튼해지면 피부가 건강해지면서 자연스럽게 맑아지는 효과를 기대할 수 있습니다.', '지성 피부에도 효과적인 비타민C 화장품 사용법과 미백 관리 방법을 피부과 전문의 권수현이 안내합니다.', array['비타민C', '미백', '지성피부', '피부톤', '보습제', '세라마이드', '피부장벽']::text[]),
    ('HFZyhJjGGT4', 'kwonsuhyun', '지성 피부인데 가성비 좋게 피부 관리하려면 뭐가 최고예요?', '지성 피부라면 비싼 울쎄라나 써마지 대신 압출 스케일링부터 시작하는 게 가성비 면에서 최고입니다. 모공 속 피지를 빼주고 묵은 각질을 걷어주는 것만으로도 피부톤이 밝아지고 피부결이 매끈해지는 차이가 은근히 크거든요. 피부가 하얀 것도 중요하지만 피부 위에 있는 붉은기나 어두운기를 걷어주는 것도 밝아 보이게 하는 데 큰 역할을 합니다. 출산 후에는 여기에 레티날 크림이나 디페린 연고를 추가하면 피부결이 보들보들해지고 유분기가 잡히면서 피부톤 균일화에도 도움이 돼요. 다만 디페린 연고는 임신 중에는 사용이 불가하고, 한 달 정도 발라보면 아침 세안 시 피부 질감 변화를 느낄 수 있습니다. 비타민A 제품은 꾸준히 사용해야 효과가 누적되니 인내심을 갖고 관리해보세요.', '지성 피부의 가성비 좋은 관리법으로 압출 스케일링과 비타민A 제품 사용법을 피부과 전문의 권수현이 설명합니다.', array['압출스케일링', '지성피부', '레티날', '디페린', '피부톤', '각질관리', '모공']::text[]),
    ('HFZyhJjGGT4', 'kwonsuhyun', '백옥 주사나 미백 주사 진짜 효과 있어요?', '미백 주사의 주성분인 글루타치온과 비타민C는 항산화 물질로, 멜라닌 색소 생성을 억제하고 활성산소를 제거해서 피부를 맑게 만드는 데 도움을 줍니다. 다만 타고난 피부색을 한두 번의 시술로 완전히 바꾸는 것은 어렵고, 꾸준한 관리가 차곡차곡 쌓여야 피부톤이 점점 밝아져요. 주사 외에 레이저 토닝도 미백에 효과적인데, 강하게 한 번에 하는 게 아니라 약하게 여러 번 치료해서 피부톤을 균일하게 하고 밝게 하는 방식입니다. 피코토닝이나 큐스위치 엔디야그 레이저 토닝이 대표적이고, 작은 잡티들도 이 시술로 차츰 옅게 만들면 전체 피부톤이 밝아지는 효과를 기대할 수 있어요. 피부가 하얗고 맑은 사람들의 공통점은 잡티가 없다는 것이니, 잡티 제거에도 신경 쓰시는 게 좋습니다.', '미백 주사의 실제 효과와 레이저 토닝으로 피부톤을 밝히는 방법을 피부과 전문의 권수현이 정리합니다.', array['미백주사', '글루타치온', '레이저토닝', '피코토닝', '멜라닌', '잡티', '항산화']::text[]),
    ('HFZyhJjGGT4', 'kwonsuhyun', '선크림 하루에 한 번 바르면 충분하지 않나요?', '아닙니다. 선크림은 바르고 2-3시간이 지나면 거의 다 지워져서 자외선 차단 역할을 못하기 때문에 덧바르는 게 정말 중요합니다. 제대로 된 양은 얼굴 한 면에 손가락 한 마디를 가득 채울 만큼인데, 이 정도를 발라야 효과를 볼 수 있어요. 실내에서는 크게 상관없지만 여름철 야외 활동이나 물놀이 시에는 워터프루프 선크림을 지속적으로 덧발라 주셔야 합니다. 피부 미백을 원하면서 자외선 차단을 소홀히 하는 건 물을 퍼내면서 구멍을 막지 않는 것과 같아요. 선크림 외에 나이아신아마이드(비타민B3) 성분이 든 화장품도 미백에 도움이 되고, 항산화 효과가 있는 키위, 오렌지, 브로콜리, 빨간 파프리카 같은 음식을 충분히 섭취하는 것도 피부를 맑게 유지하는 데 기여합니다.', '선크림 덧바르기의 중요성과 올바른 사용량을 포함한 미백 습관을 피부과 전문의 권수현이 안내합니다.', array['선크림', '자외선차단', '나이아신아마이드', '덧바르기', '미백', '워터프루프', '항산화']::text[]),
    ('WN957NjRQ8I', 'jeonghanmi', '아침에 물 세안만 하면 진짜 피부에 좋은 건가요?', '아닙니다. 아침에도 클렌저를 사용해서 세안하는 게 좋습니다. 잠자는 동안 베개나 이불에 묻어있는 먼지와 노폐물이 얼굴에 옮겨오고, 피부에서도 피지와 땀이 배출되거든요. 이런 것들은 기름 성분이기 때문에 물로만 세안해서는 깨끗하게 씻기지 않습니다. 다만 아침에는 너무 강한 세안제를 쓸 필요는 없어서 순한 약산성 폼클렌저 정도면 충분해요. 밤 사이 배출된 피지가 그대로 남아있으면 모공을 막거나 피부 트러블의 원인이 될 수 있으니 가볍게라도 세안제를 사용하시는 걸 권합니다. 클렌징은 스킨케어에서 가장 기본이 되는 단계이니 아침 세안을 간과하지 마세요.', '아침 물 세안만으로 충분한지와 올바른 아침 클렌징 방법을 피부과 전문의 정한미가 설명합니다.', array['아침세안', '클렌저', '폼클렌저', '약산성', '피지', '스킨케어', '세안법']::text[]),
    ('WN957NjRQ8I', 'jeonghanmi', '선크림 바른 날 이중세안 꼭 해야 하나요?', '사용하는 선크림 종류에 따라 다릅니다. 확인하는 방법은 간단한데, 바르고 있는 선크림을 손등에 발라보고 폼클렌저로 씻어보세요. 언뜻 보면 깨끗한 것 같아도 주름 사이사이에 잔여물이 남아있다면 폼클렌저만으로는 부족한 거예요. 그 경우에는 클렌징 오일이나 밀크로 1차 세안을 한 뒤 폼클렌저로 2차 세안을 해줘야 합니다. 반대로 이지워시 타입이거나 물리적 차단제가 들어있지 않고 오일리하지 않은 선크림이라면 폼클렌저 하나만으로도 충분히 세정될 수 있어요. 무조건 이중세안을 해야 한다거나 하지 말아야 한다가 아니라, 본인이 쓰는 제품에 맞게 판단하시면 됩니다.', '선크림 사용 후 이중세안 필요 여부를 판단하는 테스트 방법을 피부과 전문의 정한미가 안내합니다.', array['이중세안', '선크림', '클렌징오일', '폼클렌저', '세안법', '자외선차단제']::text[]),
    ('WN957NjRQ8I', 'jeonghanmi', '홈케어 디바이스 진짜 효과 있어요? 써도 되나요?', '네, 홈케어 디바이스는 써도 됩니다. 초음파, 고주파, 갈바닉 같은 기기들은 병원 장비만큼 출력이 강하지 않아서 집에서 적절히 사용하면 제품 흡수를 도와주고 보습 효과를 높이는 데 도움이 될 수 있어요. 다만 주의할 점이 하나 있는데, 흡수시킬 화장품이 피부에 자극을 줄 수 있는 제품이라면 디바이스 사용을 조심해야 합니다. 그냥 바르기만 해도 자극이 되는 제품인데 도구를 써서 흡수가 더 많이 되면 당연히 자극감도 증가하거든요. 그래서 자극성 있는 성분의 화장품과 함께 쓸 때는 주의가 필요하고, 같이 썼을 때 특별한 문제가 없다면 계속 사용하셔도 괜찮습니다. 기기를 쓴다고 해서 부작용이 생기는 건 아니니 너무 겁내지 마세요.', '홈케어 디바이스의 효과와 사용 시 주의사항을 피부과 전문의 정한미가 정리합니다.', array['홈케어디바이스', '초음파', '고주파', '갈바닉', '스킨케어', '제품흡수']::text[]),
    ('WN957NjRQ8I', 'jeonghanmi', '코 모공이 넓고 피지가 계속 끼는데 코팩 자주 해도 돼요?', '코팩이나 모공 브러시로 반복적으로 피지를 빼는 건 근본적인 해결이 아니라 오히려 피부에 자극을 줄 수 있습니다. T존 부위는 피지샘이 발달해서 모공이 넓고 피지가 많이 분비되는 게 정상이에요. 일시적으로 깨끗해진 느낌이 나도 시간이 지나면 다시 피지가 차기 때문에 과도하게 빼주는 건 해결책이 되지 못합니다. 더 효과적인 방법은 피지를 줄여주는 성분이 든 화장품을 사용하거나, 그래도 해결이 안 되면 피지샘 크기를 줄여줄 수 있는 레이저 시술을 받는 거예요. 무조건 깨끗하게 씻어내는 것보다 피지 분비 자체를 조절하는 쪽으로 접근하시는 게 장기적으로 훨씬 좋습니다. 코 모공이 넓은 건 자연스러운 현상이니 너무 스트레스 받지 마세요.', '코 모공 피지 관리에서 코팩 대신 효과적인 해결법을 피부과 전문의 정한미가 설명합니다.', array['코모공', '피지', '코팩', 'T존', '모공관리', '피지샘', '레이저']::text[]),
    ('ohLthnwZ4XQ', 'parkhyojin', '스컬트라가 필러보다 좋다는데, 둘의 차이가 정확히 뭐예요?', '스컬트라와 필러는 목적 자체가 다릅니다. 필러는 젤리 같은 덩어리를 직접 넣어서 즉시 볼륨을 만드는 반면, 스컬트라는 콜라겐 씨앗을 피부에 심어 몸이 스스로 볼륨을 만들도록 유도하는 시술이에요. 필러는 다이나믹하게 볼륨이 바로 필요한 분이나, 사고로 국소적으로 패인 부분을 정확한 모양으로 채워야 할 때 적합합니다. 스컬트라는 앞볼이나 뒷볼처럼 넓은 범위를 자연스럽게 채우고 싶거나, 필러의 이물감에 거부감이 있는 분들이 선호하죠. 스컬트라의 추가 장점은 콜라겐 생성을 유도하다 보니 피부 자체가 윤기 나고 건강해 보이는 효과까지 함께 얻을 수 있다는 것입니다. 전체적으로 자연스럽게 예뻐지고 싶은 분이라면 스컬트라가, 정확한 포인트에 즉각적인 볼륨이 필요한 분이라면 필러가 맞습니다.', '스컬트라와 필러의 차이점 및 각 시술이 적합한 대상을 피부과 전문의 박효진이 설명합니다.', array['스컬트라', '필러', '콜라겐', '볼륨', '동안', '이물감', '볼꺼짐']::text[]),
    ('ohLthnwZ4XQ', 'parkhyojin', '스컬트라 결절 부작용이 무서운데 안전한 거 맞아요?', '결절은 아주 드물게 생길 수 있지만, 요즘에는 희석 비율이 표준화되어 거의 걱정하지 않아도 됩니다. 예전에는 스컬트라 가루를 생리식염수에 녹이는 수화 과정에서 비율을 잘못 맞추거나 골고루 녹이지 못해 한쪽에 가루가 뭉치면서 염증이 과하게 일어나 결절로 이어지는 경우가 있었어요. 하지만 현재는 표준화된 희석 방법을 사용하고, 시술자가 피부 여러 층에 소량씩 나눠 주입하는 기법이 확립돼서 매우 안전합니다. 환자분도 시술 후 5-5-5 룰(5일간 하루 5번 5분 마사지)을 지키면 가루가 고르게 퍼져서 효과도 좋고 결절 예방에도 도움이 돼요. 스컬트라는 미국 FDA 승인을 받은 지도 매우 오래된 시술이고, 원래 에이즈 환자의 안면 위축 치료용으로 개발된 만큼 안전성이 검증되어 있습니다.', '스컬트라 결절 부작용의 원인과 현재 안전하게 시술하는 방법을 피부과 전문의 박효진이 안내합니다.', array['스컬트라', '결절', '부작용', '수화', '마사지', 'FDA', '콜라겐']::text[]),
    ('ohLthnwZ4XQ', 'parkhyojin', '스컬트라 맞고 나서 효과가 바로 사라지는 건 정상인가요?', '네, 시술 직후 볼륨이 2-3일 만에 꺼지는 건 완전히 정상적인 과정입니다. 스컬트라 시술 시 가루를 생리식염수에 녹여서 주입하는데, 직후에 보이는 볼륨은 이 식염수 때문에 생긴 일시적인 효과예요. 체내에 흡수되면서 2-3일이면 다 꺼져버리고 일주일 뒤에는 원래대로 돌아온 것처럼 느껴질 수 있습니다. 하지만 실제로는 2-3주부터 콜라겐이 생성되기 시작해서, 2-3개월 뒤에는 확연한 볼륨을 체감할 수 있어요. 보통 4주 간격으로 3회 시술을 권하는데, 반복할수록 콜라겐 생성이 증대되어 최종적으로 6개월 후에는 자연스러운 볼륨이 완성됩니다. 효과는 우리 몸이 직접 만든 콜라겐이라 2-3년 정도 유지되는 것이 최대 장점이에요.', '스컬트라 시술 후 효과 발현 시기와 2-3년 유지되는 원리를 피부과 전문의 박효진이 정리합니다.', array['스컬트라', '효과기간', '콜라겐', '볼륨', '유지기간', '시술횟수']::text[]),
    ('ohLthnwZ4XQ', 'parkhyojin', '스컬트라 시술할 때 많이 아파요? 일상생활 바로 가능한가요?', '통증은 거의 없고 일상생활도 바로 가능합니다. 스컬트라는 바늘로 콕콕 찌르는 게 아니라, 볼류마이징할 부위에 양쪽으로 한 포인트씩만 주사로 구멍을 뚫어요. 이때 국소마취 주사가 한 번 따끔한 정도이고, 그 뒤로는 케뉼라(끝이 뭉뚱한 긴 관)를 구멍으로 넣어서 스컬트라를 뿌리기 때문에 불편한 느낌은 있을 수 있지만 지속적인 통증은 없습니다. 시술 후 주사 부위에 멍이 살짝 들 수 있으나 2-3일이면 거의 사라지고, 가족도 말하지 않으면 모를 정도예요. 다만 스컬트라는 수화 과정에 2-3일이 필요하기 때문에 당일 시술은 불가능하고, 미리 상담 후 예약을 잡아야 합니다. 다운타임이 거의 없어서 직장인도 부담 없이 받을 수 있는 시술이에요.', '스컬트라 시술의 통증 정도와 다운타임, 시술 전 준비사항을 피부과 전문의 박효진이 안내합니다.', array['스컬트라', '통증', '케뉼라', '다운타임', '멍', '시술과정', '국소마취']::text[]),
    ('7ZAB6oEn6s8', 'jeonghanmi', '리프팅 시술 받다가 중단하면 오히려 더 처지나요?', '아닙니다, 이건 흔한 오해예요. 리프팅 효과가 영구적일 거라고 기대하기 때문에 시간이 지나 다시 처지면 시술 전보다 더 나빠졌다고 느끼는 것뿐입니다. 실제로는 리프팅을 받고 나서도 우리 피부는 계속 노화가 진행되고 있기 때문에, 리프팅을 하고 더 처진 게 아니라 그거라도 안 했으면 더 빨리 노화가 왔을 거예요. 피부과에서 기계로 하는 리프팅은 세월을 10-20년 거스르려는 게 아니라, 지금 내 모습에서 좀 더 천천히 늙으려는 시술이라고 이해해야 합니다. 그래서 한 번 받고 끝이 아니라 꾸준한 치료와 홈케어가 함께 필요한 거죠. 리프팅을 안 받겠다고 결정하기보다는 속도를 늦추는 관리라고 생각하시면 됩니다.', '리프팅을 중단해도 더 처지지는 않습니다. 시술 효과가 사라지면 원래 노화 속도로 돌아갈 뿐이라는 오해와 진실을 피부과 전문의 정한미가 바로잡습니다.', array['리프팅', '노화', '처짐', '안티에이징', '울쎄라', '써마지', '유지관리']::text[]),
    ('7ZAB6oEn6s8', 'jeonghanmi', '보톡스 효과가 없는 것 같은데 내성이 생긴 건가요?', '보톡스 내성은 실제로 매우 드물고, 효과가 없다고 느끼는 대부분의 원인은 용량 부족입니다. 충분한 용량을 놓아주거나 리터치를 하면 다시 효과를 보시는 경우가 많아요. 만약 정말 내성이 생겼다면 특정 부위만이 아니라 어딜 맞아도 효과가 없어지는데, 이는 몸이 보톡스에 대한 항체를 만들어 전신을 돌아다니기 때문입니다. 스킨보톡스든 종아리 보톡스든 같은 보툴리눔 톡신을 쓰기 때문에 마찬가지로 효과가 없어져요. 내성을 예방하려면 시술 간격을 잘 지키고 너무 자주 맞지 않는 게 중요합니다. 제오민이나 코어톡스처럼 내성을 줄여주는 제품도 있으니 걱정되는 분들은 이런 제품을 선택해보세요.', '보톡스 효과가 없다면 내성보다 용량 부족이 원인일 가능성이 높습니다. 항체 형성 원리와 제오민·코어톡스 대안까지 피부과 전문의 정한미가 설명합니다.', array['보톡스', '내성', '용량부족', '항체', '제오민', '코어톡스', '스킨보톡스']::text[]),
    ('7ZAB6oEn6s8', 'jeonghanmi', '써마지 300샷이랑 600샷 차이가 큰가요? 적게 맞아도 되나요?', '한 번에 충분한 에너지를 주는 것이 나눠서 여러 번 하는 것보다 효과적입니다. 써마지는 진피층에 열을 주는 원리인데, 이걸 물 끓이기에 비유하면 3분 동안 쭉 끓인 물은 끓지만, 1분 끓이고 쉬고를 반복하면 같은 시간 에너지를 줘도 물이 끓지 않는 것과 같아요. 과학적으로 확정된 근거는 아니지만, 샷 수를 나눠서 약하게 여러 번 하는 것보다 한 번에 충분히 주고 재생을 시키는 게 효과가 더 좋다고 봅니다. 실제로 외국에서는 600샷보다 900샷을 훨씬 더 선호한다고 하고요. 물론 얼굴 크기와 처진 정도에 따라 달라질 수 있고 선생님마다 의견이 다를 수 있지만, 맛보기로 적은 샷 수만 받는 건 비용 대비 효과가 떨어질 수 있습니다.', '써마지는 한 번에 충분한 에너지를 주는 것이 나눠서 약하게 하는 것보다 효과적입니다. 300샷 vs 600샷 차이와 적정 샷 수 기준을 피부과 전문의 정한미가 안내합니다.', array['써마지', '리프팅', '샷수', '고주파', '콜라겐', '진피', '에너지']::text[]),
    ('7ZAB6oEn6s8', 'jeonghanmi', '리프팅 시술 후에 관리 안 하면 돈 버리는 건가요?', '맞습니다. 시술 후 자외선 차단을 안 하면 아무 소용이 없고 돈을 버리는 것과 같아요. 리프팅 시술 후 관리에서 가장 중요한 첫 번째는 자외선 차단입니다. 햇빛을 안 가리면 시술 효과가 빠르게 사라지기 때문에 환자분들께 항상 강조하는 부분이에요. 두 번째로는 안티에이징 시술 효과를 오래 유지하고 싶다면 비타민C, 레티놀, 레티날 같은 항산화 화장품을 꾸준히 바르는 게 도움이 됩니다. 비타민을 먹는 것도 항산화에 기여하니 함께 챙기시면 좋죠. 또한 얼굴에 살이 없어서 리프팅을 못 받는다고 생각하는 분들이 많은데, 턱 라인 처짐이나 팔자주름 부위에 집중 디자인해서 시술하면 충분히 가능하니 무조건 포기하지 마세요.', '리프팅 후 자외선 차단을 안 하면 시술 효과가 빠르게 사라집니다. 비타민C·레티놀 홈케어와 시술 효과 유지법을 피부과 전문의 정한미가 정리합니다.', array['리프팅', '시술후관리', '자외선차단', '레티놀', '비타민C', '안티에이징', '볼꺼짐']::text[]),
    ('BZ4T5UM-EFY', 'kimsoohyung', '상처에 빨간약(포비돈) 계속 바르면 안 되나요?', '빨간약(포비돈)을 반복해서 바르면 세균뿐 아니라 피부 재생을 돕는 세포까지 파괴시켜 오히려 상처가 아무는 시간이 길어집니다. 포비돈은 세균을 죽이는 효과가 강력해서 수술 전 소독에도 사용하는 약이지만, 밴드를 갈 때마다 매일 바르는 건 전혀 다른 문제예요. 처음 다쳤을 때 감염 위험이 있는 상황에서 최초 1회만 사용하시는 게 맞습니다. 과산화수소수도 마찬가지로 처음 피를 닦아낼 때만 쓰고 반복 사용하지 마세요. 참고로 포비돈은 피부에 갈색 착색이 될 수 있어서 바른 후에는 생리식염수로 꼭 닦아주는 게 좋습니다. 소독약이 없는 상황이라면 흐르는 깨끗한 수돗물로 충분히 씻어주시면 됩니다.', '빨간약을 반복 사용하면 안 되는 이유와 올바른 상처 초기 소독법을 피부과 전문의 김수형이 설명합니다.', array['빨간약', '포비돈', '상처소독', '과산화수소', '상처관리', '감염예방', '생리식염수']::text[]),
    ('BZ4T5UM-EFY', 'kimsoohyung', '상처에 마데카솔이랑 에스로반 중 뭘 발라야 해요?', '감염 위험이 있는 상처에는 에스로반, 감염 위험이 없는 가벼운 상처에는 마데카솔을 바르면 됩니다. 에스로반과 후시딘은 항생제만 들어있는 연고이고, 마데카솔은 항생제에 피부 재생을 돕는 병풀추출물이 추가된 복합 제재예요. 균을 죽이는 힘은 항생제 단독 연고가 더 강하기 때문에 소독 직후에는 에스로반이 좋습니다. 후시딘은 내성이 있는 균이 많아서 세균이 잘 안 죽는 경우가 있어 에스로반을 더 추천해요. 항생제 연고는 하루 2-3번, 마데카솔 같은 재생 연고는 하루 3-4번 좀 더 자주 발라주시는 게 효과적입니다. 마데카솔은 콜라겐 합성을 촉진하는 재생 연고에 가깝기 때문에 깊지 않고 감염 위험이 없는 살짝 베이거나 까진 상처에 적합합니다.', '상처 상태에 따른 에스로반과 마데카솔의 올바른 선택 기준을 피부과 전문의 김수형이 안내합니다.', array['마데카솔', '에스로반', '후시딘', '항생제연고', '상처연고', '병풀추출물', '재생연고']::text[]),
    ('BZ4T5UM-EFY', 'kimsoohyung', '상처에 딱지가 생겨야 빨리 낫는 거 아닌가요?', '아닙니다, 딱지가 생기면 오히려 상처 치유가 더 느려집니다. 딱지는 진물이나 피가 마르면서 생기는 껍질인데, 진물 안에 있는 상처 치유를 돕는 물질들까지 굳어서 회복을 방해하고 새살이 올라오는 것도 더뎌져요. 새살이 못 올라오면 당연히 흉터가 더 많이 남게 됩니다. 실제로 병원에서는 상처가 잘 안 나을 때 일부러 딱지를 뜯어내기도 해요. 딱지를 방지하려면 상처가 마르지 않게 드레싱으로 덮어줘야 합니다. 거즈, 메디폼, 듀오덤 세 가지가 대표적인데 상처 크기와 진물 양에 맞게 선택하세요. 진물이 많으면 메디폼, 작은 상처나 진물이 줄어든 단계면 듀오덤, 움직임 많은 부위면 연고를 충분히 바른 뒤 거즈가 적합합니다.', '딱지가 오히려 상처 회복을 방해하는 이유와 올바른 드레싱 방법을 피부과 전문의 김수형이 정리합니다.', array['딱지', '습윤드레싱', '듀오덤', '메디폼', '거즈', '상처치유', '흉터예방']::text[]),
    ('BZ4T5UM-EFY', 'kimsoohyung', '이미 생긴 흉터, 연고로도 없앨 수 있나요?', '흉터 연고를 꾸준히 2-3개월 이상 바르면 확연히 옅어질 수 있습니다. 흉터 치료의 골든타임은 상처 발생 후 2개월 이내에 시작하는 것이고, 보통 상처가 아물고 1-2주 후부터 흉터 연고를 사용하면 돼요. 흉터 연고는 크게 양파추출물 계열과 실리콘 계열 두 가지가 있습니다. 양파추출물 연고(콘투락투벡스겔, 노스카나겔 등)는 흉터를 부드럽게 하고 붉은기를 빼주는 효과가 있어서 패이거나 붉은 흉터에 좋고, 실리콘 연고(더마틱스 울트라겔 등)는 흉터를 편평하게 만들어줘서 튀어나온 봉합 흉터나 켈로이드에 적합합니다. 양파추출물 연고는 마사지하듯 문질러 흡수시키고, 실리콘은 덧바르듯 발라주세요. 레이저(브이빔+프랙셔널)를 병행하면 효과가 더 좋으니 전문의 상담도 받아보시길 권합니다.', '흉터 연고의 종류별 사용법과 레이저 병행 치료 효과를 피부과 전문의 김수형이 안내합니다.', array['흉터연고', '콘투락투벡스', '실리콘연고', '브이빔', '프랙셔널레이저', '흉터치료', '켈로이드']::text[])
)
insert into public.qas (video_id, doctor_id, question, answer, meta, keywords, published)
select v.id, d.id, nq.question, nq.answer, nq.meta, nq.keywords, true
from new_qas nq
join public.videos  v on v.youtube_id = nq.youtube_id
join public.doctors d on d.slug = nq.doctor_slug
where not exists (
  select 1 from public.qas q
  where q.video_id = v.id and q.question = nq.question
);
